import { PublicCard } from '../../../types';

export const technologyCards: PublicCard[] = [
  { id: 'dc-technology-0001', deck_id: 'deck-technology', sort_order: 1, front: "Array", back: "A data structure storing elements of the same type in contiguous memory locations. Supports O(1) random access by index but O(n) insertion/deletion in the middle. Most fundamental data structure." , front_translations: {"es":"Array","it":"Array","de":"Array","fr":"Tableau (Array)","tr":"Dizi (Array)","nl":"Array","ru":"Массив","zh":"数组","pt_BR":"Array","pt_PT":"Array"}, back_translations: {"es":"Una estructura de datos que almacena elementos del mismo tipo en ubicaciones de memoria contiguos. Suporta acceso aleatório El(1) por índice, pero inserción/exclusão en el medio en El(n). La estructura de datos más fundamental.","it":"Una structure di donnees stockant dei elements del stesso type in dei emplacements memoire contigus. Acces aleatoire en O(1) per index, ma inserzione/suppression al milieu en O(n). Structure di donnees la più fondamentale.","de":"Eine Datenstruktur, die Elemente des gleichen Typs an zusammenhängenden Speicheradressen speichert. Unterstützt O(1) Direktzugriff per Index, aber O(n) beim Einfügen/Löschen in der Mitte. Die grundlegendste Datenstruktur.","fr":"Une structure de données stockant des éléments du même type dans des emplacements mémoire contigus. Accès aléatoire en O(1) par index, mais insertion/suppression au milieu en O(n). Structure de données la plus fondamentale.","tr":"Aynı türdeki elemanları ardışık bellek konumlarında depolayan bir veri yapısı. İndeks ile O(1) rastgele erişimi destekler, ancak ortaya ekleme/silme O(n) sürer. En temel veri yapısıdır.","nl":"Een datastructuur die elementen van hetzelfde type op aaneengesloten geheugenlocaties opslaat. Ondersteunt O(1) willekeurige toegang via index, maar O(n) voor invoegen/verwijderen in het midden. Meest fundamentele datastructuur.","ru":"Структура данных, хранящая элементы одного типа в смежных ячейках памяти. Поддерживает O(1) произвольный доступ по индексу, но O(n) для вставки/удаления в середине. Самая фундаментальная структура данных.","zh":"一种将相同类型的元素存储在连续内存位置的数据结构。支持通过索引进行O(1)随机访问，但在中间插入/删除为O(n)。最基本的数据结构。","pt_BR":"Uma estrutura de dados que armazena elementos do mesmo tipo em locais de memória contíguos. Suporta acesso aleatório O(1) por índice, mas inserção/exclusão no meio em O(n). A estrutura de dados mais fundamental.","pt_PT":"Uma estrutura de dados que armazena elementos do mesmo tipo em localizações de memória contíguas. Suporta acesso aleatório O(1) por índice, mas inserção/eliminação no meio em O(n). A estrutura de dados mais fundamental."}},
  { id: 'dc-technology-0002', deck_id: 'deck-technology', sort_order: 2, front: "Linked List", back: "A data structure of nodes where each node contains data and a pointer to the next node. O(1) insertion/deletion at known positions but O(n) access by index. No contiguous memory required." , front_translations: {"es":"Lista Ligada","it":"Lista concatenata","de":"Verkettete Liste","fr":"Liste chaînée","tr":"Bağlı Liste","nl":"Gelinkte lijst","ru":"Связный список","zh":"链表","pt_BR":"Lista Ligada","pt_PT":"Lista Ligada"}, back_translations: {"es":"Una estructura de datos de nós donde cada nó contiene datos y un pontero para el próximo nó. Inserción/exclusão en El(1) en posiciones conocidas, pero acceso por índice en El(n). No requiere memoria contigua.","it":"Una structure di donnees compostoe di nœuds où ogni nœud contiene dei donnees e un pointore verso il nœud suivant. Inserzione/suppression en O(1) à dei posizioni connues, ma acces per index en O(n). Aucune memoire contigue requise.","de":"Eine Datenstruktur aus Knoten, wobei jeder Knoten Daten und einen Zeiger auf den nächsten Knoten enthält. O(1) Einfügen/Löschen an bekannten Positionen, aber O(n) Zugriff per Index. Kein zusammenhängender Speicher erforderlich.","fr":"Une structure de données composée de nœuds où chaque nœud contient des données et un pointeur vers le nœud suivant. Insertion/suppression en O(1) à des positions connues, mais accès par index en O(n). Aucune mémoire contiguë requise.","tr":"Her düğümün veri ve bir sonraki düğüme işaretçi içerdiği düğümlerden oluşan bir veri yapısı. Bilinen konumlarda O(1) ekleme/silme, ancak indeks ile erişim O(n). Ardışık bellek gerektirmez.","nl":"Een datastructuur van knopen waarbij elke knoop gegevens en een verwijzing naar de volgende knoop bevat. O(1) invoegen/verwijderen op bekende posities, maar O(n) toegang via index. Geen aaneengesloten geheugen vereist.","ru":"Структура данных из узлов, где каждый узел содержит данные и указатель на следующий узел. O(1) вставка/удаление в известных позициях, но O(n) доступ по индексу. Не требует смежной памяти.","zh":"由节点组成的数据结构，每个节点包含数据和指向下一个节点的指针。在已知位置插入/删除为O(1)，但按索引访问为O(n)。不需要连续内存。","pt_BR":"Uma estrutura de dados de nós onde cada nó contém dados e um ponteiro para o próximo nó. Inserção/exclusão em O(1) em posições conhecidas, mas acesso por índice em O(n). Não requer memória contígua.","pt_PT":"Uma estrutura de dados de nós onde cada nó contém dados e um apontador para o nó seguinte. Inserção/eliminação em O(1) em posições conhecidas, mas acesso por índice em O(n). Não requer memória contígua."}},
  { id: 'dc-technology-0003', deck_id: 'deck-technology', sort_order: 3, front: "Doubly Linked List", back: "A linked list where each node has pointers to both the next and previous nodes. Allows O(1) traversal in both directions and efficient deletion of any known node. Uses more memory than singly linked list." , front_translations: {"es":"Lista Duplamente Ligada","it":"Liste doublemento chainee","de":"Doppelt verkettete Liste","fr":"Liste doublement chaînée","tr":"Çift Yönlü Bağlı Liste","nl":"Dubbel gelinkte lijst","ru":"Двусвязный список","zh":"双向链表","pt_BR":"Lista Duplamente Ligada","pt_PT":"Lista Duplamente Ligada"}, back_translations: {"es":"Una lista ligada donde cada nó tiene ponteros para el próximo y el anterior. Permite travessia El(1) en ambas las direcciones y exclusão eficiente de cualquier nó conocido. Usa más memoria que a lista simplemente ligada.","it":"Una liste chainee où ogni nœud possedi dei pointori verso il nœud suivant e il nœud precedent. Permet una traversee en O(1) in i deux sens e la suppression efficace di tutto nœud conosciuto. Utilise più di memoire che una liste simplement chainee.","de":"Eine verkettete Liste, bei der jeder Knoten Zeiger auf den nächsten und den vorherigen Knoten hat. Ermöglicht O(1) Traversierung in beide Richtungen und effizientes Löschen beliebiger bekannter Knoten. Verbraucht mehr Speicher als einfach verkettete Liste.","fr":"Une liste chaînée où chaque nœud possède des pointeurs vers le nœud suivant et le nœud précédent. Permet une traversée en O(1) dans les deux sens et la suppression efficace de tout nœud connu. Utilise plus de mémoire qu'une liste simplement chaînée.","tr":"Her düğümün hem sonraki hem de önceki düğüme işaretçi içerdiği bir bağlı liste. Her iki yönde O(1) geçiş ve bilinen herhangi bir düğümün verimli silinmesine olanak tanır. Tek bağlı listeden daha fazla bellek kullanır.","nl":"Een gelinkte lijst waarbij elke knoop verwijzingen heeft naar zowel de volgende als de vorige knoop. Maakt O(1) doorloop in beide richtingen mogelijk en efficiënt verwijderen van elke bekende knoop. Gebruikt meer geheugen dan enkelvoudig gelinkte lijst.","ru":"Связный список, в котором каждый узел имеет указатели на следующий и предыдущий узлы. Позволяет O(1) обход в обоих направлениях и эффективное удаление любого известного узла. Использует больше памяти, чем односвязный список.","zh":"每个节点同时拥有指向下一个和前一个节点指针的链表。允许在两个方向上以O(1)遍历，并能高效删除任意已知节点。比单向链表占用更多内存。","pt_BR":"Uma lista ligada onde cada nó tem ponteiros para o próximo e o anterior. Permite travessia O(1) em ambas as direções e exclusão eficiente de qualquer nó conhecido. Usa mais memória que a lista simplesmente ligada.","pt_PT":"Uma lista ligada onde cada nó tem apontadores para o próximo e o anterior. Permite travessia O(1) em ambas as direções e eliminação eficiente de qualquer nó conhecido. Usa mais memória que a lista simplesmente ligada."}},
  { id: 'dc-technology-0004', deck_id: 'deck-technology', sort_order: 4, front: "Stack", back: "A Last-In-First-Out (LIFO) data structure. Operations: push (add to top), pop (remove from top), peek (view top). Used for function call stacks, undo operations, and expression evaluation." , front_translations: {"es":"Pilha (Stack)","it":"Pila (stack)","de":"Stapel (Stack)","fr":"Pile (Stack)","tr":"Yığın (Stack)","nl":"Stapel (Stack)","ru":"Стек","zh":"栈","pt_BR":"Pilha (Stack)","pt_PT":"Pilha (Stack)"}, back_translations: {"es":"Una estructura de datos Last-In-First-Out (LIFO). Operaciones: push (adicionar al topo), pop (remover del topo), peek (visualizar topo). Usada para pilhas de llamadas de función, operaciones de desfazer y avaliación de expresiones.","it":"Una structure di donnees Last-In-First-Out (LIFO). Operazioni : push (ajouter al sommet), pop (retirer del sommet), peek (voir il sommet). Utilisee per i piles d'appels di fonczioni, i operazioni d'annulazione e l'evaluazione d'expressions.","de":"Eine Last-In-First-Out (LIFO) Datenstruktur. Operationen: push (oben hinzufügen), pop (oben entfernen), peek (oben ansehen). Verwendet für Funktionsaufruf-Stacks, Rückgängig-Operationen und Ausdrucksauswertung.","fr":"Une structure de données Last-In-First-Out (LIFO). Opérations : push (ajouter au sommet), pop (retirer du sommet), peek (voir le sommet). Utilisée pour les piles d'appels de fonctions, les opérations d'annulation et l'évaluation d'expressions.","tr":"Son Giren İlk Çıkar (LIFO) veri yapısı. İşlemler: push (üste ekle), pop (üstten çıkar), peek (üstü görüntüle). Fonksiyon çağrı yığınları, geri alma işlemleri ve ifade değerlendirmesi için kullanılır.","nl":"Een Last-In-First-Out (LIFO) datastructuur. Bewerkingen: push (bovenaan toevoegen), pop (bovenaan verwijderen), peek (bovenaan bekijken). Gebruikt voor functie-aanroepstapels, ongedaan maken en expressie-evaluatie.","ru":"Структура данных «последним пришёл — первым ушёл» (LIFO). Операции: push (добавить на вершину), pop (удалить с вершины), peek (просмотреть вершину). Используется для стеков вызовов, отмены операций и вычисления выражений.","zh":"后进先出（LIFO）数据结构。操作：push（添加到顶部）、pop（从顶部移除）、peek（查看顶部）。用于函数调用栈、撤销操作和表达式求值。","pt_BR":"Uma estrutura de dados Last-In-First-Out (LIFO). Operações: push (adicionar ao topo), pop (remover do topo), peek (visualizar topo). Usada para pilhas de chamadas de função, operações de desfazer e avaliação de expressões.","pt_PT":"Uma estrutura de dados Last-In-First-Out (LIFO). Operações: push (adicionar ao topo), pop (remover do topo), peek (ver o topo). Usada para pilhas de chamadas de função, operações de desfazer e avaliação de expressões."}},
  { id: 'dc-technology-0005', deck_id: 'deck-technology', sort_order: 5, front: "Queue", back: "A First-In-First-Out (FIFO) data structure. Operations: enqueue (add to rear), dequeue (remove from front). Used for task scheduling, BFS, and print queues. Deque supports both ends." , front_translations: {"es":"Fila (Queue)","it":"Coda (queue)","de":"Warteschlange (Queue)","fr":"File d'attente (Queue)","tr":"Kuyruk (Queue)","nl":"Wachtrij (Queue)","ru":"Очередь","zh":"队列","pt_BR":"Fila (Queue)","pt_PT":"Fila (Queue)"}, back_translations: {"es":"Una estructura de datos First-In-First-Out (FIFO). Operaciones: enqueue (adicionar en la trasera), dequeue (remover de la frente). Usada para escalonamento de tarefas, BFS y filas de impresión. Deque suporta ambas las extremidades.","it":"Una structure di donnees First-In-First-Out (FIFO). Operazioni : enqueue (ajouter all'arriere), dequeue (retirer all'avant). Utilisee per la planificazione di tâches, BFS e i files d'impression. Il Deque supporte i deux extremites.","de":"Eine First-In-First-Out (FIFO) Datenstruktur. Operationen: enqueue (hinten hinzufügen), dequeue (vorne entfernen). Verwendet für Aufgabenplanung, BFS und Druckwarteschlangen. Deque unterstützt beide Enden.","fr":"Une structure de données First-In-First-Out (FIFO). Opérations : enqueue (ajouter à l'arrière), dequeue (retirer à l'avant). Utilisée pour la planification de tâches, BFS et les files d'impression. Le Deque supporte les deux extrémités.","tr":"İlk Giren İlk Çıkar (FIFO) veri yapısı. İşlemler: enqueue (arkaya ekle), dequeue (önden çıkar). Görev planlama, BFS ve yazdırma kuyrukları için kullanılır. Deque her iki ucu da destekler.","nl":"Een First-In-First-Out (FIFO) datastructuur. Bewerkingen: enqueue (achteraan toevoegen), dequeue (vooraan verwijderen). Gebruikt voor taakplanning, BFS en printerwachtrijen. Deque ondersteunt beide uiteinden.","ru":"Структура данных «первым пришёл — первым ушёл» (FIFO). Операции: enqueue (добавить в конец), dequeue (удалить из начала). Используется для планирования задач, BFS и очередей печати. Deque поддерживает оба конца.","zh":"先进先出（FIFO）数据结构。操作：enqueue（添加到后端）、dequeue（从前端移除）。用于任务调度、BFS和打印队列。双端队列支持两端操作。","pt_BR":"Uma estrutura de dados First-In-First-Out (FIFO). Operações: enqueue (adicionar na traseira), dequeue (remover da frente). Usada para escalonamento de tarefas, BFS e filas de impressão. Deque suporta ambas as extremidades.","pt_PT":"Uma estrutura de dados First-In-First-Out (FIFO). Operações: enqueue (adicionar na traseira), dequeue (remover da frente). Usada para escalonamento de tarefas, BFS e filas de impressão. Deque suporta ambas as extremidades."}},
  { id: 'dc-technology-0006', deck_id: 'deck-technology', sort_order: 6, front: "Hash Table (Hash Map)", back: "A data structure that maps keys to values using a hash function. Average O(1) for insert, delete, and lookup. Collisions resolved by chaining or open addressing. Used for caches, dictionaries, and sets." , front_translations: {"es":"Tabela Hash (Hash Map)","it":"Tabile di hachage (Hash Map)","de":"Hash-Tabelle (Hash Map)","fr":"Table de hachage (Hash Map)","tr":"Hash Tablosu (Hash Map)","nl":"Hashtabel (Hash Map)","ru":"Хеш-таблица","zh":"哈希表","pt_BR":"Tabela Hash (Hash Map)","pt_PT":"Tabela de Hash (Hash Map)"}, back_translations: {"es":"Una estructura de datos que mapeia chaves para valores usando una función hash. Média de El(1) para inserción, exclusão y busca. Colisões resolvidas por encadeamento o endereçamento aberto. Usada para caches, dicionários y conjuntos.","it":"Una structure di donnees che associe dei cles à dei valori all'aide d'una fonczione di hachage. O(1) en moyenne per l'inserzione, la suppression e la recherche. I collisions sono resolues per chainage o adressage ouvert. Utilisee per i caches, dictionnaires e ensembles.","de":"Eine Datenstruktur, die Schlüssel mithilfe einer Hash-Funktion auf Werte abbildet. Durchschnittlich O(1) für Einfügen, Löschen und Suchen. Kollisionen werden durch Verkettung oder offenes Adressieren gelöst. Verwendet für Caches, Wörterbücher und Mengen.","fr":"Une structure de données qui associe des clés à des valeurs à l'aide d'une fonction de hachage. O(1) en moyenne pour l'insertion, la suppression et la recherche. Les collisions sont résolues par chaînage ou adressage ouvert. Utilisée pour les caches, dictionnaires et ensembles.","tr":"Bir hash fonksiyonu kullanarak anahtarları değerlere eşleyen veri yapısı. Ekleme, silme ve arama için ortalama O(1). Çakışmalar zincirleme veya açık adresleme ile çözülür. Önbellekler, sözlükler ve kümeler için kullanılır.","nl":"Een datastructuur die sleutels met behulp van een hashfunctie aan waarden koppelt. Gemiddeld O(1) voor invoegen, verwijderen en opzoeken. Botsingen opgelost door chaining of open adressering. Gebruikt voor caches, woordenboeken en verzamelingen.","ru":"Структура данных, сопоставляющая ключи значениям с помощью хеш-функции. В среднем O(1) для вставки, удаления и поиска. Коллизии разрешаются методом цепочек или открытой адресацией. Используется для кешей, словарей и множеств.","zh":"使用哈希函数将键映射到值的数据结构。插入、删除和查找的平均时间为O(1)。通过链接法或开放地址法解决冲突。用于缓存、字典和集合。","pt_BR":"Uma estrutura de dados que mapeia chaves para valores usando uma função hash. Média de O(1) para inserção, exclusão e busca. Colisões resolvidas por encadeamento ou endereçamento aberto. Usada para caches, dicionários e conjuntos.","pt_PT":"Uma estrutura de dados que mapeia chaves para valores usando uma função hash. Média de O(1) para inserção, eliminação e pesquisa. Colisões resolvidas por encadeamento ou endereçamento aberto. Usada para caches, dicionários e conjuntos."}},
  { id: 'dc-technology-0007', deck_id: 'deck-technology', sort_order: 7, front: "Binary Tree", back: "A tree data structure where each node has at most two children (left and right). The basis for binary search trees, heaps, and many algorithms. Traversals: in-order, pre-order, post-order." , front_translations: {"es":"Árvore Binária","it":"Arbre binaire","de":"Binärbaum","fr":"Arbre binaire","tr":"İkili Ağaç","nl":"Binaire boom","ru":"Двоичное дерево","zh":"二叉树","pt_BR":"Árvore Binária","pt_PT":"Árvore Binária"}, back_translations: {"es":"Una estructura de datos en árvore donde cada nó tiene en el máximo de los hijos (esquerdo y derecho). La base para árvores de busca binária, heaps y muchos algoritmos. Travessias: en-ordem, pré-ordem, pós-ordem.","it":"Una structure di donnees arborescente où ogni nœud ha al più deux enfants (gauche e droit). La base dei arbres di recherche binaire, dei tas e di nombreux algorithmes. Parcours : inordre, preordre, postordre.","de":"Eine Baumdatenstruktur, bei der jeder Knoten höchstens zwei Kinder hat (links und rechts). Die Basis für binäre Suchbäume, Heaps und viele Algorithmen. Traversierungen: In-Order, Pre-Order, Post-Order.","fr":"Une structure de données arborescente où chaque nœud a au plus deux enfants (gauche et droit). La base des arbres de recherche binaire, des tas et de nombreux algorithmes. Parcours : inordre, préordre, postordre.","tr":"Her düğümün en fazla iki çocuğu (sol ve sağ) olan ağaç veri yapısı. İkili arama ağaçları, yığınlar ve birçok algoritmanın temeli. Gezmeler: sıralı, ön sıralı, son sıralı.","nl":"Een boomgegevensstructuur waarbij elke knoop maximaal twee kinderen heeft (links en rechts). De basis voor binaire zoekbomen, heaps en vele algoritmen. Doorloop: in-volgorde, voor-volgorde, na-volgorde.","ru":"Древовидная структура данных, в которой каждый узел имеет не более двух дочерних узлов (левый и правый). Основа для двоичных деревьев поиска, куч и многих алгоритмов. Обходы: симметричный, прямой, обратный.","zh":"每个节点最多有两个子节点（左和右）的树形数据结构。是二叉搜索树、堆和许多算法的基础。遍历方式：中序、前序、后序。","pt_BR":"Uma estrutura de dados em árvore onde cada nó tem no máximo dois filhos (esquerdo e direito). A base para árvores de busca binária, heaps e muitos algoritmos. Travessias: em-ordem, pré-ordem, pós-ordem.","pt_PT":"Uma estrutura de dados em árvore onde cada nó tem no máximo dois filhos (esquerdo e direito). A base para árvores de pesquisa binária, heaps e muitos algoritmos. Travessias: em-ordem, pré-ordem, pós-ordem."}},
  { id: 'dc-technology-0008', deck_id: 'deck-technology', sort_order: 8, front: "Binary Search Tree (BST)", back: "A binary tree where every node's left subtree has values less than the node, and the right subtree has greater values. O(log n) average for search, insert, delete; degrades to O(n) if unbalanced." , front_translations: {"es":"Árvore Binária de Busca (BST)","it":"Albero binario di ricerca (BST)","de":"Binärer Suchbaum (BST)","fr":"Arbre binaire de recherche (ABR)","tr":"İkili Arama Ağacı (BST)","nl":"Binaire zoekboom (BST)","ru":"Двоичное дерево поиска (BST)","zh":"二叉搜索树（BST）","pt_BR":"Árvore Binária de Busca (BST)","pt_PT":"Árvore Binária de Pesquisa (BST)"}, back_translations: {"es":"Una árvore binária donde a subárvore esquerda de cada nó tiene valores menores y a direita tiene valores mayores. Média de El(log n) para busca, inserción, exclusão; degrada para El(n) se desbalanceada.","it":"Un arbre binaire où il sotto-arbre gauche di ogni nœud contiene dei valori inferieures e il sotto-arbre droit dei valori superieures. O(log n) en moyenne per recherche, inserzione, suppression ; se degrade en O(n) se desequilibre.","de":"Ein Binärbaum, bei dem der linke Teilbaum jedes Knotens nur kleinere Werte und der rechte Teilbaum nur größere Werte enthält. Durchschnittlich O(log n) für Suche, Einfügen, Löschen; verschlechtert sich auf O(n) bei Unausgewogenheit.","fr":"Un arbre binaire où le sous-arbre gauche de chaque nœud contient des valeurs inférieures et le sous-arbre droit des valeurs supérieures. O(log n) en moyenne pour recherche, insertion, suppression ; se dégrade en O(n) si déséquilibré.","tr":"Her düğümün sol alt ağacının daha küçük, sağ alt ağacının daha büyük değerler içerdiği ikili ağaç. Arama, ekleme, silme için ortalama O(log n); dengesiz ise O(n)'ye düşer.","nl":"Een binaire boom waarbij de linkerdeelboom van elke knoop kleinere waarden bevat en de rechterdeelboom grotere waarden. Gemiddeld O(log n) voor zoeken, invoegen, verwijderen; degradeert naar O(n) bij onbalans.","ru":"Двоичное дерево, в котором левое поддерево каждого узла содержит значения меньше узла, а правое — больше. В среднем O(log n) для поиска, вставки, удаления; ухудшается до O(n) при несбалансированности.","zh":"每个节点的左子树包含比该节点小的值、右子树包含更大值的二叉树。搜索、插入、删除的平均时间为O(log n)；不平衡时退化为O(n)。","pt_BR":"Uma árvore binária onde a subárvore esquerda de cada nó tem valores menores e a direita tem valores maiores. Média de O(log n) para busca, inserção, exclusão; degrada para O(n) se desbalanceada.","pt_PT":"Uma árvore binária onde a subárvore esquerda de cada nó tem valores menores e a direita tem valores maiores. Média de O(log n) para pesquisa, inserção, eliminação; degrada para O(n) se desequilibrada."}},
  { id: 'dc-technology-0009', deck_id: 'deck-technology', sort_order: 9, front: "AVL Tree", back: "A self-balancing BST where the heights of the two child subtrees differ by at most one. Automatically rebalances via rotations after insertions/deletions, guaranteeing O(log n) for all operations." , front_translations: {"es":"Árvore AVL","it":"Arbre AVL","de":"AVL-Baum","fr":"Arbre AVL","tr":"AVL Ağacı","nl":"AVL-boom","ru":"АВЛ-дерево","zh":"AVL树","pt_BR":"Árvore AVL","pt_PT":"Árvore AVL"}, back_translations: {"es":"Una BST auto-balanceada donde las alturas de las de los subárvores hijas diferem en en el máximo un. Rebalanceia automáticamente via rotaciones após inserciones/exclusões, garantizando El(log n) para todas las operaciones.","it":"Un ABR auto-equilibrio où i hautori dei deux sotto-arbres enfants different d'al più un. Se reequilibre automatiquement per rotazioni apres inserzioni/suppressions, garantissant O(log n) per tutte i operazioni.","de":"Ein selbstbalancierender BST, bei dem die Höhen der beiden Kindteilbäume um höchstens eins abweichen. Balanciert sich nach Einfügungen/Löschungen automatisch über Rotationen neu, wodurch O(log n) für alle Operationen garantiert wird.","fr":"Un ABR auto-équilibré où les hauteurs des deux sous-arbres enfants diffèrent d'au plus un. Se rééquilibre automatiquement par rotations après insertions/suppressions, garantissant O(log n) pour toutes les opérations.","tr":"İki çocuk alt ağacının yükseklikleri en fazla bir farklı olan dengeli BST. Ekleme/silme sonrası rotasyonlarla otomatik olarak yeniden dengelenir, tüm işlemler için O(log n) garantiler.","nl":"Een zelfbalancerende BST waarbij de hoogten van de twee kinddeelbomen maximaal één verschillen. Herbalanceert automatisch via rotaties na invoegingen/verwijderingen, garandeert O(log n) voor alle bewerkingen.","ru":"Самобалансирующееся BST, в котором высоты двух дочерних поддеревьев отличаются не более чем на единицу. Автоматически перебалансируется через повороты после вставок/удалений, гарантируя O(log n) для всех операций.","zh":"一种自平衡BST，两个子树的高度差最多为1。在插入/删除后通过旋转自动重新平衡，保证所有操作的O(log n)复杂度。","pt_BR":"Uma BST auto-balanceada onde as alturas das duas subárvores filhas diferem em no máximo um. Rebalanceia automaticamente via rotações após inserções/exclusões, garantindo O(log n) para todas as operações.","pt_PT":"Uma BST auto-equilibrada onde as alturas das duas subárvores filhas diferem em no máximo um. Reequilibra automaticamente via rotações após inserções/eliminações, garantindo O(log n) para todas as operações."}},
  { id: 'dc-technology-0010', deck_id: 'deck-technology', sort_order: 10, front: "Red-Black Tree", back: "A self-balancing BST with color properties that ensure the tree remains approximately balanced. Guarantees O(log n) operations. Used in many standard library implementations (Java TreeMap, C++ std::map)." , front_translations: {"es":"Árvore Rubro-Negra","it":"Arbre rouge-noir","de":"Rot-Schwarz-Baum","fr":"Arbre rouge-noir","tr":"Kırmızı-Siyah Ağaç","nl":"Rood-zwart boom","ru":"Красно-чёрное дерево","zh":"红黑树","pt_BR":"Árvore Rubro-Negra","pt_PT":"Árvore Vermelho-Preto"}, back_translations: {"es":"Una BST auto-balanceada con propiedades de cor que garantizan que a árvore permaneça aproximadamente balanceada. Garantiza operaciones El(log n). Usada en muchas implementaciones de biblioteca padrão (Java TreeMap, C++ std::map).","it":"Un ABR auto-equilibrio con dei proprietàs di coulore garantissant che l'arbre reste approximativement equilibrio. Garantit dei operazioni en O(log n). Utilise in di nombreuses implementazioni di bibliotheques standard (Java TreeMap, C++ std::map).","de":"Ein selbstbalancierender BST mit Farbregeln, die sicherstellen, dass der Baum annähernd balanciert bleibt. Garantiert O(log n) Operationen. Verwendet in vielen Standardbibliotheken (Java TreeMap, C++ std::map).","fr":"Un ABR auto-équilibré avec des propriétés de couleur garantissant que l'arbre reste approximativement équilibré. Garantit des opérations en O(log n). Utilisé dans de nombreuses implémentations de bibliothèques standard (Java TreeMap, C++ std::map).","tr":"Ağacın yaklaşık dengeli kalmasını sağlayan renk özelliklerine sahip dengeli BST. O(log n) işlemleri garanti eder. Birçok standart kütüphane uygulamasında kullanılır (Java TreeMap, C++ std::map).","nl":"Een zelfbalancerende BST met kleureigenschappen die ervoor zorgen dat de boom ongeveer gebalanceerd blijft. Garandeert O(log n) bewerkingen. Gebruikt in vele standaardbibliotheken (Java TreeMap, C++ std::map).","ru":"Самобалансирующееся BST с цветовыми свойствами, обеспечивающими приближённую сбалансированность дерева. Гарантирует O(log n) операции. Используется во многих реализациях стандартных библиотек (Java TreeMap, C++ std::map).","zh":"一种具有颜色属性的自平衡BST，确保树保持近似平衡。保证O(log n)操作。用于许多标准库实现（Java TreeMap、C++ std::map）。","pt_BR":"Uma BST auto-balanceada com propriedades de cor que garantem que a árvore permaneça aproximadamente balanceada. Garante operações O(log n). Usada em muitas implementações de biblioteca padrão (Java TreeMap, C++ std::map).","pt_PT":"Uma BST auto-equilibrada com propriedades de cor que garantem que a árvore permaneça aproximadamente equilibrada. Garante operações O(log n). Usada em muitas implementações de biblioteca padrão (Java TreeMap, C++ std::map)."}},
  { id: 'dc-technology-0011', deck_id: 'deck-technology', sort_order: 11, front: "Heap", back: "A complete binary tree satisfying the heap property: in a max-heap, every parent is ≥ its children; in a min-heap, every parent is ≤ its children. Enables O(1) access to the max/min and O(log n) insert/delete." , front_translations: {"es":"Heap","it":"Heap","de":"Heap","fr":"Tas (Heap)","tr":"Yığın (Heap)","nl":"Heap","ru":"Куча (Heap)","zh":"堆","pt_BR":"Heap","pt_PT":"Heap"}, back_translations: {"es":"Una árvore binária completa satisfazendo a propiedad de heap: en un max-heap, todo pai es ≥ sus hijos; en un min-heap, todo pai es ≤ sus hijos. Permite acceso El(1) al max/min y inserción/exclusão en El(log n).","it":"Un arbre binaire complet satisfaisant la propriete di tas : in un tas max, ogni parent e ≥ i suoi enfants ; in un tas min, ogni parent e ≤ i suoi enfants. Permet un acces O(1) al max/min e una inserzione/suppression en O(log n).","de":"Ein vollständiger Binärbaum, der die Heap-Eigenschaft erfüllt: in einem Max-Heap ist jedes Elternteil ≥ seine Kinder; in einem Min-Heap ist jedes Elternteil ≤ seine Kinder. Ermöglicht O(1) Zugriff auf Max/Min und O(log n) Einfügen/Löschen.","fr":"Un arbre binaire complet satisfaisant la propriété de tas : dans un tas max, chaque parent est ≥ ses enfants ; dans un tas min, chaque parent est ≤ ses enfants. Permet un accès O(1) au max/min et une insertion/suppression en O(log n).","tr":"Yığın özelliğini sağlayan tam ikili ağaç: max-yığında her ebeveyn ≥ çocukları; min-yığında her ebeveyn ≤ çocukları. Max/min'e O(1) erişim ve O(log n) ekleme/silme sağlar.","nl":"Een volledige binaire boom die de heapeigenschap satisficeert: in een max-heap is elke ouder ≥ zijn kinderen; in een min-heap is elke ouder ≤ zijn kinderen. Maakt O(1) toegang tot max/min en O(log n) invoegen/verwijderen mogelijk.","ru":"Полное двоичное дерево, удовлетворяющее свойству кучи: в max-куче каждый родитель ≥ своих потомков; в min-куче каждый родитель ≤ своих потомков. Обеспечивает O(1) доступ к max/min и O(log n) вставку/удаление.","zh":"满足堆性质的完全二叉树：在最大堆中，每个父节点≥其子节点；在最小堆中，每个父节点≤其子节点。支持O(1)访问最大/最小值和O(log n)插入/删除。","pt_BR":"Uma árvore binária completa satisfazendo a propriedade de heap: em um max-heap, todo pai é ≥ seus filhos; em um min-heap, todo pai é ≤ seus filhos. Permite acesso O(1) ao max/min e inserção/exclusão em O(log n).","pt_PT":"Uma árvore binária completa satisfazendo a propriedade de heap: num max-heap, cada pai é ≥ seus filhos; num min-heap, cada pai é ≤ seus filhos. Permite acesso O(1) ao max/min e inserção/eliminação em O(log n)."}},
  { id: 'dc-technology-0012', deck_id: 'deck-technology', sort_order: 12, front: "Graph", back: "A data structure of vertices (nodes) connected by edges. Can be directed or undirected, weighted or unweighted. Used to model networks, dependencies, maps, and social connections." , front_translations: {"es":"Grafo","it":"Grafo","de":"Graph","fr":"Graphe","tr":"Graf","nl":"Graaf","ru":"Граф","zh":"图","pt_BR":"Grafo","pt_PT":"Grafo"}, back_translations: {"es":"Una estructura de datos de vértices (nós) conectados por arestas. Puede ser dirigido o no dirigido, ponderado o no ponderado. Usado para modelar redes, dependencias, mapas y conexiones sociais.","it":"Una structure di donnees compostoe di sommets (nœuds) relies per dei aretes. Peut etre oriente o non oriente, pondere o non pondere. Utilise per modeliser dei reseaux, dei dependanze, dei cartes e dei connexions sociales.","de":"Eine Datenstruktur aus Knoten (Vertices), die durch Kanten verbunden sind. Kann gerichtet oder ungerichtet, gewichtet oder ungewichtet sein. Verwendet zur Modellierung von Netzwerken, Abhängigkeiten, Karten und sozialen Verbindungen.","fr":"Une structure de données composée de sommets (nœuds) reliés par des arêtes. Peut être orienté ou non orienté, pondéré ou non pondéré. Utilisé pour modéliser des réseaux, des dépendances, des cartes et des connexions sociales.","tr":"Kenarlarla bağlanan köşelerden (düğümler) oluşan veri yapısı. Yönlü veya yönsüz, ağırlıklı veya ağırlıksız olabilir. Ağları, bağımlılıkları, haritaları ve sosyal bağlantıları modellemek için kullanılır.","nl":"Een datastructuur van hoekpunten (knopen) verbonden door kanten. Kan gericht of ongericht, gewogen of ongewogen zijn. Gebruikt om netwerken, afhankelijkheden, kaarten en sociale verbindingen te modelleren.","ru":"Структура данных из вершин (узлов), соединённых рёбрами. Может быть ориентированным или неориентированным, взвешенным или невзвешенным. Используется для моделирования сетей, зависимостей, карт и социальных связей.","zh":"由通过边连接的顶点（节点）组成的数据结构。可以是有向或无向、加权或无权的。用于建模网络、依赖关系、地图和社交连接。","pt_BR":"Uma estrutura de dados de vértices (nós) conectados por arestas. Pode ser dirigido ou não dirigido, ponderado ou não ponderado. Usado para modelar redes, dependências, mapas e conexões sociais.","pt_PT":"Uma estrutura de dados de vértices (nós) ligados por arestas. Pode ser dirigido ou não dirigido, ponderado ou não ponderado. Usado para modelar redes, dependências, mapas e ligações sociais."}},
  { id: 'dc-technology-0013', deck_id: 'deck-technology', sort_order: 13, front: "Graph: Adjacency Matrix vs. Adjacency List", back: "Adjacency matrix: O(V²) space, O(1) edge lookup. Adjacency list: O(V+E) space, O(degree) edge lookup. Lists are preferred for sparse graphs; matrices for dense graphs or frequent edge queries." , front_translations: {"es":"Grafo: Matriz de Adjacencia vs. Lista de Adjacencia","it":"Graphe : Matrice d'adjacenza vs. Liste d'adjacenza","de":"Graph: Adjazenzmatrix vs. Adjazenzliste","fr":"Graphe : Matrice d'adjacence vs. Liste d'adjacence","tr":"Graf: Komşuluk Matrisi vs. Komşuluk Listesi","nl":"Graaf: Aangrenzingsmatrix vs. Aangrenzingslijst","ru":"Граф: матрица смежности vs. список смежности","zh":"图：邻接矩阵 vs. 邻接表","pt_BR":"Grafo: Matriz de Adjacência vs. Lista de Adjacência","pt_PT":"Grafo: Matriz de Adjacência vs. Lista de Adjacência"}, back_translations: {"es":"Matriz de adjacencia: espacio El(V²), busca de aresta El(1). Lista de adjacencia: espacio El(V+Y), busca de aresta El(grau). Listas preferidas para grafos esparsos; matrizes para grafos densos o consultas frequentes de arestas.","it":"Matrice d'adjacenza : espace O(V²), consultazione d'arete O(1). Liste d'adjacenza : espace O(V+E), consultazione d'arete O(grado). I listes sono preferees per i graphes creux ; i matrices per i graphes denses o i requetes d'aretes frequentes.","de":"Adjazenzmatrix: O(V²) Speicher, O(1) Kantenabfrage. Adjazenzliste: O(V+E) Speicher, O(Grad) Kantenabfrage. Listen bevorzugt für dünn besetzte Graphen; Matrizen für dichte Graphen oder häufige Kantenabfragen.","fr":"Matrice d'adjacence : espace O(V²), consultation d'arête O(1). Liste d'adjacence : espace O(V+E), consultation d'arête O(degré). Les listes sont préférées pour les graphes creux ; les matrices pour les graphes denses ou les requêtes d'arêtes fréquentes.","tr":"Komşuluk matrisi: O(V²) alan, O(1) kenar sorgusu. Komşuluk listesi: O(V+E) alan, O(derece) kenar sorgusu. Listeler seyrek graflar için tercih edilir; matrisler yoğun graflar veya sık kenar sorguları için.","nl":"Aangrenzingsmatrix: O(V²) ruimte, O(1) kantopzoekingen. Aangrenzingslijst: O(V+E) ruimte, O(graad) kantopzoekingen. Lijsten zijn te verkiezen voor ijle grafen; matrices voor dichte grafen of frequente kantopzoekingen.","ru":"Матрица смежности: O(V²) памяти, O(1) для поиска ребра. Список смежности: O(V+E) памяти, O(степень) для поиска ребра. Списки предпочтительны для разреженных графов; матрицы — для плотных или частых запросов рёбер.","zh":"邻接矩阵：O(V²)空间，O(1)边查询。邻接表：O(V+E)空间，O(度)边查询。稀疏图倾向于使用列表；密集图或频繁边查询时使用矩阵。","pt_BR":"Matriz de adjacência: espaço O(V²), busca de aresta O(1). Lista de adjacência: espaço O(V+E), busca de aresta O(grau). Listas preferidas para grafos esparsos; matrizes para grafos densos ou consultas frequentes de arestas.","pt_PT":"Matriz de adjacência: espaço O(V²), pesquisa de aresta O(1). Lista de adjacência: espaço O(V+E), pesquisa de aresta O(grau). Listas preferidas para grafos esparsos; matrizes para grafos densos ou consultas frequentes de arestas."}},
  { id: 'dc-technology-0014', deck_id: 'deck-technology', sort_order: 14, front: "Trie (Prefix Tree)", back: "A tree where each node represents a character; paths from root to node represent strings. Efficient for prefix searches, autocomplete, and spell-checking. O(L) for search/insert where L is word length." , front_translations: {"es":"Trie (Árvore de Prefijo)","it":"Trie (Arbre prefixe)","de":"Trie (Präfixbaum)","fr":"Trie (Arbre préfixe)","tr":"Trie (Önek Ağacı)","nl":"Trie (Prefixboom)","ru":"Префиксное дерево (Trie)","zh":"字典树（Trie）","pt_BR":"Trie (Árvore de Prefixo)","pt_PT":"Trie (Árvore de Prefixo)"}, back_translations: {"es":"Una árvore donde cada nó representa un caractere; caminhos de la raíz al nó representan strings. Eficiente para buscas de prefijo, autocompletar y verificación ortográfica. El(L) para busca/inserción donde L es el comprimento de la palavra.","it":"Un arbre où ogni nœud represente un caractere ; i chemins della racine al nœud representent dei chaines. Efficace per i recherches per prefixe, la completion automatico e la verificazione orthographico. O(L) per recherche/inserzione où L e la longuore del mot.","de":"Ein Baum, bei dem jeder Knoten ein Zeichen darstellt; Pfade von der Wurzel zum Knoten repräsentieren Zeichenketten. Effizient für Präfixsuchen, Autovervollständigung und Rechtschreibprüfung. O(L) für Suche/Einfügen, wobei L die Wortlänge ist.","fr":"Un arbre où chaque nœud représente un caractère ; les chemins de la racine au nœud représentent des chaînes. Efficace pour les recherches par préfixe, la complétion automatique et la vérification orthographique. O(L) pour recherche/insertion où L est la longueur du mot.","tr":"Her düğümün bir karakteri temsil ettiği ağaç; kökten düğüme giden yollar dizeleri temsil eder. Önek aramaları, otomatik tamamlama ve yazım denetimi için verimli. L kelime uzunluğu olmak üzere arama/ekleme için O(L).","nl":"Een boom waarbij elke knoop een teken vertegenwoordigt; paden van wortel naar knoop stellen strings voor. Efficiënt voor voorvoegsels zoeken, autocomplete en spellingcontrole. O(L) voor zoeken/invoegen waarbij L de woordlengte is.","ru":"Дерево, в котором каждый узел представляет символ; пути от корня до узла представляют строки. Эффективно для поиска по префиксу, автодополнения и проверки орфографии. O(L) для поиска/вставки, где L — длина слова.","zh":"每个节点代表一个字符的树；从根到节点的路径代表字符串。适用于前缀搜索、自动补全和拼写检查。搜索/插入为O(L)，其中L是单词长度。","pt_BR":"Uma árvore onde cada nó representa um caractere; caminhos da raiz ao nó representam strings. Eficiente para buscas de prefixo, autocompletar e verificação ortográfica. O(L) para busca/inserção onde L é o comprimento da palavra.","pt_PT":"Uma árvore onde cada nó representa um carácter; caminhos da raiz ao nó representam strings. Eficiente para pesquisas de prefixo, autocompletar e verificação ortográfica. O(L) para pesquisa/inserção onde L é o comprimento da palavra."}},
  { id: 'dc-technology-0015', deck_id: 'deck-technology', sort_order: 15, front: "Big O Notation", back: "A mathematical notation describing the upper bound of algorithm complexity (time or space) in the worst case as input size grows. O(1) is constant, O(n) is linear, O(n²) is quadratic." , front_translations: {"es":"Notación Big El","it":"Notazione Big O","de":"Big-O-Notation","fr":"Notation grand O","tr":"Büyük O Notasyonu","nl":"Big O-notatie","ru":"Нотация «O» большое","zh":"大O符号","pt_BR":"Notação Big O","pt_PT":"Notação Big O"}, back_translations: {"es":"Una notación matemática descrevendo el limite superior de la complexidad del algoritmo (tiempo o espacio) en el peor caso a la medida que el tamaño de la entrada crece. El(1) es constante, El(n) es linear, El(n²) es cuadrático.","it":"Una notazione mathematico decrivant la borne superieure della complexite di un algorithme (temps o espace) in il pire cas à mesure che la taille dell'entree croit. O(1) e constant, O(n) e lineaire, O(n²) e quadratico.","de":"Eine mathematische Notation, die die obere Schranke der Algorithmuskomplexität (Zeit oder Speicher) im schlimmsten Fall beschreibt, wenn die Eingabegröße wächst. O(1) ist konstant, O(n) ist linear, O(n²) ist quadratisch.","fr":"Une notation mathématique décrivant la borne supérieure de la complexité d'un algorithme (temps ou espace) dans le pire cas à mesure que la taille de l'entrée croît. O(1) est constant, O(n) est linéaire, O(n²) est quadratique.","tr":"Giriş boyutu büyüdükçe en kötü durumda algoritma karmaşıklığının (zaman veya alan) üst sınırını açıklayan matematiksel notasyon. O(1) sabit, O(n) doğrusal, O(n²) kareseldir.","nl":"Een wiskundige notatie die de bovengrens van algoritmecomplexiteit (tijd of ruimte) in het slechtste geval beschrijft naarmate de invoergrootte groeit. O(1) is constant, O(n) is lineair, O(n²) is kwadratisch.","ru":"Математическая нотация, описывающая верхнюю границу сложности алгоритма (по времени или памяти) в худшем случае при росте размера входных данных. O(1) — константа, O(n) — линейная, O(n²) — квадратичная.","zh":"一种数学符号，描述算法复杂度（时间或空间）在最坏情况下随输入规模增长的上界。O(1)是常数，O(n)是线性，O(n²)是二次方。","pt_BR":"Uma notação matemática descrevendo o limite superior da complexidade do algoritmo (tempo ou espaço) no pior caso à medida que o tamanho da entrada cresce. O(1) é constante, O(n) é linear, O(n²) é quadrático.","pt_PT":"Uma notação matemática que descreve o limite superior da complexidade do algoritmo (tempo ou espaço) no pior caso à medida que o tamanho da entrada cresce. O(1) é constante, O(n) é linear, O(n²) é quadrático."}},
  { id: 'dc-technology-0016', deck_id: 'deck-technology', sort_order: 16, front: "Time Complexity Classes", back: "O(1) constant, O(log n) logarithmic, O(n) linear, O(n log n) linearithmic, O(n²) quadratic, O(2ⁿ) exponential, O(n!) factorial. Each class grows significantly faster than the previous." , front_translations: {"es":"Clases de Complexidad de Tiempo","it":"Classes di complexite temporelle","de":"Zeitkomplexitätsklassen","fr":"Classes de complexité temporelle","tr":"Zaman Karmaşıklığı Sınıfları","nl":"Tijdcomplexiteitsklassen","ru":"Классы временной сложности","zh":"时间复杂度类","pt_BR":"Classes de Complexidade de Tempo","pt_PT":"Classes de Complexidade de Tempo"}, back_translations: {"es":"El(1) constante, El(log n) logarítmico, El(n) linear, El(n log n) linearítmico, El(n²) cuadrático, El(2ⁿ) exponencial, El(n!) fatorial. Cada clase crece significativamente más rápido que a anterior.","it":"O(1) constant, O(log n) logarithmico, O(n) lineaire, O(n log n) linearithmico, O(n²) quadratico, O(2ⁿ) exponentiel, O(n!) factoriel. Chaque classe croit significativement più vite che la precedente.","de":"O(1) konstant, O(log n) logarithmisch, O(n) linear, O(n log n) linearithmisch, O(n²) quadratisch, O(2ⁿ) exponentiell, O(n!) faktoriell. Jede Klasse wächst deutlich schneller als die vorherige.","fr":"O(1) constant, O(log n) logarithmique, O(n) linéaire, O(n log n) linéarithmique, O(n²) quadratique, O(2ⁿ) exponentiel, O(n!) factoriel. Chaque classe croît significativement plus vite que la précédente.","tr":"O(1) sabit, O(log n) logaritmik, O(n) doğrusal, O(n log n) doğrusal-logaritmik, O(n²) karesel, O(2ⁿ) üstel, O(n!) faktöriyel. Her sınıf bir öncekinden önemli ölçüde daha hızlı büyür.","nl":"O(1) constant, O(log n) logaritmisch, O(n) lineair, O(n log n) lineair-logaritmisch, O(n²) kwadratisch, O(2ⁿ) exponentieel, O(n!) faculteit. Elke klasse groeit aanzienlijk sneller dan de vorige.","ru":"O(1) — константа, O(log n) — логарифмическая, O(n) — линейная, O(n log n) — линейно-логарифмическая, O(n²) — квадратичная, O(2ⁿ) — экспоненциальная, O(n!) — факториальная. Каждый класс растёт значительно быстрее предыдущего.","zh":"O(1)常数，O(log n)对数，O(n)线性，O(n log n)线性对数，O(n²)二次方，O(2ⁿ)指数，O(n!)阶乘。每个类别的增长速度都显著快于前一个。","pt_BR":"O(1) constante, O(log n) logarítmico, O(n) linear, O(n log n) linearítmico, O(n²) quadrático, O(2ⁿ) exponencial, O(n!) fatorial. Cada classe cresce significativamente mais rápido que a anterior.","pt_PT":"O(1) constante, O(log n) logarítmico, O(n) linear, O(n log n) linearítmico, O(n²) quadrático, O(2ⁿ) exponencial, O(n!) fatorial. Cada classe cresce significativamente mais rápido que a anterior."}},
  { id: 'dc-technology-0017', deck_id: 'deck-technology', sort_order: 17, front: "Binary Search", back: "An efficient search algorithm for sorted arrays that repeatedly halves the search space. Time complexity O(log n), far faster than linear search O(n) for large datasets." , front_translations: {"es":"Busca Binária","it":"Ricerca binaria","de":"Binäre Suche","fr":"Recherche binaire","tr":"İkili Arama","nl":"Binair zoeken","ru":"Двоичный поиск","zh":"二分搜索","pt_BR":"Busca Binária","pt_PT":"Pesquisa Binária"}, back_translations: {"es":"Un algoritmo de busca eficiente para arrays ordenados que divide repetidamente el espacio de busca por la metade. Complexidad de tiempo El(log n), muy más rápido que a busca linear El(n) para grandes conjuntos de datos.","it":"Un algorithme di recherche efficace per i tableaux tries che divise repetitivement l'espace di recherche en deux. Complexite temporelle O(log n), bien più rapide che la recherche lineaire O(n) per di grands ensembles di donnees.","de":"Ein effizienter Suchalgorithmus für sortierte Arrays, der den Suchraum wiederholt halbiert. Zeitkomplexität O(log n), viel schneller als lineare Suche O(n) bei großen Datensätzen.","fr":"Un algorithme de recherche efficace pour les tableaux triés qui divise répétitivement l'espace de recherche en deux. Complexité temporelle O(log n), bien plus rapide que la recherche linéaire O(n) pour de grands ensembles de données.","tr":"Arama alanını tekrar tekrar yarıya indiren sıralı diziler için verimli arama algoritması. Zaman karmaşıklığı O(log n), büyük veri kümeleri için doğrusal arama O(n)'den çok daha hızlı.","nl":"Een efficiënt zoekalgoritme voor gesorteerde arrays dat de zoekruimte herhaaldelijk halveert. Tijdcomplexiteit O(log n), veel sneller dan lineair zoeken O(n) voor grote datasets.","ru":"Эффективный алгоритм поиска в отсортированных массивах, многократно разделяющий пространство поиска пополам. Временная сложность O(log n), намного быстрее линейного поиска O(n) для больших наборов данных.","zh":"一种在有序数组中通过反复将搜索空间减半的高效搜索算法。时间复杂度O(log n)，对于大数据集远快于线性搜索O(n)。","pt_BR":"Um algoritmo de busca eficiente para arrays ordenados que divide repetidamente o espaço de busca pela metade. Complexidade de tempo O(log n), muito mais rápido que a busca linear O(n) para grandes conjuntos de dados.","pt_PT":"Um algoritmo de pesquisa eficiente para arrays ordenados que divide repetidamente o espaço de pesquisa ao meio. Complexidade de tempo O(log n), muito mais rápido que a pesquisa linear O(n) para grandes conjuntos de dados."}},
  { id: 'dc-technology-0018', deck_id: 'deck-technology', sort_order: 18, front: "Bubble Sort", back: "A simple sorting algorithm that repeatedly swaps adjacent elements in the wrong order. O(n²) average and worst case. O(n) best case (already sorted with optimization). Rarely used in practice." , front_translations: {"es":"Ordenación por Bolha","it":"Tri à bulles","de":"Bubble Sort","fr":"Tri à bulles","tr":"Kabarcık Sıralama","nl":"Bubbelsorteeralgoritme","ru":"Сортировка пузырьком","zh":"冒泡排序","pt_BR":"Ordenação por Bolha","pt_PT":"Ordenação por Bolha"}, back_translations: {"es":"Un algoritmo de ordenación simples que troca repetidamente elementos adjacentes en la ordem errada. El(n²) en el caso médio y peor caso. El(n) en el mejor caso (ya ordenado con otimización). Raramente usado en la prática.","it":"Un algorithme di tri simple che echange repetitivement i elements adjacents in il mauvais ordre. O(n²) en moyenne e in il pire cas. O(n) in il meillore cas (dejà trie con optimisazione). Rarement utilise en pratico.","de":"Ein einfacher Sortieralgorithmus, der benachbarte Elemente in der falschen Reihenfolge wiederholt vertauscht. O(n²) im Durchschnitt und im schlechtesten Fall. O(n) im besten Fall (bereits sortiert mit Optimierung). In der Praxis selten verwendet.","fr":"Un algorithme de tri simple qui échange répétitivement les éléments adjacents dans le mauvais ordre. O(n²) en moyenne et dans le pire cas. O(n) dans le meilleur cas (déjà trié avec optimisation). Rarement utilisé en pratique.","tr":"Yanlış sıradaki komşu elemanları tekrar tekrar değiştiren basit sıralama algoritması. Ortalama ve en kötü durum O(n²). En iyi durum O(n) (optimizasyonla zaten sıralı). Pratikte nadiren kullanılır.","nl":"Een eenvoudig sorteeralgoritme dat herhaaldelijk aangrenzende elementen in de verkeerde volgorde verwisselt. O(n²) gemiddeld en in het slechtste geval. O(n) in het beste geval (al gesorteerd met optimalisatie). Zelden gebruikt in de praktijk.","ru":"Простой алгоритм сортировки, многократно меняющий местами соседние элементы в неправильном порядке. O(n²) в среднем и худшем случае. O(n) в лучшем случае (уже отсортировано с оптимизацией). Редко используется на практике.","zh":"一种简单的排序算法，反复交换相邻的错误顺序元素。平均和最坏情况O(n²)。最佳情况O(n)（已排序并优化）。实践中很少使用。","pt_BR":"Um algoritmo de ordenação simples que troca repetidamente elementos adjacentes na ordem errada. O(n²) no caso médio e pior caso. O(n) no melhor caso (já ordenado com otimização). Raramente usado na prática.","pt_PT":"Um algoritmo de ordenação simples que troca repetidamente elementos adjacentes na ordem errada. O(n²) no caso médio e pior caso. O(n) no melhor caso (já ordenado com otimização). Raramente usado na prática."}},
  { id: 'dc-technology-0019', deck_id: 'deck-technology', sort_order: 19, front: "Selection Sort", back: "Sorts by repeatedly selecting the minimum element and placing it at the front. O(n²) for all cases. Makes fewer swaps than bubble sort; simple but inefficient for large datasets." , front_translations: {"es":"Ordenación por Seleción","it":"Tri per selectione","de":"Auswahlsortierung","fr":"Tri par sélection","tr":"Seçimli Sıralama","nl":"Selectiesorteeralgoritme","ru":"Сортировка выбором","zh":"选择排序","pt_BR":"Ordenação por Seleção","pt_PT":"Ordenação por Seleção"}, back_translations: {"es":"Ordena selecionando repetidamente el elemento mínimo y colocando-el en la frente. El(n²) para todos los casos. Hace menos trocas que a ordenación por bolha; simples pero ineficiente para grandes conjuntos de datos.","it":"Trie en selectionnant repetitivement l'elemento minimum e en il plazant al debut. O(n²) in tutti i cas. Effectue meno d'echanges che il tri à bulles ; simple ma inefficace per di grands ensembles di donnees.","de":"Sortiert, indem das Minimum wiederholt ausgewählt und an den Anfang gestellt wird. O(n²) für alle Fälle. Macht weniger Vertauschungen als Bubble Sort; einfach, aber ineffizient für große Datensätze.","fr":"Trie en sélectionnant répétitivement l'élément minimum et en le plaçant au début. O(n²) dans tous les cas. Effectue moins d'échanges que le tri à bulles ; simple mais inefficace pour de grands ensembles de données.","tr":"Minimum elemanı tekrar tekrar seçerek öne yerleştirerek sıralama yapar. Tüm durumlar için O(n²). Kabarcık sıralamadan daha az değiştirme yapar; basit ama büyük veri kümeleri için verimsiz.","nl":"Sorteert door herhaaldelijk het minimale element te selecteren en vooraan te plaatsen. O(n²) voor alle gevallen. Maakt minder swaps dan bubbelsorteeralgoritme; eenvoudig maar inefficiënt voor grote datasets.","ru":"Сортирует, многократно выбирая минимальный элемент и помещая его в начало. O(n²) для всех случаев. Делает меньше перестановок, чем пузырьковая сортировка; простой, но неэффективный для больших наборов данных.","zh":"通过反复选择最小元素并将其放在前面来排序。所有情况下均为O(n²)。比冒泡排序交换次数少；简单但对大数据集效率低。","pt_BR":"Ordena selecionando repetidamente o elemento mínimo e colocando-o na frente. O(n²) para todos os casos. Faz menos trocas que a ordenação por bolha; simples mas ineficiente para grandes conjuntos de dados.","pt_PT":"Ordena selecionando repetidamente o elemento mínimo e colocando-o na frente. O(n²) para todos os casos. Faz menos trocas que a ordenação por bolha; simples mas ineficiente para grandes conjuntos de dados."}},
  { id: 'dc-technology-0020', deck_id: 'deck-technology', sort_order: 20, front: "Insertion Sort", back: "Builds a sorted array one element at a time by inserting each element into its correct position. O(n²) worst case but O(n) for nearly sorted input. Efficient for small or nearly sorted arrays." , front_translations: {"es":"Ordenación por Inserción","it":"Tri per insertione","de":"Einfügesortierung","fr":"Tri par insertion","tr":"Eklemeli Sıralama","nl":"Invoegsorteren","ru":"Сортировка вставками","zh":"插入排序","pt_BR":"Ordenação por Inserção","pt_PT":"Ordenação por Inserção"}, back_translations: {"es":"Constrói un array ordenado un elemento de cada vez, inserindo cada elemento en su posición correta. El(n²) en el peor caso pero El(n) para entrada casi ordenada. Eficiente para arrays pequeños o casi ordenados.","it":"Construit un tableau trie un elemento allo stesso tempo en inserant ogni elemento alla sua posizione correcte. O(n²) in il pire cas ma O(n) per una entree presque triee. Efficace per i petits tableaux o presque tries.","de":"Erstellt ein sortiertes Array Element für Element, indem jedes Element an seiner richtigen Position eingefügt wird. O(n²) im schlechtesten Fall, aber O(n) für nahezu sortierte Eingaben. Effizient für kleine oder nahezu sortierte Arrays.","fr":"Construit un tableau trié un élément à la fois en insérant chaque élément à sa position correcte. O(n²) dans le pire cas mais O(n) pour une entrée presque triée. Efficace pour les petits tableaux ou presque triés.","tr":"Her elemanı doğru konumuna ekleyerek sıralı diziyi tek tek oluşturur. En kötü durum O(n²), ancak neredeyse sıralı giriş için O(n). Küçük veya neredeyse sıralı diziler için verimli.","nl":"Bouwt een gesorteerde array één element tegelijk door elk element op de juiste positie in te voegen. O(n²) in het slechtste geval maar O(n) voor bijna gesorteerde invoer. Efficiënt voor kleine of bijna gesorteerde arrays.","ru":"Строит отсортированный массив по одному элементу, вставляя каждый элемент на правильную позицию. O(n²) в худшем случае, но O(n) для почти отсортированных данных. Эффективна для малых или почти отсортированных массивов.","zh":"通过将每个元素插入正确位置来逐个构建排序数组。最坏情况O(n²)，但对于接近有序的输入为O(n)。对小型或接近有序的数组效率高。","pt_BR":"Constrói um array ordenado um elemento de cada vez, inserindo cada elemento em sua posição correta. O(n²) no pior caso mas O(n) para entrada quase ordenada. Eficiente para arrays pequenos ou quase ordenados.","pt_PT":"Constrói um array ordenado um elemento de cada vez, inserindo cada elemento na sua posição correta. O(n²) no pior caso mas O(n) para entrada quase ordenada. Eficiente para arrays pequenos ou quase ordenados."}},
  { id: 'dc-technology-0021', deck_id: 'deck-technology', sort_order: 21, front: "Merge Sort", back: "A divide-and-conquer sorting algorithm that divides the array in half, sorts each half recursively, then merges. O(n log n) guaranteed. Stable and excellent for linked lists but requires O(n) extra space." , front_translations: {"es":"Ordenación por Fusión","it":"Tri fusione","de":"Merge Sort","fr":"Tri fusion","tr":"Birleştirme Sıralaması","nl":"Merge sort","ru":"Сортировка слиянием","zh":"归并排序","pt_BR":"Ordenação por Fusão","pt_PT":"Ordenação por Fusão"}, back_translations: {"es":"Un algoritmo de ordenación de divisão y conquista que divide el array al medio, ordena cada metade recursivamente y entonces mescla. El(n log n) garantido. Estable y excelente para listas ligadas, pero requiere El(n) de espacio extra.","it":"Un algorithme di tri diviser-per-regner che divise il tableau en deux, trie ogni moitie recursivement, puis i fusionne. O(n log n) garanti. Stable e excellent per i listes chainees ma necessite un espace supplementaire O(n).","de":"Ein Teile-und-Herrsche-Sortieralgorithmus, der das Array halbiert, jede Hälfte rekursiv sortiert und dann zusammenführt. O(n log n) garantiert. Stabil und ausgezeichnet für verkettete Listen, erfordert jedoch O(n) zusätzlichen Speicher.","fr":"Un algorithme de tri diviser-pour-régner qui divise le tableau en deux, trie chaque moitié récursivement, puis les fusionne. O(n log n) garanti. Stable et excellent pour les listes chaînées mais nécessite un espace supplémentaire O(n).","tr":"Diziyi yarıya bölen, her yarıyı özyinelemeli olarak sıralayan, ardından birleştiren böl ve yönet sıralama algoritması. O(n log n) garantili. Kararlı ve bağlı listeler için mükemmel, ancak O(n) ekstra alan gerektirir.","nl":"Een verdeel-en-heers sorteeralgoritme dat de array halveert, elke helft recursief sorteert en dan samenvoegt. O(n log n) gegarandeerd. Stabiel en uitstekend voor gelinkte lijsten maar vereist O(n) extra ruimte.","ru":"Алгоритм сортировки «разделяй и властвуй», который делит массив пополам, рекурсивно сортирует каждую половину, затем объединяет. O(n log n) гарантировано. Стабильный и отличный для связных списков, но требует O(n) дополнительной памяти.","zh":"一种分治排序算法，将数组分成两半，递归地对每一半排序，然后合并。保证O(n log n)。稳定，非常适合链表，但需要O(n)额外空间。","pt_BR":"Um algoritmo de ordenação de divisão e conquista que divide o array ao meio, ordena cada metade recursivamente e então mescla. O(n log n) garantido. Estável e excelente para listas ligadas, mas requer O(n) de espaço extra.","pt_PT":"Um algoritmo de ordenação de divisão e conquista que divide o array ao meio, ordena cada metade recursivamente e depois funde. O(n log n) garantido. Estável e excelente para listas ligadas, mas requer O(n) de espaço extra."}},
  { id: 'dc-technology-0022', deck_id: 'deck-technology', sort_order: 22, front: "Quick Sort", back: "A divide-and-conquer algorithm that picks a pivot and partitions elements. O(n log n) average, O(n²) worst case (poor pivot choice). Typically fastest in practice; in-place; not stable." , front_translations: {"es":"Ordenación Rápida","it":"Tri rapide","de":"Quick Sort","fr":"Tri rapide","tr":"Hızlı Sıralama","nl":"Quicksort","ru":"Быстрая сортировка","zh":"快速排序","pt_BR":"Ordenação Rápida","pt_PT":"Ordenação Rápida"}, back_translations: {"es":"Un algoritmo de divisão y conquista que escolhe un pivo y particiona los elementos. Média El(n log n), El(n²) en el peor caso (escolha ruim de pivo). Típicamente el más rápido en la prática; in-place; no estable.","it":"Un algorithme diviser-per-regner che choisit un pivot e partitionne i elements. O(n log n) en moyenne, O(n²) in il pire cas (mauvais choix di pivot). Generalement il più rapide en pratico ; en place ; non stable.","de":"Ein Teile-und-Herrsche-Algorithmus, der ein Pivot-Element wählt und Elemente partitioniert. Durchschnittlich O(n log n), O(n²) im schlechtesten Fall (schlechte Pivot-Wahl). Typischerweise der schnellste in der Praxis; in-place; nicht stabil.","fr":"Un algorithme diviser-pour-régner qui choisit un pivot et partitionne les éléments. O(n log n) en moyenne, O(n²) dans le pire cas (mauvais choix de pivot). Généralement le plus rapide en pratique ; en place ; non stable.","tr":"Pivot seçip elemanları bölen böl ve yönet algoritması. Ortalama O(n log n), en kötü durum O(n²) (kötü pivot seçimi). Pratikte genellikle en hızlı; yerinde; kararlı değil.","nl":"Een verdeel-en-heers algoritme dat een spilelement kiest en elementen partitioneert. Gemiddeld O(n log n), O(n²) in het slechtste geval (slechte pivotkeuze). Typisch het snelst in de praktijk; in-place; niet stabiel.","ru":"Алгоритм «разделяй и властвуй», выбирающий опорный элемент и разбивающий массив. В среднем O(n log n), O(n²) в худшем случае (неудачный выбор опорного). Обычно быстрейший на практике; in-place; нестабильный.","zh":"一种选择基准元素并对元素进行分区的分治算法。平均O(n log n)，最坏情况O(n²)（糟糕的基准选择）。实践中通常最快；原地排序；不稳定。","pt_BR":"Um algoritmo de divisão e conquista que escolhe um pivô e particiona os elementos. Média O(n log n), O(n²) no pior caso (escolha ruim de pivô). Tipicamente o mais rápido na prática; in-place; não estável.","pt_PT":"Um algoritmo de divisão e conquista que escolhe um pivô e particiona os elementos. Média O(n log n), O(n²) no pior caso (escolha má de pivô). Tipicamente o mais rápido na prática; in-place; não estável."}},
  { id: 'dc-technology-0023', deck_id: 'deck-technology', sort_order: 23, front: "Heap Sort", back: "Builds a max-heap then repeatedly extracts the maximum to produce a sorted array. O(n log n) guaranteed, in-place. Not stable; in practice slower than quicksort due to poor cache performance." , front_translations: {"es":"Ordenación por Heap","it":"Tri per tas","de":"Heap Sort","fr":"Tri par tas","tr":"Yığın Sıralaması","nl":"Heapsorteeralgoritme","ru":"Пирамидальная сортировка","zh":"堆排序","pt_BR":"Ordenação por Heap","pt_PT":"Ordenação por Heap"}, back_translations: {"es":"Constrói un max-heap y entonces extrai repetidamente el máximo para produzir un array ordenado. El(n log n) garantido, in-place. No estable; en la prática más lento que quicksort debido al débil rendimiento de cache.","it":"Construit un tas max puis extrait repetitivement il maximum per produire un tableau trie. O(n log n) garanti, en place. Non stable ; en pratico più lent che il tri rapide a causa dii mauvaises performanze del cache.","de":"Erstellt einen Max-Heap und extrahiert dann wiederholt das Maximum, um ein sortiertes Array zu erzeugen. O(n log n) garantiert, in-place. Nicht stabil; in der Praxis langsamer als Quicksort aufgrund schlechter Cache-Performance.","fr":"Construit un tas max puis extrait répétitivement le maximum pour produire un tableau trié. O(n log n) garanti, en place. Non stable ; en pratique plus lent que le tri rapide en raison des mauvaises performances du cache.","tr":"Max-yığın oluşturur, ardından sıralı dizi üretmek için maksimumu tekrar tekrar çıkarır. O(n log n) garantili, yerinde. Kararlı değil; pratikte zayıf önbellek performansı nedeniyle quicksort'tan daha yavaş.","nl":"Bouwt een max-heap en extraheert dan herhaaldelijk het maximum om een gesorteerde array te produceren. O(n log n) gegarandeerd, in-place. Niet stabiel; in de praktijk langzamer dan quicksort vanwege slechte cache-prestaties.","ru":"Строит max-кучу, затем многократно извлекает максимум для получения отсортированного массива. O(n log n) гарантировано, in-place. Нестабильный; на практике медленнее быстрой сортировки из-за плохой работы с кешем.","zh":"构建最大堆，然后反复提取最大值以产生排序数组。保证O(n log n)，原地排序。不稳定；由于缓存性能差，实践中比快速排序慢。","pt_BR":"Constrói um max-heap e então extrai repetidamente o máximo para produzir um array ordenado. O(n log n) garantido, in-place. Não estável; na prática mais lento que quicksort devido ao fraco desempenho de cache.","pt_PT":"Constrói um max-heap e depois extrai repetidamente o máximo para produzir um array ordenado. O(n log n) garantido, in-place. Não estável; na prática mais lento que quicksort devido ao fraco desempenho de cache."}},
  { id: 'dc-technology-0024', deck_id: 'deck-technology', sort_order: 24, front: "Counting Sort", back: "A non-comparison sort that counts occurrences of each value and reconstructs the sorted array. O(n+k) where k is the range of values. Efficient when k is small relative to n; not suitable for large ranges." , front_translations: {"es":"Ordenación por Contaje","it":"Tri per comptage","de":"Zählsortierung","fr":"Tri par comptage","tr":"Sayma Sıralaması","nl":"Telsorteeralgoritme","ru":"Сортировка подсчётом","zh":"计数排序","pt_BR":"Ordenação por Contagem","pt_PT":"Ordenação por Contagem"}, back_translations: {"es":"Una ordenación no comparativa que conta ocorrencias de cada valor y reconstrói el array ordenado. El(n+k) donde k es el intervalo de valores. Eficiente cuando k es pequeño en relación con n; no adequado para grandes intervalos.","it":"Un tri non comparatif che compte i occurrenze di ogni valore e reconstruit il tableau trie. O(n+k) où k e la plage di valori. Efficace quando k e piccolo per rapport à n ; inadapte ai grandes plages.","de":"Eine nicht-vergleichsbasierte Sortierung, die Vorkommen jedes Werts zählt und das sortierte Array rekonstruiert. O(n+k), wobei k der Wertebereich ist. Effizient, wenn k klein relativ zu n ist; nicht geeignet für große Bereiche.","fr":"Un tri non comparatif qui compte les occurrences de chaque valeur et reconstruit le tableau trié. O(n+k) où k est la plage de valeurs. Efficace quand k est petit par rapport à n ; inadapté aux grandes plages.","tr":"Her değerin oluşumlarını sayan ve sıralı diziyi yeniden oluşturan karşılaştırmasız sıralama. k değer aralığı olmak üzere O(n+k). k, n'ye göre küçük olduğunda verimli; büyük aralıklar için uygun değil.","nl":"Een niet-vergelijkende sortering die het voorkomen van elke waarde telt en de gesorteerde array reconstrueert. O(n+k) waarbij k het waardenbereik is. Efficiënt wanneer k klein is ten opzichte van n; niet geschikt voor grote bereiken.","ru":"Несравнительная сортировка, подсчитывающая вхождения каждого значения и восстанавливающая отсортированный массив. O(n+k), где k — диапазон значений. Эффективна, когда k мало по сравнению с n; не подходит для больших диапазонов.","zh":"一种非比较排序，统计每个值的出现次数并重建排序数组。O(n+k)，其中k是值的范围。当k相对于n较小时效率高；不适用于大范围。","pt_BR":"Uma ordenação não comparativa que conta ocorrências de cada valor e reconstrói o array ordenado. O(n+k) onde k é o intervalo de valores. Eficiente quando k é pequeno em relação a n; não adequado para grandes intervalos.","pt_PT":"Uma ordenação não comparativa que conta ocorrências de cada valor e reconstrói o array ordenado. O(n+k) onde k é o intervalo de valores. Eficiente quando k é pequeno em relação a n; não adequado para grandes intervalos."}},
  { id: 'dc-technology-0025', deck_id: 'deck-technology', sort_order: 25, front: "BFS — Breadth-First Search", back: "Graph traversal that visits all neighbors of a node before moving deeper. Uses a queue. O(V+E) time. Finds shortest path in unweighted graphs. Also used for level-order tree traversal." , front_translations: {"es":"BFS — Busca en Largura","it":"BFS — Parcours en largore","de":"BFS — Breitensuche","fr":"BFS — Parcours en largeur","tr":"BFS — Genişlik Öncelikli Arama","nl":"BFS — Breedte-eerst zoeken","ru":"BFS — Обход в ширину","zh":"BFS — 广度优先搜索","pt_BR":"BFS — Busca em Largura","pt_PT":"BFS — Pesquisa em Largura"}, back_translations: {"es":"Travessia de grafo que visita todos los vizinhos de un nó antes de ir más fundo. Usa una fila. Tiempo El(V+Y). Encontra el caminho más corto en grafos no ponderados. También usado para travessia en nivel de árvore.","it":"Traversee di graphe che visite tutti i voisins di un nœud avant d'aller più en profondore. Utilise una file d'attente. Temps O(V+E). Trouve il chemin il più court in i graphes non ponderes. Aussi utilise per la traversee d'arbre en ordre di niveau.","de":"Graph-Traversierung, die alle Nachbarn eines Knotens besucht, bevor sie tiefer geht. Verwendet eine Warteschlange. O(V+E) Zeit. Findet den kürzesten Pfad in ungewichteten Graphen. Auch für Level-Order-Baumtraversierung verwendet.","fr":"Traversée de graphe qui visite tous les voisins d'un nœud avant d'aller plus en profondeur. Utilise une file d'attente. Temps O(V+E). Trouve le chemin le plus court dans les graphes non pondérés. Aussi utilisé pour la traversée d'arbre en ordre de niveau.","tr":"Daha derine inmeden önce bir düğümün tüm komşularını ziyaret eden graf gezmesi. Kuyruk kullanır. O(V+E) zaman. Ağırlıksız graflarda en kısa yolu bulur. Seviye sırası ağaç gezmesi için de kullanılır.","nl":"Graaftraversaal dat alle buren van een knoop bezoekt voordat het dieper gaat. Gebruikt een wachtrij. O(V+E) tijd. Vindt kortste pad in ongewogen grafen. Ook gebruikt voor niveauvolgorde boomtraversaal.","ru":"Обход графа, посещающий всех соседей узла прежде чем двигаться глубже. Использует очередь. Время O(V+E). Находит кратчайший путь в невзвешенных графах. Также используется для обхода дерева по уровням.","zh":"在深入之前访问节点所有邻居的图遍历算法。使用队列。时间O(V+E)。在无权图中找最短路径。也用于树的层次遍历。","pt_BR":"Travessia de grafo que visita todos os vizinhos de um nó antes de ir mais fundo. Usa uma fila. Tempo O(V+E). Encontra o caminho mais curto em grafos não ponderados. Também usado para travessia em nível de árvore.","pt_PT":"Travessia de grafo que visita todos os vizinhos de um nó antes de ir mais fundo. Usa uma fila. Tempo O(V+E). Encontra o caminho mais curto em grafos não ponderados. Também usado para travessia por nível de árvore."}},
  { id: 'dc-technology-0026', deck_id: 'deck-technology', sort_order: 26, front: "DFS — Depth-First Search", back: "Graph traversal that explores as far as possible along each branch before backtracking. Uses a stack (or recursion). O(V+E) time. Used for topological sort, cycle detection, and maze solving." , front_translations: {"es":"DFS — Busca en Profundidad","it":"DFS — Parcours en profondaur","de":"DFS — Tiefensuche","fr":"DFS — Parcours en profondeur","tr":"DFS — Önce Derinlik Araması","nl":"DFS — Diepte-eerst zoeken","ru":"DFS — Поиск в глубину","zh":"DFS — 深度优先搜索","pt_BR":"DFS — Busca em Profundidade","pt_PT":"DFS — Pesquisa em Profundidade"}, back_translations: {"es":"Travessia de grafos que explora cada ramo el más longe posible antes de retroceder. Usa una pilha (o recursão). Tiempo El(V+Y). Usado para ordenación topológica, detección de ciclos y resolución de labirintos.","it":"Parcours di graphe explorant ogni branche anche loin che possible avant di revenir en arriere. Utilise una pile (o la recursion). Complexite O(V+E). Utilise per il tri topologico, la deteczione di cycles e la resoluzione di labyrinthes.","de":"Graphdurchlauf, der jeden Zweig so weit wie möglich erkundet, bevor er zurückverfolgt. Verwendet einen Stack (oder Rekursion). O(V+E) Zeitkomplexität. Wird für topologische Sortierung, Zykluserkennung und Labyrinth-Lösung verwendet.","fr":"Parcours de graphe explorant chaque branche aussi loin que possible avant de revenir en arrière. Utilise une pile (ou la récursion). Complexité O(V+E). Utilisé pour le tri topologique, la détection de cycles et la résolution de labyrinthes.","tr":"Geri izleme yapmadan önce her dalı mümkün olduğunca ileri giderek keşfeden graf dolaşma yöntemi. Yığın (veya özyineleme) kullanır. O(V+E) zaman karmaşıklığı. Topolojik sıralama, döngü tespiti ve labirent çözmede kullanılır.","nl":"Graaftraversatie die elke tak zo ver mogelijk verkent voordat wordt teruggespoeld. Gebruikt een stack (of recursie). O(V+E) tijd. Wordt gebruikt voor topologisch sorteren, cyclusdetectie en doolhof oplossen.","ru":"Обход графа, который исследует каждую ветвь как можно дальше перед возвратом. Использует стек (или рекурсию). Время O(V+E). Применяется для топологической сортировки, обнаружения циклов и решения лабиринтов.","zh":"图遍历算法，沿每个分支尽可能深入探索后再回溯。使用栈（或递归）。时间复杂度 O(V+E)。用于拓扑排序、环检测和迷宫求解。","pt_BR":"Travessia de grafos que explora cada ramo o mais longe possível antes de retroceder. Usa uma pilha (ou recursão). Tempo O(V+E). Usado para ordenação topológica, detecção de ciclos e resolução de labirintos.","pt_PT":"Travessia de grafos que explora cada ramo o mais longe possível antes de retroceder. Usa uma pilha (ou recursão). Tempo O(V+E). Usado para ordenação topológica, deteção de ciclos e resolução de labirintos."}},
  { id: 'dc-technology-0027', deck_id: 'deck-technology', sort_order: 27, front: "Dijkstra's Algorithm", back: "Finds the shortest path from a source to all vertices in a weighted graph with non-negative edges. Uses a priority queue. O((V+E) log V) with a binary heap. Not suitable for negative edge weights." , front_translations: {"es":"Algoritmo de Dijkstra","it":"Algorithme di Dijkstra","de":"Dijkstra-Algorithmus","fr":"Algorithme de Dijkstra","tr":"Dijkstra Algoritması","nl":"Dijkstra's Algoritme","ru":"Алгоритм Дейкстры","zh":"Dijkstra 算法","pt_BR":"Algoritmo de Dijkstra","pt_PT":"Algoritmo de Dijkstra"}, back_translations: {"es":"Encontra el caminho más corto de una origem para todos los vértices en un grafo ponderado con arestas no negativas. Usa una fila de prioridad. El((V+Y) log V) con heap binário. No es adequado para pesos de arestas negativos.","it":"Trouve il più court chemin d'una source verso tutti i sommets di un graphe pondere à aretes non negatives. Utilise una file di priorite. O((V+E) log V) con un tas binaire. Non adapte ai poids d'aretes negatifs.","de":"Findet den kürzesten Pfad von einer Quelle zu allen Knoten in einem gewichteten Graphen mit nicht-negativen Kanten. Verwendet eine Prioritätswarteschlange. O((V+E) log V) mit einem Binärheap. Nicht geeignet für negative Kantengewichte.","fr":"Trouve le plus court chemin d'une source vers tous les sommets d'un graphe pondéré à arêtes non négatives. Utilise une file de priorité. O((V+E) log V) avec un tas binaire. Non adapté aux poids d'arêtes négatifs.","tr":"Negatif olmayan kenarlara sahip ağırlıklı bir grafta kaynaktan tüm düğümlere en kısa yolu bulur. Öncelik kuyruğu kullanır. İkili yığınla O((V+E) log V). Negatif kenar ağırlıkları için uygun değildir.","nl":"Vindt het kortste pad van een bron naar alle knooppunten in een gewogen graaf met niet-negatieve randen. Gebruikt een prioriteitswachtrij. O((V+E) log V) met een binaire heap. Niet geschikt voor negatieve randgewichten.","ru":"Находит кратчайший путь от источника до всех вершин взвешенного графа с неотрицательными рёбрами. Использует очередь с приоритетом. O((V+E) log V) с двоичной кучей. Не подходит для отрицательных весов рёбер.","zh":"在具有非负边权的加权图中，找到从源点到所有顶点的最短路径。使用优先队列。使用二叉堆时为 O((V+E) log V)。不适用于负边权。","pt_BR":"Encontra o caminho mais curto de uma origem para todos os vértices em um grafo ponderado com arestas não negativas. Usa uma fila de prioridade. O((V+E) log V) com heap binário. Não é adequado para pesos de arestas negativos.","pt_PT":"Encontra o caminho mais curto de uma origem para todos os vértices num grafo ponderado com arestas não negativas. Usa uma fila de prioridade. O((V+E) log V) com heap binário. Não é adequado para pesos de arestas negativos."}},
  { id: 'dc-technology-0028', deck_id: 'deck-technology', sort_order: 28, front: "Dynamic Programming (DP)", back: "A technique solving complex problems by breaking them into overlapping subproblems, solving each once and storing results (memoization or tabulation). Key: optimal substructure + overlapping subproblems. E.g., Fibonacci, knapsack." , front_translations: {"es":"Programación Dinámica (DP)","it":"Programmatione dynamico (DP)","de":"Dynamische Programmierung (DP)","fr":"Programmation dynamique (DP)","tr":"Dinamik Programlama (DP)","nl":"Dynamisch Programmeren (DP)","ru":"Динамическое программирование (DP)","zh":"动态规划 (DP)","pt_BR":"Programação Dinâmica (DP)","pt_PT":"Programação Dinâmica (DP)"}, back_translations: {"es":"Una técnica que resuelve problemas complexos dividindo-los en subproblemas sobrepostos, resolvendo cada un solo una vez y almacenando resultados (memoización o tabulación). Chave: subestrutura ótima + subproblemas sobrepostos. Ex.: Fibonacci, mochila.","it":"Una technico resolvant dei problemes complexes en i decomposant en sotto-problemes chevauchants, chacun resolu una seule fois e il resultat stocke (memoisazione o tabulazione). Cle : sotto-structure optimale + sotto-problemes chevauchants. Ex. : Fibonacci, sac à dos.","de":"Eine Technik zur Lösung komplexer Probleme durch Zerlegung in überlappende Teilprobleme, wobei jedes nur einmal gelöst und das Ergebnis gespeichert wird (Memoisation oder Tabellierung). Schlüssel: optimale Teilstruktur + überlappende Teilprobleme. Z.B. Fibonacci, Rucksackproblem.","fr":"Une technique résolvant des problèmes complexes en les décomposant en sous-problèmes chevauchants, chacun résolu une seule fois et le résultat stocké (mémoïsation ou tabulation). Clé : sous-structure optimale + sous-problèmes chevauchants. Ex. : Fibonacci, sac à dos.","tr":"Karmaşık problemleri örtüşen alt problemlere bölerek, her birini bir kez çözüp sonuçları saklayarak (memoizasyon veya tablolama) çözen bir teknik. Anahtar: optimal alt yapı + örtüşen alt problemler. Örn.: Fibonacci, sırt çantası.","nl":"Een techniek die complexe problemen oplost door ze op te splitsen in overlappende deelproblemen, elk slechts één keer op te lossen en resultaten op te slaan (memoisatie of tabulatie). Sleutel: optimale deelstructuur + overlappende deelproblemen. Bijv. Fibonacci, rugzakprobleem.","ru":"Техника решения сложных задач путём разбиения на перекрывающиеся подзадачи, каждая из которых решается один раз, а результат сохраняется (мемоизация или табуляция). Ключ: оптимальная подструктура + перекрывающиеся подзадачи. Напр.: Фибоначчи, задача о рюкзаке.","zh":"一种将复杂问题分解为重叠子问题的技术，每个子问题只求解一次并存储结果（记忆化或制表法）。关键：最优子结构 + 重叠子问题。例如：斐波那契、背包问题。","pt_BR":"Uma técnica que resolve problemas complexos dividindo-os em subproblemas sobrepostos, resolvendo cada um apenas uma vez e armazenando resultados (memoização ou tabulação). Chave: subestrutura ótima + subproblemas sobrepostos. Ex.: Fibonacci, mochila.","pt_PT":"Uma técnica que resolve problemas complexos dividindo-os em subproblemas sobrepostos, resolvendo cada um apenas uma vez e armazenando resultados (memoização ou tabulação). Chave: subestrutura ótima + subproblemas sobrepostos. Ex.: Fibonacci, mochila."}},
  { id: 'dc-technology-0029', deck_id: 'deck-technology', sort_order: 29, front: "Greedy Algorithm", back: "Makes the locally optimal choice at each step hoping to find the global optimum. Simple and efficient but not always correct. Works for: activity selection, Huffman coding, Dijkstra's. Does not work for: 0/1 knapsack." , front_translations: {"es":"Algoritmo Guloso","it":"Algorithme glouton","de":"Greedy-Algorithmus","fr":"Algorithme glouton","tr":"Açgözlü Algoritma","nl":"Greedy-algoritme","ru":"Жадный алгоритм","zh":"贪心算法","pt_BR":"Algoritmo Guloso","pt_PT":"Algoritmo Guloso"}, back_translations: {"es":"Hace a escolha localmente ótima en cada etapa esperando encontrar el ótimo global. Simples y eficiente, pero nem siempre correto. Funciona para: seleción de atividades, codificación de Huffman, Dijkstra. No funciona para: mochila 0/1.","it":"Fait il choix localement optimal à ogni etape en esperant trouver l'optimum global. Simple e efficace ma toujours correct. Fonctionne per : seleczione d'activites, codage di Huffman, Dijkstra. Ne fonctionne per : sac à dos 0/1.","de":"Trifft bei jedem Schritt die lokal optimale Wahl in der Hoffnung, das globale Optimum zu finden. Einfach und effizient, aber nicht immer korrekt. Funktioniert für: Aktivitätsauswahl, Huffman-Kodierung, Dijkstra. Funktioniert nicht für: 0/1-Rucksackproblem.","fr":"Fait le choix localement optimal à chaque étape en espérant trouver l'optimum global. Simple et efficace mais pas toujours correct. Fonctionne pour : sélection d'activités, codage de Huffman, Dijkstra. Ne fonctionne pas pour : sac à dos 0/1.","tr":"Her adımda global optimumu bulmayı umarak yerel olarak en iyi seçimi yapar. Basit ve verimli ama her zaman doğru değildir. Çalışır: etkinlik seçimi, Huffman kodlama, Dijkstra. Çalışmaz: 0/1 sırt çantası.","nl":"Maakt bij elke stap de lokaal optimale keuze in de hoop het globale optimum te vinden. Eenvoudig en efficiënt maar niet altijd correct. Werkt voor: activiteitenselectie, Huffman-codering, Dijkstra. Werkt niet voor: 0/1-rugzakprobleem.","ru":"На каждом шаге делает локально оптимальный выбор в надежде найти глобальный оптимум. Прост и эффективен, но не всегда корректен. Работает для: выбора активностей, кодирования Хаффмана, Дейкстры. Не работает для: задачи о рюкзаке 0/1.","zh":"每一步都做出局部最优选择，期望找到全局最优解。简单高效但不总是正确。适用于：活动选择、霍夫曼编码、Dijkstra。不适用于：0/1 背包问题。","pt_BR":"Faz a escolha localmente ótima em cada etapa esperando encontrar o ótimo global. Simples e eficiente, mas nem sempre correto. Funciona para: seleção de atividades, codificação de Huffman, Dijkstra. Não funciona para: mochila 0/1.","pt_PT":"Faz a escolha localmente ótima em cada etapa esperando encontrar o ótimo global. Simples e eficiente, mas nem sempre correto. Funciona para: seleção de atividades, codificação de Huffman, Dijkstra. Não funciona para: mochila 0/1."}},
  { id: 'dc-technology-0030', deck_id: 'deck-technology', sort_order: 30, front: "Divide and Conquer", back: "An algorithm design paradigm: divide the problem into smaller subproblems, solve recursively, and combine results. Examples: merge sort, quicksort, binary search, Strassen's matrix multiplication." , front_translations: {"es":"Divisão y Conquista","it":"Divide et impera","de":"Teile und Herrsche","fr":"Diviser pour régner","tr":"Böl ve Fethet","nl":"Verdeel en heers","ru":"Разделяй и властвуй","zh":"分治法","pt_BR":"Divisão e Conquista","pt_PT":"Divisão e Conquista"}, back_translations: {"es":"Un paradigma de projeto de algoritmos: dividir el problema en subproblemas menores, resolver recursivamente y combinar los resultados. Ejemplos: merge sort, quicksort, busca binária, multiplicación de matrizes de Strassen.","it":"Un paradigme di concepzione d'algorithmes : diviser il probleme en sotto-problemes più petits, resoudre recursivement e combiner i resultats. Exemples : tri fusion, tri rapide, recherche binaire, multiplicazione matricielle di Strassen.","de":"Ein Algorithmus-Entwurfsparadigma: Problem in kleinere Teilprobleme aufteilen, rekursiv lösen und Ergebnisse zusammenführen. Beispiele: Merge Sort, Quicksort, binäre Suche, Strassens Matrixmultiplikation.","fr":"Un paradigme de conception d'algorithmes : diviser le problème en sous-problèmes plus petits, résoudre récursivement et combiner les résultats. Exemples : tri fusion, tri rapide, recherche binaire, multiplication matricielle de Strassen.","tr":"Bir algoritma tasarım paradigması: problemi daha küçük alt problemlere böl, özyinelemeli olarak çöz ve sonuçları birleştir. Örnekler: birleştirmeli sıralama, hızlı sıralama, ikili arama, Strassen matris çarpımı.","nl":"Een algoritme-ontwerpparadigma: verdeel het probleem in kleinere deelproblemen, los recursief op en combineer de resultaten. Voorbeelden: merge sort, quicksort, binair zoeken, Strassens matrixvermenigvuldiging.","ru":"Парадигма проектирования алгоритмов: разделить задачу на меньшие подзадачи, решить рекурсивно и объединить результаты. Примеры: сортировка слиянием, быстрая сортировка, бинарный поиск, умножение матриц Штрассена.","zh":"一种算法设计范式：将问题分解为更小的子问题，递归求解，然后合并结果。示例：归并排序、快速排序、二分查找、Strassen 矩阵乘法。","pt_BR":"Um paradigma de projeto de algoritmos: dividir o problema em subproblemas menores, resolver recursivamente e combinar os resultados. Exemplos: merge sort, quicksort, busca binária, multiplicação de matrizes de Strassen.","pt_PT":"Um paradigma de projeto de algoritmos: dividir o problema em subproblemas menores, resolver recursivamente e combinar os resultados. Exemplos: merge sort, quicksort, pesquisa binária, multiplicação de matrizes de Strassen."}},
  { id: 'dc-technology-0031', deck_id: 'deck-technology', sort_order: 31, front: "Recursion", back: "A function that calls itself with a smaller input until a base case is reached. Elegant for tree/graph problems, but can cause stack overflow if too deep. Often converted to iteration with explicit stack for efficiency." , front_translations: {"es":"Recursão","it":"Ricorsione","de":"Rekursion","fr":"Récursion","tr":"Özyineleme","nl":"Recursie","ru":"Рекурсия","zh":"递归","pt_BR":"Recursão","pt_PT":"Recursão"}, back_translations: {"es":"Una función que chama a si misma con una entrada menor hasta atingir un caso base. Elegante para problemas de árvores/grafos, pero puede causar estouro de pilha se muy profunda. Frecuentemente convertida en iteración con pilha explícita para eficiencia.","it":"Una fonczione che s'appelle elle-stesso con una entree più piccola jusqu'à atteindre un cas di base. Elegante per i problemes d'arbres/graphes, ma può provoquer un debordement di pile se trop profonde. Souvent convertie en iterazione con pile explicite per l'efficacite.","de":"Eine Funktion, die sich selbst mit einer kleineren Eingabe aufruft, bis ein Basisfall erreicht wird. Elegant für Baum-/Graphprobleme, kann aber bei zu großer Tiefe einen Stapelüberlauf verursachen. Oft für Effizienz in Iteration mit explizitem Stack umgewandelt.","fr":"Une fonction qui s'appelle elle-même avec une entrée plus petite jusqu'à atteindre un cas de base. Élégante pour les problèmes d'arbres/graphes, mais peut provoquer un débordement de pile si trop profonde. Souvent convertie en itération avec pile explicite pour l'efficacité.","tr":"Bir temel duruma ulaşana kadar kendini daha küçük bir girdiyle çağıran fonksiyon. Ağaç/graf problemleri için zarif, ancak çok derin olursa yığın taşmasına neden olabilir. Verimlilik için genellikle açık yığınla yinelemeye dönüştürülür.","nl":"Een functie die zichzelf aanroept met een kleinere invoer totdat een basisgeval wordt bereikt. Elegant voor boom-/graafproblemen, maar kan stackoverloop veroorzaken als de diepte te groot is. Vaak omgezet naar iteratie met expliciete stack voor efficiëntie.","ru":"Функция, которая вызывает саму себя с меньшим входом до достижения базового случая. Элегантна для задач на деревьях/графах, но может вызвать переполнение стека при большой глубине. Часто преобразуется в итерацию с явным стеком для эффективности.","zh":"一种函数，以更小的输入调用自身，直到达到基本情况。对树/图问题很优雅，但深度过大时可能导致栈溢出。通常为了效率而转换为使用显式栈的迭代。","pt_BR":"Uma função que chama a si mesma com uma entrada menor até atingir um caso base. Elegante para problemas de árvores/grafos, mas pode causar estouro de pilha se muito profunda. Frequentemente convertida em iteração com pilha explícita para eficiência.","pt_PT":"Uma função que chama a si mesma com uma entrada menor até atingir um caso base. Elegante para problemas de árvores/grafos, mas pode causar estouro de pilha se muito profunda. Frequentemente convertida em iteração com pilha explícita para eficiência."}},
  { id: 'dc-technology-0032', deck_id: 'deck-technology', sort_order: 32, front: "Memoization", back: "An optimization technique for recursion where results of expensive function calls are stored (cached) so they don't need to be recomputed. Top-down approach to dynamic programming." , front_translations: {"es":"Memoización","it":"Memoisatione","de":"Memoisation","fr":"Mémoïsation","tr":"Memoizasyon","nl":"Memoisatie","ru":"Мемоизация","zh":"记忆化","pt_BR":"Memoização","pt_PT":"Memoização"}, back_translations: {"es":"Una técnica de otimización para recursão donde los resultados de llamadas de función caras son armazenados (cacheados) para no precisarem ser recalculados. Abordaje top-down de la programación dinámica.","it":"Una technico d'optimisazione per la recursion où i resultats d'appels di fonczioni couteux sono stockes (mis en cache) per eviter di i recalculer. Approche descendante della programmazione dynamico.","de":"Eine Optimierungstechnik für Rekursion, bei der Ergebnisse teurer Funktionsaufrufe gespeichert (gecacht) werden, damit sie nicht erneut berechnet werden müssen. Top-Down-Ansatz der dynamischen Programmierung.","fr":"Une technique d'optimisation pour la récursion où les résultats d'appels de fonctions coûteux sont stockés (mis en cache) pour éviter de les recalculer. Approche descendante de la programmation dynamique.","tr":"Pahalı fonksiyon çağrılarının sonuçlarının saklandığı (önbelleğe alındığı) bir özyineleme optimizasyon tekniği; böylece yeniden hesaplanmaları gerekmez. Dinamik programlamaya yukarıdan aşağıya yaklaşım.","nl":"Een optimalisatietechniek voor recursie waarbij resultaten van dure functieaanroepen worden opgeslagen (gecacht) zodat ze niet opnieuw berekend hoeven te worden. Top-down benadering van dynamisch programmeren.","ru":"Техника оптимизации рекурсии, при которой результаты дорогих вызовов функций сохраняются (кешируются), чтобы не вычислять их повторно. Нисходящий подход к динамическому программированию.","zh":"一种递归优化技术，将昂贵的函数调用结果存储（缓存），避免重复计算。动态规划的自顶向下方法。","pt_BR":"Uma técnica de otimização para recursão onde os resultados de chamadas de função caras são armazenados (cacheados) para não precisarem ser recalculados. Abordagem top-down da programação dinâmica.","pt_PT":"Uma técnica de otimização para recursão onde os resultados de chamadas de função dispendiosas são armazenados (em cache) para não precisarem de ser recalculados. Abordagem top-down da programação dinâmica."}},
  { id: 'dc-technology-0033', deck_id: 'deck-technology', sort_order: 33, front: "Encapsulation (OOP)", back: "The bundling of data (attributes) and the methods that operate on that data within a class, hiding internal implementation details and exposing only what is necessary through a public interface." , front_translations: {"es":"Encapsulamento (POO)","it":"Encapsulatione (POO)","de":"Kapselung (OOP)","fr":"Encapsulation (POO)","tr":"Kapsülleme (OOP)","nl":"Inkapseling (OOP)","ru":"Инкапсуляция (ООП)","zh":"封装 (OOP)","pt_BR":"Encapsulamento (POO)","pt_PT":"Encapsulamento (POO)"}, back_translations: {"es":"El agrupamento de datos (atributos) y de los métodos que operam sobre esses datos dentro de una clase, ocultando detalhes de implementación internos y expondo solo el necesario por medio de una interfaz pública.","it":"Il regroupement dei donnees (attributs) e dei methodes che i manipulent al sein d'una classe, masquant i details d'implementazione internes e n'exposant che il necessario via una interface publico.","de":"Die Bündelung von Daten (Attributen) und den Methoden, die auf diesen Daten arbeiten, innerhalb einer Klasse. Verbirgt interne Implementierungsdetails und stellt nur das Nötige über eine öffentliche Schnittstelle bereit.","fr":"Le regroupement des données (attributs) et des méthodes qui les manipulent au sein d'une classe, masquant les détails d'implémentation internes et n'exposant que le nécessaire via une interface publique.","tr":"Verilerin (özniteliklerin) ve bu veriler üzerinde çalışan yöntemlerin bir sınıf içinde bir araya getirilmesi; iç uygulama ayrıntılarını gizleyerek yalnızca gerekli olanı genel bir arayüz üzerinden sunma.","nl":"Het bundelen van gegevens (attributen) en de methoden die op die gegevens werken binnen een klasse, waarbij interne implementatiedetails worden verborgen en alleen het noodzakelijke via een publieke interface wordt blootgesteld.","ru":"Объединение данных (атрибутов) и методов, работающих с этими данными, внутри класса, скрывая внутренние детали реализации и предоставляя доступ только к необходимому через публичный интерфейс.","zh":"将数据（属性）和操作这些数据的方法捆绑在一个类中，隐藏内部实现细节，仅通过公共接口暴露必要内容。","pt_BR":"O agrupamento de dados (atributos) e dos métodos que operam sobre esses dados dentro de uma classe, ocultando detalhes de implementação internos e expondo apenas o necessário por meio de uma interface pública.","pt_PT":"O agrupamento de dados (atributos) e dos métodos que operam sobre esses dados dentro de uma classe, ocultando detalhes de implementação internos e expondo apenas o necessário através de uma interface pública."}},
  { id: 'dc-technology-0034', deck_id: 'deck-technology', sort_order: 34, front: "Inheritance (OOP)", back: "A mechanism where a subclass acquires the properties and behaviors of a parent class. Promotes code reuse. Types: single, multiple (C++, Python), multilevel. Violating Liskov Substitution Principle is a common pitfall." , front_translations: {"es":"Herança (POO)","it":"Heritage (POO)","de":"Vererbung (OOP)","fr":"Héritage (POO)","tr":"Kalıtım (OOP)","nl":"Overerving (OOP)","ru":"Наследование (ООП)","zh":"继承 (OOP)","pt_BR":"Herança (POO)","pt_PT":"Herança (POO)"}, back_translations: {"es":"Un mecanismo donde una subclasse adquire las propiedades y comportamientos de una clase pai. Promueve a reutilización de código. Tipos: simples, múltipla (C++, Python), multinible. Violar el Principio de la Substituición de Liskov es una armadilha comum.","it":"Un mecanisme per lequel una sotto-classe acquiert i proprietàs e comportements d'una classe parente. Favorise la reutilisazione del code. Types : simple, multiple (C++, Python), multiniveau. Violer il principe di substituzione di Liskov e un piege courant.","de":"Ein Mechanismus, bei dem eine Unterklasse die Eigenschaften und Verhaltensweisen einer Elternklasse übernimmt. Fördert Wiederverwendung von Code. Typen: einfach, mehrfach (C++, Python), mehrstufig. Verletzung des Liskov-Substitutionsprinzips ist ein häufiger Fehler.","fr":"Un mécanisme par lequel une sous-classe acquiert les propriétés et comportements d'une classe parente. Favorise la réutilisation du code. Types : simple, multiple (C++, Python), multiniveau. Violer le principe de substitution de Liskov est un piège courant.","tr":"Bir alt sınıfın bir üst sınıfın özelliklerini ve davranışlarını edindiği mekanizma. Kod yeniden kullanımını teşvik eder. Türleri: tekli, çoklu (C++, Python), çok seviyeli. Liskov Yerine Geçme İlkesinin ihlali yaygın bir tuzaktır.","nl":"Een mechanisme waarbij een subklasse de eigenschappen en gedragingen van een ouderklasse overneemt. Bevordert hergebruik van code. Typen: enkelvoudig, meervoudig (C++, Python), meerniveaus. Schending van het Liskov-substitutieprincipe is een veelvoorkomende valkuil.","ru":"Механизм, при котором подкласс приобретает свойства и поведение родительского класса. Способствует повторному использованию кода. Типы: одиночное, множественное (C++, Python), многоуровневое. Нарушение принципа подстановки Лисков — распространённая ошибка.","zh":"子类获取父类属性和行为的机制。促进代码复用。类型：单继承、多继承（C++、Python）、多级继承。违反里氏替换原则是常见陷阱。","pt_BR":"Um mecanismo onde uma subclasse adquire as propriedades e comportamentos de uma classe pai. Promove a reutilização de código. Tipos: simples, múltipla (C++, Python), multinível. Violar o Princípio da Substituição de Liskov é uma armadilha comum.","pt_PT":"Um mecanismo onde uma subclasse adquire as propriedades e comportamentos de uma classe pai. Promove a reutilização de código. Tipos: simples, múltipla (C++, Python), multinível. Violar o Princípio da Substituição de Liskov é uma armadilha comum."}},
  { id: 'dc-technology-0035', deck_id: 'deck-technology', sort_order: 35, front: "Polymorphism (OOP)", back: "The ability of different objects to respond to the same interface in different ways. Compile-time polymorphism: method overloading. Runtime polymorphism: method overriding via virtual functions or interfaces." , front_translations: {"es":"Polimorfismo (POO)","it":"Polymorphisme (POO)","de":"Polymorphismus (OOP)","fr":"Polymorphisme (POO)","tr":"Çok Biçimlilik (OOP)","nl":"Polymorfisme (OOP)","ru":"Полиморфизм (ООП)","zh":"多态 (OOP)","pt_BR":"Polimorfismo (POO)","pt_PT":"Polimorfismo (POO)"}, back_translations: {"es":"La capacidad de diferentes objetos responderem a la misma interfaz de maneras diferentes. Polimorfismo en tiempo de compilación: sobrecarga de métodos. Polimorfismo en tiempo de execución: sobrescrita de métodos via funciones virtuais o interfaces.","it":"La capacite di differents objets à repondre alla stesso interface di manieres differentes. Polymorphisme alla compilazione : surcharge di methodes. Polymorphisme all'execuzione : redefinizione di methodes via dei fonczioni virtuelles o dei interfaces.","de":"Die Fähigkeit verschiedener Objekte, auf dieselbe Schnittstelle unterschiedlich zu reagieren. Kompilierzeit-Polymorphismus: Methodenüberladung. Laufzeit-Polymorphismus: Methodenüberschreibung über virtuelle Funktionen oder Schnittstellen.","fr":"La capacité de différents objets à répondre à la même interface de manières différentes. Polymorphisme à la compilation : surcharge de méthodes. Polymorphisme à l'exécution : redéfinition de méthodes via des fonctions virtuelles ou des interfaces.","tr":"Farklı nesnelerin aynı arayüze farklı şekillerde yanıt verebilme yeteneği. Derleme zamanı çok biçimliliği: metot aşırı yükleme. Çalışma zamanı çok biçimliliği: sanal fonksiyonlar veya arayüzler aracılığıyla metot geçersiz kılma.","nl":"Het vermogen van verschillende objecten om op dezelfde interface op verschillende manieren te reageren. Compile-time polymorfisme: method overloading. Runtime polymorfisme: method overriding via virtuele functies of interfaces.","ru":"Способность различных объектов по-разному реагировать на один и тот же интерфейс. Полиморфизм времени компиляции: перегрузка методов. Полиморфизм времени выполнения: переопределение методов через виртуальные функции или интерфейсы.","zh":"不同对象以不同方式响应同一接口的能力。编译时多态：方法重载。运行时多态：通过虚函数或接口的方法重写。","pt_BR":"A capacidade de diferentes objetos responderem à mesma interface de maneiras diferentes. Polimorfismo em tempo de compilação: sobrecarga de métodos. Polimorfismo em tempo de execução: sobrescrita de métodos via funções virtuais ou interfaces.","pt_PT":"A capacidade de diferentes objetos responderem à mesma interface de maneiras diferentes. Polimorfismo em tempo de compilação: sobrecarga de métodos. Polimorfismo em tempo de execução: sobreposição de métodos via funções virtuais ou interfaces."}},
  { id: 'dc-technology-0036', deck_id: 'deck-technology', sort_order: 36, front: "Abstraction (OOP)", back: "Hiding complex implementation details and showing only the essential features. Achieved through abstract classes and interfaces. Reduces complexity and allows focus on what an object does rather than how." , front_translations: {"es":"Abstración (POO)","it":"Abstractione (POO)","de":"Abstraktion (OOP)","fr":"Abstraction (POO)","tr":"Soyutlama (OOP)","nl":"Abstractie (OOP)","ru":"Абстракция (ООП)","zh":"抽象 (OOP)","pt_BR":"Abstração (POO)","pt_PT":"Abstração (POO)"}, back_translations: {"es":"Ocultar detalhes complexos de implementación y mostrar solo las características esenciales. Alcançada por medio de clases abstratas y interfaces. Reduce a complexidad y permite focar en el que un objeto hace en vez de como.","it":"Masquer i details d'implementazione complexes e non montrer che i caracteristici essentielles. Realisee via dei classes abstraites e dei interfaces. Reduit la complexite e permette di se concentrer su questo che fait un objet plutot che comment.","de":"Verbergen komplexer Implementierungsdetails und Zeigen nur der wesentlichen Merkmale. Erreicht durch abstrakte Klassen und Schnittstellen. Reduziert Komplexität und erlaubt den Fokus darauf, was ein Objekt tut, statt wie.","fr":"Masquer les détails d'implémentation complexes et ne montrer que les caractéristiques essentielles. Réalisée via des classes abstraites et des interfaces. Réduit la complexité et permet de se concentrer sur ce que fait un objet plutôt que comment.","tr":"Karmaşık uygulama ayrıntılarını gizleyerek yalnızca temel özellikleri gösterme. Soyut sınıflar ve arayüzler aracılığıyla elde edilir. Karmaşıklığı azaltır ve bir nesnenin nasıl yaptığından çok ne yaptığına odaklanmayı sağlar.","nl":"Het verbergen van complexe implementatiedetails en alleen de essentiële kenmerken tonen. Bereikt via abstracte klassen en interfaces. Vermindert complexiteit en maakt het mogelijk te focussen op wat een object doet in plaats van hoe.","ru":"Сокрытие сложных деталей реализации и показ только существенных характеристик. Достигается через абстрактные классы и интерфейсы. Снижает сложность и позволяет сосредоточиться на том, что объект делает, а не как.","zh":"隐藏复杂的实现细节，只展示基本特性。通过抽象类和接口实现。降低复杂性，使关注点集中在对象做什么而非如何做。","pt_BR":"Ocultar detalhes complexos de implementação e mostrar apenas as características essenciais. Alcançada por meio de classes abstratas e interfaces. Reduz a complexidade e permite focar no que um objeto faz em vez de como.","pt_PT":"Ocultar detalhes complexos de implementação e mostrar apenas as características essenciais. Alcançada através de classes abstratas e interfaces. Reduz a complexidade e permite focar no que um objeto faz em vez de como."}},
  { id: 'dc-technology-0037', deck_id: 'deck-technology', sort_order: 37, front: "Interface vs. Abstract Class", back: "Interface: a contract with no implementation (in most languages); a class can implement multiple interfaces. Abstract class: can have partial implementation; typically single inheritance. Interfaces favor composition over inheritance." , front_translations: {"es":"Interfaz vs. Clase Abstrata","it":"Interface vs. Classe abstraite","de":"Interface vs. Abstrakte Klasse","fr":"Interface vs. Classe abstraite","tr":"Arayüz vs. Soyut Sınıf","nl":"Interface vs. Abstracte Klasse","ru":"Интерфейс vs. Абстрактный класс","zh":"接口 vs. 抽象类","pt_BR":"Interface vs. Classe Abstrata","pt_PT":"Interface vs. Classe Abstrata"}, back_translations: {"es":"Interfaz: un contrato sin implementación (en la maioria de las linguajes); una clase puede implementar múltiplas interfaces. Clase abstrata: puede ter implementación parcial; típicamente herança simples. Interfaces favorecem composición sobre herança.","it":"Interface : un contrat senza implementazione (in la plupart dei langages) ; una classe può implementer plusiori interfaces. Classe abstraite : può avoir una implementazione partielle ; typiquement heritage simple. I interfaces favorisent la composizione plutot che l'heritage.","de":"Interface: ein Vertrag ohne Implementierung (in den meisten Sprachen); eine Klasse kann mehrere Interfaces implementieren. Abstrakte Klasse: kann teilweise Implementierung haben; typischerweise Einfachvererbung. Interfaces bevorzugen Komposition über Vererbung.","fr":"Interface : un contrat sans implémentation (dans la plupart des langages) ; une classe peut implémenter plusieurs interfaces. Classe abstraite : peut avoir une implémentation partielle ; typiquement héritage simple. Les interfaces favorisent la composition plutôt que l'héritage.","tr":"Arayüz: uygulaması olmayan bir sözleşme (çoğu dilde); bir sınıf birden fazla arayüz uygulayabilir. Soyut sınıf: kısmi uygulamaya sahip olabilir; genellikle tekli kalıtım. Arayüzler, kalıtım yerine bileşimi tercih eder.","nl":"Interface: een contract zonder implementatie (in de meeste talen); een klasse kan meerdere interfaces implementeren. Abstracte klasse: kan gedeeltelijke implementatie hebben; typisch enkelvoudige overerving. Interfaces bevorderen compositie boven overerving.","ru":"Интерфейс: контракт без реализации (в большинстве языков); класс может реализовать несколько интерфейсов. Абстрактный класс: может иметь частичную реализацию; обычно одиночное наследование. Интерфейсы предпочитают композицию наследованию.","zh":"接口：无实现的契约（在大多数语言中）；一个类可以实现多个接口。抽象类：可以有部分实现；通常是单继承。接口倾向于组合优于继承。","pt_BR":"Interface: um contrato sem implementação (na maioria das linguagens); uma classe pode implementar múltiplas interfaces. Classe abstrata: pode ter implementação parcial; tipicamente herança simples. Interfaces favorecem composição sobre herança.","pt_PT":"Interface: um contrato sem implementação (na maioria das linguagens); uma classe pode implementar múltiplas interfaces. Classe abstrata: pode ter implementação parcial; tipicamente herança simples. Interfaces favorecem composição em vez de herança."}},
  { id: 'dc-technology-0038', deck_id: 'deck-technology', sort_order: 38, front: "SOLID Principles", back: "Five OOP design principles: Single Responsibility, Open/Closed, Liskov Substitution, Interface Segregation, Dependency Inversion. Guide toward maintainable, extensible, and testable code." , front_translations: {"es":"Principios SOLID","it":"Principes SOLID","de":"SOLID-Prinzipien","fr":"Principes SOLID","tr":"SOLID İlkeleri","nl":"SOLID-principes","ru":"Принципы SOLID","zh":"SOLID 原则","pt_BR":"Princípios SOLID","pt_PT":"Princípios SOLID"}, back_translations: {"es":"Cinco principios de design OOP: Responsabilidad Única, Aberto/Fechado, Substituición de Liskov, Segregación de Interfaz, Inversão de Dependencia. Orientam para código sustentable, extensible y testable.","it":"Cinq principes di concepzione POO : Responsabilite unico, Ouvert/Ferme, Substituzione di Liskov, Segregazione dei interfaces, Inversion dei dependanze. Guident verso un code maintenable, extensible e testable.","de":"Fünf OOP-Designprinzipien: Single Responsibility, Open/Closed, Liskov Substitution, Interface Segregation, Dependency Inversion. Leiten zu wartbarem, erweiterbarem und testbarem Code.","fr":"Cinq principes de conception POO : Responsabilité unique, Ouvert/Fermé, Substitution de Liskov, Ségrégation des interfaces, Inversion des dépendances. Guident vers un code maintenable, extensible et testable.","tr":"Beş OOP tasarım ilkesi: Tek Sorumluluk, Açık/Kapalı, Liskov Yerine Geçme, Arayüz Ayrımı, Bağımlılık Tersine Çevirme. Bakımı kolay, genişletilebilir ve test edilebilir koda yönlendirir.","nl":"Vijf OOP-ontwerpprincipes: Single Responsibility, Open/Closed, Liskov Substitution, Interface Segregation, Dependency Inversion. Leiden naar onderhoudbare, uitbreidbare en testbare code.","ru":"Пять принципов проектирования ООП: единственная ответственность, открытость/закрытость, подстановка Лисков, разделение интерфейсов, инверсия зависимостей. Направляют к поддерживаемому, расширяемому и тестируемому коду.","zh":"五大 OOP 设计原则：单一职责、开闭原则、里氏替换、接口隔离、依赖倒置。指导编写可维护、可扩展和可测试的代码。","pt_BR":"Cinco princípios de design OOP: Responsabilidade Única, Aberto/Fechado, Substituição de Liskov, Segregação de Interface, Inversão de Dependência. Orientam para código sustentável, extensível e testável.","pt_PT":"Cinco princípios de design OOP: Responsabilidade Única, Aberto/Fechado, Substituição de Liskov, Segregação de Interface, Inversão de Dependência. Orientam para código sustentável, extensível e testável."}},
  { id: 'dc-technology-0039', deck_id: 'deck-technology', sort_order: 39, front: "Design Pattern: Singleton", back: "A creational pattern ensuring only one instance of a class exists and providing a global access point. Useful for shared resources (database connection, logger). Criticized for making testing difficult (global state)." , front_translations: {"es":"Padrão de Projeto: Singleton","it":"Patron di concettoione : Singleton","de":"Entwurfsmuster: Singleton","fr":"Patron de conception : Singleton","tr":"Tasarım Kalıbı: Singleton","nl":"Ontwerppatroon: Singleton","ru":"Паттерн проектирования: Одиночка","zh":"设计模式：单例模式","pt_BR":"Padrão de Projeto: Singleton","pt_PT":"Padrão de Projeto: Singleton"}, back_translations: {"es":"Un padrão criacional que garantiza que solo una instancia de una clase exista y proporciona un punto de acceso global. Útil para recursos compartilhados (conexión de base de datos, logger). Criticado por dificultar pruebas (estado global).","it":"Un patron di creazione garantissant che una seule instanza d'una classe existe e fournissant un point d'acces global. Utile per i resurces partagees (connexion base di donnees, logger). Critique car il rend i tests difficiles (etat global).","de":"Ein Erzeugungsmuster, das sicherstellt, dass nur eine Instanz einer Klasse existiert und einen globalen Zugriffspunkt bereitstellt. Nützlich für gemeinsame Ressourcen (Datenbankverbindung, Logger). Kritisiert, weil es Tests erschwert (globaler Zustand).","fr":"Un patron de création garantissant qu'une seule instance d'une classe existe et fournissant un point d'accès global. Utile pour les ressources partagées (connexion base de données, logger). Critiqué car il rend les tests difficiles (état global).","tr":"Bir sınıfın yalnızca bir örneğinin var olmasını sağlayan ve global bir erişim noktası sunan yaratımsal kalıp. Paylaşılan kaynaklar (veritabanı bağlantısı, logger) için kullanışlıdır. Test etmeyi zorlaştırdığı için eleştirilir (global durum).","nl":"Een creatiepatroon dat ervoor zorgt dat er slechts één instantie van een klasse bestaat en een globaal toegangspunt biedt. Nuttig voor gedeelde bronnen (databaseverbinding, logger). Bekritiseerd omdat het testen bemoeilijkt (globale toestand).","ru":"Порождающий паттерн, гарантирующий существование только одного экземпляра класса и предоставляющий глобальную точку доступа. Полезен для общих ресурсов (подключение к БД, логгер). Критикуется за усложнение тестирования (глобальное состояние).","zh":"一种创建型模式，确保一个类只有一个实例并提供全局访问点。适用于共享资源（数据库连接、日志记录器）。因使测试困难（全局状态）而受到批评。","pt_BR":"Um padrão criacional que garante que apenas uma instância de uma classe exista e fornece um ponto de acesso global. Útil para recursos compartilhados (conexão de banco de dados, logger). Criticado por dificultar testes (estado global).","pt_PT":"Um padrão criacional que garante que apenas uma instância de uma classe exista e fornece um ponto de acesso global. Útil para recursos partilhados (ligação à base de dados, logger). Criticado por dificultar testes (estado global)."}},
  { id: 'dc-technology-0040', deck_id: 'deck-technology', sort_order: 40, front: "Design Pattern: Factory Method", back: "A creational pattern defining an interface for creating objects but letting subclasses decide which class to instantiate. Decouples object creation from usage and makes code more extensible." , front_translations: {"es":"Padrão de Projeto: Factory Method","it":"Patron di concettoione : Methode fabrico","de":"Entwurfsmuster: Fabrikmethode","fr":"Patron de conception : Méthode fabrique","tr":"Tasarım Kalıbı: Fabrika Metodu","nl":"Ontwerppatroon: Factory Method","ru":"Паттерн проектирования: Фабричный метод","zh":"设计模式：工厂方法","pt_BR":"Padrão de Projeto: Factory Method","pt_PT":"Padrão de Projeto: Factory Method"}, back_translations: {"es":"Un padrão criacional que define una interfaz para criar objetos, pero permite que subclasses decidam qual clase instanciar. Desacopla a criación de objetos del uso y torna el código más extensible.","it":"Un patron di creazione definissant una interface per creer dei objets ma laissant i sotto-classes decider quelle classe instancier. Decouple la creazione d'objets di il loro utilisazione e rend il code più extensible.","de":"Ein Erzeugungsmuster, das eine Schnittstelle zum Erstellen von Objekten definiert, aber Unterklassen entscheiden lässt, welche Klasse instanziiert wird. Entkoppelt Objekterstellung von Nutzung und macht Code erweiterbarer.","fr":"Un patron de création définissant une interface pour créer des objets mais laissant les sous-classes décider quelle classe instancier. Découple la création d'objets de leur utilisation et rend le code plus extensible.","tr":"Nesne oluşturmak için bir arayüz tanımlayan ancak hangi sınıfın örnekleneceğine alt sınıfların karar vermesini sağlayan yaratımsal kalıp. Nesne oluşturmayı kullanımdan ayırır ve kodu daha genişletilebilir yapar.","nl":"Een creatiepatroon dat een interface definieert voor het maken van objecten maar subklassen laat beslissen welke klasse wordt geïnstantieerd. Ontkoppelt objectcreatie van gebruik en maakt code uitbreidbaarder.","ru":"Порождающий паттерн, определяющий интерфейс для создания объектов, но позволяющий подклассам решать, какой класс инстанцировать. Отделяет создание объектов от использования и делает код более расширяемым.","zh":"一种创建型模式，定义创建对象的接口，但让子类决定实例化哪个类。将对象创建与使用解耦，使代码更具可扩展性。","pt_BR":"Um padrão criacional que define uma interface para criar objetos, mas permite que subclasses decidam qual classe instanciar. Desacopla a criação de objetos do uso e torna o código mais extensível.","pt_PT":"Um padrão criacional que define uma interface para criar objetos, mas permite que subclasses decidam qual classe instanciar. Desacopla a criação de objetos da utilização e torna o código mais extensível."}},
  { id: 'dc-technology-0041', deck_id: 'deck-technology', sort_order: 41, front: "Design Pattern: Observer", back: "A behavioral pattern where an object (subject) maintains a list of dependents (observers) and notifies them of state changes. Forms the basis of event-driven programming and reactive frameworks." , front_translations: {"es":"Padrão de Projeto: Observer","it":"Patron di concettoione : Observatore","de":"Entwurfsmuster: Observer","fr":"Patron de conception : Observateur","tr":"Tasarım Kalıbı: Gözlemci","nl":"Ontwerppatroon: Observer","ru":"Паттерн проектирования: Наблюдатель","zh":"设计模式：观察者模式","pt_BR":"Padrão de Projeto: Observer","pt_PT":"Padrão de Projeto: Observer"}, back_translations: {"es":"Un padrão comportamental donde un objeto (sujeito) mantiene una lista de dependentes (observadores) y los notifica sobre cambios de estado. Forma a base de la programación orientada a eventos y frameworks reativos.","it":"Un patron comportemental où un objet (sujet) maintient una liste di dependants (observatori) e i notifie dei changements d'etat. Constitue la base della programmazione evenementielle e dei frameworks reactifs.","de":"Ein Verhaltensmuster, bei dem ein Objekt (Subjekt) eine Liste von Abhängigen (Beobachtern) pflegt und sie über Zustandsänderungen benachrichtigt. Bildet die Grundlage der ereignisgesteuerten Programmierung und reaktiver Frameworks.","fr":"Un patron comportemental où un objet (sujet) maintient une liste de dépendants (observateurs) et les notifie des changements d'état. Constitue la base de la programmation événementielle et des frameworks réactifs.","tr":"Bir nesnenin (konu) bağımlıların (gözlemciler) bir listesini tuttuğu ve durum değişikliklerini onlara bildirdiği davranışsal kalıp. Olay güdümlü programlamanın ve reaktif çerçevelerin temelini oluşturur.","nl":"Een gedragspatroon waarbij een object (subject) een lijst van afhankelijken (observers) bijhoudt en hen op de hoogte stelt van toestandsveranderingen. Vormt de basis van event-driven programmering en reactieve frameworks.","ru":"Поведенческий паттерн, в котором объект (субъект) поддерживает список зависимых (наблюдателей) и уведомляет их об изменениях состояния. Лежит в основе событийно-ориентированного программирования и реактивных фреймворков.","zh":"一种行为型模式，其中一个对象（主题）维护一个依赖者（观察者）列表，并在状态变化时通知它们。构成事件驱动编程和响应式框架的基础。","pt_BR":"Um padrão comportamental onde um objeto (sujeito) mantém uma lista de dependentes (observadores) e os notifica sobre mudanças de estado. Forma a base da programação orientada a eventos e frameworks reativos.","pt_PT":"Um padrão comportamental onde um objeto (sujeito) mantém uma lista de dependentes (observadores) e os notifica sobre mudanças de estado. Forma a base da programação orientada a eventos e frameworks reativos."}},
  { id: 'dc-technology-0042', deck_id: 'deck-technology', sort_order: 42, front: "Design Pattern: MVC", back: "Model-View-Controller: separates an application into Model (data/business logic), View (user interface), and Controller (handles input, updates model). Promotes separation of concerns and testability." , front_translations: {"es":"Padrão de Projeto: MVC","it":"Patron di concettoione : MVC","de":"Entwurfsmuster: MVC","fr":"Patron de conception : MVC","tr":"Tasarım Kalıbı: MVC","nl":"Ontwerppatroon: MVC","ru":"Паттерн проектирования: MVC","zh":"设计模式：MVC","pt_BR":"Padrão de Projeto: MVC","pt_PT":"Padrão de Projeto: MVC"}, back_translations: {"es":"Model-View-Controller: separa una aplicación en Model (datos/lógica de negocios), View (interfaz del usuario) y Controller (lida con entrada, atualiza el modelo). Promueve separación de responsabilidades y testabilidad.","it":"Modeil-Vue-Controil loro : separe una applicazione en Modeil (donnees/logico metier), Vue (interface utilisatore) e Controil loro (gere i entrees, met à jour il modeil). Favorise la separazione dei preoccupazioni e la testabilite.","de":"Model-View-Controller: trennt eine Anwendung in Model (Daten/Geschäftslogik), View (Benutzeroberfläche) und Controller (verarbeitet Eingaben, aktualisiert Model). Fördert Trennung der Zuständigkeiten und Testbarkeit.","fr":"Modèle-Vue-Contrôleur : sépare une application en Modèle (données/logique métier), Vue (interface utilisateur) et Contrôleur (gère les entrées, met à jour le modèle). Favorise la séparation des préoccupations et la testabilité.","tr":"Model-View-Controller: bir uygulamayı Model (veri/iş mantığı), View (kullanıcı arayüzü) ve Controller (girdiyi yönetir, modeli günceller) olarak ayırır. Sorumlulukların ayrılmasını ve test edilebilirliği teşvik eder.","nl":"Model-View-Controller: scheidt een applicatie in Model (gegevens/bedrijfslogica), View (gebruikersinterface) en Controller (verwerkt invoer, werkt model bij). Bevordert scheiding van verantwoordelijkheden en testbaarheid.","ru":"Model-View-Controller: разделяет приложение на Model (данные/бизнес-логика), View (пользовательский интерфейс) и Controller (обрабатывает ввод, обновляет модель). Способствует разделению ответственности и тестируемости.","zh":"模型-视图-控制器：将应用程序分为 Model（数据/业务逻辑）、View（用户界面）和 Controller（处理输入、更新模型）。促进关注点分离和可测试性。","pt_BR":"Model-View-Controller: separa uma aplicação em Model (dados/lógica de negócios), View (interface do usuário) e Controller (lida com entrada, atualiza o modelo). Promove separação de responsabilidades e testabilidade.","pt_PT":"Model-View-Controller: separa uma aplicação em Model (dados/lógica de negócios), View (interface do utilizador) e Controller (lida com entrada, atualiza o modelo). Promove separação de responsabilidades e testabilidade."}},
  { id: 'dc-technology-0043', deck_id: 'deck-technology', sort_order: 43, front: "Design Pattern: Strategy", back: "A behavioral pattern that defines a family of algorithms, encapsulates each one, and makes them interchangeable. The client can select the algorithm at runtime. Replaces complex if-else or switch statements." , front_translations: {"es":"Padrão de Projeto: Strategy","it":"Patron di concettoione : Stratàgie","de":"Entwurfsmuster: Strategie","fr":"Patron de conception : Stratégie","tr":"Tasarım Kalıbı: Strateji","nl":"Ontwerppatroon: Strategy","ru":"Паттерн проектирования: Стратегия","zh":"设计模式：策略模式","pt_BR":"Padrão de Projeto: Strategy","pt_PT":"Padrão de Projeto: Strategy"}, back_translations: {"es":"Un padrão comportamental que define una família de algoritmos, encapsula cada un y los torna intercambiables. El cliente puede selecionar el algoritmo en tiempo de execución. Substitui instrucciones if-else o switch complexas.","it":"Un patron comportemental che definit una famille d'algorithmes, encapsule chacun e i rend interchangeables. Il client può selectionner l'algorithme all'execuzione. Remplace i instruczioni if-else o switch complexes.","de":"Ein Verhaltensmuster, das eine Familie von Algorithmen definiert, jeden kapselt und sie austauschbar macht. Der Client kann den Algorithmus zur Laufzeit auswählen. Ersetzt komplexe if-else- oder switch-Anweisungen.","fr":"Un patron comportemental qui définit une famille d'algorithmes, encapsule chacun et les rend interchangeables. Le client peut sélectionner l'algorithme à l'exécution. Remplace les instructions if-else ou switch complexes.","tr":"Bir algoritma ailesi tanımlayan, her birini kapsülleyen ve birbiriyle değiştirilebilir kılan davranışsal kalıp. İstemci algoritmayı çalışma zamanında seçebilir. Karmaşık if-else veya switch ifadelerinin yerini alır.","nl":"Een gedragspatroon dat een familie van algoritmen definieert, elk inkapselt en ze onderling verwisselbaar maakt. De client kan het algoritme tijdens runtime selecteren. Vervangt complexe if-else of switch-statements.","ru":"Поведенческий паттерн, определяющий семейство алгоритмов, инкапсулирующий каждый и делающий их взаимозаменяемыми. Клиент может выбрать алгоритм во время выполнения. Заменяет сложные конструкции if-else или switch.","zh":"一种行为型模式，定义一系列算法，封装每个算法并使它们可互换。客户端可以在运行时选择算法。替代复杂的 if-else 或 switch 语句。","pt_BR":"Um padrão comportamental que define uma família de algoritmos, encapsula cada um e os torna intercambiáveis. O cliente pode selecionar o algoritmo em tempo de execução. Substitui instruções if-else ou switch complexas.","pt_PT":"Um padrão comportamental que define uma família de algoritmos, encapsula cada um e os torna intercambiáveis. O cliente pode selecionar o algoritmo em tempo de execução. Substitui instruções if-else ou switch complexas."}},
  { id: 'dc-technology-0044', deck_id: 'deck-technology', sort_order: 44, front: "Design Pattern: Decorator", back: "A structural pattern that adds behavior to objects dynamically by wrapping them in decorator objects implementing the same interface. Favors composition over inheritance. E.g., Java I/O streams." , front_translations: {"es":"Padrão de Projeto: Decorator","it":"Patron di concettoione : Decoratore","de":"Entwurfsmuster: Dekorator","fr":"Patron de conception : Décorateur","tr":"Tasarım Kalıbı: Dekoratör","nl":"Ontwerppatroon: Decorator","ru":"Паттерн проектирования: Декоратор","zh":"设计模式：装饰器模式","pt_BR":"Padrão de Projeto: Decorator","pt_PT":"Padrão de Projeto: Decorator"}, back_translations: {"es":"Un padrão estrutural que adiciona comportamiento a objetos dinamicamente, involucrando-los en objetos decoradores que implementam a misma interfaz. Favorece composición sobre herança. Ex.: streams de I/El del Java.","it":"Un patron structurel che ajoute dynamiquement del comportement ai objets en i enveloppant in dei objets decoratori implementant la stesso interface. Favorise la composizione plutot che l'heritage. Ex. : flux I/O Java.","de":"Ein Strukturmuster, das Objekten dynamisch Verhalten hinzufügt, indem es sie in Dekorator-Objekte einwickelt, die dieselbe Schnittstelle implementieren. Bevorzugt Komposition über Vererbung. Z.B. Java I/O Streams.","fr":"Un patron structurel qui ajoute dynamiquement du comportement aux objets en les enveloppant dans des objets décorateurs implémentant la même interface. Favorise la composition plutôt que l'héritage. Ex. : flux I/O Java.","tr":"Aynı arayüzü uygulayan dekoratör nesnelerine sararak nesnelere dinamik olarak davranış ekleyen yapısal kalıp. Kalıtım yerine bileşimi tercih eder. Örn.: Java I/O akışları.","nl":"Een structuurpatroon dat dynamisch gedrag toevoegt aan objecten door ze te wrappen in decorator-objecten die dezelfde interface implementeren. Geeft voorkeur aan compositie boven overerving. Bijv. Java I/O streams.","ru":"Структурный паттерн, динамически добавляющий поведение объектам путём оборачивания их в объекты-декораторы, реализующие тот же интерфейс. Предпочитает композицию наследованию. Напр.: потоки ввода-вывода Java.","zh":"一种结构型模式，通过将对象包装在实现相同接口的装饰器对象中，动态地为对象添加行为。倾向于组合优于继承。例如：Java I/O 流。","pt_BR":"Um padrão estrutural que adiciona comportamento a objetos dinamicamente, envolvendo-os em objetos decoradores que implementam a mesma interface. Favorece composição sobre herança. Ex.: streams de I/O do Java.","pt_PT":"Um padrão estrutural que adiciona comportamento a objetos dinamicamente, envolvendo-os em objetos decoradores que implementam a mesma interface. Favorece composição em vez de herança. Ex.: streams de I/O do Java."}},
  { id: 'dc-technology-0045', deck_id: 'deck-technology', sort_order: 45, front: "TCP/IP", back: "Transmission Control Protocol / Internet Protocol. The foundational suite of communication protocols for the internet. TCP ensures reliable, ordered data delivery; IP handles addressing and routing." , front_translations: {"es":"TCP/IP","it":"TCP/IP","de":"TCP/IP","fr":"TCP/IP","tr":"TCP/IP","nl":"TCP/IP","ru":"TCP/IP","zh":"TCP/IP","pt_BR":"TCP/IP","pt_PT":"TCP/IP"}, back_translations: {"es":"Transmission Control Protocol / Internet Protocol. El conjunto fundamental de protocolos de comunicación para a internet. TCP garantiza entrega confiable y ordenada de datos; IP lida con endereçamento y roteamento.","it":"Transmission Control Protocol / Internet Protocol. La suite fondamentale di protocoles di communicazione per Internet. TCP assure una livraison fiable e ordonnee dei donnees ; IP gere l'adressage e il routage.","de":"Transmission Control Protocol / Internet Protocol. Die grundlegende Protokollsuite für Kommunikation im Internet. TCP gewährleistet zuverlässige, geordnete Datenübertragung; IP kümmert sich um Adressierung und Routing.","fr":"Transmission Control Protocol / Internet Protocol. La suite fondamentale de protocoles de communication pour Internet. TCP assure une livraison fiable et ordonnée des données ; IP gère l'adressage et le routage.","tr":"Transmission Control Protocol / Internet Protocol. İnternet için temel iletişim protokol paketi. TCP güvenilir, sıralı veri iletimini sağlar; IP adresleme ve yönlendirmeyi yönetir.","nl":"Transmission Control Protocol / Internet Protocol. De fundamentele suite van communicatieprotocollen voor het internet. TCP zorgt voor betrouwbare, geordende dataoverdracht; IP regelt adressering en routering.","ru":"Transmission Control Protocol / Internet Protocol. Основной набор протоколов связи для интернета. TCP обеспечивает надёжную, упорядоченную доставку данных; IP отвечает за адресацию и маршрутизацию.","zh":"传输控制协议 / 互联网协议。互联网的基础通信协议套件。TCP 确保可靠、有序的数据传输；IP 处理寻址和路由。","pt_BR":"Transmission Control Protocol / Internet Protocol. O conjunto fundamental de protocolos de comunicação para a internet. TCP garante entrega confiável e ordenada de dados; IP lida com endereçamento e roteamento.","pt_PT":"Transmission Control Protocol / Internet Protocol. O conjunto fundamental de protocolos de comunicação para a internet. TCP garante entrega fiável e ordenada de dados; IP trata do endereçamento e encaminhamento."}},
  { id: 'dc-technology-0046', deck_id: 'deck-technology', sort_order: 46, front: "OSI Model", back: "A 7-layer conceptual framework: Physical, Data Link, Network, Transport, Session, Presentation, Application. Each layer provides services to the layer above and uses services of the layer below." , front_translations: {"es":"Modelo OSI","it":"Modello OSI","de":"OSI-Modell","fr":"Modèle OSI","tr":"OSI Modeli","nl":"OSI-model","ru":"Модель OSI","zh":"OSI 模型","pt_BR":"Modelo OSI","pt_PT":"Modelo OSI"}, back_translations: {"es":"Un framework conceitual de 7 capas: Física, Enlace de Datos, Red, Transporte, Sesión, Apresentación, Aplicación. Cada capa proporciona serviços a la capa encima y utiliza serviços de la capa debajo.","it":"Un cadre conceptuel à 7 couches : Physico, Liaison di donnees, Reseau, Transport, Session, Presentazione, Applicazione. Chaque couche fornisce dei services alla couche superieure e utilise ceux della couche inferieure.","de":"Ein konzeptionelles 7-Schichten-Modell: Physisch, Sicherung, Netzwerk, Transport, Sitzung, Darstellung, Anwendung. Jede Schicht bietet Dienste für die darüberliegende und nutzt Dienste der darunterliegenden Schicht.","fr":"Un cadre conceptuel à 7 couches : Physique, Liaison de données, Réseau, Transport, Session, Présentation, Application. Chaque couche fournit des services à la couche supérieure et utilise ceux de la couche inférieure.","tr":"7 katmanlı kavramsal çerçeve: Fiziksel, Veri Bağlantısı, Ağ, Taşıma, Oturum, Sunum, Uygulama. Her katman üstündeki katmana hizmet sağlar ve altındaki katmanın hizmetlerini kullanır.","nl":"Een conceptueel raamwerk met 7 lagen: Fysiek, Dataverbinding, Netwerk, Transport, Sessie, Presentatie, Applicatie. Elke laag biedt diensten aan de bovenliggende laag en gebruikt diensten van de onderliggende laag.","ru":"Концептуальная модель из 7 уровней: Физический, Канальный, Сетевой, Транспортный, Сеансовый, Представления, Прикладной. Каждый уровень предоставляет услуги вышестоящему и использует услуги нижестоящего.","zh":"7 层概念框架：物理层、数据链路层、网络层、传输层、会话层、表示层、应用层。每层为上层提供服务并使用下层的服务。","pt_BR":"Um framework conceitual de 7 camadas: Física, Enlace de Dados, Rede, Transporte, Sessão, Apresentação, Aplicação. Cada camada fornece serviços à camada acima e utiliza serviços da camada abaixo.","pt_PT":"Um framework conceptual de 7 camadas: Física, Ligação de Dados, Rede, Transporte, Sessão, Apresentação, Aplicação. Cada camada fornece serviços à camada acima e utiliza serviços da camada abaixo."}},
  { id: 'dc-technology-0047', deck_id: 'deck-technology', sort_order: 47, front: "OSI Model Layers Mnemonic", back: "All People Seem To Need Data Processing (Application, Presentation, Session, Transport, Network, Data Link, Physical). Or from bottom: Please Do Not Throw Sausage Pizza Away." , front_translations: {"es":"Mnemonico de las Capas del Modelo OSI","it":"Mnemonico dei couches OSI","de":"OSI-Modell Schichten-Eselsbrücke","fr":"Mnémonique des couches OSI","tr":"OSI Modeli Katman Hatırlatıcısı","nl":"OSI-model lagen geheugensteun","ru":"Мнемоника уровней модели OSI","zh":"OSI 模型层级助记口诀","pt_BR":"Mnemônico das Camadas do Modelo OSI","pt_PT":"Mnemónica das Camadas do Modelo OSI"}, back_translations: {"es":"All People Seem To Need Data Processing (Application, Presentation, Session, Transport, Network, Data Link, Physical). O de bajo: Please Do Not Throw Sausage Pizza Away.","it":"All People Seem To Need Data Processing (Applicazione, Presentazione, Session, Transport, Network, Data Link, Physical). O depuis il bas : Please Do Not Throw Sausage Pizza Away.","de":"All People Seem To Need Data Processing (Application, Presentation, Session, Transport, Network, Data Link, Physical). Oder von unten: Please Do Not Throw Sausage Pizza Away.","fr":"All People Seem To Need Data Processing (Application, Presentation, Session, Transport, Network, Data Link, Physical). Ou depuis le bas : Please Do Not Throw Sausage Pizza Away.","tr":"All People Seem To Need Data Processing (Application, Presentation, Session, Transport, Network, Data Link, Physical). Ya da alttan: Please Do Not Throw Sausage Pizza Away.","nl":"All People Seem To Need Data Processing (Application, Presentation, Session, Transport, Network, Data Link, Physical). Of van onder: Please Do Not Throw Sausage Pizza Away.","ru":"All People Seem To Need Data Processing (Application, Presentation, Session, Transport, Network, Data Link, Physical). Или снизу: Please Do Not Throw Sausage Pizza Away.","zh":"All People Seem To Need Data Processing（Application, Presentation, Session, Transport, Network, Data Link, Physical）。或从下往上：Please Do Not Throw Sausage Pizza Away。","pt_BR":"All People Seem To Need Data Processing (Application, Presentation, Session, Transport, Network, Data Link, Physical). Ou de baixo: Please Do Not Throw Sausage Pizza Away.","pt_PT":"All People Seem To Need Data Processing (Application, Presentation, Session, Transport, Network, Data Link, Physical). Ou de baixo: Please Do Not Throw Sausage Pizza Away."}},
  { id: 'dc-technology-0048', deck_id: 'deck-technology', sort_order: 48, front: "HTTP vs. HTTPS", back: "HTTP: HyperText Transfer Protocol; transfers data in plaintext, port 80. HTTPS: HTTP Secure; encrypts with TLS/SSL, port 443. HTTPS protects data confidentiality, integrity, and authenticates the server." , front_translations: {"es":"HTTP vs. HTTPS","it":"HTTP vs. HTTPS","de":"HTTP vs. HTTPS","fr":"HTTP vs. HTTPS","tr":"HTTP vs. HTTPS","nl":"HTTP vs. HTTPS","ru":"HTTP vs. HTTPS","zh":"HTTP vs. HTTPS","pt_BR":"HTTP vs. HTTPS","pt_PT":"HTTP vs. HTTPS"}, back_translations: {"es":"HTTP: HyperText Transfer Protocol; transfere datos en texto simples, porta 80. HTTPS: HTTP Secure; criptografa con TLS/SSL, porta 443. HTTPS protege confidencialidad, integridad y autentica el servidor.","it":"HTTP : HyperText Transfer Protocol ; transfere i donnees en texte clair, port 80. HTTPS : HTTP Secure ; chiffre con TLS/SSL, port 443. HTTPS protege la confidentialite, l'integrite e authentifie il servore.","de":"HTTP: HyperText Transfer Protocol; überträgt Daten im Klartext, Port 80. HTTPS: HTTP Secure; verschlüsselt mit TLS/SSL, Port 443. HTTPS schützt Vertraulichkeit, Integrität und authentifiziert den Server.","fr":"HTTP : HyperText Transfer Protocol ; transfère les données en texte clair, port 80. HTTPS : HTTP Secure ; chiffre avec TLS/SSL, port 443. HTTPS protège la confidentialité, l'intégrité et authentifie le serveur.","tr":"HTTP: HyperText Transfer Protocol; verileri düz metin olarak aktarır, port 80. HTTPS: HTTP Secure; TLS/SSL ile şifreler, port 443. HTTPS veri gizliliğini, bütünlüğünü korur ve sunucuyu doğrular.","nl":"HTTP: HyperText Transfer Protocol; verstuurt gegevens in platte tekst, poort 80. HTTPS: HTTP Secure; versleutelt met TLS/SSL, poort 443. HTTPS beschermt vertrouwelijkheid, integriteit en authenticeert de server.","ru":"HTTP: HyperText Transfer Protocol; передаёт данные открытым текстом, порт 80. HTTPS: HTTP Secure; шифрует с помощью TLS/SSL, порт 443. HTTPS защищает конфиденциальность, целостность данных и аутентифицирует сервер.","zh":"HTTP：超文本传输协议；以明文传输数据，端口 80。HTTPS：安全 HTTP；使用 TLS/SSL 加密，端口 443。HTTPS 保护数据机密性、完整性并验证服务器身份。","pt_BR":"HTTP: HyperText Transfer Protocol; transfere dados em texto simples, porta 80. HTTPS: HTTP Secure; criptografa com TLS/SSL, porta 443. HTTPS protege confidencialidade, integridade e autentica o servidor.","pt_PT":"HTTP: HyperText Transfer Protocol; transfere dados em texto simples, porta 80. HTTPS: HTTP Secure; encripta com TLS/SSL, porta 443. HTTPS protege a confidencialidade, integridade e autentica o servidor."}},
  { id: 'dc-technology-0049', deck_id: 'deck-technology', sort_order: 49, front: "DNS — Domain Name System", back: "Translates human-readable domain names (e.g., google.com) into IP addresses. Hierarchical distributed database. DNS resolution: browser cache → OS cache → recursive resolver → root → TLD → authoritative nameserver." , front_translations: {"es":"DNS — Sistema de Nombres de Domínio","it":"DNS — Domain Name System","de":"DNS — Domain Name System","fr":"DNS — Domain Name System","tr":"DNS — Alan Adı Sistemi","nl":"DNS — Domain Name System","ru":"DNS — система доменных имён","zh":"DNS — 域名系统","pt_BR":"DNS — Sistema de Nomes de Domínio","pt_PT":"DNS — Sistema de Nomes de Domínio"}, back_translations: {"es":"Traduz nombres de domínio legibles (ex.: google.con) en endereços IP. Base de datos distribuído hierárquico. Resolución DNS: cache del navegador → cache del SO → resolvedor recursivo → raíz → TLD → servidor de nombres autoritativo.","it":"Traduit i noms di domaine lisibles (ex. : google.com) en adresses IP. Base di donnees distribuee hierarchico. Resoluzione DNS : cache navigatore → cache OS → resolvore recursif → racine → TLD → servore di noms autoritaire.","de":"Übersetzt menschenlesbare Domainnamen (z.B. google.com) in IP-Adressen. Hierarchische verteilte Datenbank. DNS-Auflösung: Browser-Cache → OS-Cache → Rekursiver Resolver → Root → TLD → Autoritativer Nameserver.","fr":"Traduit les noms de domaine lisibles (ex. : google.com) en adresses IP. Base de données distribuée hiérarchique. Résolution DNS : cache navigateur → cache OS → résolveur récursif → racine → TLD → serveur de noms autoritaire.","tr":"İnsan tarafından okunabilir alan adlarını (örn. google.com) IP adreslerine çevirir. Hiyerarşik dağıtık veritabanı. DNS çözümleme: tarayıcı önbelleği → OS önbelleği → özyinelemeli çözümleyici → kök → TLD → yetkili ad sunucusu.","nl":"Vertaalt menselijk leesbare domeinnamen (bijv. google.com) naar IP-adressen. Hiërarchische gedistribueerde database. DNS-resolutie: browsercache → OS-cache → recursieve resolver → root → TLD → autoritatieve nameserver.","ru":"Преобразует понятные человеку доменные имена (напр., google.com) в IP-адреса. Иерархическая распределённая база данных. Разрешение DNS: кеш браузера → кеш ОС → рекурсивный резолвер → корневой → TLD → авторитетный сервер имён.","zh":"将人类可读的域名（如 google.com）转换为 IP 地址。层级分布式数据库。DNS 解析流程：浏览器缓存 → 操作系统缓存 → 递归解析器 → 根服务器 → TLD → 权威域名服务器。","pt_BR":"Traduz nomes de domínio legíveis (ex.: google.com) em endereços IP. Banco de dados distribuído hierárquico. Resolução DNS: cache do navegador → cache do SO → resolvedor recursivo → raiz → TLD → servidor de nomes autoritativo.","pt_PT":"Traduz nomes de domínio legíveis (ex.: google.com) em endereços IP. Base de dados distribuída hierárquica. Resolução DNS: cache do navegador → cache do SO → resolvedor recursivo → raiz → TLD → servidor de nomes autoritativo."}},
  { id: 'dc-technology-0050', deck_id: 'deck-technology', sort_order: 50, front: "TLS/SSL", back: "Transport Layer Security / Secure Sockets Layer. A cryptographic protocol providing secure communication over a network. Uses asymmetric encryption for key exchange, then symmetric encryption for data. Certificates verify identity." , front_translations: {"es":"TLS/SSL","it":"TLS/SSL","de":"TLS/SSL","fr":"TLS/SSL","tr":"TLS/SSL","nl":"TLS/SSL","ru":"TLS/SSL","zh":"TLS/SSL","pt_BR":"TLS/SSL","pt_PT":"TLS/SSL"}, back_translations: {"es":"Transport Layer Security / Secure Sockets Layer. Un protocolo criptográfico que proporciona comunicación segura en una red. Usa criptografia assimétrica para troca de chaves, después criptografia simétrica para datos. Certificados verificam a identidad.","it":"Transport Layer Security / Secure Sockets Layer. Un protocole cryptographico assurant una communicazione securisee su un reseau. Utilise il chiffrement asymetrico per l'echange di cles, puis il chiffrement symetrico per i donnees. I certificats verifient l'identite.","de":"Transport Layer Security / Secure Sockets Layer. Ein kryptografisches Protokoll für sichere Kommunikation über ein Netzwerk. Verwendet asymmetrische Verschlüsselung für den Schlüsselaustausch, dann symmetrische Verschlüsselung für Daten. Zertifikate verifizieren die Identität.","fr":"Transport Layer Security / Secure Sockets Layer. Un protocole cryptographique assurant une communication sécurisée sur un réseau. Utilise le chiffrement asymétrique pour l'échange de clés, puis le chiffrement symétrique pour les données. Les certificats vérifient l'identité.","tr":"Transport Layer Security / Secure Sockets Layer. Bir ağ üzerinde güvenli iletişim sağlayan kriptografik bir protokol. Anahtar değişimi için asimetrik şifreleme, ardından veriler için simetrik şifreleme kullanır. Sertifikalar kimliği doğrular.","nl":"Transport Layer Security / Secure Sockets Layer. Een cryptografisch protocol dat veilige communicatie over een netwerk biedt. Gebruikt asymmetrische encryptie voor sleuteluitwisseling, vervolgens symmetrische encryptie voor data. Certificaten verifiëren de identiteit.","ru":"Transport Layer Security / Secure Sockets Layer. Криптографический протокол, обеспечивающий безопасную связь по сети. Использует асимметричное шифрование для обмена ключами, затем симметричное шифрование для данных. Сертификаты подтверждают личность.","zh":"传输层安全协议 / 安全套接层。一种通过网络提供安全通信的加密协议。使用非对称加密进行密钥交换，然后使用对称加密传输数据。证书用于验证身份。","pt_BR":"Transport Layer Security / Secure Sockets Layer. Um protocolo criptográfico que fornece comunicação segura em uma rede. Usa criptografia assimétrica para troca de chaves, depois criptografia simétrica para dados. Certificados verificam a identidade.","pt_PT":"Transport Layer Security / Secure Sockets Layer. Um protocolo criptográfico que fornece comunicação segura numa rede. Usa encriptação assimétrica para troca de chaves, depois encriptação simétrica para dados. Os certificados verificam a identidade."}},
  { id: 'dc-technology-0051', deck_id: 'deck-technology', sort_order: 51, front: "TCP Three-Way Handshake", back: "The process establishing a TCP connection: SYN (client initiates) → SYN-ACK (server acknowledges and responds) → ACK (client acknowledges). After this, data can be transmitted reliably." , front_translations: {"es":"Handshake de tres vias del TCP","it":"Poignee di main TCP en tres etapes","de":"TCP-Drei-Wege-Handshake","fr":"Poignée de main TCP en trois étapes","tr":"TCP Üçlü El Sıkışma","nl":"TCP Drieweg-handshake","ru":"Трёхстороннее рукопожатие TCP","zh":"TCP 三次握手","pt_BR":"Handshake de três vias do TCP","pt_PT":"Handshake de três vias do TCP"}, back_translations: {"es":"El proceso de estabelecimento de una conexión TCP: SYN (cliente inicia) → SYN-ACK (servidor confirma y responde) → ACK (cliente confirma). Después disso, los datos pueden ser transmitidos de forma confiable.","it":"Il processo d'etablissement d'una connexion TCP : SYN (il client initie) → SYN-ACK (il servore accuse recepzione e repond) → ACK (il client accuse recepzione). Ensuite, i donnees possono etre transmises di maniere fiable.","de":"Der Prozess zum Aufbau einer TCP-Verbindung: SYN (Client initiiert) → SYN-ACK (Server bestätigt und antwortet) → ACK (Client bestätigt). Danach können Daten zuverlässig übertragen werden.","fr":"Le processus d'établissement d'une connexion TCP : SYN (le client initie) → SYN-ACK (le serveur accuse réception et répond) → ACK (le client accuse réception). Ensuite, les données peuvent être transmises de manière fiable.","tr":"Bir TCP bağlantısı kurma süreci: SYN (istemci başlatır) → SYN-ACK (sunucu onaylar ve yanıt verir) → ACK (istemci onaylar). Bundan sonra veriler güvenilir şekilde iletilebilir.","nl":"Het proces voor het opzetten van een TCP-verbinding: SYN (client initieert) → SYN-ACK (server bevestigt en reageert) → ACK (client bevestigt). Hierna kunnen gegevens betrouwbaar worden verzonden.","ru":"Процесс установления TCP-соединения: SYN (клиент инициирует) → SYN-ACK (сервер подтверждает и отвечает) → ACK (клиент подтверждает). После этого данные могут передаваться надёжно.","zh":"建立 TCP 连接的过程：SYN（客户端发起）→ SYN-ACK（服务器确认并响应）→ ACK（客户端确认）。此后数据可以可靠传输。","pt_BR":"O processo de estabelecimento de uma conexão TCP: SYN (cliente inicia) → SYN-ACK (servidor confirma e responde) → ACK (cliente confirma). Depois disso, os dados podem ser transmitidos de forma confiável.","pt_PT":"O processo de estabelecimento de uma ligação TCP: SYN (cliente inicia) → SYN-ACK (servidor confirma e responde) → ACK (cliente confirma). Depois disso, os dados podem ser transmitidos de forma fiável."}},
  { id: 'dc-technology-0052', deck_id: 'deck-technology', sort_order: 52, front: "UDP — User Datagram Protocol", back: "A connectionless transport protocol with no guaranteed delivery, ordering, or duplicate protection. Much lower overhead than TCP. Used where speed > reliability: video streaming, DNS, VoIP, gaming." , front_translations: {"es":"UDP — User Datagram Protocol","it":"UDP — User Datagram Protocol","de":"UDP — User Datagram Protocol","fr":"UDP — User Datagram Protocol","tr":"UDP — User Datagram Protocol","nl":"UDP — User Datagram Protocol","ru":"UDP — User Datagram Protocol","zh":"UDP — 用户数据报协议","pt_BR":"UDP — User Datagram Protocol","pt_PT":"UDP — User Datagram Protocol"}, back_translations: {"es":"Un protocolo de transporte sin conexión, sin entrega garantida, ordenación o protección contra duplicatas. Overhead muy menor que el TCP. Usado cuando velocidad > confiabilidad: streaming de vídeo, DNS, VoIP, jogos.","it":"Un protocole di transport senza connexion, senza garantie di livraison, d'ordre o di proteczione contre i doublons. Surcharge bien inferieure à TCP. Utilise quando la vitesse > fiabilite : streaming video, DNS, VoIP, jeux.","de":"Ein verbindungsloses Transportprotokoll ohne garantierte Zustellung, Reihenfolge oder Duplikatschutz. Deutlich geringerer Overhead als TCP. Verwendet, wenn Geschwindigkeit > Zuverlässigkeit: Video-Streaming, DNS, VoIP, Gaming.","fr":"Un protocole de transport sans connexion, sans garantie de livraison, d'ordre ou de protection contre les doublons. Surcharge bien inférieure à TCP. Utilisé quand la vitesse > fiabilité : streaming vidéo, DNS, VoIP, jeux.","tr":"Garantili teslimat, sıralama veya kopya koruması olmayan bağlantısız bir taşıma protokolü. TCP'den çok daha düşük ek yük. Hız > güvenilirlik olduğunda kullanılır: video akışı, DNS, VoIP, oyunlar.","nl":"Een verbindingsloos transportprotocol zonder gegarandeerde levering, volgorde of duplicaatbescherming. Veel minder overhead dan TCP. Gebruikt waar snelheid > betrouwbaarheid: videostreaming, DNS, VoIP, gaming.","ru":"Протокол транспортного уровня без установления соединения, без гарантированной доставки, упорядочивания или защиты от дубликатов. Значительно меньше накладных расходов, чем у TCP. Используется там, где скорость важнее надёжности: видеостриминг, DNS, VoIP, игры.","zh":"一种无连接的传输协议，不保证交付、排序或重复保护。比 TCP 开销低得多。用于速度优先于可靠性的场景：视频流、DNS、VoIP、游戏。","pt_BR":"Um protocolo de transporte sem conexão, sem entrega garantida, ordenação ou proteção contra duplicatas. Overhead muito menor que o TCP. Usado quando velocidade > confiabilidade: streaming de vídeo, DNS, VoIP, jogos.","pt_PT":"Um protocolo de transporte sem ligação, sem entrega garantida, ordenação ou proteção contra duplicados. Overhead muito menor que o TCP. Usado quando velocidade > fiabilidade: streaming de vídeo, DNS, VoIP, jogos."}},
  { id: 'dc-technology-0053', deck_id: 'deck-technology', sort_order: 53, front: "IP Address: IPv4 vs. IPv6", back: "IPv4: 32-bit address (e.g., 192.168.1.1), ~4.3 billion addresses. IPv6: 128-bit address (e.g., 2001:0db8::1), ~3.4×10³⁸ addresses; solves IPv4 exhaustion. IPv6 also improves routing and security." , front_translations: {"es":"Endereço IP: IPv4 vs. IPv6","it":"Adresse IP : IPv4 vs. IPv6","de":"IP-Adresse: IPv4 vs. IPv6","fr":"Adresse IP : IPv4 vs. IPv6","tr":"IP Adresi: IPv4 ve IPv6","nl":"IP-adres: IPv4 vs. IPv6","ru":"IP-адрес: IPv4 и IPv6","zh":"IP 地址：IPv4 与 IPv6","pt_BR":"Endereço IP: IPv4 vs. IPv6","pt_PT":"Endereço IP: IPv4 vs. IPv6"}, back_translations: {"es":"IPv4: endereço de 32 bits (ex.: 192.168.1.1), ~4,3 bilhões de endereços. IPv6: endereço de 128 bits (ex.: 2001:0db8::1), ~3,4×10³⁸ endereços; resuelve el esgotamento del IPv4. IPv6 también melhora roteamento y seguridad.","it":"IPv4 : adresse 32 bits (ex. 192.168.1.1), ~4,3 milliards d'adresses. IPv6 : adresse 128 bits (ex. 2001:0db8::1), ~3,4×10³⁸ adresses ; resout l'epuisement d'IPv4. IPv6 ameliore anche il routage e la securite.","de":"IPv4: 32-Bit-Adresse (z. B. 192.168.1.1), ~4,3 Milliarden Adressen. IPv6: 128-Bit-Adresse (z. B. 2001:0db8::1), ~3,4×10³⁸ Adressen; löst die IPv4-Erschöpfung. IPv6 verbessert auch Routing und Sicherheit.","fr":"IPv4 : adresse 32 bits (ex. 192.168.1.1), ~4,3 milliards d'adresses. IPv6 : adresse 128 bits (ex. 2001:0db8::1), ~3,4×10³⁸ adresses ; résout l'épuisement d'IPv4. IPv6 améliore aussi le routage et la sécurité.","tr":"IPv4: 32 bit adres (ör. 192.168.1.1), ~4,3 milyar adres. IPv6: 128 bit adres (ör. 2001:0db8::1), ~3,4×10³⁸ adres; IPv4 tükenmesini çözer. IPv6 ayrıca yönlendirme ve güvenliği iyileştirir.","nl":"IPv4: 32-bits adres (bijv. 192.168.1.1), ~4,3 miljard adressen. IPv6: 128-bits adres (bijv. 2001:0db8::1), ~3,4×10³⁸ adressen; lost IPv4-uitputting op. IPv6 verbetert ook routing en beveiliging.","ru":"IPv4: 32-битный адрес (напр. 192.168.1.1), ~4,3 миллиарда адресов. IPv6: 128-битный адрес (напр. 2001:0db8::1), ~3,4×10³⁸ адресов; решает проблему исчерпания IPv4. IPv6 также улучшает маршрутизацию и безопасность.","zh":"IPv4：32 位地址（如 192.168.1.1），约 43 亿个地址。IPv6：128 位地址（如 2001:0db8::1），约 3.4×10³⁸ 个地址；解决了 IPv4 耗尽问题。IPv6 还改善了路由和安全性。","pt_BR":"IPv4: endereço de 32 bits (ex.: 192.168.1.1), ~4,3 bilhões de endereços. IPv6: endereço de 128 bits (ex.: 2001:0db8::1), ~3,4×10³⁸ endereços; resolve o esgotamento do IPv4. IPv6 também melhora roteamento e segurança.","pt_PT":"IPv4: endereço de 32 bits (ex.: 192.168.1.1), ~4,3 mil milhões de endereços. IPv6: endereço de 128 bits (ex.: 2001:0db8::1), ~3,4×10³⁸ endereços; resolve o esgotamento do IPv4. IPv6 também melhora encaminhamento e segurança."}},
  { id: 'dc-technology-0054', deck_id: 'deck-technology', sort_order: 54, front: "NAT — Network Address Translation", back: "Maps private IP addresses to a public IP address and vice versa at a router. Allows multiple devices on a LAN to share one public IP. A key response to IPv4 address exhaustion." , front_translations: {"es":"NAT — Tradución de Endereços de Red","it":"NAT — Network Address Translatione","de":"NAT — Network Address Translation","fr":"NAT — Network Address Translation","tr":"NAT — Ağ Adresi Çevirisi","nl":"NAT — Network Address Translation","ru":"NAT — трансляция сетевых адресов","zh":"NAT — 网络地址转换","pt_BR":"NAT — Tradução de Endereços de Rede","pt_PT":"NAT — Tradução de Endereços de Rede"}, back_translations: {"es":"Mapeia endereços IP privados para un endereço IP público y vice-versa en el roteador. Permite que vários dispositivos en una LAN compartilhem un IP público. Una respuesta fundamental al esgotamento de endereços IPv4.","it":"Fait correspondre dei adresses IP privees à una adresse IP publico e inversement al niveau del routore. Permet à plusiori appareils su un LAN di partager una stesso IP publico. Una reponse cle all'epuisement dei adresses IPv4.","de":"Ordnet private IP-Adressen einer öffentlichen IP-Adresse zu und umgekehrt am Router. Ermöglicht mehreren Geräten in einem LAN, eine öffentliche IP zu teilen. Eine wichtige Antwort auf die IPv4-Adresserschöpfung.","fr":"Fait correspondre des adresses IP privées à une adresse IP publique et inversement au niveau du routeur. Permet à plusieurs appareils sur un LAN de partager une même IP publique. Une réponse clé à l'épuisement des adresses IPv4.","tr":"Yönlendiricide özel IP adreslerini genel bir IP adresine ve tam tersine eşler. Bir LAN'daki birden fazla cihazın tek bir genel IP'yi paylaşmasını sağlar. IPv4 adres tükenmesine karşı önemli bir çözümdür.","nl":"Wijst privé-IP-adressen toe aan een publiek IP-adres en vice versa op de router. Stelt meerdere apparaten op een LAN in staat één publiek IP te delen. Een belangrijke reactie op IPv4-adresuitputting.","ru":"Сопоставляет частные IP-адреса с публичным IP-адресом и наоборот на маршрутизаторе. Позволяет нескольким устройствам в локальной сети использовать один публичный IP. Ключевой ответ на исчерпание адресов IPv4.","zh":"在路由器上将私有 IP 地址映射为公共 IP 地址，反之亦然。允许局域网中的多个设备共享一个公共 IP。是应对 IPv4 地址耗尽的关键方案。","pt_BR":"Mapeia endereços IP privados para um endereço IP público e vice-versa no roteador. Permite que vários dispositivos em uma LAN compartilhem um IP público. Uma resposta fundamental ao esgotamento de endereços IPv4.","pt_PT":"Mapeia endereços IP privados para um endereço IP público e vice-versa no router. Permite que vários dispositivos numa LAN partilhem um IP público. Uma resposta fundamental ao esgotamento de endereços IPv4."}},
  { id: 'dc-technology-0055', deck_id: 'deck-technology', sort_order: 55, front: "Firewall", back: "A network security device (hardware or software) that monitors and controls incoming/outgoing traffic based on rules. Stateful firewalls track active connections; stateless inspect individual packets." , front_translations: {"es":"Firewall","it":"Firewall","de":"Firewall","fr":"Pare-feu","tr":"Güvenlik Duvarı","nl":"Firewall","ru":"Межсетевой экран (Firewall)","zh":"防火墙","pt_BR":"Firewall","pt_PT":"Firewall"}, back_translations: {"es":"Un dispositivo de seguridad de red (hardware o software) que monitora y controla el tráfego de entrada/saída con base en regras. Firewalls con estado rastreiam conexiones ativas; sin estado inspecionam pacotes individuais.","it":"Un dispositif di securite reseau (materiel o logiciel) che surveille e controil il trafic entrant/sortant selon dei regles. I pare-feu à etat suivent i connexions actives ; i pare-feu senza etat inspectent i paquets individuels.","de":"Ein Netzwerksicherheitsgerät (Hardware oder Software), das ein- und ausgehenden Datenverkehr anhand von Regeln überwacht und steuert. Zustandsbehaftete Firewalls verfolgen aktive Verbindungen; zustandslose prüfen einzelne Pakete.","fr":"Un dispositif de sécurité réseau (matériel ou logiciel) qui surveille et contrôle le trafic entrant/sortant selon des règles. Les pare-feu à état suivent les connexions actives ; les pare-feu sans état inspectent les paquets individuels.","tr":"Gelen/giden trafiği kurallara göre izleyen ve kontrol eden bir ağ güvenlik cihazı (donanım veya yazılım). Durum bilgisi olan güvenlik duvarları aktif bağlantıları izler; durum bilgisi olmayanlar tek tek paketleri inceler.","nl":"Een netwerkbeveiligingsapparaat (hardware of software) dat inkomend/uitgaand verkeer bewaakt en controleert op basis van regels. Stateful firewalls volgen actieve verbindingen; stateless inspecteren individuele pakketten.","ru":"Устройство сетевой безопасности (аппаратное или программное), которое отслеживает и контролирует входящий/исходящий трафик на основе правил. Межсетевые экраны с отслеживанием состояния отслеживают активные соединения; без отслеживания — проверяют отдельные пакеты.","zh":"一种网络安全设备（硬件或软件），根据规则监控和控制进出流量。有状态防火墙跟踪活动连接；无状态防火墙检查单个数据包。","pt_BR":"Um dispositivo de segurança de rede (hardware ou software) que monitora e controla o tráfego de entrada/saída com base em regras. Firewalls com estado rastreiam conexões ativas; sem estado inspecionam pacotes individuais.","pt_PT":"Um dispositivo de segurança de rede (hardware ou software) que monitoriza e controla o tráfego de entrada/saída com base em regras. Firewalls com estado rastreiam ligações ativas; sem estado inspecionam pacotes individuais."}},
  { id: 'dc-technology-0056', deck_id: 'deck-technology', sort_order: 56, front: "REST — Representational State Transfer", back: "An architectural style for web APIs using standard HTTP methods: GET (read), POST (create), PUT/PATCH (update), DELETE (delete). Stateless; resources identified by URLs. Most common web API pattern." , front_translations: {"es":"REST — Transferencia de Estado Representacional","it":"REST — Representationeal State Transferro","de":"REST — Representational State Transfer","fr":"REST — Representational State Transfer","tr":"REST — Representational State Transfer","nl":"REST — Representational State Transfer","ru":"REST — Representational State Transfer","zh":"REST — 表述性状态转移","pt_BR":"REST — Transferência de Estado Representacional","pt_PT":"REST — Transferência de Estado Representacional"}, back_translations: {"es":"Un estilo arquitetural para APIs web usando métodos HTTP padrão: GET (ler), POST (criar), PUT/PATCH (atualizar), DELETE (excluir). Sin estado; recursos identificados por URLs. El padrão de API web más comum.","it":"Un style architectural per i API web utilisant i methodes HTTP standard : GET (lire), POST (creer), PUT/PATCH (mettre à jour), DELETE (supprimer). Sans etat ; i resurces sono identifiees per dei URL. Il modeil d'API web il più courant.","de":"Ein Architekturstil für Web-APIs mit Standard-HTTP-Methoden: GET (lesen), POST (erstellen), PUT/PATCH (aktualisieren), DELETE (löschen). Zustandslos; Ressourcen werden durch URLs identifiziert. Das häufigste Web-API-Muster.","fr":"Un style architectural pour les API web utilisant les méthodes HTTP standard : GET (lire), POST (créer), PUT/PATCH (mettre à jour), DELETE (supprimer). Sans état ; les ressources sont identifiées par des URL. Le modèle d'API web le plus courant.","tr":"Standart HTTP yöntemlerini kullanan web API'leri için bir mimari stil: GET (okuma), POST (oluşturma), PUT/PATCH (güncelleme), DELETE (silme). Durumsuz; kaynaklar URL'lerle tanımlanır. En yaygın web API kalıbı.","nl":"Een architectuurstijl voor web-API's met standaard HTTP-methoden: GET (lezen), POST (aanmaken), PUT/PATCH (bijwerken), DELETE (verwijderen). Stateless; bronnen worden geïdentificeerd door URL's. Het meest voorkomende web-API-patroon.","ru":"Архитектурный стиль для веб-API, использующий стандартные HTTP-методы: GET (чтение), POST (создание), PUT/PATCH (обновление), DELETE (удаление). Без состояния; ресурсы идентифицируются по URL. Самый распространённый шаблон веб-API.","zh":"一种使用标准 HTTP 方法的 Web API 架构风格：GET（读取）、POST（创建）、PUT/PATCH（更新）、DELETE（删除）。无状态；资源通过 URL 标识。最常见的 Web API 模式。","pt_BR":"Um estilo arquitetural para APIs web usando métodos HTTP padrão: GET (ler), POST (criar), PUT/PATCH (atualizar), DELETE (excluir). Sem estado; recursos identificados por URLs. O padrão de API web mais comum.","pt_PT":"Um estilo arquitetural para APIs web usando métodos HTTP padrão: GET (ler), POST (criar), PUT/PATCH (atualizar), DELETE (eliminar). Sem estado; recursos identificados por URLs. O padrão de API web mais comum."}},
  { id: 'dc-technology-0057', deck_id: 'deck-technology', sort_order: 57, front: "HTTP Status Codes", back: "2xx: success (200 OK, 201 Created, 204 No Content). 3xx: redirection (301 Moved Permanently, 304 Not Modified). 4xx: client error (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx: server error (500 Internal Server Error)." , front_translations: {"es":"Códigos de Status HTTP","it":"Codes di statut HTTP","de":"HTTP-Statuscodes","fr":"Codes de statut HTTP","tr":"HTTP Durum Kodları","nl":"HTTP-statuscodes","ru":"Коды состояния HTTP","zh":"HTTP 状态码","pt_BR":"Códigos de Status HTTP","pt_PT":"Códigos de Estado HTTP"}, back_translations: {"es":"2xx: éxito (200 OK, 201 Created, 204 No Content). 3xx: redirecionamento (301 Moved Permanently, 304 Not Modified). 4xx: erro del cliente (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx: erro del servidor (500 Internal Server Error).","it":"2xx : succes (200 OK, 201 Created, 204 No Content). 3xx : redireczione (301 Moved Permanently, 304 Not Modified). 4xx : errore client (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx : errore servore (500 Internal Server Error).","de":"2xx: Erfolg (200 OK, 201 Created, 204 No Content). 3xx: Umleitung (301 Moved Permanently, 304 Not Modified). 4xx: Client-Fehler (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx: Server-Fehler (500 Internal Server Error).","fr":"2xx : succès (200 OK, 201 Created, 204 No Content). 3xx : redirection (301 Moved Permanently, 304 Not Modified). 4xx : erreur client (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx : erreur serveur (500 Internal Server Error).","tr":"2xx: başarı (200 OK, 201 Created, 204 No Content). 3xx: yönlendirme (301 Moved Permanently, 304 Not Modified). 4xx: istemci hatası (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx: sunucu hatası (500 Internal Server Error).","nl":"2xx: succes (200 OK, 201 Created, 204 No Content). 3xx: omleiding (301 Moved Permanently, 304 Not Modified). 4xx: clientfout (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx: serverfout (500 Internal Server Error).","ru":"2xx: успех (200 OK, 201 Created, 204 No Content). 3xx: перенаправление (301 Moved Permanently, 304 Not Modified). 4xx: ошибка клиента (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx: ошибка сервера (500 Internal Server Error).","zh":"2xx：成功（200 OK、201 Created、204 No Content）。3xx：重定向（301 Moved Permanently、304 Not Modified）。4xx：客户端错误（400 Bad Request、401 Unauthorized、404 Not Found）。5xx：服务器错误（500 Internal Server Error）。","pt_BR":"2xx: sucesso (200 OK, 201 Created, 204 No Content). 3xx: redirecionamento (301 Moved Permanently, 304 Not Modified). 4xx: erro do cliente (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx: erro do servidor (500 Internal Server Error).","pt_PT":"2xx: sucesso (200 OK, 201 Created, 204 No Content). 3xx: redirecionamento (301 Moved Permanently, 304 Not Modified). 4xx: erro do cliente (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx: erro do servidor (500 Internal Server Error)."}},
  { id: 'dc-technology-0058', deck_id: 'deck-technology', sort_order: 58, front: "Cookies and Sessions", back: "Cookies: small data stored in the browser, sent with each request; used for authentication and tracking. Sessions: server-side storage of user state, identified by a session ID in a cookie. Sessions are more secure." , front_translations: {"es":"Cookies y Sesiones","it":"Cookies e sessiones","de":"Cookies und Sitzungen","fr":"Cookies et sessions","tr":"Çerezler ve Oturumlar","nl":"Cookies en sessies","ru":"Cookies и сессии","zh":"Cookie 与会话","pt_BR":"Cookies e Sessões","pt_PT":"Cookies e Sessões"}, back_translations: {"es":"Cookies: pequeños datos armazenados en el navegador, enviados con cada solicitud; usados para autenticación y rastreamento. Sesiones: almacenamiento del estado del usuario en el lado del servidor, identificado por un ID de sesión en un cookie. Sesiones son más seguras.","it":"Cookies : petites donnees stockees in il navigatore, envoyees con ogni requete ; utilizzatoes per l'authentificazione e il suivi. Sessions : stockage cote servore dell'etat utilisatore, identifie per un ID di session in un cookie. I sessions sono più securisees.","de":"Cookies: kleine Daten, die im Browser gespeichert und bei jeder Anfrage mitgesendet werden; verwendet für Authentifizierung und Tracking. Sitzungen: serverseitige Speicherung des Benutzerzustands, identifiziert durch eine Sitzungs-ID in einem Cookie. Sitzungen sind sicherer.","fr":"Cookies : petites données stockées dans le navigateur, envoyées avec chaque requête ; utilisées pour l'authentification et le suivi. Sessions : stockage côté serveur de l'état utilisateur, identifié par un ID de session dans un cookie. Les sessions sont plus sécurisées.","tr":"Çerezler: tarayıcıda saklanan ve her istekle gönderilen küçük veriler; kimlik doğrulama ve izleme için kullanılır. Oturumlar: bir çerezdeki oturum kimliğiyle tanımlanan, sunucu tarafında kullanıcı durumu depolaması. Oturumlar daha güvenlidir.","nl":"Cookies: kleine gegevens opgeslagen in de browser, meegestuurd bij elk verzoek; gebruikt voor authenticatie en tracking. Sessies: serveropslag van gebruikersstatus, geïdentificeerd door een sessie-ID in een cookie. Sessies zijn veiliger.","ru":"Cookies: небольшие данные, хранящиеся в браузере и отправляемые с каждым запросом; используются для аутентификации и отслеживания. Сессии: серверное хранилище состояния пользователя, идентифицируемое ID сессии в cookie. Сессии более безопасны.","zh":"Cookie：存储在浏览器中的小数据，随每个请求发送；用于身份验证和追踪。会话：用户状态的服务器端存储，通过 cookie 中的会话 ID 识别。会话更安全。","pt_BR":"Cookies: pequenos dados armazenados no navegador, enviados com cada requisição; usados para autenticação e rastreamento. Sessões: armazenamento do estado do usuário no lado do servidor, identificado por um ID de sessão em um cookie. Sessões são mais seguras.","pt_PT":"Cookies: pequenos dados armazenados no navegador, enviados com cada pedido; usados para autenticação e rastreamento. Sessões: armazenamento do estado do utilizador no lado do servidor, identificado por um ID de sessão num cookie. As sessões são mais seguras."}},
  { id: 'dc-technology-0059', deck_id: 'deck-technology', sort_order: 59, front: "JWT — JSON Web Token", back: "A compact, self-contained token encoding claims as a JSON object, signed with a secret or public/private key. Used for stateless authentication. Structure: header.payload.signature. Can be verified without a database lookup." , front_translations: {"es":"JWT — JSON Web Token","it":"JWT — JSON Web Token","de":"JWT — JSON Web Token","fr":"JWT — JSON Web Token","tr":"JWT — JSON Web Token","nl":"JWT — JSON Web Token","ru":"JWT — JSON Web Token","zh":"JWT — JSON Web Token","pt_BR":"JWT — JSON Web Token","pt_PT":"JWT — JSON Web Token"}, back_translations: {"es":"Un token compacto y autocontido que codifica declaraciones como un objeto JSON, assinado con un segredo o chave pública/privada. Usado para autenticación sin estado. Estructura: header.payload.signature. Puede ser verificado sin consulta al base de datos.","it":"Un jeton compact e autonome encodant dei revendicazioni sotto forme d'objet JSON, signe con un secret o una cle publico/privee. Utilise per l'authentificazione senza etat. Structure : header.payload.signature. Peut etre verifie senza requete en base di donnees.","de":"Ein kompaktes, eigenständiges Token, das Ansprüche als JSON-Objekt kodiert, signiert mit einem Geheimnis oder öffentlichem/privatem Schlüssel. Wird für zustandslose Authentifizierung verwendet. Struktur: header.payload.signature. Kann ohne Datenbankabfrage verifiziert werden.","fr":"Un jeton compact et autonome encodant des revendications sous forme d'objet JSON, signé avec un secret ou une clé publique/privée. Utilisé pour l'authentification sans état. Structure : header.payload.signature. Peut être vérifié sans requête en base de données.","tr":"İddiaları JSON nesnesi olarak kodlayan, bir gizli anahtar veya açık/özel anahtar çiftiyle imzalanan kompakt ve bağımsız bir token. Durumsuz kimlik doğrulama için kullanılır. Yapı: header.payload.signature. Veritabanı sorgusu olmadan doğrulanabilir.","nl":"Een compact, zelfstandig token dat claims codeert als een JSON-object, ondertekend met een geheim of publiek/privé-sleutelpaar. Gebruikt voor stateless authenticatie. Structuur: header.payload.signature. Kan worden geverifieerd zonder databasequery.","ru":"Компактный автономный токен, кодирующий утверждения в виде JSON-объекта, подписанный секретом или парой открытый/закрытый ключ. Используется для аутентификации без сохранения состояния. Структура: header.payload.signature. Можно проверить без обращения к базе данных.","zh":"一种紧凑的自包含令牌，将声明编码为 JSON 对象，使用密钥或公钥/私钥签名。用于无状态身份验证。结构：header.payload.signature。无需数据库查询即可验证。","pt_BR":"Um token compacto e autocontido que codifica declarações como um objeto JSON, assinado com um segredo ou chave pública/privada. Usado para autenticação sem estado. Estrutura: header.payload.signature. Pode ser verificado sem consulta ao banco de dados.","pt_PT":"Um token compacto e autocontido que codifica declarações como um objeto JSON, assinado com um segredo ou chave pública/privada. Usado para autenticação sem estado. Estrutura: header.payload.signature. Pode ser verificado sem consulta à base de dados."}},
  { id: 'dc-technology-0060', deck_id: 'deck-technology', sort_order: 60, front: "OAuth 2.0", back: "An authorization framework allowing third-party applications to access resources on behalf of a user without sharing credentials. Uses access tokens. Used by Google, Facebook, GitHub for 'Login with...' features." , front_translations: {"es":"OAuth 2.0","it":"OAuth 2.0","de":"OAuth 2.0","fr":"OAuth 2.0","tr":"OAuth 2.0","nl":"OAuth 2.0","ru":"OAuth 2.0","zh":"OAuth 2.0","pt_BR":"OAuth 2.0","pt_PT":"OAuth 2.0"}, back_translations: {"es":"Un framework de autorización que permite que aplicaciones de terceros acessem recursos en nombre de un usuario sin compartilhar credenciais. Usa tokens de acceso. Usado por Google, Facebook, GitHub para recursos de 'Login con…'.","it":"Un cadre d'autorisazione permettant ai applicazioni tierces d'acceder ai resurces al nom di un utilisatore senza partager i identifiants. Utilise dei jetons d'acces. Utilise per Google, Facebook, GitHub per i fonctionnalites 'Se connecter con...'.","de":"Ein Autorisierungsframework, das Drittanbieteranwendungen den Zugriff auf Ressourcen im Namen eines Benutzers ermöglicht, ohne Anmeldedaten zu teilen. Verwendet Zugriffstoken. Wird von Google, Facebook, GitHub für 'Anmelden mit...'-Funktionen verwendet.","fr":"Un cadre d'autorisation permettant aux applications tierces d'accéder aux ressources au nom d'un utilisateur sans partager les identifiants. Utilise des jetons d'accès. Utilisé par Google, Facebook, GitHub pour les fonctionnalités 'Se connecter avec...'.","tr":"Üçüncü taraf uygulamaların, kimlik bilgilerini paylaşmadan bir kullanıcı adına kaynaklara erişmesini sağlayan bir yetkilendirme çerçevesi. Erişim tokenları kullanır. Google, Facebook, GitHub tarafından '… ile giriş yap' özellikleri için kullanılır.","nl":"Een autorisatieframework waarmee applicaties van derden namens een gebruiker toegang krijgen tot bronnen zonder inloggegevens te delen. Gebruikt toegangstokens. Gebruikt door Google, Facebook, GitHub voor 'Inloggen met…'-functies.","ru":"Фреймворк авторизации, позволяющий сторонним приложениям получать доступ к ресурсам от имени пользователя без передачи учётных данных. Использует токены доступа. Используется Google, Facebook, GitHub для функции 'Войти через...'.","zh":"一种授权框架，允许第三方应用代表用户访问资源而无需共享凭据。使用访问令牌。被 Google、Facebook、GitHub 用于'使用...登录'功能。","pt_BR":"Um framework de autorização que permite que aplicações de terceiros acessem recursos em nome de um usuário sem compartilhar credenciais. Usa tokens de acesso. Usado por Google, Facebook, GitHub para recursos de 'Login com…'.","pt_PT":"Um framework de autorização que permite que aplicações de terceiros acedam a recursos em nome de um utilizador sem partilhar credenciais. Usa tokens de acesso. Usado por Google, Facebook, GitHub para funcionalidades de 'Iniciar sessão com…'."}},
  { id: 'dc-technology-0061', deck_id: 'deck-technology', sort_order: 61, front: "SQL — Structured Query Language", back: "The standard language for relational database management. Core commands: SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Declarative: describes what you want, not how to get it." , front_translations: {"es":"SQL — Linguaje de Consulta Estruturada","it":"SQL — Structured Query Language","de":"SQL — Structured Query Language","fr":"SQL — Structured Query Language","tr":"SQL — Yapılandırılmış Sorgu Dili","nl":"SQL — Structured Query Language","ru":"SQL — язык структурированных запросов","zh":"SQL — 结构化查询语言","pt_BR":"SQL — Linguagem de Consulta Estruturada","pt_PT":"SQL — Linguagem de Consulta Estruturada"}, back_translations: {"es":"La linguaje padrão para gerenciamento de bases de datos relacionais. Comandos principales: SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Declarativa: descreve el que voce quer, no como obte-lo.","it":"Il langage standard per la geszione di basi di donnees relationnelles. Commandes principales : SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Declaratif : decrit questo che l'on veut, comment l'obtenir.","de":"Die Standardsprache für relationale Datenbankverwaltung. Kernbefehle: SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Deklarativ: beschreibt, was man will, nicht wie man es bekommt.","fr":"Le langage standard pour la gestion de bases de données relationnelles. Commandes principales : SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Déclaratif : décrit ce que l'on veut, pas comment l'obtenir.","tr":"İlişkisel veritabanı yönetimi için standart dil. Temel komutlar: SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Bildirimsel: ne istediğinizi tanımlar, nasıl alacağınızı değil.","nl":"De standaardtaal voor relationeel databasebeheer. Kerncommando's: SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Declaratief: beschrijft wat je wilt, niet hoe je het krijgt.","ru":"Стандартный язык для управления реляционными базами данных. Основные команды: SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Декларативный: описывает, что нужно, а не как это получить.","zh":"关系数据库管理的标准语言。核心命令：SELECT、INSERT、UPDATE、DELETE、CREATE、DROP、ALTER。声明式：描述你想要什么，而非如何获取。","pt_BR":"A linguagem padrão para gerenciamento de bancos de dados relacionais. Comandos principais: SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Declarativa: descreve o que você quer, não como obtê-lo.","pt_PT":"A linguagem padrão para gestão de bases de dados relacionais. Comandos principais: SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Declarativa: descreve o que se pretende, não como obtê-lo."}},
  { id: 'dc-technology-0062', deck_id: 'deck-technology', sort_order: 62, front: "SQL Joins", back: "INNER JOIN: only matching rows in both tables. LEFT JOIN: all from left + matching from right (NULLs for non-matches). RIGHT JOIN: vice versa. FULL OUTER JOIN: all rows from both tables. CROSS JOIN: cartesian product." , front_translations: {"es":"SQL Joins","it":"Jointures SQL","de":"SQL Joins","fr":"Jointures SQL","tr":"SQL Joins","nl":"SQL Joins","ru":"SQL Joins (соединения)","zh":"SQL 连接（Joins）","pt_BR":"SQL Joins","pt_PT":"SQL Joins"}, back_translations: {"es":"INNER JOIN: solo líneas correspondentes en ambas las tabelas. LEFT JOIN: todas de la esquerda + correspondentes de la direita (NULL para no correspondentes). RIGHT JOIN: vice-versa. FULL OUTER JOIN: todas las líneas de ambas las tabelas. CROSS JOIN: producto cartesiano.","it":"INNER JOIN : uniquement i lignes correspondantes dei deux tables. LEFT JOIN : tutte i lignes di gauche + correspondanze di droite (NULL sinon). RIGHT JOIN : l'inverse. FULL OUTER JOIN : tutte i lignes dei deux tables. CROSS JOIN : prodotto cartesien.","de":"INNER JOIN: nur übereinstimmende Zeilen in beiden Tabellen. LEFT JOIN: alle aus der linken + übereinstimmende aus der rechten Tabelle (NULL bei Nichtübereinstimmung). RIGHT JOIN: umgekehrt. FULL OUTER JOIN: alle Zeilen aus beiden Tabellen. CROSS JOIN: kartesisches Produkt.","fr":"INNER JOIN : uniquement les lignes correspondantes des deux tables. LEFT JOIN : toutes les lignes de gauche + correspondances de droite (NULL sinon). RIGHT JOIN : l'inverse. FULL OUTER JOIN : toutes les lignes des deux tables. CROSS JOIN : produit cartésien.","tr":"INNER JOIN: yalnızca her iki tablodaki eşleşen satırlar. LEFT JOIN: soldaki tüm satırlar + sağdaki eşleşenler (eşleşmeyenler NULL). RIGHT JOIN: tam tersi. FULL OUTER JOIN: her iki tablodaki tüm satırlar. CROSS JOIN: kartezyen çarpım.","nl":"INNER JOIN: alleen overeenkomende rijen in beide tabellen. LEFT JOIN: alle rijen links + overeenkomende rechts (NULL bij geen match). RIGHT JOIN: omgekeerd. FULL OUTER JOIN: alle rijen uit beide tabellen. CROSS JOIN: cartesisch product.","ru":"INNER JOIN: только совпадающие строки из обеих таблиц. LEFT JOIN: все из левой + совпадающие из правой (NULL при отсутствии). RIGHT JOIN: наоборот. FULL OUTER JOIN: все строки из обеих таблиц. CROSS JOIN: декартово произведение.","zh":"INNER JOIN：仅返回两个表中匹配的行。LEFT JOIN：左表所有行 + 右表匹配行（不匹配为 NULL）。RIGHT JOIN：反之。FULL OUTER JOIN：两个表的所有行。CROSS JOIN：笛卡尔积。","pt_BR":"INNER JOIN: apenas linhas correspondentes em ambas as tabelas. LEFT JOIN: todas da esquerda + correspondentes da direita (NULL para não correspondentes). RIGHT JOIN: vice-versa. FULL OUTER JOIN: todas as linhas de ambas as tabelas. CROSS JOIN: produto cartesiano.","pt_PT":"INNER JOIN: apenas linhas correspondentes em ambas as tabelas. LEFT JOIN: todas da esquerda + correspondentes da direita (NULL para não correspondentes). RIGHT JOIN: vice-versa. FULL OUTER JOIN: todas as linhas de ambas as tabelas. CROSS JOIN: produto cartesiano."}},
  { id: 'dc-technology-0063', deck_id: 'deck-technology', sort_order: 63, front: "Database Normalization", back: "Organizing a database to reduce redundancy and improve data integrity. 1NF: atomic values, no repeating groups. 2NF: no partial dependencies. 3NF: no transitive dependencies. Higher forms exist but 3NF is the standard." , front_translations: {"es":"Normalización de Base de Datos","it":"Normalisatione di base di dati","de":"Datenbanknormalisierung","fr":"Normalisation de base de données","tr":"Veritabanı Normalizasyonu","nl":"Databasenormalisatie","ru":"Нормализация базы данных","zh":"数据库规范化","pt_BR":"Normalização de Banco de Dados","pt_PT":"Normalização de Base de Dados"}, back_translations: {"es":"Organización de un base de datos para reduzir redundancia y melhorar a integridad de los datos. 1NF: valores atomicos, sin grupos repetidos. 2NF: sin dependencias parciais. 3NF: sin dependencias transitivas. Formas superiores existen, pero a 3NF es el padrão.","it":"Organisazione d'una base di donnees per reduire la redondanza e ameliorer l'integrite dei donnees. 1NF : valori atomici, di groupes repetitifs. 2NF : di dependanze partielles. 3NF : di dependanze transitives. Dei formes superieures existent, ma la 3NF e il standard.","de":"Organisation einer Datenbank zur Reduzierung von Redundanz und Verbesserung der Datenintegrität. 1NF: atomare Werte, keine Wiederholungsgruppen. 2NF: keine partiellen Abhängigkeiten. 3NF: keine transitiven Abhängigkeiten. Höhere Formen existieren, aber 3NF ist der Standard.","fr":"Organisation d'une base de données pour réduire la redondance et améliorer l'intégrité des données. 1NF : valeurs atomiques, pas de groupes répétitifs. 2NF : pas de dépendances partielles. 3NF : pas de dépendances transitives. Des formes supérieures existent, mais la 3NF est le standard.","tr":"Tekrarlamayı azaltmak ve veri bütünlüğünü artırmak için bir veritabanının düzenlenmesi. 1NF: atomik değerler, tekrar eden gruplar yok. 2NF: kısmi bağımlılıklar yok. 3NF: geçişli bağımlılıklar yok. Daha yüksek formlar var ancak 3NF standarttır.","nl":"Het organiseren van een database om redundantie te verminderen en gegevensintegriteit te verbeteren. 1NF: atomaire waarden, geen herhalende groepen. 2NF: geen partiële afhankelijkheden. 3NF: geen transitieve afhankelijkheden. Hogere vormen bestaan, maar 3NF is de standaard.","ru":"Организация базы данных для уменьшения избыточности и повышения целостности данных. 1НФ: атомарные значения, нет повторяющихся групп. 2НФ: нет частичных зависимостей. 3НФ: нет транзитивных зависимостей. Более высокие формы существуют, но 3НФ — стандарт.","zh":"组织数据库以减少冗余并提高数据完整性。第一范式：原子值，无重复组。第二范式：无部分依赖。第三范式：无传递依赖。存在更高范式，但第三范式是标准。","pt_BR":"Organização de um banco de dados para reduzir redundância e melhorar a integridade dos dados. 1NF: valores atômicos, sem grupos repetidos. 2NF: sem dependências parciais. 3NF: sem dependências transitivas. Formas superiores existem, mas a 3NF é o padrão.","pt_PT":"Organização de uma base de dados para reduzir redundância e melhorar a integridade dos dados. 1NF: valores atómicos, sem grupos repetidos. 2NF: sem dependências parciais. 3NF: sem dependências transitivas. Formas superiores existem, mas a 3NF é o padrão."}},
  { id: 'dc-technology-0064', deck_id: 'deck-technology', sort_order: 64, front: "ACID Properties", back: "Properties ensuring reliable database transactions: Atomicity (all or nothing), Consistency (valid state to valid state), Isolation (concurrent transactions don't interfere), Durability (committed data persists after failure)." , front_translations: {"es":"Propiedades ACID","it":"Proprietà ACID","de":"ACID-Eigenschaften","fr":"Propriétés ACID","tr":"ACID Özellikleri","nl":"ACID-eigenschappen","ru":"Свойства ACID","zh":"ACID 属性","pt_BR":"Propriedades ACID","pt_PT":"Propriedades ACID"}, back_translations: {"es":"Propiedades que garantizan transaciones de base de datos confiables: Atomicidad (tudo o nada), Consistencia (de estado válido para estado válido), Isolamento (transaciones competidores no interferem), Durabilidad (datos confirmados persistem após falha).","it":"Proprietes garantissant dei transaczioni di base di donnees fiables : Atomicite (tutto o rien), Coherenza (di un etat valide à un etat valide), Isolazione (i transaczioni concurrentes n'interferent ), Durabilite (i donnees validees persistent apres una panne).","de":"Eigenschaften für zuverlässige Datenbanktransaktionen: Atomarität (alles oder nichts), Konsistenz (gültiger Zustand zu gültigem Zustand), Isolation (parallele Transaktionen beeinflussen sich nicht), Dauerhaftigkeit (bestätigte Daten bleiben nach einem Ausfall erhalten).","fr":"Propriétés garantissant des transactions de base de données fiables : Atomicité (tout ou rien), Cohérence (d'un état valide à un état valide), Isolation (les transactions concurrentes n'interfèrent pas), Durabilité (les données validées persistent après une panne).","tr":"Güvenilir veritabanı işlemlerini sağlayan özellikler: Atomiklik (ya hep ya hiç), Tutarlılık (geçerli durumdan geçerli duruma), İzolasyon (eşzamanlı işlemler birbirini etkilemez), Dayanıklılık (onaylanan veriler arızadan sonra kalıcıdır).","nl":"Eigenschappen die betrouwbare databasetransacties garanderen: Atomiciteit (alles of niets), Consistentie (van geldige staat naar geldige staat), Isolatie (gelijktijdige transacties interfereren niet), Duurzaamheid (vastgelegde data blijft bestaan na een storing).","ru":"Свойства, обеспечивающие надёжные транзакции базы данных: Атомарность (всё или ничего), Согласованность (из допустимого состояния в допустимое), Изоляция (параллельные транзакции не мешают друг другу), Долговечность (зафиксированные данные сохраняются после сбоя).","zh":"确保可靠数据库事务的属性：原子性（全部完成或全部回滚）、一致性（从有效状态到有效状态）、隔离性（并发事务互不干扰）、持久性（已提交数据在故障后仍然存在）。","pt_BR":"Propriedades que garantem transações de banco de dados confiáveis: Atomicidade (tudo ou nada), Consistência (de estado válido para estado válido), Isolamento (transações concorrentes não interferem), Durabilidade (dados confirmados persistem após falha).","pt_PT":"Propriedades que garantem transações de base de dados fiáveis: Atomicidade (tudo ou nada), Consistência (de estado válido para estado válido), Isolamento (transações concorrentes não interferem), Durabilidade (dados confirmados persistem após falha)."}},
  { id: 'dc-technology-0065', deck_id: 'deck-technology', sort_order: 65, front: "Database Index", back: "A data structure (usually a B-tree) that speeds up data retrieval at the cost of extra storage and slower writes. Indexes on frequently queried columns dramatically reduce O(n) scans to O(log n) lookups." , front_translations: {"es":"Índice de Base de Datos","it":"Index di base di dati","de":"Datenbankindex","fr":"Index de base de données","tr":"Veritabanı İndeksi","nl":"Database-index","ru":"Индекс базы данных","zh":"数据库索引","pt_BR":"Índice de Banco de Dados","pt_PT":"Índice de Base de Dados"}, back_translations: {"es":"Una estructura de datos (generalmente una B-tree) que acelera a recuperación de datos al costo de almacenamiento extra y escritas más lentas. Índices en colunas frecuentemente consultadas reducen drasticamente varreduras El(n) para buscas El(log n).","it":"Una structure di donnees (generalement un B-tree) che accelere la recuperazione di donnees al prix di un stockage supplementaire e d'ecritures più lentes. I index su i colonnes frequemment interrogees reduisent drastiquement i balayages O(n) à dei recherches O(log n).","de":"Eine Datenstruktur (meist ein B-Baum), die den Datenabruf beschleunigt, auf Kosten von zusätzlichem Speicherplatz und langsameren Schreibvorgängen. Indizes auf häufig abgefragten Spalten reduzieren O(n)-Scans drastisch auf O(log n)-Lookups.","fr":"Une structure de données (généralement un B-tree) qui accélère la récupération de données au prix d'un stockage supplémentaire et d'écritures plus lentes. Les index sur les colonnes fréquemment interrogées réduisent drastiquement les balayages O(n) à des recherches O(log n).","tr":"Ek depolama alanı ve daha yavaş yazma pahasına veri alımını hızlandıran bir veri yapısı (genellikle B-tree). Sık sorgulanan sütunlardaki indeksler O(n) taramalarını önemli ölçüde O(log n) aramalarına düşürür.","nl":"Een datastructuur (meestal een B-tree) die het ophalen van gegevens versnelt ten koste van extra opslag en tragere schrijfbewerkingen. Indexen op veelgevraagde kolommen verminderen O(n)-scans drastisch tot O(log n)-lookups.","ru":"Структура данных (обычно B-дерево), ускоряющая извлечение данных ценой дополнительного хранилища и более медленной записи. Индексы на часто запрашиваемых столбцах резко сокращают сканирование O(n) до поиска O(log n).","zh":"一种数据结构（通常是 B 树），以额外存储空间和更慢写入为代价加速数据检索。在频繁查询的列上建立索引可将 O(n) 扫描大幅降低为 O(log n) 查找。","pt_BR":"Uma estrutura de dados (geralmente uma B-tree) que acelera a recuperação de dados ao custo de armazenamento extra e escritas mais lentas. Índices em colunas frequentemente consultadas reduzem drasticamente varreduras O(n) para buscas O(log n).","pt_PT":"Uma estrutura de dados (geralmente uma B-tree) que acelera a recuperação de dados ao custo de armazenamento extra e escritas mais lentas. Índices em colunas frequentemente consultadas reduzem drasticamente varrimentos O(n) para pesquisas O(log n)."}},
  { id: 'dc-technology-0066', deck_id: 'deck-technology', sort_order: 66, front: "NoSQL Databases", back: "Non-relational databases designed for flexible schemas, horizontal scaling, and high performance. Types: document (MongoDB), key-value (Redis), column-family (Cassandra), graph (Neo4j). Sacrifice some ACID for scalability." , front_translations: {"es":"Bases de Datos NoSQL","it":"Database NoSQL","de":"NoSQL-Datenbanken","fr":"Bases de données NoSQL","tr":"NoSQL Veritabanları","nl":"NoSQL-databases","ru":"Базы данных NoSQL","zh":"NoSQL 数据库","pt_BR":"Bancos de Dados NoSQL","pt_PT":"Bases de Dados NoSQL"}, back_translations: {"es":"Bases de datos no relacionais projetados para esquemas flexibles, escalabilidad horizontal y alto rendimiento. Tipos: documento (MongoDB), chave-valor (Redis), família de colunas (Cassandra), grafo (Neo4j). Sacrificam parte del ACID por la escalabilidad.","it":"Bases di donnees non relationnelles conzues per dei schemas flexibles, una mise all'echelle horizontale e di hautes performanze. Types : document (MongoDB), cle-valore (Redis), famille di colonnes (Cassandra), graphe (Neo4j). Sacrifient partiellement ACID per la scalabilite.","de":"Nicht-relationale Datenbanken für flexible Schemata, horizontale Skalierung und hohe Leistung. Typen: Dokument (MongoDB), Schlüssel-Wert (Redis), Spaltenfamilie (Cassandra), Graph (Neo4j). Opfern teilweise ACID zugunsten der Skalierbarkeit.","fr":"Bases de données non relationnelles conçues pour des schémas flexibles, une mise à l'échelle horizontale et de hautes performances. Types : document (MongoDB), clé-valeur (Redis), famille de colonnes (Cassandra), graphe (Neo4j). Sacrifient partiellement ACID pour la scalabilité.","tr":"Esnek şemalar, yatay ölçekleme ve yüksek performans için tasarlanmış ilişkisel olmayan veritabanları. Türleri: belge (MongoDB), anahtar-değer (Redis), sütun ailesi (Cassandra), graf (Neo4j). Ölçeklenebilirlik için bazı ACID özelliklerinden ödün verir.","nl":"Niet-relationele databases ontworpen voor flexibele schema's, horizontale schaalbaarheid en hoge prestaties. Types: document (MongoDB), key-value (Redis), column-family (Cassandra), graph (Neo4j). Offeren deels ACID voor schaalbaarheid.","ru":"Нереляционные базы данных, разработанные для гибких схем, горизонтального масштабирования и высокой производительности. Типы: документные (MongoDB), ключ-значение (Redis), колоночные (Cassandra), графовые (Neo4j). Жертвуют частью ACID ради масштабируемости.","zh":"为灵活模式、水平扩展和高性能设计的非关系型数据库。类型：文档型（MongoDB）、键值型（Redis）、列族型（Cassandra）、图型（Neo4j）。为可扩展性牺牲部分 ACID 特性。","pt_BR":"Bancos de dados não relacionais projetados para esquemas flexíveis, escalabilidade horizontal e alto desempenho. Tipos: documento (MongoDB), chave-valor (Redis), família de colunas (Cassandra), grafo (Neo4j). Sacrificam parte do ACID pela escalabilidade.","pt_PT":"Bases de dados não relacionais projetadas para esquemas flexíveis, escalabilidade horizontal e alto desempenho. Tipos: documento (MongoDB), chave-valor (Redis), família de colunas (Cassandra), grafo (Neo4j). Sacrificam parte do ACID pela escalabilidade."}},
  { id: 'dc-technology-0067', deck_id: 'deck-technology', sort_order: 67, front: "CAP Theorem", back: "A distributed system can guarantee at most two of: Consistency (all nodes see the same data), Availability (every request gets a response), Partition Tolerance (works despite network partitions). Networks partition, so tradeoff is C vs. A." , front_translations: {"es":"Teorema CAP","it":"Teorema CAP","de":"CAP-Theorem","fr":"Théorème CAP","tr":"CAP Teoremi","nl":"CAP-theorema","ru":"Теорема CAP","zh":"CAP 定理","pt_BR":"Teorema CAP","pt_PT":"Teorema CAP"}, back_translations: {"es":"Un sistema distribuído puede garantir en el máximo de los de tres: Consistencia (todos los nós veem los mismos datos), Disponibilidad (toda solicitud obtiene una respuesta), Tolerancia a Partición (funciona apesar de particiones de red). Redes se particionam, entonces el trade-off es C vs. La.","it":"Un sistema distribue può garantir al maximum deux dei trois : Coherenza (tutti i nœuds voient i memes donnees), Disponibilite (ogni requete obtient una reponse), Toleranza al partitionnement (fonctionne malgre i partizioni reseau). I reseaux se partitionnent, quindi il compromis e C vs. A.","de":"Ein verteiltes System kann höchstens zwei von drei garantieren: Konsistenz (alle Knoten sehen dieselben Daten), Verfügbarkeit (jede Anfrage erhält eine Antwort), Partitionstoleranz (funktioniert trotz Netzwerkpartitionen). Netzwerke partitionieren, also ist der Kompromiss C vs. A.","fr":"Un système distribué peut garantir au maximum deux des trois : Cohérence (tous les nœuds voient les mêmes données), Disponibilité (chaque requête obtient une réponse), Tolérance au partitionnement (fonctionne malgré les partitions réseau). Les réseaux se partitionnent, donc le compromis est C vs. A.","tr":"Dağıtık bir sistem en fazla ikisini garanti edebilir: Tutarlılık (tüm düğümler aynı veriyi görür), Erişilebilirlik (her istek yanıt alır), Bölünme Toleransı (ağ bölünmelerine rağmen çalışır). Ağlar bölünür, bu yüzden denge C ile A arasındadır.","nl":"Een gedistribueerd systeem kan maximaal twee van drie garanderen: Consistentie (alle nodes zien dezelfde data), Beschikbaarheid (elk verzoek krijgt een antwoord), Partitietolerantie (werkt ondanks netwerkpartities). Netwerken partitioneren, dus de afweging is C vs. A.","ru":"Распределённая система может гарантировать не более двух из трёх: Согласованность (все узлы видят одинаковые данные), Доступность (каждый запрос получает ответ), Устойчивость к разделению (работает несмотря на сетевые разделения). Сети разделяются, поэтому компромисс — C против A.","zh":"分布式系统最多只能保证三者中的两个：一致性（所有节点看到相同数据）、可用性（每个请求都能得到响应）、分区容错性（在网络分区时仍能工作）。网络会分区，因此需要在 C 和 A 之间权衡。","pt_BR":"Um sistema distribuído pode garantir no máximo dois de três: Consistência (todos os nós veem os mesmos dados), Disponibilidade (toda requisição obtém uma resposta), Tolerância a Partição (funciona apesar de partições de rede). Redes se particionam, então o trade-off é C vs. A.","pt_PT":"Um sistema distribuído pode garantir no máximo dois de três: Consistência (todos os nós veem os mesmos dados), Disponibilidade (cada pedido obtém uma resposta), Tolerância a Partição (funciona apesar de partições de rede). As redes particionam-se, portanto o compromisso é C vs. A."}},
  { id: 'dc-technology-0068', deck_id: 'deck-technology', sort_order: 68, front: "Process vs. Thread", back: "Process: an independent program in execution with its own memory space. Thread: a lightweight execution unit within a process sharing the same memory. Threads are cheaper to create but require synchronization for shared data." , front_translations: {"es":"Proceso vs. Thread","it":"Processo vs. Thread","de":"Prozess vs. Thread","fr":"Processus vs. Thread","tr":"Süreç ve İş Parçacığı","nl":"Proces vs. Thread","ru":"Процесс и поток","zh":"进程与线程","pt_BR":"Processo vs. Thread","pt_PT":"Processo vs. Thread"}, back_translations: {"es":"Proceso: un programa independente en execución con su propio espacio de memoria. Thread: una unidad de execución ligero dentro de un proceso que compartilha a misma memoria. Threads son más baratas de criar, pero requieren sincronización para datos compartilhados.","it":"Processo : un programme independant en execuzione con il suo propre espace memoire. Thread : una unite d'execuzione legere al sein di un processo partageant la stesso memoire. I threads sono meno couteux à creer ma necessitent una synchronisazione per i donnees partagees.","de":"Prozess: ein unabhängiges laufendes Programm mit eigenem Speicherbereich. Thread: eine leichtgewichtige Ausführungseinheit innerhalb eines Prozesses, die denselben Speicher teilt. Threads sind günstiger zu erstellen, erfordern aber Synchronisation für gemeinsame Daten.","fr":"Processus : un programme indépendant en exécution avec son propre espace mémoire. Thread : une unité d'exécution légère au sein d'un processus partageant la même mémoire. Les threads sont moins coûteux à créer mais nécessitent une synchronisation pour les données partagées.","tr":"Süreç: kendi bellek alanına sahip bağımsız bir çalışan program. İş parçacığı: aynı belleği paylaşan bir süreç içindeki hafif bir yürütme birimi. İş parçacıkları oluşturması daha ucuzdur ancak paylaşılan veriler için senkronizasyon gerektirir.","nl":"Proces: een onafhankelijk draaiend programma met eigen geheugenruimte. Thread: een lichtgewicht uitvoeringseenheid binnen een proces die hetzelfde geheugen deelt. Threads zijn goedkoper om te maken maar vereisen synchronisatie voor gedeelde gegevens.","ru":"Процесс: независимая выполняющаяся программа с собственным адресным пространством. Поток: легковесная единица выполнения внутри процесса, разделяющая ту же память. Потоки дешевле в создании, но требуют синхронизации для общих данных.","zh":"进程：具有独立内存空间的独立运行程序。线程：进程内共享同一内存的轻量级执行单元。线程创建成本更低，但共享数据需要同步。","pt_BR":"Processo: um programa independente em execução com seu próprio espaço de memória. Thread: uma unidade de execução leve dentro de um processo que compartilha a mesma memória. Threads são mais baratas de criar, mas requerem sincronização para dados compartilhados.","pt_PT":"Processo: um programa independente em execução com o seu próprio espaço de memória. Thread: uma unidade de execução leve dentro de um processo que partilha a mesma memória. Threads são mais baratas de criar, mas requerem sincronização para dados partilhados."}},
  { id: 'dc-technology-0069', deck_id: 'deck-technology', sort_order: 69, front: "Deadlock", back: "A situation where two or more processes are each waiting for the other to release a resource, causing all of them to be stuck indefinitely. Prevented through resource ordering or timeouts." , front_translations: {"es":"Deadlock","it":"Interblocage (Deadlock)","de":"Deadlock","fr":"Interblocage (Deadlock)","tr":"Kilitlenme (Deadlock)","nl":"Deadlock","ru":"Взаимная блокировка (Deadlock)","zh":"死锁","pt_BR":"Deadlock","pt_PT":"Deadlock"}, back_translations: {"es":"Una situación en que de los el más procesos están cada un esperando el outro liberar un recurso, haciendo con que todos fiquem bloqueados indefinidamente. Prevenido por ordenación de recursos o timeouts.","it":"Una situazione où deux processo o più attendent chacun che l'autre libere una resurce, i bloquant tutti indefiniment. Prevenu per l'ordonnancement dei resurces o i delais d'expirazione.","de":"Eine Situation, in der zwei oder mehr Prozesse jeweils darauf warten, dass der andere eine Ressource freigibt, wodurch alle auf unbestimmte Zeit blockiert sind. Wird durch Ressourcenordnung oder Timeouts verhindert.","fr":"Une situation où deux processus ou plus attendent chacun que l'autre libère une ressource, les bloquant tous indéfiniment. Prévenu par l'ordonnancement des ressources ou les délais d'expiration.","tr":"İki veya daha fazla sürecin her birinin diğerinin bir kaynağı serbest bırakmasını beklediği ve hepsinin süresiz olarak takılı kaldığı durum. Kaynak sıralama veya zaman aşımları ile önlenir.","nl":"Een situatie waarin twee of meer processen elk wachten tot de ander een bron vrijgeeft, waardoor ze allemaal voor onbepaalde tijd vastzitten. Voorkomen door bronordening of time-outs.","ru":"Ситуация, когда два или более процессов ожидают друг от друга освобождения ресурса, что приводит к бесконечной блокировке всех. Предотвращается упорядочиванием ресурсов или тайм-аутами.","zh":"两个或多个进程各自等待对方释放资源，导致所有进程无限期阻塞的情况。通过资源排序或超时来预防。","pt_BR":"Uma situação em que dois ou mais processos estão cada um esperando o outro liberar um recurso, fazendo com que todos fiquem bloqueados indefinidamente. Prevenido por ordenação de recursos ou timeouts.","pt_PT":"Uma situação em que dois ou mais processos estão cada um à espera que o outro liberte um recurso, fazendo com que todos fiquem bloqueados indefinidamente. Prevenido por ordenação de recursos ou timeouts."}},
  { id: 'dc-technology-0070', deck_id: 'deck-technology', sort_order: 70, front: "Race Condition", back: "A bug where the outcome of a program depends on the relative timing of operations between threads. Prevented with synchronization mechanisms: mutexes, semaphores, atomic operations." , front_translations: {"es":"Condición de Corrida (Race Condition)","it":"Conditione di course (Race Conditione)","de":"Race Condition","fr":"Condition de course (Race Condition)","tr":"Yarış Durumu (Race Condition)","nl":"Race Condition","ru":"Состояние гонки (Race Condition)","zh":"竞态条件","pt_BR":"Condição de Corrida (Race Condition)","pt_PT":"Condição de Corrida (Race Condition)"}, back_translations: {"es":"Un bug en que el resultado de un programa depende del timing relativo de las operaciones entre threads. Prevenido con mecanismos de sincronización: mutexes, semáforos, operaciones atomicas.","it":"Un bug où il resultat di un programme depend del timing relatif dei operazioni tra threads. Prevenu per dei mecanismes di synchronisazione : mutex, semaphores, operazioni atomici.","de":"Ein Fehler, bei dem das Ergebnis eines Programms von der relativen Reihenfolge der Operationen zwischen Threads abhängt. Wird mit Synchronisationsmechanismen verhindert: Mutexe, Semaphoren, atomare Operationen.","fr":"Un bug où le résultat d'un programme dépend du timing relatif des opérations entre threads. Prévenu par des mécanismes de synchronisation : mutex, sémaphores, opérations atomiques.","tr":"Bir programın sonucunun iş parçacıkları arasındaki işlemlerin göreceli zamanlamasına bağlı olduğu bir hata. Senkronizasyon mekanizmalarıyla önlenir: mutex'ler, semaforlar, atomik işlemler.","nl":"Een bug waarbij het resultaat van een programma afhangt van de relatieve timing van bewerkingen tussen threads. Voorkomen met synchronisatiemechanismen: mutexen, semaforen, atomaire operaties.","ru":"Ошибка, при которой результат программы зависит от относительного порядка выполнения операций между потоками. Предотвращается механизмами синхронизации: мьютексы, семафоры, атомарные операции.","zh":"一种程序结果取决于线程间操作相对时序的缺陷。通过同步机制预防：互斥锁、信号量、原子操作。","pt_BR":"Um bug em que o resultado de um programa depende do timing relativo das operações entre threads. Prevenido com mecanismos de sincronização: mutexes, semáforos, operações atômicas.","pt_PT":"Um bug em que o resultado de um programa depende do timing relativo das operações entre threads. Prevenido com mecanismos de sincronização: mutexes, semáforos, operações atómicas."}},
  { id: 'dc-technology-0071', deck_id: 'deck-technology', sort_order: 71, front: "Mutex (Mutual Exclusion)", back: "A synchronization primitive ensuring only one thread accesses a critical section at a time. The thread that locks the mutex must unlock it. Different from a semaphore (which can be signaled by a different thread)." , front_translations: {"es":"Mutex (Exclusão Mútua)","it":"Mutex (Exclusione mutuelle)","de":"Mutex (Gegenseitiger Ausschluss)","fr":"Mutex (Exclusion mutuelle)","tr":"Mutex (Karşılıklı Dışlama)","nl":"Mutex (Wederzijdse Uitsluiting)","ru":"Мьютекс (взаимное исключение)","zh":"互斥锁（Mutex）","pt_BR":"Mutex (Exclusão Mútua)","pt_PT":"Mutex (Exclusão Mútua)"}, back_translations: {"es":"Un primitivo de sincronización que garantiza que solo una thread acesse una seción crítica por vez. La thread que bloqueia el mutex deve desbloqueá-lo. Diferente de un semáforo (que puede ser sinalizado por una thread diferente).","it":"Una primitive di synchronisazione garantissant che un seul thread accedi à una seczione critico allo stesso tempo. Il thread che verrouille il mutex doit il deverrouiller. Different di un semaphore (che può etre signale per un thread different).","de":"Ein Synchronisationsprimitiv, das sicherstellt, dass nur ein Thread gleichzeitig auf einen kritischen Abschnitt zugreift. Der Thread, der den Mutex sperrt, muss ihn auch entsperren. Unterscheidet sich von einem Semaphor (der von einem anderen Thread signalisiert werden kann).","fr":"Une primitive de synchronisation garantissant qu'un seul thread accède à une section critique à la fois. Le thread qui verrouille le mutex doit le déverrouiller. Différent d'un sémaphore (qui peut être signalé par un thread différent).","tr":"Bir seferde yalnızca bir iş parçacığının kritik bölüme erişmesini sağlayan bir senkronizasyon ilkesi. Mutex'i kilitleyen iş parçacığı onu açmalıdır. Semafordan farklıdır (semafor farklı bir iş parçacığı tarafından sinyal verilebilir).","nl":"Een synchronisatieprimitief die ervoor zorgt dat slechts één thread tegelijk toegang heeft tot een kritieke sectie. De thread die de mutex vergrendelt, moet deze ontgrendelen. Verschilt van een semafoor (die door een andere thread kan worden gesignaleerd).","ru":"Примитив синхронизации, гарантирующий, что только один поток обращается к критической секции одновременно. Поток, заблокировавший мьютекс, должен его разблокировать. Отличается от семафора (который может быть просигнализирован другим потоком).","zh":"一种同步原语，确保同一时间只有一个线程访问临界区。锁定互斥锁的线程必须解锁它。与信号量不同（信号量可以由不同线程发出信号）。","pt_BR":"Um primitivo de sincronização que garante que apenas uma thread acesse uma seção crítica por vez. A thread que bloqueia o mutex deve desbloqueá-lo. Diferente de um semáforo (que pode ser sinalizado por uma thread diferente).","pt_PT":"Um primitivo de sincronização que garante que apenas uma thread aceda a uma secção crítica de cada vez. A thread que bloqueia o mutex deve desbloqueá-lo. Diferente de um semáforo (que pode ser sinalizado por uma thread diferente)."}},
  { id: 'dc-technology-0072', deck_id: 'deck-technology', sort_order: 72, front: "Semaphore", back: "A synchronization primitive using a counter. A binary semaphore acts like a mutex. A counting semaphore controls access to a pool of resources. Can be signaled by a different thread than the one that waited." , front_translations: {"es":"Semáforo","it":"Semaphore","de":"Semaphor","fr":"Sémaphore","tr":"Semafor","nl":"Semafoor","ru":"Семафор","zh":"信号量","pt_BR":"Semáforo","pt_PT":"Semáforo"}, back_translations: {"es":"Un primitivo de sincronización usando un contador. Un semáforo binário age como un mutex. Un semáforo de contaje controla el acceso a un pool de recursos. Puede ser sinalizado por una thread diferente daquela que esperou.","it":"Una primitive di synchronisazione utilisant un comptore. Un semaphore binaire agit come un mutex. Un semaphore à comptore controil l'acces à un pool di resurces. Peut etre signale per un thread different di celui che ha attendu.","de":"Ein Synchronisationsprimitiv mit einem Zähler. Ein binärer Semaphor funktioniert wie ein Mutex. Ein zählender Semaphor steuert den Zugriff auf einen Pool von Ressourcen. Kann von einem anderen Thread signalisiert werden als dem, der gewartet hat.","fr":"Une primitive de synchronisation utilisant un compteur. Un sémaphore binaire agit comme un mutex. Un sémaphore à compteur contrôle l'accès à un pool de ressources. Peut être signalé par un thread différent de celui qui a attendu.","tr":"Bir sayaç kullanan bir senkronizasyon ilkesi. İkili semafor bir mutex gibi davranır. Saymalı semafor bir kaynak havuzuna erişimi kontrol eder. Bekleyen iş parçacığından farklı bir iş parçacığı tarafından sinyal verilebilir.","nl":"Een synchronisatieprimitief met een teller. Een binaire semafoor werkt als een mutex. Een tellende semafoor regelt de toegang tot een pool van bronnen. Kan worden gesignaleerd door een andere thread dan degene die heeft gewacht.","ru":"Примитив синхронизации, использующий счётчик. Бинарный семафор действует как мьютекс. Счётный семафор управляет доступом к пулу ресурсов. Может быть просигнализирован потоком, отличным от того, который ожидал.","zh":"一种使用计数器的同步原语。二进制信号量类似于互斥锁。计数信号量控制对资源池的访问。可以由与等待线程不同的线程发出信号。","pt_BR":"Um primitivo de sincronização usando um contador. Um semáforo binário age como um mutex. Um semáforo de contagem controla o acesso a um pool de recursos. Pode ser sinalizado por uma thread diferente daquela que esperou.","pt_PT":"Um primitivo de sincronização usando um contador. Um semáforo binário age como um mutex. Um semáforo de contagem controla o acesso a um conjunto de recursos. Pode ser sinalizado por uma thread diferente daquela que esperou."}},
  { id: 'dc-technology-0073', deck_id: 'deck-technology', sort_order: 73, front: "Virtual Memory", back: "An OS abstraction that gives each process the illusion of having its own large private memory space. Physical RAM is supplemented by disk (swap). Uses page tables for address translation; enables memory isolation." , front_translations: {"es":"Memoria Virtual","it":"Memoria virtuale","de":"Virtueller Speicher","fr":"Mémoire virtuelle","tr":"Sanal Bellek","nl":"Virtueel geheugen","ru":"Виртуальная память","zh":"虚拟内存","pt_BR":"Memória Virtual","pt_PT":"Memória Virtual"}, back_translations: {"es":"Una abstración del SO que dá a cada proceso a ilusão de ter su propio grande espacio de memoria privado. La RAM física es complementada por el disco (swap). Usa tabelas de páginas para tradución de endereços; permite isolamento de memoria.","it":"Una abstraczione del sistema d'exploitazione donnant à ogni processo l'illusion d'avoir il suo propre grande espace memoire prive. La RAM fisico e completee per il disque (swap). Utilise dei tables di pages per la traduczione d'adresses ; permette l'isolazione memoire.","de":"Eine Betriebssystem-Abstraktion, die jedem Prozess die Illusion eines eigenen großen privaten Speicherbereichs gibt. Physischer RAM wird durch Festplatte (Swap) ergänzt. Verwendet Seitentabellen zur Adressübersetzung; ermöglicht Speicherisolation.","fr":"Une abstraction du système d'exploitation donnant à chaque processus l'illusion d'avoir son propre grand espace mémoire privé. La RAM physique est complétée par le disque (swap). Utilise des tables de pages pour la traduction d'adresses ; permet l'isolation mémoire.","tr":"Her sürece kendi büyük özel bellek alanına sahip olduğu yanılsamasını veren bir işletim sistemi soyutlaması. Fiziksel RAM, disk (takas alanı) ile desteklenir. Adres çevirisi için sayfa tabloları kullanır; bellek izolasyonu sağlar.","nl":"Een OS-abstractie die elk proces de illusie geeft van een eigen groot privégeheugen. Fysiek RAM wordt aangevuld met schijf (swap). Gebruikt paginatabellen voor adresvertaling; maakt geheugenisolatie mogelijk.","ru":"Абстракция ОС, создающая для каждого процесса иллюзию собственного большого частного адресного пространства. Физическая оперативная память дополняется диском (подкачка). Использует таблицы страниц для трансляции адресов; обеспечивает изоляцию памяти.","zh":"一种操作系统抽象，让每个进程拥有独立的大型私有内存空间的假象。物理内存由磁盘（交换空间）补充。使用页表进行地址转换；实现内存隔离。","pt_BR":"Uma abstração do SO que dá a cada processo a ilusão de ter seu próprio grande espaço de memória privado. A RAM física é complementada pelo disco (swap). Usa tabelas de páginas para tradução de endereços; permite isolamento de memória.","pt_PT":"Uma abstração do SO que dá a cada processo a ilusão de ter o seu próprio grande espaço de memória privado. A RAM física é complementada pelo disco (swap). Usa tabelas de páginas para tradução de endereços; permite isolamento de memória."}},
  { id: 'dc-technology-0074', deck_id: 'deck-technology', sort_order: 74, front: "Page Fault", back: "Occurs when a program accesses a page not currently in physical memory. The OS must load it from disk. Minor page faults: page is in memory but not mapped. Major page faults: page must be retrieved from disk (expensive)." , front_translations: {"es":"Falha de Página (Page Fault)","it":"Defaut di page (Page Fault)","de":"Seitenfehler (Page Fault)","fr":"Défaut de page (Page Fault)","tr":"Sayfa Hatası (Page Fault)","nl":"Paginafout (Page Fault)","ru":"Ошибка страницы (Page Fault)","zh":"缺页错误","pt_BR":"Falha de Página (Page Fault)","pt_PT":"Falha de Página (Page Fault)"}, back_translations: {"es":"Ocurre cuando un programa acessa una página que no está actualmente en la memoria física. El SO deve carregá-la del disco. Falhas menores: página está en la memoria pero no mapeada. Falhas mayores: página deve ser recuperada del disco (custoso).","it":"Se prodotto quando un programme accedi à una page absente della memoire fisico. Il SE doit la charger depuis il disque. Defauts minori : la page e en memoire ma non mappee. Defauts majori : la page doit etre recuperee del disque (couteux).","de":"Tritt auf, wenn ein Programm auf eine Seite zugreift, die sich derzeit nicht im physischen Speicher befindet. Das Betriebssystem muss sie von der Festplatte laden. Geringfügige Seitenfehler: Seite ist im Speicher, aber nicht zugeordnet. Schwerwiegende Seitenfehler: Seite muss von der Festplatte geladen werden (teuer).","fr":"Se produit quand un programme accède à une page absente de la mémoire physique. Le SE doit la charger depuis le disque. Défauts mineurs : la page est en mémoire mais non mappée. Défauts majeurs : la page doit être récupérée du disque (coûteux).","tr":"Bir program fiziksel bellekte bulunmayan bir sayfaya eriştiğinde oluşur. İşletim sistemi onu diskten yüklemelidir. Küçük sayfa hataları: sayfa bellekte ama eşlenmemiş. Büyük sayfa hataları: sayfa diskten alınmalıdır (maliyetli).","nl":"Treedt op wanneer een programma een pagina benadert die momenteel niet in het fysieke geheugen staat. Het OS moet deze van schijf laden. Kleine paginafouten: pagina is in geheugen maar niet gemapped. Grote paginafouten: pagina moet van schijf worden opgehaald (kostbaar).","ru":"Возникает, когда программа обращается к странице, отсутствующей в физической памяти. ОС должна загрузить её с диска. Мягкие ошибки: страница в памяти, но не отображена. Жёсткие ошибки: страница должна быть загружена с диска (дорого).","zh":"当程序访问当前不在物理内存中的页面时发生。操作系统必须从磁盘加载该页面。次要缺页：页面在内存中但未映射。主要缺页：页面必须从磁盘检索（开销大）。","pt_BR":"Ocorre quando um programa acessa uma página que não está atualmente na memória física. O SO deve carregá-la do disco. Falhas menores: página está na memória mas não mapeada. Falhas maiores: página deve ser recuperada do disco (custoso).","pt_PT":"Ocorre quando um programa acede a uma página que não está atualmente na memória física. O SO deve carregá-la do disco. Falhas menores: página está na memória mas não mapeada. Falhas maiores: página deve ser recuperada do disco (dispendioso)."}},
  { id: 'dc-technology-0075', deck_id: 'deck-technology', sort_order: 75, front: "Context Switch", back: "The OS process of saving the state of one process/thread and loading another. Allows multitasking. Involves saving registers, program counter, and memory mappings. Has overhead; too many reduce CPU efficiency." , front_translations: {"es":"Troca de contexto","it":"Changemento di contexte","de":"Kontextwechsel","fr":"Changement de contexte","tr":"Bağlam Değiştirme","nl":"Contextwisseling","ru":"Переключение контекста","zh":"上下文切换","pt_BR":"Troca de contexto","pt_PT":"Mudança de contexto"}, back_translations: {"es":"El proceso del sistema operativo de salvar el estado de un proceso/thread y carregar outro. Permite multitarefa. Involucra salvar registradores, contador de programa y mapeamentos de memoria. Tiene overhead; muchas trocas reducen a eficiencia de la CPU.","it":"Il processo del sistema d'exploitazione consistant à sauvegarder l'etat di un processo/thread e à en charger un autre. Permet il multitâche. Implico la sauvegarde dei registres, del comptore di programme e dei mappages memoire. Genere un surcout ; trop di changements reduisent l'efficacite del CPU.","de":"Der Betriebssystemprozess des Speicherns des Zustands eines Prozesses/Threads und des Ladens eines anderen. Ermöglicht Multitasking. Umfasst das Speichern von Registern, Programmzähler und Speicherzuordnungen. Hat Overhead; zu viele verringern die CPU-Effizienz.","fr":"Le processus du système d'exploitation consistant à sauvegarder l'état d'un processus/thread et à en charger un autre. Permet le multitâche. Implique la sauvegarde des registres, du compteur de programme et des mappages mémoire. Génère un surcoût ; trop de changements réduisent l'efficacité du CPU.","tr":"İşletim sisteminin bir işlem/iş parçacığının durumunu kaydedip diğerini yükleme süreci. Çoklu görev yapılmasını sağlar. Yazmaçların, program sayacının ve bellek eşlemelerinin kaydedilmesini içerir. Ek yük oluşturur; çok fazlası CPU verimliliğini düşürür.","nl":"Het besturingssysteemproces van het opslaan van de staat van een proces/thread en het laden van een ander. Maakt multitasking mogelijk. Omvat het opslaan van registers, programmateller en geheugenafbeeldingen. Heeft overhead; te veel verminderen de CPU-efficiëntie.","ru":"Процесс операционной системы по сохранению состояния одного процесса/потока и загрузке другого. Обеспечивает многозадачность. Включает сохранение регистров, счётчика команд и отображений памяти. Имеет накладные расходы; слишком частое переключение снижает эффективность CPU.","zh":"操作系统保存一个进程/线程状态并加载另一个的过程。实现多任务处理。涉及保存寄存器、程序计数器和内存映射。有开销；过多的上下文切换会降低CPU效率。","pt_BR":"O processo do sistema operacional de salvar o estado de um processo/thread e carregar outro. Permite multitarefa. Envolve salvar registradores, contador de programa e mapeamentos de memória. Tem overhead; muitas trocas reduzem a eficiência da CPU.","pt_PT":"O processo do sistema operativo de guardar o estado de um processo/thread e carregar outro. Permite multitarefa. Envolve guardar registos, contador de programa e mapeamentos de memória. Tem overhead; demasiadas trocas reduzem a eficiência do CPU."}},
  { id: 'dc-technology-0076', deck_id: 'deck-technology', sort_order: 76, front: "Garbage Collection", back: "Automatic memory management that reclaims memory no longer referenced by the program. Approaches: reference counting (Swift, Python), mark-and-sweep (JVM, .NET). Eliminates manual memory management bugs but adds overhead." , front_translations: {"es":"Coleta de Lixo (Garbage Collection)","it":"Ramassa-miettes (Garbage Collectione)","de":"Garbage Collection","fr":"Ramasse-miettes (Garbage Collection)","tr":"Çöp Toplama (Garbage Collection)","nl":"Garbage Collection","ru":"Сборка мусора (Garbage Collection)","zh":"垃圾回收（Garbage Collection）","pt_BR":"Coleta de Lixo (Garbage Collection)","pt_PT":"Recolha de Lixo (Garbage Collection)"}, back_translations: {"es":"Gerenciamento automático de memoria que recupera memoria no más referenciada por el programa. Abordajes: contaje de referencias (Swift, Python), mark-and-sweep (JVM, .NET). Elimina erros de gerenciamento manual de memoria, pero adiciona overhead.","it":"Geszione automatico della memoire che recupere la memoire non referencee per il programme. Approches : comptage di referenze (Swift, Python), mark-and-sweep (JVM, .NET). Elimine i bugs di geszione manuelle ma ajoute del surcout.","de":"Automatische Speicherverwaltung, die nicht mehr referenzierten Speicher freigibt. Ansätze: Referenzzählung (Swift, Python), Mark-and-Sweep (JVM, .NET). Eliminiert manuelle Speicherverwaltungsfehler, verursacht aber Overhead.","fr":"Gestion automatique de la mémoire qui récupère la mémoire non référencée par le programme. Approches : comptage de références (Swift, Python), mark-and-sweep (JVM, .NET). Élimine les bugs de gestion manuelle mais ajoute du surcoût.","tr":"Program tarafından artık referans verilmeyen belleği geri kazanan otomatik bellek yönetimi. Yaklaşımlar: referans sayımı (Swift, Python), mark-and-sweep (JVM, .NET). Manuel bellek yönetimi hatalarını ortadan kaldırır ancak ek yük getirir.","nl":"Automatisch geheugenbeheer dat geheugen terugwint dat niet meer wordt gerefereerd door het programma. Benaderingen: referentietelling (Swift, Python), mark-and-sweep (JVM, .NET). Elimineert handmatige geheugenbeheerproblemen maar voegt overhead toe.","ru":"Автоматическое управление памятью, освобождающее память, на которую больше нет ссылок. Подходы: подсчёт ссылок (Swift, Python), mark-and-sweep (JVM, .NET). Устраняет ошибки ручного управления памятью, но создаёт накладные расходы.","zh":"自动内存管理，回收程序不再引用的内存。方法：引用计数（Swift、Python）、标记-清除（JVM、.NET）。消除手动内存管理错误，但增加开销。","pt_BR":"Gerenciamento automático de memória que recupera memória não mais referenciada pelo programa. Abordagens: contagem de referências (Swift, Python), mark-and-sweep (JVM, .NET). Elimina erros de gerenciamento manual de memória, mas adiciona overhead.","pt_PT":"Gestão automática de memória que recupera memória já não referenciada pelo programa. Abordagens: contagem de referências (Swift, Python), mark-and-sweep (JVM, .NET). Elimina erros de gestão manual de memória, mas adiciona overhead."}},
  { id: 'dc-technology-0077', deck_id: 'deck-technology', sort_order: 77, front: "Stack vs. Heap (Memory)", back: "Stack: automatically managed LIFO memory for local variables and function calls; fast but limited in size. Heap: dynamically allocated memory; larger but requires manual management (C/C++) or garbage collection; slower allocation." , front_translations: {"es":"Stack vs. Heap (Memoria)","it":"Pile vs. Tas (Memoire)","de":"Stack vs. Heap (Speicher)","fr":"Pile vs. Tas (Mémoire)","tr":"Stack vs. Heap (Bellek)","nl":"Stack vs. Heap (Geheugen)","ru":"Стек vs. Куча (Память)","zh":"栈 vs. 堆（内存）","pt_BR":"Stack vs. Heap (Memória)","pt_PT":"Stack vs. Heap (Memória)"}, back_translations: {"es":"Stack: memoria LIFO gerenciada automáticamente para variables ubicaciones y llamadas de función; rápida pero limitada en tamaño. Heap: memoria alocada dinamicamente; mayor pero requiere gerenciamento manual (C/C++) o coleta de lixo; alocación más lenta.","it":"Pile : memoire LIFO geree automatiquement per i variables locales e appels di fonczione ; rapide ma limitee. Tas : memoire allouee dynamiquement ; più grande ma necessite geszione manuelle (C/C++) o ramasse-miettes ; allocazione più lente.","de":"Stack: automatisch verwalteter LIFO-Speicher für lokale Variablen und Funktionsaufrufe; schnell, aber begrenzt. Heap: dynamisch allokierter Speicher; größer, erfordert aber manuelle Verwaltung (C/C++) oder Garbage Collection; langsamere Allokation.","fr":"Pile : mémoire LIFO gérée automatiquement pour les variables locales et appels de fonction ; rapide mais limitée. Tas : mémoire allouée dynamiquement ; plus grande mais nécessite gestion manuelle (C/C++) ou ramasse-miettes ; allocation plus lente.","tr":"Stack: yerel değişkenler ve fonksiyon çağrıları için otomatik yönetilen LIFO bellek; hızlı ama boyut olarak sınırlı. Heap: dinamik olarak ayrılan bellek; daha büyük ama manuel yönetim (C/C++) veya çöp toplama gerektirir; daha yavaş tahsis.","nl":"Stack: automatisch beheerd LIFO-geheugen voor lokale variabelen en functieaanroepen; snel maar beperkt in grootte. Heap: dynamisch toegewezen geheugen; groter maar vereist handmatig beheer (C/C++) of garbage collection; tragere toewijzing.","ru":"Стек: автоматически управляемая LIFO-память для локальных переменных и вызовов функций; быстрая, но ограниченная. Куча: динамически выделяемая память; больше, но требует ручного управления (C/C++) или сборки мусора; более медленное выделение.","zh":"栈：自动管理的后进先出内存，用于局部变量和函数调用；快速但大小有限。堆：动态分配的内存；更大但需要手动管理（C/C++）或垃圾回收；分配速度较慢。","pt_BR":"Stack: memória LIFO gerenciada automaticamente para variáveis locais e chamadas de função; rápida mas limitada em tamanho. Heap: memória alocada dinamicamente; maior mas requer gerenciamento manual (C/C++) ou coleta de lixo; alocação mais lenta.","pt_PT":"Stack: memória LIFO gerida automaticamente para variáveis locais e chamadas de função; rápida mas limitada em tamanho. Heap: memória alocada dinamicamente; maior mas requer gestão manual (C/C++) ou recolha de lixo; alocação mais lenta."}},
  { id: 'dc-technology-0078', deck_id: 'deck-technology', sort_order: 78, front: "Cache (CPU)", back: "A small, fast memory between the CPU and main RAM storing frequently accessed data. L1 (fastest, smallest), L2, L3 (slowest, largest) caches. Cache miss: data must be fetched from slower memory." , front_translations: {"es":"Cache (CPU)","it":"Cache (CPU)","de":"Cache (CPU)","fr":"Cache (CPU)","tr":"Önbellek (CPU)","nl":"Cache (CPU)","ru":"Кэш (CPU)","zh":"缓存（CPU）","pt_BR":"Cache (CPU)","pt_PT":"Cache (CPU)"}, back_translations: {"es":"Una memoria pequeña y rápida entre a CPU y a RAM principal que almacena datos acessados frecuentemente. Caches L1 (más rápido, menor), L2, L3 (más lento, mayor). Cache miss: los datos devem ser buscados en la memoria más lenta.","it":"Una piccola memoire rapide tra il CPU e la RAM principale stockant i donnees frequemment accedees. Caches L1 (il più rapide, il più piccolo), L2, L3 (il più lent, il più grande). Cache miss : i donnees doivent etre recuperees depuis una memoire più lente.","de":"Ein kleiner, schneller Speicher zwischen CPU und Hauptspeicher (RAM), der häufig genutzte Daten speichert. L1 (schnellster, kleinster), L2, L3 (langsamster, größter) Caches. Cache-Miss: Daten müssen aus langsamerem Speicher geladen werden.","fr":"Une petite mémoire rapide entre le CPU et la RAM principale stockant les données fréquemment accédées. Caches L1 (le plus rapide, le plus petit), L2, L3 (le plus lent, le plus grand). Cache miss : les données doivent être récupérées depuis une mémoire plus lente.","tr":"CPU ile ana RAM arasında, sık erişilen verileri saklayan küçük ve hızlı bir bellek. L1 (en hızlı, en küçük), L2, L3 (en yavaş, en büyük) önbellekleri. Önbellek ıskalama: verinin daha yavaş bellekten getirilmesi gerekir.","nl":"Een klein, snel geheugen tussen de CPU en het hoofdgeheugen (RAM) dat veelgebruikte gegevens opslaat. L1 (snelste, kleinste), L2, L3 (traagste, grootste) caches. Cache miss: gegevens moeten uit trager geheugen worden opgehaald.","ru":"Небольшая быстрая память между CPU и основной оперативной памятью, хранящая часто используемые данные. Кэши L1 (самый быстрый, самый маленький), L2, L3 (самый медленный, самый большой). Промах кэша: данные нужно загрузить из более медленной памяти.","zh":"位于CPU和主内存（RAM）之间的小型快速存储器，存储频繁访问的数据。L1（最快、最小）、L2、L3（最慢、最大）缓存。缓存未命中：数据必须从较慢的内存中获取。","pt_BR":"Uma memória pequena e rápida entre a CPU e a RAM principal que armazena dados acessados frequentemente. Caches L1 (mais rápido, menor), L2, L3 (mais lento, maior). Cache miss: os dados devem ser buscados na memória mais lenta.","pt_PT":"Uma memória pequena e rápida entre o CPU e a RAM principal que armazena dados acedidos frequentemente. Caches L1 (mais rápida, menor), L2, L3 (mais lenta, maior). Cache miss: os dados devem ser obtidos da memória mais lenta."}},
  { id: 'dc-technology-0079', deck_id: 'deck-technology', sort_order: 79, front: "Compiler vs. Interpreter", back: "Compiler: translates entire source code to machine code before execution (e.g., C, Rust). Fast runtime but slow compilation. Interpreter: executes source code line-by-line (e.g., Python). Slower runtime but immediate execution. JIT compilation is a hybrid." , front_translations: {"es":"Compilador vs. Interpretador","it":"Compilatore vs. Interpretore","de":"Compiler vs. Interpreter","fr":"Compilateur vs. Interpréteur","tr":"Derleyici vs. Yorumlayıcı","nl":"Compiler vs. Interpreter","ru":"Компилятор vs. Интерпретатор","zh":"编译器 vs. 解释器","pt_BR":"Compilador vs. Interpretador","pt_PT":"Compilador vs. Interpretador"}, back_translations: {"es":"Compilador: traduz todo el código fuente para código de máquina antes de la execución (ex.: C, Rust). Execución rápida, compilación lenta. Interpretador: executa el código fuente línea por línea (ex.: Python). Execución más lenta, pero imediata. Compilación JIT es un híbrido.","it":"Compilatore : traduit tutto il code source en code machine avant execuzione (ex. C, Rust). Execuzione rapide ma compilazione lente. Interpretore : execute il code source ligne per ligne (ex. Python). Execuzione più lente ma immediate. La compilazione JIT e un hybride.","de":"Compiler: übersetzt den gesamten Quellcode vor der Ausführung in Maschinencode (z.B. C, Rust). Schnelle Laufzeit, langsame Kompilierung. Interpreter: führt Quellcode Zeile für Zeile aus (z.B. Python). Langsamere Laufzeit, sofortige Ausführung. JIT-Kompilierung ist ein Hybrid.","fr":"Compilateur : traduit tout le code source en code machine avant exécution (ex. C, Rust). Exécution rapide mais compilation lente. Interpréteur : exécute le code source ligne par ligne (ex. Python). Exécution plus lente mais immédiate. La compilation JIT est un hybride.","tr":"Derleyici: tüm kaynak kodu çalıştırmadan önce makine koduna çevirir (ör. C, Rust). Hızlı çalışma, yavaş derleme. Yorumlayıcı: kaynak kodu satır satır çalıştırır (ör. Python). Daha yavaş çalışma ama anında yürütme. JIT derleme bir hibrit yaklaşımdır.","nl":"Compiler: vertaalt de volledige broncode naar machinecode vóór uitvoering (bijv. C, Rust). Snelle runtime maar trage compilatie. Interpreter: voert broncode regel voor regel uit (bijv. Python). Tragere runtime maar directe uitvoering. JIT-compilatie is een hybride.","ru":"Компилятор: переводит весь исходный код в машинный код перед выполнением (например, C, Rust). Быстрое выполнение, медленная компиляция. Интерпретатор: выполняет исходный код построчно (например, Python). Медленнее, но мгновенный запуск. JIT-компиляция — гибрид.","zh":"编译器：在执行前将整个源代码翻译为机器码（如C、Rust）。运行速度快但编译慢。解释器：逐行执行源代码（如Python）。运行较慢但可立即执行。JIT编译是一种混合方式。","pt_BR":"Compilador: traduz todo o código-fonte para código de máquina antes da execução (ex.: C, Rust). Execução rápida, compilação lenta. Interpretador: executa o código-fonte linha por linha (ex.: Python). Execução mais lenta, mas imediata. Compilação JIT é um híbrido.","pt_PT":"Compilador: traduz todo o código-fonte para código de máquina antes da execução (ex.: C, Rust). Execução rápida, compilação lenta. Interpretador: executa o código-fonte linha a linha (ex.: Python). Execução mais lenta, mas imediata. Compilação JIT é um híbrido."}},
  { id: 'dc-technology-0080', deck_id: 'deck-technology', sort_order: 80, front: "Version Control: Git", back: "A distributed version control system tracking changes in source code. Key concepts: commit (snapshot), branch (parallel development), merge (combine branches), clone (copy repo), push/pull (sync with remote). Created by Linus Torvalds." , front_translations: {"es":"Controle de Versão: Git","it":"Contruolo di versione : Git","de":"Versionskontrolle: Git","fr":"Contrôle de version : Git","tr":"Sürüm Kontrolü: Git","nl":"Versiebeheer: Git","ru":"Система контроля версий: Git","zh":"版本控制：Git","pt_BR":"Controle de Versão: Git","pt_PT":"Controlo de Versões: Git"}, back_translations: {"es":"Un sistema de controle de versão distribuído que rastreia alteraciones en el código fuente. Conceptos-chave: commit (snapshot), branch (desarrollo paralelo), merge (combinar branches), clone (copiar repositório), push/pull (sincronizar con remoto). Creado por Linus Torvalds.","it":"Un sistema di controil di version distribue suivant i modificazioni del code source. Concepts cles : commit (instantane), branche (sviluppo paralleil), merge (fusionner i branches), clone (copier il depot), push/pull (synchroniser con il distant). Cree per Linus Torvalds.","de":"Ein verteiltes Versionskontrollsystem zur Nachverfolgung von Quellcode-Änderungen. Schlüsselkonzepte: Commit (Snapshot), Branch (parallele Entwicklung), Merge (Branches zusammenführen), Clone (Repo kopieren), Push/Pull (mit Remote synchronisieren). Erstellt von Linus Torvalds.","fr":"Un système de contrôle de version distribué suivant les modifications du code source. Concepts clés : commit (instantané), branche (développement parallèle), merge (fusionner les branches), clone (copier le dépôt), push/pull (synchroniser avec le distant). Créé par Linus Torvalds.","tr":"Kaynak kodundaki değişiklikleri izleyen dağıtık bir sürüm kontrol sistemi. Temel kavramlar: commit (anlık görüntü), branch (paralel geliştirme), merge (dalları birleştirme), clone (depoyu kopyalama), push/pull (uzak sunucuyla senkronizasyon). Linus Torvalds tarafından oluşturulmuştur.","nl":"Een gedistribueerd versiebeheersysteem dat wijzigingen in broncode bijhoudt. Kernconcepten: commit (snapshot), branch (parallelle ontwikkeling), merge (branches samenvoegen), clone (repo kopiëren), push/pull (synchroniseren met remote). Gemaakt door Linus Torvalds.","ru":"Распределённая система контроля версий для отслеживания изменений в исходном коде. Ключевые понятия: коммит (снимок), ветка (параллельная разработка), слияние (объединение веток), клон (копия репозитория), push/pull (синхронизация с удалённым). Создан Линусом Торвальдсом.","zh":"分布式版本控制系统，用于跟踪源代码的更改。关键概念：提交（快照）、分支（并行开发）、合并（合并分支）、克隆（复制仓库）、推送/拉取（与远程同步）。由Linus Torvalds创建。","pt_BR":"Um sistema de controle de versão distribuído que rastreia alterações no código-fonte. Conceitos-chave: commit (snapshot), branch (desenvolvimento paralelo), merge (combinar branches), clone (copiar repositório), push/pull (sincronizar com remoto). Criado por Linus Torvalds.","pt_PT":"Um sistema de controlo de versões distribuído que rastreia alterações no código-fonte. Conceitos-chave: commit (snapshot), branch (desenvolvimento paralelo), merge (combinar branches), clone (copiar repositório), push/pull (sincronizar com remoto). Criado por Linus Torvalds."}},
  { id: 'dc-technology-0081', deck_id: 'deck-technology', sort_order: 81, front: "Git Branching Strategies", back: "Common strategies: GitHub Flow (feature branches → main), Git Flow (develop/feature/release/hotfix branches), trunk-based development (frequent commits to main). Branching enables parallel feature development without conflicts." , front_translations: {"es":"Estrategias de Branching del Git","it":"Stratàgies di branchemento Git","de":"Git-Branching-Strategien","fr":"Stratégies de branchement Git","tr":"Git Dallanma Stratejileri","nl":"Git-vertakkingsstrategieën","ru":"Стратегии ветвления в Git","zh":"Git 分支策略","pt_BR":"Estratégias de Branching do Git","pt_PT":"Estratégias de Branching do Git"}, back_translations: {"es":"Estrategias comuns: GitHub Flow (branches de feature → main), Git Flow (branches develop/feature/release/hotfix), desarrollo basado en trunk (commits frequentes en el main). Branching permite desarrollo paralelo de funcionalidades sin conflitos.","it":"Strategies courantes : GitHub Flow (branches di fonctionnalite → main), Git Flow (branches develop/feature/release/hotfix), sviluppo base su il tronc (commits frequents su main). Il branchement permette il sviluppo paralleil senza conflits.","de":"Gängige Strategien: GitHub Flow (Feature-Branches → main), Git Flow (develop/feature/release/hotfix-Branches), Trunk-basierte Entwicklung (häufige Commits auf main). Branching ermöglicht parallele Feature-Entwicklung ohne Konflikte.","fr":"Stratégies courantes : GitHub Flow (branches de fonctionnalité → main), Git Flow (branches develop/feature/release/hotfix), développement basé sur le tronc (commits fréquents sur main). Le branchement permet le développement parallèle sans conflits.","tr":"Yaygın stratejiler: GitHub Flow (özellik dalları → main), Git Flow (develop/feature/release/hotfix dalları), trunk tabanlı geliştirme (main'e sık commit). Dallanma, çakışma olmadan paralel özellik geliştirmeyi sağlar.","nl":"Veelgebruikte strategieën: GitHub Flow (feature branches → main), Git Flow (develop/feature/release/hotfix branches), trunk-based development (frequente commits naar main). Vertakking maakt parallelle featureontwikkeling zonder conflicten mogelijk.","ru":"Распространённые стратегии: GitHub Flow (feature-ветки → main), Git Flow (ветки develop/feature/release/hotfix), trunk-based development (частые коммиты в main). Ветвление позволяет вести параллельную разработку без конфликтов.","zh":"常见策略：GitHub Flow（功能分支 → main）、Git Flow（develop/feature/release/hotfix 分支）、基于主干的开发（频繁提交到 main）。分支支持无冲突的并行功能开发。","pt_BR":"Estratégias comuns: GitHub Flow (branches de feature → main), Git Flow (branches develop/feature/release/hotfix), desenvolvimento baseado em trunk (commits frequentes no main). Branching permite desenvolvimento paralelo de funcionalidades sem conflitos.","pt_PT":"Estratégias comuns: GitHub Flow (branches de feature → main), Git Flow (branches develop/feature/release/hotfix), desenvolvimento baseado em trunk (commits frequentes no main). Branching permite desenvolvimento paralelo de funcionalidades sem conflitos."}},
  { id: 'dc-technology-0082', deck_id: 'deck-technology', sort_order: 82, front: "CI/CD — Continuous Integration / Continuous Deployment", back: "CI: automated testing on every code commit to catch bugs early. CD: automated deployment to production after passing tests. Reduces manual errors and enables frequent, reliable software releases." , front_translations: {"es":"CI/CD — Integración Contínua / Implantación Contínua","it":"CI/CD — Intàgratione continue / Depleggeemento continu","de":"CI/CD — Continuous Integration / Continuous Deployment","fr":"CI/CD — Intégration continue / Déploiement continu","tr":"CI/CD — Sürekli Entegrasyon / Sürekli Dağıtım","nl":"CI/CD — Continuous Integration / Continuous Deployment","ru":"CI/CD — Непрерывная интеграция / Непрерывное развёртывание","zh":"CI/CD — 持续集成 / 持续部署","pt_BR":"CI/CD — Integração Contínua / Implantação Contínua","pt_PT":"CI/CD — Integração Contínua / Implementação Contínua"}, back_translations: {"es":"CI: pruebas automatizados a cada commit de código para detectar bugs temprano. CD: implantación automatizada en producción após passar en los pruebas. Reduce erros manuais y permite lançamentos de software frequentes y confiables.","it":"CI : tests automatises à ogni commit per detecter i bugs tot. CD : deploiement automatise en produczione apres reussite dei tests. Reduit i errori manuelles e permette dei livraisons logicielles frequentes e fiables.","de":"CI: automatisiertes Testen bei jedem Code-Commit, um Fehler frühzeitig zu erkennen. CD: automatisiertes Deployment in die Produktion nach bestandenen Tests. Reduziert manuelle Fehler und ermöglicht häufige, zuverlässige Software-Releases.","fr":"CI : tests automatisés à chaque commit pour détecter les bugs tôt. CD : déploiement automatisé en production après réussite des tests. Réduit les erreurs manuelles et permet des livraisons logicielles fréquentes et fiables.","tr":"CI: hataları erken yakalamak için her kod commit'inde otomatik test. CD: testleri geçtikten sonra üretime otomatik dağıtım. Manuel hataları azaltır ve sık, güvenilir yazılım sürümlerini mümkün kılar.","nl":"CI: geautomatiseerd testen bij elke code-commit om bugs vroeg te ontdekken. CD: geautomatiseerde deployment naar productie na het slagen van tests. Vermindert handmatige fouten en maakt frequente, betrouwbare softwarereleases mogelijk.","ru":"CI: автоматическое тестирование при каждом коммите для раннего обнаружения ошибок. CD: автоматическое развёртывание в продакшен после прохождения тестов. Уменьшает ручные ошибки и обеспечивает частые, надёжные релизы.","zh":"CI：每次代码提交时自动测试以尽早发现错误。CD：通过测试后自动部署到生产环境。减少人为错误，实现频繁、可靠的软件发布。","pt_BR":"CI: testes automatizados a cada commit de código para detectar bugs cedo. CD: implantação automatizada em produção após passar nos testes. Reduz erros manuais e permite lançamentos de software frequentes e confiáveis.","pt_PT":"CI: testes automatizados a cada commit de código para detetar bugs cedo. CD: implementação automatizada em produção após passar nos testes. Reduz erros manuais e permite lançamentos de software frequentes e fiáveis."}},
  { id: 'dc-technology-0083', deck_id: 'deck-technology', sort_order: 83, front: "Containerization (Docker)", back: "Packages an application and its dependencies into a portable container that runs consistently across environments. Unlike VMs, containers share the host OS kernel, making them lightweight and fast to start." , front_translations: {"es":"Containerización (Docker)","it":"Conteneurisatione (Docker)","de":"Containerisierung (Docker)","fr":"Conteneurisation (Docker)","tr":"Konteynerizasyon (Docker)","nl":"Containerisatie (Docker)","ru":"Контейнеризация (Docker)","zh":"容器化（Docker）","pt_BR":"Containerização (Docker)","pt_PT":"Contentorização (Docker)"}, back_translations: {"es":"Empacota una aplicación y sus dependencias en un conteiner portátil que executa de forma consistente en diferentes ambientes. Diferente de VMs, conteineres compartilham el kernel del SO host, tornando-los leves y rápidos para iniciar.","it":"Empaquette una applicazione e i suoi dependanze in un contenore portable che fonctionne di maniere coherente in differents environnements. Contrairement ai VMs, i contenori partagent il noyau dell'OS hote, i rendant legers e rapides à demarrer.","de":"Verpackt eine Anwendung und ihre Abhängigkeiten in einen portablen Container, der konsistent in verschiedenen Umgebungen läuft. Im Gegensatz zu VMs teilen Container den Host-OS-Kernel, was sie leichtgewichtig und schnell startbar macht.","fr":"Empaquette une application et ses dépendances dans un conteneur portable qui fonctionne de manière cohérente dans différents environnements. Contrairement aux VMs, les conteneurs partagent le noyau de l'OS hôte, les rendant légers et rapides à démarrer.","tr":"Bir uygulamayı ve bağımlılıklarını, ortamlar arasında tutarlı çalışan taşınabilir bir konteynere paketler. VM'lerin aksine, konteynerler ana işletim sistemi çekirdeğini paylaşır, bu da onları hafif ve hızlı başlatılabilir yapar.","nl":"Verpakt een applicatie en zijn afhankelijkheden in een draagbare container die consistent draait in verschillende omgevingen. In tegenstelling tot VM's delen containers de host OS-kernel, waardoor ze lichtgewicht en snel op te starten zijn.","ru":"Упаковывает приложение и его зависимости в переносимый контейнер, работающий одинаково в разных средах. В отличие от виртуальных машин, контейнеры разделяют ядро хостовой ОС, что делает их легковесными и быстрыми в запуске.","zh":"将应用程序及其依赖项打包到可移植的容器中，在不同环境中一致运行。与虚拟机不同，容器共享主机操作系统内核，使其轻量且启动快速。","pt_BR":"Empacota uma aplicação e suas dependências em um contêiner portátil que executa de forma consistente em diferentes ambientes. Diferente de VMs, contêineres compartilham o kernel do SO host, tornando-os leves e rápidos para iniciar.","pt_PT":"Empacota uma aplicação e as suas dependências num contentor portátil que executa de forma consistente em diferentes ambientes. Ao contrário das VMs, os contentores partilham o kernel do SO anfitrião, tornando-os leves e rápidos a iniciar."}},
  { id: 'dc-technology-0084', deck_id: 'deck-technology', sort_order: 84, front: "Kubernetes (K8s)", back: "An open-source container orchestration platform for automating deployment, scaling, and management of containerized applications. Key concepts: pod (smallest unit), service (networking), deployment (desired state)." , front_translations: {"es":"Kubernetes (K8s)","it":"Kubernetes (K8s)","de":"Kubernetes (K8s)","fr":"Kubernetes (K8s)","tr":"Kubernetes (K8s)","nl":"Kubernetes (K8s)","ru":"Kubernetes (K8s)","zh":"Kubernetes（K8s）","pt_BR":"Kubernetes (K8s)","pt_PT":"Kubernetes (K8s)"}, back_translations: {"es":"Una plataforma de orquestración de conteineres de código aberto para automatizar a implantación, escalabilidad y gerenciamento de aplicaciones conteinerizadas. Conceptos-chave: pod (menor unidad), service (red), deployment (estado desejado).","it":"Una plateforme open source d'orchestrazione di contenori per automatiser il deploiement, la mise all'echelle e la geszione d'applicazioni conteneurisees. Concepts cles : pod (più piccola unite), service (reseau), deployment (etat souhaite).","de":"Eine Open-Source-Container-Orchestrierungsplattform zur Automatisierung von Deployment, Skalierung und Verwaltung containerisierter Anwendungen. Schlüsselkonzepte: Pod (kleinste Einheit), Service (Netzwerk), Deployment (gewünschter Zustand).","fr":"Une plateforme open source d'orchestration de conteneurs pour automatiser le déploiement, la mise à l'échelle et la gestion d'applications conteneurisées. Concepts clés : pod (plus petite unité), service (réseau), deployment (état souhaité).","tr":"Konteynerleştirilmiş uygulamaların dağıtımını, ölçeklenmesini ve yönetimini otomatikleştiren açık kaynaklı bir konteyner orkestrasyon platformu. Temel kavramlar: pod (en küçük birim), service (ağ), deployment (istenen durum).","nl":"Een open-source containerorkestratieplatform voor het automatiseren van deployment, schaling en beheer van gecontaineriseerde applicaties. Kernconcepten: pod (kleinste eenheid), service (netwerken), deployment (gewenste staat).","ru":"Платформа оркестрации контейнеров с открытым исходным кодом для автоматизации развёртывания, масштабирования и управления контейнеризированными приложениями. Ключевые понятия: pod (наименьшая единица), service (сеть), deployment (желаемое состояние).","zh":"一个开源容器编排平台，用于自动化容器化应用的部署、扩展和管理。关键概念：Pod（最小单元）、Service（网络）、Deployment（期望状态）。","pt_BR":"Uma plataforma de orquestração de contêineres de código aberto para automatizar a implantação, escalabilidade e gerenciamento de aplicações conteinerizadas. Conceitos-chave: pod (menor unidade), service (rede), deployment (estado desejado).","pt_PT":"Uma plataforma de orquestração de contentores de código aberto para automatizar a implementação, escalabilidade e gestão de aplicações contentorizadas. Conceitos-chave: pod (menor unidade), service (rede), deployment (estado desejado)."}},
  { id: 'dc-technology-0085', deck_id: 'deck-technology', sort_order: 85, front: "Microservices Architecture", back: "An architectural style decomposing an application into small, independent services each running its own process and communicating via APIs. Enables independent deployment and scaling but increases operational complexity." , front_translations: {"es":"Arquitetura de Microsserviços","it":"Architecture microservices","de":"Microservices-Architektur","fr":"Architecture microservices","tr":"Mikroservis Mimarisi","nl":"Microservices-architectuur","ru":"Микросервисная архитектура","zh":"微服务架构","pt_BR":"Arquitetura de Microsserviços","pt_PT":"Arquitetura de Microsserviços"}, back_translations: {"es":"Un estilo arquitetural que decompõe una aplicación en pequeños serviços independentes, cada un executando en su propio proceso y comunicando-se via APIs. Permite implantación y escalabilidad independentes, pero aumenta a complexidad operacional.","it":"Un style architectural decomposant una applicazione en petits services independants, chacun execute in il suo propre processo e communiquant via dei API. Permet un deploiement e una mise all'echelle independants ma augmente la complexite operationnelle.","de":"Ein Architekturstil, der eine Anwendung in kleine, unabhängige Dienste zerlegt, die jeweils in eigenen Prozessen laufen und über APIs kommunizieren. Ermöglicht unabhängiges Deployment und Skalierung, erhöht aber die operationale Komplexität.","fr":"Un style architectural décomposant une application en petits services indépendants, chacun exécuté dans son propre processus et communiquant via des API. Permet un déploiement et une mise à l'échelle indépendants mais augmente la complexité opérationnelle.","tr":"Bir uygulamayı her biri kendi sürecinde çalışan ve API'ler aracılığıyla iletişim kuran küçük, bağımsız hizmetlere ayıran bir mimari tarz. Bağımsız dağıtım ve ölçekleme sağlar ancak operasyonel karmaşıklığı artırır.","nl":"Een architectuurstijl die een applicatie ontleedt in kleine, onafhankelijke services die elk in hun eigen proces draaien en via API's communiceren. Maakt onafhankelijke deployment en schaling mogelijk maar verhoogt operationele complexiteit.","ru":"Архитектурный стиль, разбивающий приложение на маленькие, независимые сервисы, каждый из которых работает в своём процессе и взаимодействует через API. Позволяет независимое развёртывание и масштабирование, но увеличивает операционную сложность.","zh":"一种架构风格，将应用程序分解为小型独立服务，每个服务运行在自己的进程中并通过API通信。支持独立部署和扩展，但增加了运维复杂性。","pt_BR":"Um estilo arquitetural que decompõe uma aplicação em pequenos serviços independentes, cada um executando em seu próprio processo e comunicando-se via APIs. Permite implantação e escalabilidade independentes, mas aumenta a complexidade operacional.","pt_PT":"Um estilo arquitetural que decompõe uma aplicação em pequenos serviços independentes, cada um a executar no seu próprio processo e a comunicar via APIs. Permite implementação e escalabilidade independentes, mas aumenta a complexidade operacional."}},
  { id: 'dc-technology-0086', deck_id: 'deck-technology', sort_order: 86, front: "Monolithic Architecture", back: "A single, self-contained application where all components (UI, business logic, data access) are deployed as one unit. Simpler to develop initially but becomes harder to scale and maintain as it grows." , front_translations: {"es":"Arquitetura Monolítica","it":"Architecture monolithico","de":"Monolithische Architektur","fr":"Architecture monolithique","tr":"Monolitik Mimari","nl":"Monolithische architectuur","ru":"Монолитная архитектура","zh":"单体架构","pt_BR":"Arquitetura Monolítica","pt_PT":"Arquitetura Monolítica"}, back_translations: {"es":"Una aplicación única y autocontida donde todos los componentes (UI, lógica de negocios, acceso a datos) son implantados como una unidad. Más simples de desenvolver inicialmente, pero torna-se más difícil de escalar y mantener conforme crece.","it":"Una applicazione unico e autonome où tutti i composants (UI, logico metier, acces ai donnees) sono deployes come una seule unite. Plus simple à developper al depart ma devient più difficile à mettre all'echelle e à maintenir en grandissant.","de":"Eine einzelne, eigenständige Anwendung, bei der alle Komponenten (UI, Geschäftslogik, Datenzugriff) als eine Einheit deployt werden. Anfangs einfacher zu entwickeln, wird aber mit zunehmendem Wachstum schwerer zu skalieren und zu warten.","fr":"Une application unique et autonome où tous les composants (UI, logique métier, accès aux données) sont déployés comme une seule unité. Plus simple à développer au départ mais devient plus difficile à mettre à l'échelle et à maintenir en grandissant.","tr":"Tüm bileşenlerin (UI, iş mantığı, veri erişimi) tek bir birim olarak dağıtıldığı tek, bağımsız bir uygulama. Başlangıçta geliştirmesi daha basit ancak büyüdükçe ölçeklenmesi ve bakımı zorlaşır.","nl":"Een enkele, op zichzelf staande applicatie waarbij alle componenten (UI, bedrijfslogica, gegevenstoegang) als één eenheid worden gedeployd. Eenvoudiger om aanvankelijk te ontwikkelen maar wordt moeilijker te schalen en onderhouden naarmate het groeit.","ru":"Единое, самодостаточное приложение, где все компоненты (UI, бизнес-логика, доступ к данным) развёртываются как одно целое. Проще в разработке на начальном этапе, но сложнее масштабировать и поддерживать по мере роста.","zh":"一个单一的、自包含的应用程序，所有组件（UI、业务逻辑、数据访问）作为一个单元部署。最初开发更简单，但随着增长变得更难扩展和维护。","pt_BR":"Uma aplicação única e autocontida onde todos os componentes (UI, lógica de negócios, acesso a dados) são implantados como uma unidade. Mais simples de desenvolver inicialmente, mas torna-se mais difícil de escalar e manter conforme cresce.","pt_PT":"Uma aplicação única e autocontida onde todos os componentes (UI, lógica de negócio, acesso a dados) são implementados como uma unidade. Mais simples de desenvolver inicialmente, mas torna-se mais difícil de escalar e manter à medida que cresce."}},
  { id: 'dc-technology-0087', deck_id: 'deck-technology', sort_order: 87, front: "API — Application Programming Interface", back: "A set of defined rules allowing software applications to communicate. Defines the methods and data formats clients can use to interact with a service. REST and GraphQL are common web API styles." , front_translations: {"es":"API — Interfaz de Programación de Aplicaciones","it":"API — Interface di programmatione d'applicationes","de":"API — Application Programming Interface","fr":"API — Interface de programmation d'applications","tr":"API — Uygulama Programlama Arayüzü","nl":"API — Application Programming Interface","ru":"API — Интерфейс прикладного программирования","zh":"API — 应用程序编程接口","pt_BR":"API — Interface de Programação de Aplicações","pt_PT":"API — Interface de Programação de Aplicações"}, back_translations: {"es":"Un conjunto de regras definidas que permite que aplicaciones de software se comuniquem. Define los métodos y formatos de datos que clientes pueden usar para interagir con un serviço. REST y GraphQL son estilos comuns de API web.","it":"Un ensemble di regles definies permettant ai applicazioni logicielles di communiquer. Definit i methodes e formats di donnees che i clients possono utiliser per interagir con un service. REST e GraphQL sono dei styles d'API web courants.","de":"Ein Satz definierter Regeln, die Softwareanwendungen die Kommunikation ermöglichen. Definiert die Methoden und Datenformate, die Clients zur Interaktion mit einem Service nutzen können. REST und GraphQL sind gängige Web-API-Stile.","fr":"Un ensemble de règles définies permettant aux applications logicielles de communiquer. Définit les méthodes et formats de données que les clients peuvent utiliser pour interagir avec un service. REST et GraphQL sont des styles d'API web courants.","tr":"Yazılım uygulamalarının iletişim kurmasını sağlayan tanımlanmış kurallar bütünü. İstemcilerin bir hizmetle etkileşim kurmak için kullanabileceği yöntemleri ve veri formatlarını tanımlar. REST ve GraphQL yaygın web API stilleridir.","nl":"Een set gedefinieerde regels waarmee softwareapplicaties kunnen communiceren. Definieert de methoden en dataformaten die clients kunnen gebruiken om met een service te interageren. REST en GraphQL zijn veelgebruikte web-API-stijlen.","ru":"Набор определённых правил, позволяющих программным приложениям взаимодействовать. Определяет методы и форматы данных, которые клиенты могут использовать для взаимодействия с сервисом. REST и GraphQL — распространённые стили веб-API.","zh":"一组定义好的规则，允许软件应用程序相互通信。定义客户端可用于与服务交互的方法和数据格式。REST和GraphQL是常见的Web API风格。","pt_BR":"Um conjunto de regras definidas que permite que aplicações de software se comuniquem. Define os métodos e formatos de dados que clientes podem usar para interagir com um serviço. REST e GraphQL são estilos comuns de API web.","pt_PT":"Um conjunto de regras definidas que permite que aplicações de software comuniquem. Define os métodos e formatos de dados que clientes podem usar para interagir com um serviço. REST e GraphQL são estilos comuns de API web."}},
  { id: 'dc-technology-0088', deck_id: 'deck-technology', sort_order: 88, front: "GraphQL", back: "A query language and runtime for APIs where the client specifies exactly what data it needs. Avoids over-fetching and under-fetching. Single endpoint vs. multiple REST endpoints. Developed by Facebook." , front_translations: {"es":"GraphQL","it":"GraphQL","de":"GraphQL","fr":"GraphQL","tr":"GraphQL","nl":"GraphQL","ru":"GraphQL","zh":"GraphQL","pt_BR":"GraphQL","pt_PT":"GraphQL"}, back_translations: {"es":"Una linguaje de consulta y runtime para APIs donde el cliente especifica exatamente quais datos precisa. Evita over-fetching y under-fetching. Un único endpoint vs. múltiplos endpoints REST. Desarrollado por el Facebook.","it":"Un langage di requete e un environnement d'execuzione per i API où il client specifie exactement i donnees di cui il ha besoin. Evite il su-chargement e il sotto-chargement. Un seul point d'acces vs. plusiori endpoints REST. Developpe per Facebook.","de":"Eine Abfragesprache und Laufzeitumgebung für APIs, bei der der Client genau angibt, welche Daten er benötigt. Vermeidet Over-Fetching und Under-Fetching. Ein Endpunkt vs. mehrere REST-Endpunkte. Entwickelt von Facebook.","fr":"Un langage de requête et un environnement d'exécution pour les API où le client spécifie exactement les données dont il a besoin. Évite le sur-chargement et le sous-chargement. Un seul point d'accès vs. plusieurs endpoints REST. Développé par Facebook.","tr":"İstemcinin tam olarak hangi verilere ihtiyaç duyduğunu belirttiği API'ler için bir sorgu dili ve çalışma ortamı. Fazla veri çekme ve eksik veri çekme sorunlarını önler. Tek endpoint vs. birden fazla REST endpoint'i. Facebook tarafından geliştirilmiştir.","nl":"Een querytaal en runtime voor API's waarbij de client precies specificeert welke gegevens nodig zijn. Voorkomt over-fetching en under-fetching. Eén endpoint vs. meerdere REST-endpoints. Ontwikkeld door Facebook.","ru":"Язык запросов и среда выполнения для API, где клиент указывает, какие именно данные ему нужны. Избегает избыточной и недостаточной загрузки данных. Одна конечная точка vs. множество REST-эндпоинтов. Разработан Facebook.","zh":"一种API查询语言和运行时，客户端精确指定所需数据。避免过度获取和不足获取。单一端点 vs. 多个REST端点。由Facebook开发。","pt_BR":"Uma linguagem de consulta e runtime para APIs onde o cliente especifica exatamente quais dados precisa. Evita over-fetching e under-fetching. Um único endpoint vs. múltiplos endpoints REST. Desenvolvido pelo Facebook.","pt_PT":"Uma linguagem de consulta e runtime para APIs onde o cliente especifica exatamente que dados precisa. Evita over-fetching e under-fetching. Um único endpoint vs. múltiplos endpoints REST. Desenvolvido pelo Facebook."}},
  { id: 'dc-technology-0089', deck_id: 'deck-technology', sort_order: 89, front: "WebSocket", back: "A full-duplex communication protocol over a single TCP connection enabling real-time, bidirectional communication between client and server. Used for chat, live updates, multiplayer games, and financial tickers." , front_translations: {"es":"WebSocket","it":"WebSocket","de":"WebSocket","fr":"WebSocket","tr":"WebSocket","nl":"WebSocket","ru":"WebSocket","zh":"WebSocket","pt_BR":"WebSocket","pt_PT":"WebSocket"}, back_translations: {"es":"Un protocolo de comunicación full-duplex sobre una única conexión TCP que permite comunicación bidirecional en tiempo real entre cliente y servidor. Usado para chat, atualizaciones al vivo, jogos multiplayer y cotaciones financeras.","it":"Un protocole di communicazione full-duplex su una seule connexion TCP permettant una communicazione bidirectionnelle en temps reel tra client e servore. Utilise per il chat, i mises à jour en direct, i jeux multijouori e i tickers financiers.","de":"Ein Vollduplex-Kommunikationsprotokoll über eine einzelne TCP-Verbindung, das bidirektionale Echtzeit-Kommunikation zwischen Client und Server ermöglicht. Verwendet für Chat, Live-Updates, Multiplayer-Spiele und Finanzticker.","fr":"Un protocole de communication full-duplex sur une seule connexion TCP permettant une communication bidirectionnelle en temps réel entre client et serveur. Utilisé pour le chat, les mises à jour en direct, les jeux multijoueurs et les tickers financiers.","tr":"Tek bir TCP bağlantısı üzerinden istemci ve sunucu arasında gerçek zamanlı, çift yönlü iletişim sağlayan tam çift yönlü iletişim protokolü. Sohbet, canlı güncellemeler, çok oyunculu oyunlar ve finansal ticker'lar için kullanılır.","nl":"Een full-duplex communicatieprotocol over een enkele TCP-verbinding dat real-time, bidirectionele communicatie tussen client en server mogelijk maakt. Gebruikt voor chat, live updates, multiplayergames en financiële tickers.","ru":"Протокол полнодуплексной связи через одно TCP-соединение, обеспечивающий двунаправленную связь в реальном времени между клиентом и сервером. Используется для чатов, обновлений в реальном времени, многопользовательских игр и финансовых тикеров.","zh":"一种通过单个TCP连接实现全双工通信的协议，支持客户端和服务器之间的实时双向通信。用于聊天、实时更新、多人游戏和金融行情。","pt_BR":"Um protocolo de comunicação full-duplex sobre uma única conexão TCP que permite comunicação bidirecional em tempo real entre cliente e servidor. Usado para chat, atualizações ao vivo, jogos multiplayer e cotações financeiras.","pt_PT":"Um protocolo de comunicação full-duplex sobre uma única ligação TCP que permite comunicação bidirecional em tempo real entre cliente e servidor. Usado para chat, atualizações em direto, jogos multiplayer e cotações financeiras."}},
  { id: 'dc-technology-0090', deck_id: 'deck-technology', sort_order: 90, front: "CDN — Content Delivery Network", back: "A geographically distributed network of servers caching static content (images, scripts, videos) closer to end users. Reduces latency, improves load times, and increases availability. Examples: Cloudflare, AWS CloudFront." , front_translations: {"es":"CDN — Red de Distribución de Conteúdo","it":"CDN — Reseau di diffusione di contenu","de":"CDN — Content Delivery Network","fr":"CDN — Réseau de diffusion de contenu","tr":"CDN — İçerik Dağıtım Ağı","nl":"CDN — Content Delivery Network","ru":"CDN — Сеть доставки контента","zh":"CDN — 内容分发网络","pt_BR":"CDN — Rede de Distribuição de Conteúdo","pt_PT":"CDN — Rede de Distribuição de Conteúdo"}, back_translations: {"es":"Una red geograficamente distribuída de servidores que almacena en cache conteúdo estático (imajes, scripts, vídeos) más perto de los usuarios finais. Reduce latencia, melhora tiempos de carregamento y aumenta disponibilidad. Ejemplos: Cloudflare, AWS CloudFront.","it":"Un reseau geographiquement distribue di servori mettant en cache del contenu statico (images, scripts, videos) più pres dei utilisatori finaux. Reduit la latenza, ameliore i temps di chargement e augmente la disponibilite. Exemples : Cloudflare, AWS CloudFront.","de":"Ein geografisch verteiltes Netzwerk von Servern, das statische Inhalte (Bilder, Skripte, Videos) näher an Endnutzer zwischenspeichert. Reduziert Latenz, verbessert Ladezeiten und erhöht Verfügbarkeit. Beispiele: Cloudflare, AWS CloudFront.","fr":"Un réseau géographiquement distribué de serveurs mettant en cache du contenu statique (images, scripts, vidéos) plus près des utilisateurs finaux. Réduit la latence, améliore les temps de chargement et augmente la disponibilité. Exemples : Cloudflare, AWS CloudFront.","tr":"Statik içeriği (resimler, betikler, videolar) son kullanıcılara daha yakın önbelleğe alan coğrafi olarak dağıtılmış bir sunucu ağı. Gecikmeyi azaltır, yükleme sürelerini iyileştirir ve erişilebilirliği artırır. Örnekler: Cloudflare, AWS CloudFront.","nl":"Een geografisch verspreid netwerk van servers dat statische content (afbeeldingen, scripts, video's) dichter bij eindgebruikers cachet. Vermindert latentie, verbetert laadtijden en verhoogt beschikbaarheid. Voorbeelden: Cloudflare, AWS CloudFront.","ru":"Географически распределённая сеть серверов, кэширующая статический контент (изображения, скрипты, видео) ближе к конечным пользователям. Уменьшает задержку, ускоряет загрузку и повышает доступность. Примеры: Cloudflare, AWS CloudFront.","zh":"地理分布式服务器网络，将静态内容（图片、脚本、视频）缓存到更靠近终端用户的位置。减少延迟，提高加载速度，增加可用性。示例：Cloudflare、AWS CloudFront。","pt_BR":"Uma rede geograficamente distribuída de servidores que armazena em cache conteúdo estático (imagens, scripts, vídeos) mais perto dos usuários finais. Reduz latência, melhora tempos de carregamento e aumenta disponibilidade. Exemplos: Cloudflare, AWS CloudFront.","pt_PT":"Uma rede geograficamente distribuída de servidores que armazena em cache conteúdo estático (imagens, scripts, vídeos) mais perto dos utilizadores finais. Reduz latência, melhora tempos de carregamento e aumenta disponibilidade. Exemplos: Cloudflare, AWS CloudFront."}},
  { id: 'dc-technology-0091', deck_id: 'deck-technology', sort_order: 91, front: "Load Balancer", back: "A system distributing network traffic across multiple servers to prevent any single server from becoming a bottleneck. Improves availability and scalability. Algorithms: round-robin, least connections, IP hash." , front_translations: {"es":"Balanceador de Carga (Load Balancer)","it":"Repartitore di charge (Load Balancer)","de":"Load Balancer","fr":"Répartiteur de charge (Load Balancer)","tr":"Yük Dengeleyici (Load Balancer)","nl":"Load Balancer","ru":"Балансировщик нагрузки (Load Balancer)","zh":"负载均衡器（Load Balancer）","pt_BR":"Balanceador de Carga (Load Balancer)","pt_PT":"Balanceador de Carga (Load Balancer)"}, back_translations: {"es":"Un sistema que distribuye tráfego de red entre múltiplos servidores para evitar que un único servidor se torne un gargalo. Melhora disponibilidad y escalabilidad. Algoritmos: round-robin, menos conexiones, hash de IP.","it":"Un sistema distribuant il trafic reseau su plusiori servori per eviter che un seul servore non devienne un goulot d'etranglement. Ameliore la disponibilite e la scalabilite. Algorithmes : round-robin, moindre connexions, hachage IP.","de":"Ein System, das Netzwerkverkehr auf mehrere Server verteilt, um zu verhindern, dass ein einzelner Server zum Engpass wird. Verbessert Verfügbarkeit und Skalierbarkeit. Algorithmen: Round-Robin, wenigste Verbindungen, IP-Hash.","fr":"Un système distribuant le trafic réseau sur plusieurs serveurs pour éviter qu'un seul serveur ne devienne un goulot d'étranglement. Améliore la disponibilité et la scalabilité. Algorithmes : round-robin, moindre connexions, hachage IP.","tr":"Herhangi bir sunucunun darboğaz olmasını önlemek için ağ trafiğini birden fazla sunucuya dağıtan bir sistem. Erişilebilirliği ve ölçeklenebilirliği artırır. Algoritmalar: round-robin, en az bağlantı, IP hash.","nl":"Een systeem dat netwerkverkeer over meerdere servers verdeelt om te voorkomen dat één server een knelpunt wordt. Verbetert beschikbaarheid en schaalbaarheid. Algoritmen: round-robin, minste verbindingen, IP-hash.","ru":"Система, распределяющая сетевой трафик между несколькими серверами, чтобы ни один сервер не стал узким местом. Повышает доступность и масштабируемость. Алгоритмы: round-robin, наименьшее число соединений, IP-хэш.","zh":"将网络流量分配到多台服务器的系统，防止单台服务器成为瓶颈。提高可用性和可扩展性。算法：轮询、最少连接数、IP哈希。","pt_BR":"Um sistema que distribui tráfego de rede entre múltiplos servidores para evitar que um único servidor se torne um gargalo. Melhora disponibilidade e escalabilidade. Algoritmos: round-robin, menos conexões, hash de IP.","pt_PT":"Um sistema que distribui tráfego de rede entre múltiplos servidores para evitar que um único servidor se torne um estrangulamento. Melhora disponibilidade e escalabilidade. Algoritmos: round-robin, menos ligações, hash de IP."}},
  { id: 'dc-technology-0092', deck_id: 'deck-technology', sort_order: 92, front: "Caching (General)", back: "Storing the result of expensive operations to serve future requests faster. Hit: data found in cache. Miss: must fetch from source. Cache invalidation (knowing when data is stale) is the hard problem." , front_translations: {"es":"Cache (Geral)","it":"Mise en cache (General)","de":"Caching (Allgemein)","fr":"Mise en cache (Général)","tr":"Önbellekleme (Genel)","nl":"Caching (Algemeen)","ru":"Кэширование (Общее)","zh":"缓存（通用）","pt_BR":"Cache (Geral)","pt_PT":"Cache (Geral)"}, back_translations: {"es":"Armazenar el resultado de operaciones custosas para atender solicitudes futuras más rápidamente. Hit: datos encontrados en el cache. Miss: devem ser buscados en la fonte. Invalidación de cache (saber cuando los datos están desatualizados) es el problema difícil.","it":"Stocker il resultat d'operazioni couteuses per servir i requetes futures più rapidement. Hit : donnees trouvees in il cache. Miss : doivent etre recuperees della source. L'invalidazione del cache (savoir quando i donnees sono obsoletes) e il probleme difficile.","de":"Speichern des Ergebnisses aufwändiger Operationen, um zukünftige Anfragen schneller zu bedienen. Hit: Daten im Cache gefunden. Miss: müssen von der Quelle geholt werden. Cache-Invalidierung (wissen, wann Daten veraltet sind) ist das schwierige Problem.","fr":"Stocker le résultat d'opérations coûteuses pour servir les requêtes futures plus rapidement. Hit : données trouvées dans le cache. Miss : doivent être récupérées de la source. L'invalidation du cache (savoir quand les données sont obsolètes) est le problème difficile.","tr":"Gelecekteki istekleri daha hızlı karşılamak için pahalı işlemlerin sonuçlarını saklamak. Hit: veri önbellekte bulundu. Miss: kaynaktan getirilmeli. Önbellek geçersizleştirme (verinin ne zaman eskidiğini bilmek) zor problemdir.","nl":"Het opslaan van het resultaat van dure operaties om toekomstige verzoeken sneller te bedienen. Hit: gegevens in cache gevonden. Miss: moeten van bron worden opgehaald. Cache-invalidatie (weten wanneer gegevens verouderd zijn) is het moeilijke probleem.","ru":"Сохранение результатов дорогих операций для более быстрого обслуживания будущих запросов. Hit: данные найдены в кэше. Miss: нужно получить из источника. Инвалидация кэша (знать, когда данные устарели) — это сложная проблема.","zh":"存储昂贵操作的结果以更快地服务后续请求。命中：在缓存中找到数据。未命中：必须从源获取。缓存失效（知道数据何时过期）是困难的问题。","pt_BR":"Armazenar o resultado de operações custosas para atender requisições futuras mais rapidamente. Hit: dados encontrados no cache. Miss: devem ser buscados na fonte. Invalidação de cache (saber quando os dados estão desatualizados) é o problema difícil.","pt_PT":"Armazenar o resultado de operações custosas para servir pedidos futuros mais rapidamente. Hit: dados encontrados na cache. Miss: devem ser obtidos da fonte. Invalidação de cache (saber quando os dados estão desatualizados) é o problema difícil."}},
  { id: 'dc-technology-0093', deck_id: 'deck-technology', sort_order: 93, front: "Encryption: Symmetric vs. Asymmetric", back: "Symmetric: same key for encryption and decryption (AES); fast, used for bulk data. Asymmetric: public/private key pair (RSA, ECC); slower, used for key exchange and digital signatures (TLS handshake uses both)." , front_translations: {"es":"Criptografia: Simétrica vs. Assimétrica","it":"Chiffremento : Symetrico vs. Asymetrico","de":"Verschlüsselung: Symmetrisch vs. Asymmetrisch","fr":"Chiffrement : Symétrique vs. Asymétrique","tr":"Şifreleme: Simetrik vs. Asimetrik","nl":"Encryptie: Symmetrisch vs. Asymmetrisch","ru":"Шифрование: Симметричное vs. Асимметричное","zh":"加密：对称 vs. 非对称","pt_BR":"Criptografia: Simétrica vs. Assimétrica","pt_PT":"Encriptação: Simétrica vs. Assimétrica"}, back_translations: {"es":"Simétrica: misma chave para criptografia y descriptografia (AES); rápida, usada para datos en masa. Assimétrica: par de chaves pública/privada (RSA, ECC); más lenta, usada para troca de chaves y assinaturas digitais (handshake TLS usa ambas).","it":"Symetrico : stesso cle per chiffrement e dechiffrement (AES) ; rapide, per donnees volumineuses. Asymetrico : paire cle publico/privee (RSA, ECC) ; più lent, per echange di cles e signatures numerici (il handshake TLS utilise i deux).","de":"Symmetrisch: gleicher Schlüssel für Ver- und Entschlüsselung (AES); schnell, für große Datenmengen. Asymmetrisch: öffentlicher/privater Schlüssel (RSA, ECC); langsamer, für Schlüsselaustausch und digitale Signaturen (TLS-Handshake nutzt beides).","fr":"Symétrique : même clé pour chiffrement et déchiffrement (AES) ; rapide, pour données volumineuses. Asymétrique : paire clé publique/privée (RSA, ECC) ; plus lent, pour échange de clés et signatures numériques (le handshake TLS utilise les deux).","tr":"Simetrik: şifreleme ve şifre çözme için aynı anahtar (AES); hızlı, toplu veri için kullanılır. Asimetrik: açık/özel anahtar çifti (RSA, ECC); daha yavaş, anahtar değişimi ve dijital imzalar için kullanılır (TLS el sıkışması her ikisini de kullanır).","nl":"Symmetrisch: dezelfde sleutel voor versleuteling en ontsleuteling (AES); snel, voor bulkgegevens. Asymmetrisch: publiek/privaat sleutelpaar (RSA, ECC); trager, voor sleuteluitwisseling en digitale handtekeningen (TLS-handshake gebruikt beide).","ru":"Симметричное: один ключ для шифрования и дешифрования (AES); быстрое, для больших объёмов данных. Асимметричное: пара открытый/закрытый ключ (RSA, ECC); медленнее, для обмена ключами и цифровых подписей (TLS-рукопожатие использует оба).","zh":"对称加密：加密和解密使用同一密钥（AES）；速度快，用于大量数据。非对称加密：公钥/私钥对（RSA、ECC）；较慢，用于密钥交换和数字签名（TLS握手同时使用两者）。","pt_BR":"Simétrica: mesma chave para criptografia e descriptografia (AES); rápida, usada para dados em massa. Assimétrica: par de chaves pública/privada (RSA, ECC); mais lenta, usada para troca de chaves e assinaturas digitais (handshake TLS usa ambas).","pt_PT":"Simétrica: mesma chave para encriptação e desencriptação (AES); rápida, usada para dados em massa. Assimétrica: par de chaves pública/privada (RSA, ECC); mais lenta, usada para troca de chaves e assinaturas digitais (handshake TLS usa ambas)."}},
  { id: 'dc-technology-0094', deck_id: 'deck-technology', sort_order: 94, front: "Hashing (Security)", back: "A one-way function converting input data into a fixed-size digest (hash). Used to verify data integrity and store passwords. Properties: deterministic, fast to compute, collision-resistant. Examples: SHA-256, bcrypt (for passwords)." , front_translations: {"es":"Hashing (Seguridad)","it":"Hachage (Securite)","de":"Hashing (Sicherheit)","fr":"Hachage (Sécurité)","tr":"Hashing (Güvenlik)","nl":"Hashing (Beveiliging)","ru":"Хеширование (Безопасность)","zh":"哈希（安全）","pt_BR":"Hashing (Segurança)","pt_PT":"Hashing (Segurança)"}, back_translations: {"es":"Una función unidirecional que convierte datos de entrada en un resumo de tamaño fixo (hash). Usada para verificar integridad de datos y armazenar contraseñas. Propiedades: determinística, rápida de calcular, resistente a colisões. Ejemplos: SHA-256, bcrypt (para contraseñas).","it":"Una fonczione unidirectionnelle convertissant dei donnees en un condense di taille fixe (hash). Utilisee per verifier l'integrite dei donnees e stocker i mots di passe. Proprietes : deterministe, rapide à calculer, resistante ai collisions. Exemples : SHA-256, bcrypt (per i mots di passe).","de":"Eine Einwegfunktion, die Eingabedaten in einen Digest fester Größe (Hash) umwandelt. Wird zur Überprüfung der Datenintegrität und Speicherung von Passwörtern verwendet. Eigenschaften: deterministisch, schnell berechenbar, kollisionsresistent. Beispiele: SHA-256, bcrypt (für Passwörter).","fr":"Une fonction unidirectionnelle convertissant des données en un condensé de taille fixe (hash). Utilisée pour vérifier l'intégrité des données et stocker les mots de passe. Propriétés : déterministe, rapide à calculer, résistante aux collisions. Exemples : SHA-256, bcrypt (pour les mots de passe).","tr":"Girdi verilerini sabit boyutlu bir özete (hash) dönüştüren tek yönlü fonksiyon. Veri bütünlüğünü doğrulamak ve parolaları saklamak için kullanılır. Özellikler: deterministik, hızlı hesaplanır, çarpışmaya dayanıklı. Örnekler: SHA-256, bcrypt (parolalar için).","nl":"Een eenrichtingsfunctie die invoergegevens omzet in een digest van vaste grootte (hash). Gebruikt om gegevensintegriteit te verifiëren en wachtwoorden op te slaan. Eigenschappen: deterministisch, snel te berekenen, botsingbestendig. Voorbeelden: SHA-256, bcrypt (voor wachtwoorden).","ru":"Односторонняя функция, преобразующая входные данные в дайджест фиксированного размера (хеш). Используется для проверки целостности данных и хранения паролей. Свойства: детерминированная, быстро вычисляемая, устойчивая к коллизиям. Примеры: SHA-256, bcrypt (для паролей).","zh":"一种将输入数据转换为固定大小摘要（哈希）的单向函数。用于验证数据完整性和存储密码。特性：确定性、计算快速、抗碰撞。示例：SHA-256、bcrypt（用于密码）。","pt_BR":"Uma função unidirecional que converte dados de entrada em um resumo de tamanho fixo (hash). Usada para verificar integridade de dados e armazenar senhas. Propriedades: determinística, rápida de calcular, resistente a colisões. Exemplos: SHA-256, bcrypt (para senhas).","pt_PT":"Uma função unidirecional que converte dados de entrada num resumo de tamanho fixo (hash). Usada para verificar integridade de dados e armazenar palavras-passe. Propriedades: determinística, rápida de calcular, resistente a colisões. Exemplos: SHA-256, bcrypt (para palavras-passe)."}},
  { id: 'dc-technology-0095', deck_id: 'deck-technology', sort_order: 95, front: "SQL Injection", back: "A web security vulnerability where user input is included in a SQL query without sanitization, allowing attackers to manipulate the query. Prevented by parameterized queries / prepared statements." , front_translations: {"es":"Injeción de SQL","it":"Injectione SQL","de":"SQL Injection","fr":"Injection SQL","tr":"SQL Injection","nl":"SQL-injectie","ru":"SQL-инъекция","zh":"SQL注入","pt_BR":"Injeção de SQL","pt_PT":"Injeção de SQL"}, back_translations: {"es":"Una vulnerabilidad de seguridad web donde a entrada del usuario es incluída en una consulta SQL sin sanitización, permitiendo que atacantes manipulem a consulta. Prevenida por consultas parametrizadas / prepared statements.","it":"Una vulnerabilite di securite web où l'entree utilisatore e incluse in una requete SQL senza assainissement, permettant ai attaquants di manipuler la requete. Prevenue per dei requetes parametrees / instruczioni preperees.","de":"Eine Web-Sicherheitslücke, bei der Benutzereingaben ohne Bereinigung in eine SQL-Abfrage eingebunden werden, wodurch Angreifer die Abfrage manipulieren können. Verhindert durch parametrisierte Abfragen / Prepared Statements.","fr":"Une vulnérabilité de sécurité web où l'entrée utilisateur est incluse dans une requête SQL sans assainissement, permettant aux attaquants de manipuler la requête. Prévenue par des requêtes paramétrées / instructions préparées.","tr":"Kullanıcı girdisinin temizlenmeden bir SQL sorgusuna dahil edildiği, saldırganların sorguyu manipüle etmesine olanak tanıyan bir web güvenlik açığı. Parametreli sorgular / hazırlanmış ifadeler ile önlenir.","nl":"Een webbeveiligingskwetsbaarheid waarbij gebruikersinvoer zonder sanitisatie in een SQL-query wordt opgenomen, waardoor aanvallers de query kunnen manipuleren. Voorkomen door geparametriseerde query's / prepared statements.","ru":"Уязвимость веб-безопасности, при которой пользовательский ввод включается в SQL-запрос без очистки, позволяя злоумышленникам манипулировать запросом. Предотвращается параметризованными запросами / подготовленными выражениями.","zh":"一种Web安全漏洞，用户输入未经清理就被包含在SQL查询中，允许攻击者操纵查询。通过参数化查询/预编译语句来防御。","pt_BR":"Uma vulnerabilidade de segurança web onde a entrada do usuário é incluída em uma consulta SQL sem sanitização, permitindo que atacantes manipulem a consulta. Prevenida por consultas parametrizadas / prepared statements.","pt_PT":"Uma vulnerabilidade de segurança web onde a entrada do utilizador é incluída numa consulta SQL sem sanitização, permitindo que atacantes manipulem a consulta. Prevenida por consultas parametrizadas / prepared statements."}},
  { id: 'dc-technology-0096', deck_id: 'deck-technology', sort_order: 96, front: "XSS — Cross-Site Scripting", back: "A web attack injecting malicious scripts into web pages viewed by other users. Reflected XSS: from user input. Stored XSS: persisted in the database. Prevented by escaping output and Content Security Policy (CSP)." , front_translations: {"es":"XSS — Cross-Site Scripting","it":"XSS — Crossos-Site Scripting","de":"XSS — Cross-Site Scripting","fr":"XSS — Cross-Site Scripting","tr":"XSS — Siteler Arası Betik Çalıştırma","nl":"XSS — Cross-Site Scripting","ru":"XSS — Межсайтовый скриптинг","zh":"XSS — 跨站脚本攻击","pt_BR":"XSS — Cross-Site Scripting","pt_PT":"XSS — Cross-Site Scripting"}, back_translations: {"es":"Un ataque web que injeta scripts maliciosos en páginas web visualizadas por outros usuarios. XSS refletido: a partir de la entrada del usuario. XSS almacenado: persistido en el base de datos. Prevenido por escape de saída y Content Security Policy (CSP).","it":"Una attaque web injectant dei scripts malveillants in dei pages web vues per d'autres utilisatori. XSS reflechi : à partir dell'entree utilisatore. XSS stocke : persiste in la base di donnees. Prevenu per l'echappement della sortie e la Content Security Policy (CSP).","de":"Ein Webangriff, der bösartige Skripte in Webseiten einschleust, die andere Benutzer sehen. Reflected XSS: aus Benutzereingaben. Stored XSS: in der Datenbank gespeichert. Verhindert durch Output-Escaping und Content Security Policy (CSP).","fr":"Une attaque web injectant des scripts malveillants dans des pages web vues par d'autres utilisateurs. XSS réfléchi : à partir de l'entrée utilisateur. XSS stocké : persisté dans la base de données. Prévenu par l'échappement de la sortie et la Content Security Policy (CSP).","tr":"Diğer kullanıcılar tarafından görüntülenen web sayfalarına kötü amaçlı betikler enjekte eden bir web saldırısı. Reflected XSS: kullanıcı girdisinden. Stored XSS: veritabanında kalıcı. Çıktı kaçışlama ve Content Security Policy (CSP) ile önlenir.","nl":"Een webaanval die kwaadaardige scripts injecteert in webpagina's die door andere gebruikers worden bekeken. Reflected XSS: vanuit gebruikersinvoer. Stored XSS: opgeslagen in de database. Voorkomen door output-escaping en Content Security Policy (CSP).","ru":"Веб-атака, внедряющая вредоносные скрипты в веб-страницы, просматриваемые другими пользователями. Отражённый XSS: из пользовательского ввода. Хранимый XSS: сохраняется в базе данных. Предотвращается экранированием вывода и Content Security Policy (CSP).","zh":"一种向其他用户查看的网页注入恶意脚本的Web攻击。反射型XSS：来自用户输入。存储型XSS：持久化在数据库中。通过转义输出和内容安全策略（CSP）来防御。","pt_BR":"Um ataque web que injeta scripts maliciosos em páginas web visualizadas por outros usuários. XSS refletido: a partir da entrada do usuário. XSS armazenado: persistido no banco de dados. Prevenido por escape de saída e Content Security Policy (CSP).","pt_PT":"Um ataque web que injeta scripts maliciosos em páginas web visualizadas por outros utilizadores. XSS refletido: a partir da entrada do utilizador. XSS armazenado: persistido na base de dados. Prevenido por escape de saída e Content Security Policy (CSP)."}},
  { id: 'dc-technology-0097', deck_id: 'deck-technology', sort_order: 97, front: "CSRF — Cross-Site Request Forgery", back: "An attack tricking an authenticated user into unknowingly submitting a malicious request. Prevented by CSRF tokens (unique, unpredictable value validated on the server), SameSite cookie attribute." , front_translations: {"es":"CSRF — Falsificación de Solicitud entre Sites","it":"CSRF — Falsificatione di requete intersites","de":"CSRF — Cross-Site Request Forgery","fr":"CSRF — Falsification de requête intersites","tr":"CSRF — Siteler Arası İstek Sahteciliği","nl":"CSRF — Cross-Site Request Forgery","ru":"CSRF — Межсайтовая подделка запроса","zh":"CSRF — 跨站请求伪造","pt_BR":"CSRF — Falsificação de Requisição entre Sites","pt_PT":"CSRF — Falsificação de Pedido entre Sites"}, back_translations: {"es":"Un ataque que engana un usuario autenticado para enviar involuntariamente una solicitud maliciosa. Prevenido por tokens CSRF (valor único y imprevisible validado en el servidor), atributo de cookie SameSite.","it":"Una attaque trompant un utilisatore authentifie per che il soumette al suo insu una requete malveillante. Prevenue per dei jetons CSRF (valore unico e imprevisible validee su il servore), attribut di cookie SameSite.","de":"Ein Angriff, der einen authentifizierten Benutzer dazu bringt, unwissentlich eine bösartige Anfrage zu senden. Verhindert durch CSRF-Tokens (einzigartiger, unvorhersehbarer Wert, der serverseitig validiert wird), SameSite-Cookie-Attribut.","fr":"Une attaque trompant un utilisateur authentifié pour qu'il soumette à son insu une requête malveillante. Prévenue par des jetons CSRF (valeur unique et imprévisible validée sur le serveur), attribut de cookie SameSite.","tr":"Kimliği doğrulanmış bir kullanıcıyı bilmeden kötü amaçlı bir istek göndermeye kandıran bir saldırı. CSRF token'ları (sunucuda doğrulanan benzersiz, tahmin edilemez değer) ve SameSite çerez özniteliği ile önlenir.","nl":"Een aanval die een geauthenticeerde gebruiker misleidt om onbewust een kwaadaardig verzoek in te dienen. Voorkomen door CSRF-tokens (unieke, onvoorspelbare waarde gevalideerd op de server), SameSite-cookie-attribuut.","ru":"Атака, обманом заставляющая аутентифицированного пользователя неосознанно отправить вредоносный запрос. Предотвращается CSRF-токенами (уникальное, непредсказуемое значение, проверяемое на сервере), атрибутом cookie SameSite.","zh":"一种欺骗经过身份验证的用户在不知情的情况下提交恶意请求的攻击。通过CSRF令牌（在服务器端验证的唯一、不可预测的值）和SameSite cookie属性来防御。","pt_BR":"Um ataque que engana um usuário autenticado para enviar involuntariamente uma requisição maliciosa. Prevenido por tokens CSRF (valor único e imprevisível validado no servidor), atributo de cookie SameSite.","pt_PT":"Um ataque que engana um utilizador autenticado para enviar involuntariamente um pedido malicioso. Prevenido por tokens CSRF (valor único e imprevisível validado no servidor), atributo de cookie SameSite."}},
  { id: 'dc-technology-0098', deck_id: 'deck-technology', sort_order: 98, front: "Two's Complement", back: "The standard method for representing signed integers in binary. Negative numbers are the bitwise complement plus 1. This allows the same addition/subtraction circuits to work for both positive and negative numbers." , front_translations: {"es":"Complemento de Dos","it":"Complement à doso","de":"Zweierkomplement","fr":"Complément à deux","tr":"İkiye Tümleyen","nl":"Twee-complement","ru":"Дополнительный код (Two's Complement)","zh":"二进制补码","pt_BR":"Complemento de Dois","pt_PT":"Complemento para Dois"}, back_translations: {"es":"El método padrão para representar interos con señal en binário. Números negativos son el complemento bit a bit más 1. Isso permite que los mismos circuitos de adición/subtración funcionem tanto para números positivos quanto negativos.","it":"La methode standard per representer i entiers signes en binaire. I nombres negatifs sono il complement bit à bit più 1. Cela permette ai memes circuits d'addizione/soustraczione di fonctionner per i nombres positifs e negatifs.","de":"Die Standardmethode zur Darstellung vorzeichenbehafteter Ganzzahlen in Binärform. Negative Zahlen sind das bitweise Komplement plus 1. Dies ermöglicht, dass dieselben Additions-/Subtraktionsschaltungen für positive und negative Zahlen funktionieren.","fr":"La méthode standard pour représenter les entiers signés en binaire. Les nombres négatifs sont le complément bit à bit plus 1. Cela permet aux mêmes circuits d'addition/soustraction de fonctionner pour les nombres positifs et négatifs.","tr":"İşaretli tam sayıları ikili sistemde temsil etmenin standart yöntemi. Negatif sayılar, bitsel tümleyenin bir fazlasıdır. Bu, aynı toplama/çıkarma devrelerinin hem pozitif hem negatif sayılar için çalışmasını sağlar.","nl":"De standaardmethode voor het weergeven van signed integers in binair. Negatieve getallen zijn het bitsgewijze complement plus 1. Dit maakt het mogelijk dat dezelfde optelling/aftrekkingscircuits werken voor zowel positieve als negatieve getallen.","ru":"Стандартный метод представления целых чисел со знаком в двоичном виде. Отрицательные числа — это побитовое дополнение плюс 1. Это позволяет одним и тем же схемам сложения/вычитания работать как с положительными, так и с отрицательными числами.","zh":"用二进制表示有符号整数的标准方法。负数是按位取反加1。这使得相同的加法/减法电路可以同时处理正数和负数。","pt_BR":"O método padrão para representar inteiros com sinal em binário. Números negativos são o complemento bit a bit mais 1. Isso permite que os mesmos circuitos de adição/subtração funcionem tanto para números positivos quanto negativos.","pt_PT":"O método padrão para representar inteiros com sinal em binário. Números negativos são o complemento bit a bit mais 1. Isto permite que os mesmos circuitos de adição/subtração funcionem tanto para números positivos como negativos."}},
  { id: 'dc-technology-0099', deck_id: 'deck-technology', sort_order: 99, front: "Bitwise Operations", back: "Operations directly on binary representations: AND (&), OR (|), XOR (^), NOT (~), left shift (<<), right shift (>>). Used for performance optimization, flags, and low-level hardware programming." , front_translations: {"es":"Operaciones Bit a Bit","it":"Operationes bit à bit","de":"Bitweise Operationen","fr":"Opérations bit à bit","tr":"Bit Düzeyinde İşlemler","nl":"Bitgewijze bewerkingen","ru":"Побитовые операции","zh":"位运算","pt_BR":"Operações Bit a Bit","pt_PT":"Operações Bit a Bit"}, back_translations: {"es":"Operaciones directamente en representaciones binárias: AND (&), OR (|), XOR (^), NOT (~), deslocamento a la esquerda (<<), deslocamento a la direita (>>). Usadas para otimización de rendimiento, flags y programación de hardware de bajo nivel.","it":"Operazioni directement su i representazioni binaires : AND (&), OR (|), XOR (^), NOT (~), decalage à gauche (<<), decalage à droite (>>). Utilisees per l'optimisazione dei performanze, i drapeaux e la programmazione materielle bas niveau.","de":"Operationen direkt auf Binärdarstellungen: AND (&), OR (|), XOR (^), NOT (~), Linksverschiebung (<<), Rechtsverschiebung (>>). Verwendet für Leistungsoptimierung, Flags und hardwarenahe Programmierung.","fr":"Opérations directement sur les représentations binaires : AND (&), OR (|), XOR (^), NOT (~), décalage à gauche (<<), décalage à droite (>>). Utilisées pour l'optimisation des performances, les drapeaux et la programmation matérielle bas niveau.","tr":"Doğrudan ikili gösterimler üzerinde yapılan işlemler: AND (&), OR (|), XOR (^), NOT (~), sola kaydırma (<<), sağa kaydırma (>>). Performans optimizasyonu, bayraklar ve düşük seviyeli donanım programlama için kullanılır.","nl":"Bewerkingen direct op binaire representaties: AND (&), OR (|), XOR (^), NOT (~), links verschuiven (<<), rechts verschuiven (>>). Gebruikt voor prestatie-optimalisatie, flags en low-level hardwareprogrammering.","ru":"Операции непосредственно над двоичными представлениями: AND (&), OR (|), XOR (^), NOT (~), сдвиг влево (<<), сдвиг вправо (>>). Используются для оптимизации производительности, флагов и низкоуровневого программирования.","zh":"直接对二进制表示进行的操作：AND（&）、OR（|）、XOR（^）、NOT（~）、左移（<<）、右移（>>）。用于性能优化、标志位和底层硬件编程。","pt_BR":"Operações diretamente em representações binárias: AND (&), OR (|), XOR (^), NOT (~), deslocamento à esquerda (<<), deslocamento à direita (>>). Usadas para otimização de desempenho, flags e programação de hardware de baixo nível.","pt_PT":"Operações diretamente em representações binárias: AND (&), OR (|), XOR (^), NOT (~), deslocamento à esquerda (<<), deslocamento à direita (>>). Usadas para otimização de desempenho, flags e programação de hardware de baixo nível."}},
  { id: 'dc-technology-0100', deck_id: 'deck-technology', sort_order: 100, front: "Floating Point Representation (IEEE 754)", back: "Standard for representing real numbers in binary: sign bit, exponent, and mantissa. 32-bit (float) and 64-bit (double). Precision is limited; 0.1 + 0.2 ≠ 0.3 in floating point arithmetic." , front_translations: {"es":"Representación de Punto Flutuante (IEEE 754)","it":"Representatione en virgule flottante (IEEE 754)","de":"Gleitkommadarstellung (IEEE 754)","fr":"Représentation en virgule flottante (IEEE 754)","tr":"Kayan Nokta Gösterimi (IEEE 754)","nl":"Drijvende-kommarepresentatie (IEEE 754)","ru":"Представление чисел с плавающей запятой (IEEE 754)","zh":"浮点数表示（IEEE 754）","pt_BR":"Representação de Ponto Flutuante (IEEE 754)","pt_PT":"Representação de Vírgula Flutuante (IEEE 754)"}, back_translations: {"es":"Padrão para representar números reais en binário: bit de señal, exponente y mantissa. 32 bits (float) y 64 bits (double). La precisão es limitada; 0,1 + 0,2 ≠ 0,3 en aritmética de punto flutuante.","it":"Norme per representer i nombres reels en binaire : bit di signe, exposant e mantisse. 32 bits (float) e 64 bits (double). La precision e limitee ; 0,1 + 0,2 ≠ 0,3 en arithmetico à virgule flottante.","de":"Standard zur Darstellung reeller Zahlen in Binärform: Vorzeichenbit, Exponent und Mantisse. 32-Bit (float) und 64-Bit (double). Die Genauigkeit ist begrenzt; 0,1 + 0,2 ≠ 0,3 in Gleitkomma-Arithmetik.","fr":"Norme pour représenter les nombres réels en binaire : bit de signe, exposant et mantisse. 32 bits (float) et 64 bits (double). La précision est limitée ; 0,1 + 0,2 ≠ 0,3 en arithmétique à virgule flottante.","tr":"Gerçek sayıları ikili sistemde temsil etme standardı: işaret biti, üs ve mantis. 32-bit (float) ve 64-bit (double). Hassasiyet sınırlıdır; kayan nokta aritmetiğinde 0,1 + 0,2 ≠ 0,3.","nl":"Standaard voor het weergeven van reële getallen in binair: tekenbit, exponent en mantisse. 32-bit (float) en 64-bit (double). Precisie is beperkt; 0,1 + 0,2 ≠ 0,3 in drijvende-komma-rekenkunde.","ru":"Стандарт представления вещественных чисел в двоичном виде: знаковый бит, экспонента и мантисса. 32-бит (float) и 64-бит (double). Точность ограничена; 0,1 + 0,2 ≠ 0,3 в арифметике с плавающей запятой.","zh":"用二进制表示实数的标准：符号位、指数和尾数。32位（float）和64位（double）。精度有限；在浮点运算中 0.1 + 0.2 ≠ 0.3。","pt_BR":"Padrão para representar números reais em binário: bit de sinal, expoente e mantissa. 32 bits (float) e 64 bits (double). A precisão é limitada; 0,1 + 0,2 ≠ 0,3 em aritmética de ponto flutuante.","pt_PT":"Padrão para representar números reais em binário: bit de sinal, expoente e mantissa. 32 bits (float) e 64 bits (double). A precisão é limitada; 0,1 + 0,2 ≠ 0,3 em aritmética de vírgula flutuante."}},
  { id: 'dc-technology-0101', deck_id: 'deck-technology', sort_order: 101, front: "NP-Completeness", back: "A class of decision problems for which no known polynomial-time algorithm exists. If any NP-complete problem can be solved in polynomial time, all NP problems can (P=NP). Examples: SAT, traveling salesman, graph coloring." , front_translations: {"es":"NP-Completude","it":"NP-Completude","de":"NP-Vollständigkeit","fr":"NP-Complétude","tr":"NP-Tamlık","nl":"NP-Volledigheid","ru":"NP-полнота","zh":"NP完全性","pt_BR":"NP-Completude","pt_PT":"NP-Completude"}, back_translations: {"es":"Una clase de problemas de decisão para los quais ningún algoritmo de tiempo polinomial es conocido. Se cualquier problema NP-completo puder ser resolvido en tiempo polinomial, todos los problemas NP pueden (P=NP). Ejemplos: SAT, caixero-viajante, coloración de grafos.","it":"Una classe di problemes di decision per laquelle aucun algorithme en temps polynomial n'e conosciuto. Si un probleme NP-complet può etre resolu en temps polynomial, tutti i problemes NP il possono (P=NP). Exemples : SAT, voyagore di commerce, colorazione di graphe.","de":"Eine Klasse von Entscheidungsproblemen, für die kein polynomialer Algorithmus bekannt ist. Wenn ein NP-vollständiges Problem in Polynomialzeit gelöst werden kann, können alle NP-Probleme gelöst werden (P=NP). Beispiele: SAT, Traveling Salesman, Graphfärbung.","fr":"Une classe de problèmes de décision pour laquelle aucun algorithme en temps polynomial n'est connu. Si un problème NP-complet peut être résolu en temps polynomial, tous les problèmes NP le peuvent (P=NP). Exemples : SAT, voyageur de commerce, coloration de graphe.","tr":"Bilinen polinom zamanlı algoritması olmayan bir karar problemleri sınıfı. Herhangi bir NP-tam problem polinom zamanda çözülebilirse, tüm NP problemleri çözülebilir (P=NP). Örnekler: SAT, gezgin satıcı, graf renklendirme.","nl":"Een klasse van beslissingsproblemen waarvoor geen polynomiaal algoritme bekend is. Als een NP-volledig probleem in polynomiale tijd kan worden opgelost, kunnen alle NP-problemen dat ook (P=NP). Voorbeelden: SAT, handelsreizigerprobleem, grafkleuring.","ru":"Класс задач принятия решений, для которых не известен алгоритм с полиномиальным временем. Если любая NP-полная задача может быть решена за полиномиальное время, то все NP-задачи тоже (P=NP). Примеры: SAT, задача коммивояжёра, раскраска графа.","zh":"一类目前没有已知多项式时间算法的判定问题。如果任何一个NP完全问题可以在多项式时间内解决，则所有NP问题都可以（P=NP）。例如：SAT、旅行商问题、图着色。","pt_BR":"Uma classe de problemas de decisão para os quais nenhum algoritmo de tempo polinomial é conhecido. Se qualquer problema NP-completo puder ser resolvido em tempo polinomial, todos os problemas NP podem (P=NP). Exemplos: SAT, caixeiro-viajante, coloração de grafos.","pt_PT":"Uma classe de problemas de decisão para os quais não se conhece nenhum algoritmo de tempo polinomial. Se qualquer problema NP-completo puder ser resolvido em tempo polinomial, todos os problemas NP podem (P=NP). Exemplos: SAT, caixeiro-viajante, coloração de grafos."}},
  { id: 'dc-technology-0102', deck_id: 'deck-technology', sort_order: 102, front: "P vs. NP Problem", back: "One of the Millennium Prize Problems. P: problems solvable in polynomial time. NP: problems whose solutions can be verified in polynomial time. The question is whether P = NP (most believe P ≠ NP)." , front_translations: {"es":"Problema P vs. NP","it":"Probleme P vs. NP","de":"P-gegen-NP-Problem","fr":"Problème P vs. NP","tr":"P vs. NP Problemi","nl":"P vs. NP-probleem","ru":"Проблема P и NP","zh":"P与NP问题","pt_BR":"Problema P vs. NP","pt_PT":"Problema P vs. NP"}, back_translations: {"es":"Un de los Problemas del Premio del Milenio. P: problemas solucionables en tiempo polinomial. NP: problemas cujas soluciones pueden ser verificadas en tiempo polinomial. La cuestión es se P = NP (a maioria acredita que P ≠ NP).","it":"L'un dei problemes del prix del millenaire. P : problemes resolubles en temps polynomial. NP : problemes di cui i soluzioni sono verifiables en temps polynomial. La queszione e di savoir se P = NP (la plupart pensent che P ≠ NP).","de":"Eines der Millenniumsprobleme. P: Probleme, die in Polynomialzeit lösbar sind. NP: Probleme, deren Lösungen in Polynomialzeit überprüfbar sind. Die Frage ist, ob P = NP (die meisten glauben P ≠ NP).","fr":"L'un des problèmes du prix du millénaire. P : problèmes résolubles en temps polynomial. NP : problèmes dont les solutions sont vérifiables en temps polynomial. La question est de savoir si P = NP (la plupart pensent que P ≠ NP).","tr":"Milenyum Ödül Problemlerinden biri. P: polinom zamanda çözülebilen problemler. NP: çözümleri polinom zamanda doğrulanabilen problemler. Soru, P = NP olup olmadığıdır (çoğu kişi P ≠ NP olduğuna inanır).","nl":"Een van de Millenniumprijsproblemen. P: problemen oplosbaar in polynomiale tijd. NP: problemen waarvan oplossingen verifieerbaar zijn in polynomiale tijd. De vraag is of P = NP (de meesten geloven P ≠ NP).","ru":"Одна из задач тысячелетия. P: задачи, решаемые за полиномиальное время. NP: задачи, решения которых проверяемы за полиномиальное время. Вопрос в том, верно ли P = NP (большинство считает, что P ≠ NP).","zh":"千禧年大奖难题之一。P：可在多项式时间内求解的问题。NP：解可在多项式时间内验证的问题。问题是P是否等于NP（大多数人认为P ≠ NP）。","pt_BR":"Um dos Problemas do Prêmio do Milênio. P: problemas solucionáveis em tempo polinomial. NP: problemas cujas soluções podem ser verificadas em tempo polinomial. A questão é se P = NP (a maioria acredita que P ≠ NP).","pt_PT":"Um dos Problemas do Prémio do Milénio. P: problemas resolúveis em tempo polinomial. NP: problemas cujas soluções podem ser verificadas em tempo polinomial. A questão é se P = NP (a maioria acredita que P ≠ NP)."}},
  { id: 'dc-technology-0103', deck_id: 'deck-technology', sort_order: 103, front: "Topological Sort", back: "A linear ordering of vertices in a DAG (directed acyclic graph) such that for every directed edge (u → v), u comes before v. Used for dependency resolution, build systems, and task scheduling. Implemented via DFS or Kahn's algorithm." , front_translations: {"es":"Ordenación Topológica","it":"Tri topologico","de":"Topologische Sortierung","fr":"Tri topologique","tr":"Topolojik Sıralama","nl":"Topologische sortering","ru":"Топологическая сортировка","zh":"拓扑排序","pt_BR":"Ordenação Topológica","pt_PT":"Ordenação Topológica"}, back_translations: {"es":"Una ordenación linear de los vértices en un DAG (grafo acíclico direcionado) tal que, para cada aresta direcionada (u → v), u vem antes de v. Usada para resolución de dependencias, sistemas de build y agendamento de tarefas. Implementada via DFS o algoritmo de Kahn.","it":"Un ordonnancement lineaire dei sommets di un DAG (graphe oriente acyclico) tel che per ogni arete orientee (u → v), u precedi v. Utilise per la resoluzione di dependanze, i sistemi di build e la planificazione di tâches. Implemente via DFS o l'algorithme di Kahn.","de":"Eine lineare Anordnung von Knoten in einem DAG (gerichteter azyklischer Graph), sodass für jede gerichtete Kante (u → v) u vor v kommt. Verwendet für Abhängigkeitsauflösung, Build-Systeme und Aufgabenplanung. Implementiert über DFS oder Kahns Algorithmus.","fr":"Un ordonnancement linéaire des sommets d'un DAG (graphe orienté acyclique) tel que pour chaque arête orientée (u → v), u précède v. Utilisé pour la résolution de dépendances, les systèmes de build et la planification de tâches. Implémenté via DFS ou l'algorithme de Kahn.","tr":"Bir DAG'daki (yönlü çevrimsiz graf) düğümlerin, her yönlü kenar (u → v) için u'nun v'den önce geldiği doğrusal bir sıralaması. Bağımlılık çözümleme, derleme sistemleri ve görev zamanlama için kullanılır. DFS veya Kahn algoritması ile uygulanır.","nl":"Een lineaire ordening van hoekpunten in een DAG (gerichte acyclische graaf) zodat voor elke gerichte kant (u → v) u vóór v komt. Gebruikt voor afhankelijkheidsresolutie, buildsystemen en taakplanning. Geïmplementeerd via DFS of Kahns algoritme.","ru":"Линейное упорядочение вершин в DAG (направленном ациклическом графе) такое, что для каждого ребра (u → v) вершина u идёт перед v. Используется для разрешения зависимостей, систем сборки и планирования задач. Реализуется через DFS или алгоритм Кана.","zh":"DAG（有向无环图）中顶点的线性排序，使得对于每条有向边(u → v)，u排在v之前。用于依赖解析、构建系统和任务调度。通过DFS或Kahn算法实现。","pt_BR":"Uma ordenação linear dos vértices em um DAG (grafo acíclico direcionado) tal que, para cada aresta direcionada (u → v), u vem antes de v. Usada para resolução de dependências, sistemas de build e agendamento de tarefas. Implementada via DFS ou algoritmo de Kahn.","pt_PT":"Uma ordenação linear dos vértices num DAG (grafo acíclico direcionado) tal que, para cada aresta direcionada (u → v), u vem antes de v. Usada para resolução de dependências, sistemas de build e agendamento de tarefas. Implementada via DFS ou algoritmo de Kahn."}},
  { id: 'dc-technology-0104', deck_id: 'deck-technology', sort_order: 104, front: "Minimum Spanning Tree (MST)", back: "A subset of edges in a weighted undirected graph that connects all vertices with the minimum total edge weight and no cycles. Algorithms: Kruskal's (greedy, sort edges) and Prim's (greedy, grow from a vertex)." , front_translations: {"es":"Árvore Geradora Mínima (MST)","it":"Arbre couvrant di poids minimum (MST)","de":"Minimaler Spannbaum (MST)","fr":"Arbre couvrant de poids minimum (MST)","tr":"Minimum Kapsayan Ağaç (MST)","nl":"Minimale opspannende boom (MST)","ru":"Минимальное остовное дерево (MST)","zh":"最小生成树 (MST)","pt_BR":"Árvore Geradora Mínima (MST)","pt_PT":"Árvore Geradora Mínima (MST)"}, back_translations: {"es":"Un subconjunto de arestas en un grafo no direcionado ponderado que conecta todos los vértices con el peso total mínimo y sin ciclos. Algoritmos: Kruskal (guloso, ordenar arestas) y Prim (guloso, crescer a partir de un vértice).","it":"Un sotto-ensemble d'aretes in un graphe non oriente pondere che connecte tutti i sommets con il poids total minimal e senza cycles. Algorithmes : Kruskal (glouton, tri dei aretes) e Prim (glouton, croissanza à partir di un sommet).","de":"Eine Teilmenge von Kanten in einem gewichteten ungerichteten Graphen, die alle Knoten mit dem minimalen Gesamtkantengewicht ohne Zyklen verbindet. Algorithmen: Kruskal (greedy, Kanten sortieren) und Prim (greedy, von einem Knoten wachsen).","fr":"Un sous-ensemble d'arêtes dans un graphe non orienté pondéré qui connecte tous les sommets avec le poids total minimal et sans cycles. Algorithmes : Kruskal (glouton, tri des arêtes) et Prim (glouton, croissance à partir d'un sommet).","tr":"Ağırlıklı yönsüz bir graftaki tüm düğümleri döngü olmadan minimum toplam kenar ağırlığıyla birbirine bağlayan kenar alt kümesi. Algoritmalar: Kruskal (açgözlü, kenarları sırala) ve Prim (açgözlü, bir düğümden büyü).","nl":"Een deelverzameling van kanten in een gewogen ongerichte graaf die alle hoekpunten verbindt met het minimale totale kantgewicht en zonder cycli. Algoritmen: Kruskal (greedy, kanten sorteren) en Prim (greedy, groeien vanaf een hoekpunt).","ru":"Подмножество рёбер во взвешенном неориентированном графе, соединяющее все вершины с минимальным суммарным весом без циклов. Алгоритмы: Краскала (жадный, сортировка рёбер) и Прима (жадный, рост от вершины).","zh":"加权无向图中连接所有顶点的边的子集，具有最小总边权且无环。算法：Kruskal（贪心，排序边）和Prim（贪心，从一个顶点生长）。","pt_BR":"Um subconjunto de arestas em um grafo não direcionado ponderado que conecta todos os vértices com o peso total mínimo e sem ciclos. Algoritmos: Kruskal (guloso, ordenar arestas) e Prim (guloso, crescer a partir de um vértice).","pt_PT":"Um subconjunto de arestas num grafo não direcionado ponderado que conecta todos os vértices com o peso total mínimo e sem ciclos. Algoritmos: Kruskal (guloso, ordenar arestas) e Prim (guloso, crescer a partir de um vértice)."}},
  { id: 'dc-technology-0105', deck_id: 'deck-technology', sort_order: 105, front: "Amortized Analysis", back: "Analysis of the average performance of an operation over a sequence of operations, even if individual operations are sometimes expensive. Example: dynamic array doubling is O(1) amortized despite O(n) occasional copies." , front_translations: {"es":"Análise Amortizada","it":"Analisi amortie","de":"Amortisierte Analyse","fr":"Analyse amortie","tr":"Amortize Analiz","nl":"Geamortiseerde analyse","ru":"Амортизированный анализ","zh":"摊还分析","pt_BR":"Análise Amortizada","pt_PT":"Análise Amortizada"}, back_translations: {"es":"Análise del rendimiento médio de una operación a lo ancho de una secuencia de operaciones, mismo que operaciones individuais sejam a las veces custosas. Ejemplo: duplicación de array dinámico es El(1) amortizado, apesar de cópias El(n) ocasionais.","it":"Analisi della performanza moyenne d'una operazione su una sequenza d'operazioni, stesso se certaines operazioni individuelles sono parfois couteuses. Exemple : il doublage di un tableau dynamico e O(1) amorti malgre dei copies O(n) occasionnelles.","de":"Analyse der durchschnittlichen Leistung einer Operation über eine Folge von Operationen, auch wenn einzelne Operationen manchmal teuer sind. Beispiel: Verdopplung eines dynamischen Arrays ist amortisiert O(1), trotz gelegentlicher O(n)-Kopien.","fr":"Analyse de la performance moyenne d'une opération sur une séquence d'opérations, même si certaines opérations individuelles sont parfois coûteuses. Exemple : le doublage d'un tableau dynamique est O(1) amorti malgré des copies O(n) occasionnelles.","tr":"Bir işlem dizisi boyunca bir işlemin ortalama performansının analizi; bireysel işlemler bazen pahalı olsa bile. Örnek: dinamik dizi ikiye katlama, ara sıra O(n) kopyalara rağmen amortize O(1)'dir.","nl":"Analyse van de gemiddelde prestatie van een operatie over een reeks operaties, zelfs als individuele operaties soms duur zijn. Voorbeeld: het verdubbelen van een dynamische array is geamortiseerd O(1) ondanks incidentele O(n)-kopieën.","ru":"Анализ средней производительности операции на последовательности операций, даже если отдельные операции иногда дорогие. Пример: удвоение динамического массива — O(1) амортизированно, несмотря на редкие копирования O(n).","zh":"对一系列操作中单个操作的平均性能的分析，即使个别操作有时代价昂贵。例如：动态数组的倍增操作摊还后为O(1)，尽管偶尔需要O(n)次拷贝。","pt_BR":"Análise do desempenho médio de uma operação ao longo de uma sequência de operações, mesmo que operações individuais sejam às vezes custosas. Exemplo: duplicação de array dinâmico é O(1) amortizado, apesar de cópias O(n) ocasionais.","pt_PT":"Análise do desempenho médio de uma operação ao longo de uma sequência de operações, mesmo que operações individuais sejam por vezes dispendiosas. Exemplo: duplicação de array dinâmico é O(1) amortizado, apesar de cópias O(n) ocasionais."}},
  { id: 'dc-technology-0106', deck_id: 'deck-technology', sort_order: 106, front: "Concurrency vs. Parallelism", back: "Concurrency: multiple tasks make progress by interleaving (e.g., single-core with context switches). Parallelism: multiple tasks execute simultaneously (multi-core). Concurrency is about structure; parallelism is about execution." , front_translations: {"es":"Competencia vs. Paralelismo","it":"Concurrenza vs. Parallelisme","de":"Nebenläufigkeit vs. Parallelität","fr":"Concurrence vs. Parallélisme","tr":"Eşzamanlılık vs. Paralellik","nl":"Concurrency vs. Parallellisme","ru":"Конкурентность и параллелизм","zh":"并发与并行","pt_BR":"Concorrência vs. Paralelismo","pt_PT":"Concorrência vs. Paralelismo"}, back_translations: {"es":"Competencia: múltiplas tarefas progridem por intercalación (ex.: núcleo único con troca de contexto). Paralelismo: múltiplas tarefas executam simultáneamente (multi-core). Competencia es sobre estructura; paralelismo es sobre execución.","it":"Concurrenza : plusiori tâches progressent en s'entrelacant (ex. monocœur con changements di contexte). Parallelisme : plusiori tâches s'executent simultanement (multicœur). La concurrenza concerne la structure ; il parallelisme concerne l'execuzione.","de":"Nebenläufigkeit: Mehrere Aufgaben machen Fortschritt durch Verschachtelung (z. B. Einzelkern mit Kontextwechsel). Parallelität: Mehrere Aufgaben werden gleichzeitig ausgeführt (Mehrkern). Nebenläufigkeit betrifft Struktur; Parallelität betrifft Ausführung.","fr":"Concurrence : plusieurs tâches progressent en s'entrelacant (ex. monocœur avec changements de contexte). Parallélisme : plusieurs tâches s'exécutent simultanément (multicœur). La concurrence concerne la structure ; le parallélisme concerne l'exécution.","tr":"Eşzamanlılık: birden fazla görev araya girerek ilerleme kaydeder (ör. bağlam değiştirmeli tek çekirdek). Paralellik: birden fazla görev aynı anda yürütülür (çok çekirdekli). Eşzamanlılık yapıyla; paralellik yürütmeyle ilgilidir.","nl":"Concurrency: meerdere taken maken voortgang door afwisseling (bijv. single-core met contextwisselingen). Parallellisme: meerdere taken worden gelijktijdig uitgevoerd (multi-core). Concurrency gaat over structuur; parallellisme gaat over uitvoering.","ru":"Конкурентность: несколько задач продвигаются за счёт чередования (например, одноядерный процессор с переключением контекста). Параллелизм: несколько задач выполняются одновременно (многоядерный). Конкурентность — о структуре; параллелизм — о выполнении.","zh":"并发：多个任务通过交替执行来推进（例如单核上的上下文切换）。并行：多个任务同时执行（多核）。并发关乎结构；并行关乎执行。","pt_BR":"Concorrência: múltiplas tarefas progridem por intercalação (ex.: núcleo único com troca de contexto). Paralelismo: múltiplas tarefas executam simultaneamente (multi-core). Concorrência é sobre estrutura; paralelismo é sobre execução.","pt_PT":"Concorrência: múltiplas tarefas progridem por intercalação (ex.: núcleo único com troca de contexto). Paralelismo: múltiplas tarefas executam simultaneamente (multi-core). Concorrência é sobre estrutura; paralelismo é sobre execução."}},
  { id: 'dc-technology-0107', deck_id: 'deck-technology', sort_order: 107, front: "Async/Await and Event Loop", back: "Async functions return Promises in JavaScript; await pauses execution until a Promise resolves without blocking the thread. The event loop processes callbacks when the call stack is empty, enabling non-blocking I/O." , front_translations: {"es":"Async/Await y Loop de Eventos","it":"Async/Await e boucle d'evenementi","de":"Async/Await und Event Loop","fr":"Async/Await et boucle d'événements","tr":"Async/Await ve Olay Döngüsü","nl":"Async/Await en Event Loop","ru":"Async/Await и цикл событий","zh":"Async/Await与事件循环","pt_BR":"Async/Await e Loop de Eventos","pt_PT":"Async/Await e Loop de Eventos"}, back_translations: {"es":"Funciones async retornam Promises en JavaScript; await pausa a execución hasta que una Promise seja resolvida sin bloquear a thread. El loop de eventos processa callbacks cuando a pilha de llamadas está vazia, permitiendo I/El no bloqueante.","it":"I fonczioni async retournent dei Promises en JavaScript ; await suspend l'execuzione jusqu'alla resoluzione d'una Promise senza bloquer il thread. La boucle d'evenements traite i callbacks quando la pile d'appels e vide, permettant dei I/O non bloquantes.","de":"Async-Funktionen geben Promises in JavaScript zurück; await pausiert die Ausführung, bis ein Promise aufgelöst wird, ohne den Thread zu blockieren. Der Event Loop verarbeitet Callbacks, wenn der Call Stack leer ist, und ermöglicht nicht-blockierendes I/O.","fr":"Les fonctions async retournent des Promises en JavaScript ; await suspend l'exécution jusqu'à la résolution d'une Promise sans bloquer le thread. La boucle d'événements traite les callbacks lorsque la pile d'appels est vide, permettant des I/O non bloquantes.","tr":"Async fonksiyonlar JavaScript'te Promise döndürür; await, thread'i bloke etmeden bir Promise çözümlenene kadar yürütmeyi duraklatır. Olay döngüsü, çağrı yığını boş olduğunda geri çağırmaları işleyerek bloklamayan I/O sağlar.","nl":"Async-functies retourneren Promises in JavaScript; await pauzeert de uitvoering tot een Promise is opgelost zonder de thread te blokkeren. De event loop verwerkt callbacks wanneer de call stack leeg is, waardoor niet-blokkerende I/O mogelijk is.","ru":"Async-функции возвращают Promise в JavaScript; await приостанавливает выполнение до разрешения Promise, не блокируя поток. Цикл событий обрабатывает обратные вызовы, когда стек вызовов пуст, обеспечивая неблокирующий ввод-вывод.","zh":"Async函数在JavaScript中返回Promise；await暂停执行直到Promise解决，而不阻塞线程。事件循环在调用栈为空时处理回调，实现非阻塞I/O。","pt_BR":"Funções async retornam Promises em JavaScript; await pausa a execução até que uma Promise seja resolvida sem bloquear a thread. O loop de eventos processa callbacks quando a pilha de chamadas está vazia, permitindo I/O não bloqueante.","pt_PT":"Funções async retornam Promises em JavaScript; await pausa a execução até que uma Promise seja resolvida sem bloquear a thread. O loop de eventos processa callbacks quando a pilha de chamadas está vazia, permitindo I/O não bloqueante."}},
  { id: 'dc-technology-0108', deck_id: 'deck-technology', sort_order: 108, front: "Functional Programming Concepts", back: "Pure functions (no side effects, deterministic), immutability (data not modified in place), higher-order functions (take/return functions), function composition, map/filter/reduce. Leads to more predictable, testable code." , front_translations: {"es":"Conceptos de Programación Funcional","it":"Concepts di programmatione funzioneenelle","de":"Konzepte der funktionalen Programmierung","fr":"Concepts de programmation fonctionnelle","tr":"Fonksiyonel Programlama Kavramları","nl":"Concepten van functioneel programmeren","ru":"Концепции функционального программирования","zh":"函数式编程概念","pt_BR":"Conceitos de Programação Funcional","pt_PT":"Conceitos de Programação Funcional"}, back_translations: {"es":"Funciones puras (sin efectos colaterais, determinísticas), imutabilidad (datos no modificados en el lugar), funciones de ordem superior (reciben/retornam funciones), composición de funciones, map/filter/reduce. Leva a código más previsible y testable.","it":"Fonczioni pures (senza effets di bord, deterministes), immutabilite (donnees non modifiees su place), fonczioni d'ordre superiore (prennent/retournent dei fonczioni), composizione di fonczioni, map/filter/reduce. Menon à un code più previsible e testable.","de":"Reine Funktionen (keine Seiteneffekte, deterministisch), Unveränderlichkeit (Daten werden nicht direkt geändert), Funktionen höherer Ordnung (nehmen/geben Funktionen zurück), Funktionskomposition, map/filter/reduce. Führt zu vorhersagbarerem, testbarerem Code.","fr":"Fonctions pures (sans effets de bord, déterministes), immutabilité (données non modifiées sur place), fonctions d'ordre supérieur (prennent/retournent des fonctions), composition de fonctions, map/filter/reduce. Mène à un code plus prévisible et testable.","tr":"Saf fonksiyonlar (yan etkisiz, deterministik), değişmezlik (veriler yerinde değiştirilmez), yüksek dereceli fonksiyonlar (fonksiyon alır/döndürür), fonksiyon bileşimi, map/filter/reduce. Daha öngörülebilir ve test edilebilir koda yol açar.","nl":"Pure functies (geen bijwerkingen, deterministisch), onveranderlijkheid (data niet ter plaatse gewijzigd), hogere-ordefuncties (nemen/retourneren functies), functiecompositie, map/filter/reduce. Leidt tot meer voorspelbare, testbare code.","ru":"Чистые функции (без побочных эффектов, детерминированные), неизменяемость (данные не модифицируются на месте), функции высшего порядка (принимают/возвращают функции), композиция функций, map/filter/reduce. Приводит к более предсказуемому и тестируемому коду.","zh":"纯函数（无副作用、确定性）、不可变性（数据不在原处修改）、高阶函数（接受/返回函数）、函数组合、map/filter/reduce。使代码更可预测、更易测试。","pt_BR":"Funções puras (sem efeitos colaterais, determinísticas), imutabilidade (dados não modificados no lugar), funções de ordem superior (recebem/retornam funções), composição de funções, map/filter/reduce. Leva a código mais previsível e testável.","pt_PT":"Funções puras (sem efeitos colaterais, determinísticas), imutabilidade (dados não modificados no local), funções de ordem superior (recebem/retornam funções), composição de funções, map/filter/reduce. Leva a código mais previsível e testável."}},
  { id: 'dc-technology-0109', deck_id: 'deck-technology', sort_order: 109, front: "Closure", back: "A function that captures (closes over) variables from its enclosing scope, even after that scope has returned. Used for data encapsulation, callbacks, and factory functions. Fundamental to JavaScript and functional programming." , front_translations: {"es":"Closure (Fechamento)","it":"Fermeture (Closure)","de":"Closure (Abschluss)","fr":"Fermeture (Closure)","tr":"Closure (Kapanış)","nl":"Closure (Sluiting)","ru":"Замыкание (Closure)","zh":"闭包 (Closure)","pt_BR":"Closure (Fechamento)","pt_PT":"Closure (Fecho)"}, back_translations: {"es":"Una función que captura (fecha sobre) variables del su escopo envolvente, mismo após esse escopo ter retornado. Usada para encapsulamento de datos, callbacks y funciones fábrica. Fundamental para JavaScript y programación funcional.","it":"Una fonczione che capture (enferme) i variables della sua portee englobante, stesso apres il retour di questa portee. Utilisee per l'encapsulazione dei donnees, i callbacks e i fonczioni fabrico. Fondamentale en JavaScript e en programmazione fonctionnelle.","de":"Eine Funktion, die Variablen aus ihrem umgebenden Gültigkeitsbereich erfasst (einschließt), auch nachdem dieser Bereich beendet wurde. Wird für Datenkapselung, Callbacks und Fabrikfunktionen verwendet. Grundlegend für JavaScript und funktionale Programmierung.","fr":"Une fonction qui capture (enferme) les variables de sa portée englobante, même après le retour de cette portée. Utilisée pour l'encapsulation des données, les callbacks et les fonctions fabrique. Fondamentale en JavaScript et en programmation fonctionnelle.","tr":"Kapsayan kapsamındaki değişkenleri yakalayan (kapatan), bu kapsam sona erdikten sonra bile erişebilen bir fonksiyon. Veri kapsülleme, geri çağırmalar ve fabrika fonksiyonları için kullanılır. JavaScript ve fonksiyonel programlamanın temelidir.","nl":"Een functie die variabelen uit het omsluitende bereik vastlegt (afsluit), zelfs nadat dat bereik is teruggekeerd. Gebruikt voor data-inkapseling, callbacks en fabrieksfuncties. Fundamenteel voor JavaScript en functioneel programmeren.","ru":"Функция, захватывающая (замыкающая) переменные из окружающей области видимости, даже после выхода из этой области. Используется для инкапсуляции данных, обратных вызовов и фабричных функций. Фундаментальное понятие в JavaScript и функциональном программировании.","zh":"一种捕获（封闭）其外围作用域中变量的函数，即使该作用域已经返回。用于数据封装、回调和工厂函数。是JavaScript和函数式编程的基础。","pt_BR":"Uma função que captura (fecha sobre) variáveis do seu escopo envolvente, mesmo após esse escopo ter retornado. Usada para encapsulamento de dados, callbacks e funções fábrica. Fundamental para JavaScript e programação funcional.","pt_PT":"Uma função que captura (fecha sobre) variáveis do seu âmbito envolvente, mesmo após esse âmbito ter retornado. Usada para encapsulamento de dados, callbacks e funções fábrica. Fundamental para JavaScript e programação funcional."}},
  { id: 'dc-technology-0110', deck_id: 'deck-technology', sort_order: 110, front: "Dependency Injection (DI)", back: "A design principle where a component's dependencies are provided from outside rather than created internally. Improves testability (inject mocks), decoupling, and flexibility. Core to frameworks like Spring and Angular." , front_translations: {"es":"Injeción de Dependencia (DI)","it":"Injectione di dependanze (DI)","de":"Dependency Injection (DI)","fr":"Injection de dépendances (DI)","tr":"Bağımlılık Enjeksiyonu (DI)","nl":"Dependency Injection (DI)","ru":"Внедрение зависимостей (DI)","zh":"依赖注入 (DI)","pt_BR":"Injeção de Dependência (DI)","pt_PT":"Injeção de Dependências (DI)"}, back_translations: {"es":"Un principio de design donde las dependencias de un componente son fornecidas externamente en vez de creadas internamente. Melhora a testabilidad (injetar mocks), desacoplamento y flexibilidad. Central en frameworks como Spring y Angular.","it":"Un principe di concepzione où i dependanze di un composant sono fournies dell'exteriore plutot che creees en interne. Ameliore la testabilite (injeczione di mocks), il decouplage e la flexibilite. Al cœur di frameworks come Spring e Angular.","de":"Ein Designprinzip, bei dem die Abhängigkeiten einer Komponente von außen bereitgestellt werden, anstatt intern erstellt zu werden. Verbessert Testbarkeit (Mocks injizieren), Entkopplung und Flexibilität. Kernkonzept in Frameworks wie Spring und Angular.","fr":"Un principe de conception où les dépendances d'un composant sont fournies de l'extérieur plutôt que créées en interne. Améliore la testabilité (injection de mocks), le découplage et la flexibilité. Au cœur de frameworks comme Spring et Angular.","tr":"Bir bileşenin bağımlılıklarının dahili olarak oluşturulmak yerine dışarıdan sağlandığı bir tasarım prensibi. Test edilebilirliği (mock enjeksiyonu), bağımsızlığı ve esnekliği artırır. Spring ve Angular gibi çerçevelerin temelini oluşturur.","nl":"Een ontwerpprincipe waarbij de afhankelijkheden van een component van buitenaf worden geleverd in plaats van intern aangemaakt. Verbetert testbaarheid (mocks injecteren), ontkoppeling en flexibiliteit. Kernprincipe in frameworks zoals Spring en Angular.","ru":"Принцип проектирования, при котором зависимости компонента предоставляются извне, а не создаются внутри. Улучшает тестируемость (внедрение моков), слабую связанность и гибкость. Основа фреймворков Spring и Angular.","zh":"一种设计原则，组件的依赖项从外部提供而非内部创建。提高可测试性（注入模拟对象）、解耦和灵活性。是Spring和Angular等框架的核心。","pt_BR":"Um princípio de design onde as dependências de um componente são fornecidas externamente em vez de criadas internamente. Melhora a testabilidade (injetar mocks), desacoplamento e flexibilidade. Central em frameworks como Spring e Angular.","pt_PT":"Um princípio de design onde as dependências de um componente são fornecidas externamente em vez de criadas internamente. Melhora a testabilidade (injetar mocks), desacoplamento e flexibilidade. Central em frameworks como Spring e Angular."}},
  { id: 'dc-technology-0111', deck_id: 'deck-technology', sort_order: 111, front: "Test-Driven Development (TDD)", back: "A development practice of writing failing tests before writing production code (Red → Green → Refactor cycle). Ensures code is testable from the start and acts as living documentation." , front_translations: {"es":"Desarrollo Orientado a Pruebas (TDD)","it":"Sviluppoo pilote per i tests (TDD)","de":"Testgetriebene Entwicklung (TDD)","fr":"Développement piloté par les tests (TDD)","tr":"Test Güdümlü Geliştirme (TDD)","nl":"Test-Driven Development (TDD)","ru":"Разработка через тестирование (TDD)","zh":"测试驱动开发 (TDD)","pt_BR":"Desenvolvimento Orientado a Testes (TDD)","pt_PT":"Desenvolvimento Orientado a Testes (TDD)"}, back_translations: {"es":"Una prática de desarrollo de escrever pruebas que falham antes de escrever el código de producción (ciclo Rojo → Verde → Refatorar). Garantiza que el código seja testable desde el início y serve como documentación viva.","it":"Una pratico di sviluppo consistant à ecrire dei tests echouants avant il code di produczione (cycle Rouge → Vert → Refactoring). Garantit che il code e testable des il depart e sert di documentazione vivante.","de":"Eine Entwicklungspraxis, bei der fehlschlagende Tests vor dem Produktionscode geschrieben werden (Rot → Grün → Refactoring-Zyklus). Stellt sicher, dass Code von Anfang an testbar ist und dient als lebende Dokumentation.","fr":"Une pratique de développement consistant à écrire des tests échouants avant le code de production (cycle Rouge → Vert → Refactoring). Garantit que le code est testable dès le départ et sert de documentation vivante.","tr":"Üretim kodu yazmadan önce başarısız testler yazma pratiği (Kırmızı → Yeşil → Refaktör döngüsü). Kodun başından itibaren test edilebilir olmasını sağlar ve canlı dokümantasyon görevi görür.","nl":"Een ontwikkelpraktijk waarbij falende tests worden geschreven vóór productiecode (Rood → Groen → Refactor-cyclus). Zorgt ervoor dat code vanaf het begin testbaar is en dient als levende documentatie.","ru":"Практика разработки, при которой сначала пишутся падающие тесты, а затем рабочий код (цикл Красный → Зелёный → Рефакторинг). Гарантирует тестируемость кода с самого начала и служит живой документацией.","zh":"在编写生产代码之前先编写失败测试的开发实践（红 → 绿 → 重构循环）。确保代码从一开始就是可测试的，并充当活文档。","pt_BR":"Uma prática de desenvolvimento de escrever testes que falham antes de escrever o código de produção (ciclo Vermelho → Verde → Refatorar). Garante que o código seja testável desde o início e serve como documentação viva.","pt_PT":"Uma prática de desenvolvimento de escrever testes que falham antes de escrever o código de produção (ciclo Vermelho → Verde → Refatorar). Garante que o código seja testável desde o início e serve como documentação viva."}},
  { id: 'dc-technology-0112', deck_id: 'deck-technology', sort_order: 112, front: "Unit Test vs. Integration Test vs. E2E Test", back: "Unit test: tests a single function/class in isolation. Integration test: tests interaction between modules. End-to-end (E2E) test: tests entire user flows through the system. Testing pyramid: many unit, fewer integration, fewest E2E." , front_translations: {"es":"Prueba Unitário vs. Prueba de Integración vs. Prueba Y2Y","it":"Te unitaire vs. te d'intàgratione vs. te E2E","de":"Unit-Test vs. Integrationstest vs. E2E-Test","fr":"Test unitaire vs. test d'intégration vs. test E2E","tr":"Birim Testi vs. Entegrasyon Testi vs. E2E Testi","nl":"Unit test vs. integratietest vs. E2E-test","ru":"Модульный тест vs. интеграционный тест vs. E2E-тест","zh":"单元测试 vs. 集成测试 vs. E2E测试","pt_BR":"Teste Unitário vs. Teste de Integração vs. Teste E2E","pt_PT":"Teste Unitário vs. Teste de Integração vs. Teste E2E"}, back_translations: {"es":"Prueba unitário: testa una única función/clase isoladamente. Prueba de integración: testa a interacción entre módulos. Prueba ponta a ponta (Y2Y): testa fluxos completos del usuario por el sistema. Piramide de pruebas: muchos unitários, menos integración, menos aún Y2Y.","it":"Test unitaire : teste una seule fonczione/classe isolement. Test d'integrazione : teste l'interaczione tra modules. Test end-to-end (E2E) : teste dei flux utilisatore complets attraverso il sistema. Pyramide dei tests : beaucoup di tests unitaires, meno d'integrazione, molto peu di E2E.","de":"Unit-Test: testet eine einzelne Funktion/Klasse isoliert. Integrationstest: testet die Interaktion zwischen Modulen. End-to-End (E2E)-Test: testet gesamte Benutzerabläufe durch das System. Testpyramide: viele Unit-, weniger Integrations-, wenigste E2E-Tests.","fr":"Test unitaire : teste une seule fonction/classe isolément. Test d'intégration : teste l'interaction entre modules. Test end-to-end (E2E) : teste des flux utilisateur complets à travers le système. Pyramide des tests : beaucoup de tests unitaires, moins d'intégration, très peu de E2E.","tr":"Birim testi: tek bir fonksiyonu/sınıfı izole olarak test eder. Entegrasyon testi: modüller arası etkileşimi test eder. Uçtan uca (E2E) test: tüm kullanıcı akışlarını sistem boyunca test eder. Test piramidi: çok birim, daha az entegrasyon, en az E2E.","nl":"Unit test: test een enkele functie/klasse in isolatie. Integratietest: test de interactie tussen modules. End-to-end (E2E) test: test volledige gebruikersstromen door het systeem. Testpiramide: veel unit, minder integratie, minste E2E.","ru":"Модульный тест: тестирует одну функцию/класс изолированно. Интеграционный тест: тестирует взаимодействие между модулями. Сквозной (E2E) тест: тестирует полные пользовательские сценарии. Пирамида тестирования: много модульных, меньше интеграционных, минимум E2E.","zh":"单元测试：隔离测试单个函数/类。集成测试：测试模块之间的交互。端到端（E2E）测试：测试整个用户流程。测试金字塔：大量单元测试，较少集成测试，最少E2E测试。","pt_BR":"Teste unitário: testa uma única função/classe isoladamente. Teste de integração: testa a interação entre módulos. Teste ponta a ponta (E2E): testa fluxos completos do usuário pelo sistema. Pirâmide de testes: muitos unitários, menos integração, menos ainda E2E.","pt_PT":"Teste unitário: testa uma única função/classe isoladamente. Teste de integração: testa a interação entre módulos. Teste ponta a ponta (E2E): testa fluxos completos do utilizador pelo sistema. Pirâmide de testes: muitos unitários, menos integração, menos ainda E2E."}},
  { id: 'dc-technology-0113', deck_id: 'deck-technology', sort_order: 113, front: "Memory Leak", back: "A bug where memory that is no longer needed is not released back to the OS. In languages without GC (C, C++), caused by failing to free heap memory. In managed languages, caused by retaining unintended references." , front_translations: {"es":"Vazamento de Memoria","it":"Fuite di memoria","de":"Speicherleck","fr":"Fuite de mémoire","tr":"Bellek Sızıntısı","nl":"Geheugenlek","ru":"Утечка памяти","zh":"内存泄漏","pt_BR":"Vazamento de Memória","pt_PT":"Fuga de Memória"}, back_translations: {"es":"Un bug donde a memoria que no es más necesaria no es liberada de volta al sistema operativo. En linguajes sin GC (C, C++), causado por no liberar memoria del heap. En linguajes gerenciadas, causado por la retención de referencias no intencionais.","it":"Un bug où la memoire che n'e più necessario n'e liberee al sistema d'exploitazione. In i langages senza GC (C, C++), cause per l'absenza di liberazione di memoire del tas. In i langages geres, cause per la retenzione di referenze non intentionnelles.","de":"Ein Fehler, bei dem nicht mehr benötigter Speicher nicht an das Betriebssystem freigegeben wird. In Sprachen ohne GC (C, C++) verursacht durch fehlende Freigabe von Heap-Speicher. In verwalteten Sprachen durch unbeabsichtigte Referenzen verursacht.","fr":"Un bug où la mémoire qui n'est plus nécessaire n'est pas libérée au système d'exploitation. Dans les langages sans GC (C, C++), causé par l'absence de libération de mémoire du tas. Dans les langages gérés, causé par la rétention de références non intentionnelles.","tr":"Artık gerekli olmayan belleğin işletim sistemine geri verilmediği bir hata. GC olmayan dillerde (C, C++) heap belleğinin serbest bırakılmamasından kaynaklanır. Yönetilen dillerde istenmeyen referansların tutulmasından kaynaklanır.","nl":"Een bug waarbij geheugen dat niet langer nodig is niet wordt vrijgegeven aan het besturingssysteem. In talen zonder GC (C, C++) veroorzaakt door het niet vrijgeven van heap-geheugen. In beheerde talen veroorzaakt door onbedoelde referenties.","ru":"Ошибка, при которой память, которая больше не нужна, не возвращается операционной системе. В языках без GC (C, C++) вызвана отсутствием освобождения памяти кучи. В управляемых языках вызвана сохранением непреднамеренных ссылок.","zh":"一种错误，不再需要的内存没有释放回操作系统。在没有GC的语言（C、C++）中，由未释放堆内存引起。在托管语言中，由保留非预期引用引起。","pt_BR":"Um bug onde a memória que não é mais necessária não é liberada de volta ao sistema operacional. Em linguagens sem GC (C, C++), causado por não liberar memória do heap. Em linguagens gerenciadas, causado pela retenção de referências não intencionais.","pt_PT":"Um bug onde a memória que já não é necessária não é libertada de volta ao sistema operativo. Em linguagens sem GC (C, C++), causado por não libertar memória do heap. Em linguagens geridas, causado pela retenção de referências não intencionais."}},
  { id: 'dc-technology-0114', deck_id: 'deck-technology', sort_order: 114, front: "Buffer Overflow", back: "A vulnerability where a program writes more data to a buffer than it can hold, overwriting adjacent memory. Can be exploited to execute arbitrary code. Prevented by bounds checking and safe string functions." , front_translations: {"es":"Estouro de Buffer","it":"Depassemento di tampon","de":"Pufferüberlauf","fr":"Dépassement de tampon","tr":"Arabellek Taşması","nl":"Bufferoverloop","ru":"Переполнение буфера","zh":"缓冲区溢出","pt_BR":"Estouro de Buffer","pt_PT":"Transbordamento de Buffer"}, back_translations: {"es":"Una vulnerabilidad donde un programa escreve más datos en un buffer del que ele puede conter, sobrescrevendo memoria adjacente. Puede ser explorado para executar código arbitrário. Prevenido por verificación de limites y funciones de string seguras.","it":"Una vulnerabilite où un programme ecrit più di donnees in un tampon che il non può en contenir, ecrasant la memoire adjacente. Peut etre exploite per executer del code arbitraire. Prevenu per la verificazione dei limites e i fonczioni di chaines sures.","de":"Eine Schwachstelle, bei der ein Programm mehr Daten in einen Puffer schreibt, als dieser aufnehmen kann, und benachbarten Speicher überschreibt. Kann zur Ausführung beliebigen Codes ausgenutzt werden. Verhindert durch Grenzprüfung und sichere Zeichenkettenfunktionen.","fr":"Une vulnérabilité où un programme écrit plus de données dans un tampon qu'il ne peut en contenir, écrasant la mémoire adjacente. Peut être exploité pour exécuter du code arbitraire. Prévenu par la vérification des limites et les fonctions de chaînes sûres.","tr":"Bir programın bir arabelleğe tutabileceğinden fazla veri yazarak bitişik belleği üzerine yazmasıyla oluşan bir güvenlik açığı. Rastgele kod çalıştırmak için kötüye kullanılabilir. Sınır kontrolü ve güvenli string fonksiyonlarıyla önlenir.","nl":"Een kwetsbaarheid waarbij een programma meer data naar een buffer schrijft dan deze kan bevatten, waardoor aangrenzend geheugen wordt overschreven. Kan worden misbruikt om willekeurige code uit te voeren. Voorkomen door grenscontrole en veilige stringfuncties.","ru":"Уязвимость, при которой программа записывает в буфер больше данных, чем он может вместить, перезаписывая соседнюю память. Может быть использована для выполнения произвольного кода. Предотвращается проверкой границ и безопасными строковыми функциями.","zh":"一种漏洞，程序向缓冲区写入超出其容量的数据，覆盖相邻内存。可被利用执行任意代码。通过边界检查和安全字符串函数来预防。","pt_BR":"Uma vulnerabilidade onde um programa escreve mais dados em um buffer do que ele pode conter, sobrescrevendo memória adjacente. Pode ser explorado para executar código arbitrário. Prevenido por verificação de limites e funções de string seguras.","pt_PT":"Uma vulnerabilidade onde um programa escreve mais dados num buffer do que este pode conter, sobrescrevendo memória adjacente. Pode ser explorado para executar código arbitrário. Prevenido por verificação de limites e funções de string seguras."}},
  { id: 'dc-technology-0115', deck_id: 'deck-technology', sort_order: 115, front: "Binary (Number System)", back: "Base-2 number system using digits 0 and 1. All computer data is ultimately represented in binary. Each binary digit is a bit. A byte is 8 bits, representing 256 possible values (0–255)." , front_translations: {"es":"Binário (Sistema Numérico)","it":"Binaire (Sistema di numeratione)","de":"Binärsystem (Zahlensystem)","fr":"Binaire (Système de numération)","tr":"İkili Sayı Sistemi","nl":"Binair (Getalstelsel)","ru":"Двоичная система счисления","zh":"二进制（数制）","pt_BR":"Binário (Sistema Numérico)","pt_PT":"Binário (Sistema Numérico)"}, back_translations: {"es":"Sistema numérico de base 2 usando los dígitos 0 y 1. Todos los datos del computadora son, en última análise, representados en binário. Cada dígito binário es un bit. Un byte son 8 bits, representando 256 valores posibles (0–255).","it":"Sistema di numerazione en base 2 utilisant i chiffres 0 e 1. Toutes i donnees informatici sono finalement representees en binaire. Chaque chiffre binaire e un bit. Un octet e compose di 8 bits, representant 256 valori possibles (0–255).","de":"Zahlensystem zur Basis 2 mit den Ziffern 0 und 1. Alle Computerdaten werden letztlich binär dargestellt. Jede Binärziffer ist ein Bit. Ein Byte besteht aus 8 Bits und stellt 256 mögliche Werte (0–255) dar.","fr":"Système de numération en base 2 utilisant les chiffres 0 et 1. Toutes les données informatiques sont finalement représentées en binaire. Chaque chiffre binaire est un bit. Un octet est composé de 8 bits, représentant 256 valeurs possibles (0–255).","tr":"0 ve 1 rakamlarını kullanan 2 tabanlı sayı sistemi. Tüm bilgisayar verileri nihayetinde ikili olarak temsil edilir. Her ikili rakam bir bittir. Bir bayt 8 bittir ve 256 olası değeri (0–255) temsil eder.","nl":"Getalstelsel met grondtal 2 dat de cijfers 0 en 1 gebruikt. Alle computergegevens worden uiteindelijk binair weergegeven. Elk binair cijfer is een bit. Een byte is 8 bits en vertegenwoordigt 256 mogelijke waarden (0–255).","ru":"Система счисления с основанием 2, использующая цифры 0 и 1. Все данные в компьютере в конечном счёте представлены в двоичной форме. Каждая двоичная цифра — бит. Байт — 8 бит, представляющих 256 возможных значений (0–255).","zh":"以2为基数、使用0和1的数制。所有计算机数据最终都以二进制表示。每个二进制位是一个比特。一个字节是8位，表示256个可能的值（0–255）。","pt_BR":"Sistema numérico de base 2 usando os dígitos 0 e 1. Todos os dados do computador são, em última análise, representados em binário. Cada dígito binário é um bit. Um byte são 8 bits, representando 256 valores possíveis (0–255).","pt_PT":"Sistema numérico de base 2 usando os dígitos 0 e 1. Todos os dados do computador são, em última análise, representados em binário. Cada dígito binário é um bit. Um byte são 8 bits, representando 256 valores possíveis (0–255)."}},
  { id: 'dc-technology-0116', deck_id: 'deck-technology', sort_order: 116, front: "Hexadecimal (Number System)", back: "Base-16 number system using 0–9 and A–F. Compact representation of binary (1 hex digit = 4 bits). Widely used for memory addresses, color codes (#RRGGBB), and byte-level data representation." , front_translations: {"es":"Hexadecimal (Sistema Numérico)","it":"Hexadecimal (Sistema di numeratione)","de":"Hexadezimalsystem (Zahlensystem)","fr":"Hexadécimal (Système de numération)","tr":"Onaltılık Sayı Sistemi","nl":"Hexadecimaal (Getalstelsel)","ru":"Шестнадцатеричная система счисления","zh":"十六进制（数制）","pt_BR":"Hexadecimal (Sistema Numérico)","pt_PT":"Hexadecimal (Sistema Numérico)"}, back_translations: {"es":"Sistema numérico de base 16 usando 0–9 y A–F. Representación compacta del binário (1 dígito hex = 4 bits). Amplamente usado para endereços de memoria, códigos de cores (#RRGGBB) y representación de datos en nivel de byte.","it":"Sistema di numerazione en base 16 utilisant 0–9 e A–F. Representazione compacte del binaire (1 chiffre hex = 4 bits). Largement utilise per i adresses memoire, i codes coulore (#RRGGBB) e la representazione dei donnees al niveau dell'octet.","de":"Zahlensystem zur Basis 16 mit 0–9 und A–F. Kompakte Darstellung von Binär (1 Hex-Ziffer = 4 Bits). Weit verbreitet für Speicheradressen, Farbcodes (#RRGGBB) und byteweise Datendarstellung.","fr":"Système de numération en base 16 utilisant 0–9 et A–F. Représentation compacte du binaire (1 chiffre hex = 4 bits). Largement utilisé pour les adresses mémoire, les codes couleur (#RRGGBB) et la représentation des données au niveau de l'octet.","tr":"0–9 ve A–F kullanan 16 tabanlı sayı sistemi. İkilinin kompakt temsili (1 hex rakam = 4 bit). Bellek adresleri, renk kodları (#RRGGBB) ve bayt düzeyinde veri temsili için yaygın olarak kullanılır.","nl":"Getalstelsel met grondtal 16 dat 0–9 en A–F gebruikt. Compacte weergave van binair (1 hex-cijfer = 4 bits). Veel gebruikt voor geheugenadressen, kleurcodes (#RRGGBB) en byte-niveau dataweergave.","ru":"Система счисления с основанием 16, использующая 0–9 и A–F. Компактное представление двоичных данных (1 hex-цифра = 4 бита). Широко используется для адресов памяти, цветовых кодов (#RRGGBB) и побайтового представления данных.","zh":"以16为基数、使用0–9和A–F的数制。是二进制的紧凑表示（1个十六进制位 = 4比特）。广泛用于内存地址、颜色代码（#RRGGBB）和字节级数据表示。","pt_BR":"Sistema numérico de base 16 usando 0–9 e A–F. Representação compacta do binário (1 dígito hex = 4 bits). Amplamente usado para endereços de memória, códigos de cores (#RRGGBB) e representação de dados em nível de byte.","pt_PT":"Sistema numérico de base 16 usando 0–9 e A–F. Representação compacta do binário (1 dígito hex = 4 bits). Amplamente usado para endereços de memória, códigos de cores (#RRGGBB) e representação de dados ao nível do byte."}},
  { id: 'dc-technology-0117', deck_id: 'deck-technology', sort_order: 117, front: "Boolean Logic: AND / OR / NOT", back: "AND: true only if both inputs are true. OR: true if at least one input is true. NOT: inverts the input. NAND and NOR are functionally complete (any logic circuit can be built from them alone)." , front_translations: {"es":"Lógica Booleana: AND / OR / NOT","it":"Logico booleenne : AND / OR / NOT","de":"Boolesche Logik: AND / OR / NOT","fr":"Logique booléenne : AND / OR / NOT","tr":"Boole Mantığı: AND / OR / NOT","nl":"Booleaanse logica: AND / OR / NOT","ru":"Булева логика: AND / OR / NOT","zh":"布尔逻辑：AND / OR / NOT","pt_BR":"Lógica Booleana: AND / OR / NOT","pt_PT":"Lógica Booleana: AND / OR / NOT"}, back_translations: {"es":"AND: verdadero solo se ambas las entradas forem verdaderas. OR: verdadero se por el menos una entrada for verdadera. NOT: inverte a entrada. NAND y NOR son funcionalmente completos (cualquier circuito lógico puede ser construído solo con eles).","it":"AND : vrai uniquement se i deux entrees sono vraies. OR : vrai se al meno una entree e vraie. NOT : inverse l'entree. NAND e NOR sono fonctionnellement complets (tutto circuit logico può etre construit con eux seuls).","de":"AND: wahr nur wenn beide Eingaben wahr sind. OR: wahr wenn mindestens eine Eingabe wahr ist. NOT: invertiert die Eingabe. NAND und NOR sind funktional vollständig (jede Logikschaltung kann allein aus ihnen gebaut werden).","fr":"AND : vrai uniquement si les deux entrées sont vraies. OR : vrai si au moins une entrée est vraie. NOT : inverse l'entrée. NAND et NOR sont fonctionnellement complets (tout circuit logique peut être construit avec eux seuls).","tr":"AND: yalnızca her iki giriş doğruysa doğrudur. OR: en az bir giriş doğruysa doğrudur. NOT: girişi tersine çevirir. NAND ve NOR fonksiyonel olarak tamdır (herhangi bir mantık devresi yalnızca bunlarla kurulabilir).","nl":"AND: alleen waar als beide invoeren waar zijn. OR: waar als minstens één invoer waar is. NOT: inverteert de invoer. NAND en NOR zijn functioneel compleet (elke logische schakeling kan alleen met hen worden gebouwd).","ru":"AND: истина только если оба входа истинны. OR: истина если хотя бы один вход истинен. NOT: инвертирует вход. NAND и NOR функционально полны (любая логическая схема может быть построена только из них).","zh":"AND：仅当两个输入都为真时为真。OR：至少一个输入为真时为真。NOT：对输入取反。NAND和NOR是功能完备的（任何逻辑电路都可以仅用它们构建）。","pt_BR":"AND: verdadeiro apenas se ambas as entradas forem verdadeiras. OR: verdadeiro se pelo menos uma entrada for verdadeira. NOT: inverte a entrada. NAND e NOR são funcionalmente completos (qualquer circuito lógico pode ser construído apenas com eles).","pt_PT":"AND: verdadeiro apenas se ambas as entradas forem verdadeiras. OR: verdadeiro se pelo menos uma entrada for verdadeira. NOT: inverte a entrada. NAND e NOR são funcionalmente completos (qualquer circuito lógico pode ser construído apenas com eles)."}},
  { id: 'dc-technology-0118', deck_id: 'deck-technology', sort_order: 118, front: "Regular Expression (Regex)", back: "A sequence of characters defining a search pattern. Used for string matching, validation, and parsing. Special characters: . (any char), * (zero or more), + (one or more), ^ (start), $ (end), [] (character class)." , front_translations: {"es":"Expresión Regular (Regex)","it":"Espressione reguliere (Regex)","de":"Regulärer Ausdruck (Regex)","fr":"Expression régulière (Regex)","tr":"Düzenli İfade (Regex)","nl":"Reguliere expressie (Regex)","ru":"Регулярное выражение (Regex)","zh":"正则表达式 (Regex)","pt_BR":"Expressão Regular (Regex)","pt_PT":"Expressão Regular (Regex)"}, back_translations: {"es":"Una secuencia de caracteres que define un padrão de busca. Usada para correspondencia de strings, validación y análise sintática. Caracteres especiais: . (cualquier caractere), * (zero o más), + (uno el más), ^ (início), $ (fin), [] (clase de caracteres).","it":"Una sequenza di caracteres definissant un motif di recherche. Utilisee per la correspondanza di chaines, la validazione e l'analyse. Caracteres speciaux : . (tutto caractere), * (zero o più), + (un o più), ^ (debut), $ (fin), [] (classe di caracteres).","de":"Eine Zeichenfolge, die ein Suchmuster definiert. Verwendet für Zeichenkettenabgleich, Validierung und Parsing. Sonderzeichen: . (beliebiges Zeichen), * (null oder mehr), + (eins oder mehr), ^ (Anfang), $ (Ende), [] (Zeichenklasse).","fr":"Une séquence de caractères définissant un motif de recherche. Utilisée pour la correspondance de chaînes, la validation et l'analyse. Caractères spéciaux : . (tout caractère), * (zéro ou plus), + (un ou plus), ^ (début), $ (fin), [] (classe de caractères).","tr":"Bir arama kalıbını tanımlayan bir karakter dizisi. String eşleştirme, doğrulama ve ayrıştırma için kullanılır. Özel karakterler: . (herhangi bir karakter), * (sıfır veya daha fazla), + (bir veya daha fazla), ^ (başlangıç), $ (son), [] (karakter sınıfı).","nl":"Een reeks tekens die een zoekpatroon definieert. Gebruikt voor stringmatching, validatie en parsing. Speciale tekens: . (elk teken), * (nul of meer), + (een of meer), ^ (begin), $ (einde), [] (tekenklasse).","ru":"Последовательность символов, определяющая шаблон поиска. Используется для сопоставления строк, валидации и разбора. Специальные символы: . (любой символ), * (ноль или более), + (один или более), ^ (начало), $ (конец), [] (класс символов).","zh":"定义搜索模式的字符序列。用于字符串匹配、验证和解析。特殊字符：.（任意字符）、*（零个或多个）、+（一个或多个）、^（开头）、$（结尾）、[]（字符类）。","pt_BR":"Uma sequência de caracteres que define um padrão de busca. Usada para correspondência de strings, validação e análise sintática. Caracteres especiais: . (qualquer caractere), * (zero ou mais), + (um ou mais), ^ (início), $ (fim), [] (classe de caracteres).","pt_PT":"Uma sequência de caracteres que define um padrão de pesquisa. Usada para correspondência de strings, validação e análise sintática. Caracteres especiais: . (qualquer caractere), * (zero ou mais), + (um ou mais), ^ (início), $ (fim), [] (classe de caracteres)."}},
  { id: 'dc-technology-0119', deck_id: 'deck-technology', sort_order: 119, front: "Serialization / Deserialization", back: "Serialization: converting an object in memory to a format (JSON, XML, binary) for storage or transmission. Deserialization: reconstructing the object from the format. Key for APIs, persistence, and distributed systems." , front_translations: {"es":"Serialización / Desserialización","it":"Serialisatione / Deserialisatione","de":"Serialisierung / Deserialisierung","fr":"Sérialisation / Désérialisation","tr":"Serileştirme / Seriden Çıkarma","nl":"Serialisatie / Deserialisatie","ru":"Сериализация / Десериализация","zh":"序列化 / 反序列化","pt_BR":"Serialização / Desserialização","pt_PT":"Serialização / Desserialização"}, back_translations: {"es":"Serialización: conversão de un objeto en memoria para un formato (JSON, XML, binário) para almacenamiento o transmisión. Desserialización: reconstrución del objeto a partir del formato. Esencial para APIs, persistencia y sistemas distribuídos.","it":"Serialisazione : conversion di un objet en memoire in un format (JSON, XML, binaire) per il stockage o la transmission. Deserialisazione : reconstruczione dell'objet à partir del format. Essentiel per i APIs, la persistanza e i sistemi distribues.","de":"Serialisierung: Umwandlung eines Objekts im Speicher in ein Format (JSON, XML, binär) zur Speicherung oder Übertragung. Deserialisierung: Rekonstruktion des Objekts aus dem Format. Wesentlich für APIs, Persistenz und verteilte Systeme.","fr":"Sérialisation : conversion d'un objet en mémoire dans un format (JSON, XML, binaire) pour le stockage ou la transmission. Désérialisation : reconstruction de l'objet à partir du format. Essentiel pour les APIs, la persistance et les systèmes distribués.","tr":"Serileştirme: bellekteki bir nesneyi depolama veya iletim için bir formata (JSON, XML, ikili) dönüştürme. Seriden çıkarma: nesneyi formattan yeniden oluşturma. API'ler, kalıcılık ve dağıtık sistemler için önemlidir.","nl":"Serialisatie: het omzetten van een object in het geheugen naar een formaat (JSON, XML, binair) voor opslag of overdracht. Deserialisatie: het reconstrueren van het object uit het formaat. Essentieel voor APIs, persistentie en gedistribueerde systemen.","ru":"Сериализация: преобразование объекта в памяти в формат (JSON, XML, бинарный) для хранения или передачи. Десериализация: восстановление объекта из формата. Ключевое понятие для API, хранения данных и распределённых систем.","zh":"序列化：将内存中的对象转换为格式（JSON、XML、二进制）以便存储或传输。反序列化：从格式中重建对象。对API、持久化和分布式系统至关重要。","pt_BR":"Serialização: conversão de um objeto em memória para um formato (JSON, XML, binário) para armazenamento ou transmissão. Desserialização: reconstrução do objeto a partir do formato. Essencial para APIs, persistência e sistemas distribuídos.","pt_PT":"Serialização: conversão de um objeto em memória para um formato (JSON, XML, binário) para armazenamento ou transmissão. Desserialização: reconstrução do objeto a partir do formato. Essencial para APIs, persistência e sistemas distribuídos."}},
  { id: 'dc-technology-0120', deck_id: 'deck-technology', sort_order: 120, front: "JSON — JavaScript Object Notation", back: "A lightweight, human-readable data interchange format using key-value pairs and arrays. Language-independent but based on JavaScript syntax. The dominant format for REST APIs and configuration files." , front_translations: {"es":"JSON — JavaScript Object Notation","it":"JSON — JavaScript Object Notatione","de":"JSON — JavaScript Object Notation","fr":"JSON — JavaScript Object Notation","tr":"JSON — JavaScript Object Notation","nl":"JSON — JavaScript Object Notation","ru":"JSON — JavaScript Object Notation","zh":"JSON — JavaScript对象表示法","pt_BR":"JSON — JavaScript Object Notation","pt_PT":"JSON — JavaScript Object Notation"}, back_translations: {"es":"Un formato ligero y legible de intercambio de datos usando pares chave-valor y arrays. Independente de linguaje, pero basado en la sintaxe JavaScript. El formato dominante para APIs REST y archivos de configuración.","it":"Un format d'echange di donnees leger e lisible utilisant dei paires cle-valore e dei tableaux. Independant del langage ma base su la syntaxe JavaScript. Il format dominant per i APIs REST e i fichiers di configurazione.","de":"Ein leichtgewichtiges, menschenlesbares Datenaustauschformat mit Schlüssel-Wert-Paaren und Arrays. Sprachunabhängig, aber basierend auf JavaScript-Syntax. Das dominierende Format für REST APIs und Konfigurationsdateien.","fr":"Un format d'échange de données léger et lisible utilisant des paires clé-valeur et des tableaux. Indépendant du langage mais basé sur la syntaxe JavaScript. Le format dominant pour les APIs REST et les fichiers de configuration.","tr":"Anahtar-değer çiftleri ve diziler kullanan hafif, insan tarafından okunabilir bir veri değişim formatı. Dilden bağımsız ancak JavaScript söz dizimine dayalı. REST API'ler ve yapılandırma dosyaları için baskın format.","nl":"Een lichtgewicht, menselijk leesbaar gegevensuitwisselingsformaat met sleutel-waardeparen en arrays. Taalonafhankelijk maar gebaseerd op JavaScript-syntaxis. Het dominante formaat voor REST APIs en configuratiebestanden.","ru":"Легковесный, удобочитаемый формат обмена данными с использованием пар ключ-значение и массивов. Не зависит от языка, но основан на синтаксисе JavaScript. Доминирующий формат для REST API и конфигурационных файлов.","zh":"一种使用键值对和数组的轻量级、人类可读的数据交换格式。与语言无关但基于JavaScript语法。是REST API和配置文件的主流格式。","pt_BR":"Um formato leve e legível de intercâmbio de dados usando pares chave-valor e arrays. Independente de linguagem, mas baseado na sintaxe JavaScript. O formato dominante para APIs REST e arquivos de configuração.","pt_PT":"Um formato leve e legível de intercâmbio de dados usando pares chave-valor e arrays. Independente de linguagem, mas baseado na sintaxe JavaScript. O formato dominante para APIs REST e ficheiros de configuração."}},
  { id: 'dc-technology-0121', deck_id: 'deck-technology', sort_order: 121, front: "Webhook", back: "A mechanism for one server to notify another via an HTTP POST request when an event occurs ('reverse API'). The receiving server registers a URL (endpoint) and is pushed data rather than polling for updates." , front_translations: {"es":"Webhook","it":"Webhook","de":"Webhook","fr":"Webhook","tr":"Webhook","nl":"Webhook","ru":"Webhook","zh":"Webhook","pt_BR":"Webhook","pt_PT":"Webhook"}, back_translations: {"es":"Un mecanismo para un servidor notificar outro via solicitud HTTP POST cuando un evento ocurre ('API reversa'). El servidor receptor registra una URL (endpoint) y recibe datos por push en vez de consultar atualizaciones.","it":"Un mecanisme permettant à un servore di notifier un autre via una requete HTTP POST lorsqu'un evenement se prodotto ('API inversee'). Il servore receptore enregistre una URL (endpoint) e rezoit i donnees en push plutot che di i interroger.","de":"Ein Mechanismus, mit dem ein Server einen anderen über eine HTTP POST-Anfrage benachrichtigt, wenn ein Ereignis eintritt ('umgekehrte API'). Der empfangende Server registriert eine URL (Endpunkt) und erhält Daten per Push, anstatt Aktualisierungen abzufragen.","fr":"Un mécanisme permettant à un serveur de notifier un autre via une requête HTTP POST lorsqu'un événement se produit ('API inversée'). Le serveur récepteur enregistre une URL (endpoint) et reçoit les données en push plutôt que de les interroger.","tr":"Bir olay gerçekleştiğinde bir sunucunun diğerini HTTP POST isteği ile bilgilendirmesini sağlayan mekanizma ('ters API'). Alıcı sunucu bir URL (uç nokta) kaydeder ve güncellemeleri sorgulamak yerine veri push ile alır.","nl":"Een mechanisme waarmee een server een andere kan notificeren via een HTTP POST-verzoek wanneer een gebeurtenis plaatsvindt ('omgekeerde API'). De ontvangende server registreert een URL (endpoint) en ontvangt data via push in plaats van te pollen.","ru":"Механизм уведомления одного сервера другим через HTTP POST-запрос при наступлении события ('обратный API'). Принимающий сервер регистрирует URL (эндпоинт) и получает данные через push вместо опроса.","zh":"一种当事件发生时，一个服务器通过HTTP POST请求通知另一个服务器的机制（'反向API'）。接收服务器注册一个URL（端点），数据被推送而非轮询获取。","pt_BR":"Um mecanismo para um servidor notificar outro via requisição HTTP POST quando um evento ocorre ('API reversa'). O servidor receptor registra uma URL (endpoint) e recebe dados por push em vez de consultar atualizações.","pt_PT":"Um mecanismo para um servidor notificar outro via pedido HTTP POST quando um evento ocorre ('API inversa'). O servidor recetor regista uma URL (endpoint) e recebe dados por push em vez de consultar atualizações."}},
  { id: 'dc-technology-0122', deck_id: 'deck-technology', sort_order: 122, front: "Message Queue", back: "A system enabling asynchronous communication between services by placing messages in a queue for the receiver to process independently. Examples: RabbitMQ, Apache Kafka, AWS SQS. Decouples producers from consumers." , front_translations: {"es":"Fila de Mensajes","it":"File di messages","de":"Nachrichtenwarteschlange","fr":"File de messages","tr":"Mesaj Kuyruğu","nl":"Berichtenwachtrij","ru":"Очередь сообщений","zh":"消息队列","pt_BR":"Fila de Mensagens","pt_PT":"Fila de Mensagens"}, back_translations: {"es":"Un sistema que permite comunicación assíncrona entre serviços colocando mensajes en una fila para el receptor processar independentemente. Ejemplos: RabbitMQ, Apache Kafka, AWS SQS. Desacopla produtores de consumidores.","it":"Un sistema permettant la communicazione asynchrone tra services en plazant dei messages in una file d'attente che il receptore traite independamment. Exemples : RabbitMQ, Apache Kafka, AWS SQS. Decouple i productori dei consommatori.","de":"Ein System, das asynchrone Kommunikation zwischen Diensten ermöglicht, indem Nachrichten in eine Warteschlange gestellt werden, die der Empfänger unabhängig verarbeitet. Beispiele: RabbitMQ, Apache Kafka, AWS SQS. Entkoppelt Produzenten von Konsumenten.","fr":"Un système permettant la communication asynchrone entre services en plaçant des messages dans une file d'attente que le récepteur traite indépendamment. Exemples : RabbitMQ, Apache Kafka, AWS SQS. Découple les producteurs des consommateurs.","tr":"Mesajları alıcının bağımsız olarak işleyeceği bir kuyruğa yerleştirerek servisler arasında asenkron iletişim sağlayan bir sistem. Örnekler: RabbitMQ, Apache Kafka, AWS SQS. Üreticileri tüketicilerden ayırır.","nl":"Een systeem dat asynchrone communicatie tussen services mogelijk maakt door berichten in een wachtrij te plaatsen die de ontvanger onafhankelijk verwerkt. Voorbeelden: RabbitMQ, Apache Kafka, AWS SQS. Ontkoppelt producenten van consumenten.","ru":"Система, обеспечивающая асинхронную коммуникацию между сервисами, помещая сообщения в очередь для независимой обработки получателем. Примеры: RabbitMQ, Apache Kafka, AWS SQS. Отделяет производителей от потребителей.","zh":"一种通过将消息放入队列来实现服务间异步通信的系统，接收方独立处理消息。例如：RabbitMQ、Apache Kafka、AWS SQS。将生产者与消费者解耦。","pt_BR":"Um sistema que permite comunicação assíncrona entre serviços colocando mensagens em uma fila para o receptor processar independentemente. Exemplos: RabbitMQ, Apache Kafka, AWS SQS. Desacopla produtores de consumidores.","pt_PT":"Um sistema que permite comunicação assíncrona entre serviços colocando mensagens numa fila para o recetor processar independentemente. Exemplos: RabbitMQ, Apache Kafka, AWS SQS. Desacopla produtores de consumidores."}},
  { id: 'dc-technology-0123', deck_id: 'deck-technology', sort_order: 123, front: "Event-Driven Architecture", back: "A design pattern where services communicate by producing and consuming events. Decouples producers from consumers, enabling scalability and loose coupling. Used in serverless, microservices, and real-time systems." , front_translations: {"es":"Arquitetura Orientada a Eventos","it":"Architecture evenementielle","de":"Ereignisgesteuerte Architektur","fr":"Architecture événementielle","tr":"Olay Güdümlü Mimari","nl":"Event-driven architectuur","ru":"Событийно-ориентированная архитектура","zh":"事件驱动架构","pt_BR":"Arquitetura Orientada a Eventos","pt_PT":"Arquitetura Orientada a Eventos"}, back_translations: {"es":"Un padrão de design donde serviços se comunicam produciendo y consumindo eventos. Desacopla produtores de consumidores, permitiendo escalabilidad y acoplamento débil. Usado en sistemas serverless, microsserviços y tiempo real.","it":"Un patron di concepzione où i services communiquent en produisant e consommant dei evenements. Decouple i productori dei consommatori, permettant la scalabilite e un couplage faible. Utilise in i sistemi serverless, microservices e temps reel.","de":"Ein Entwurfsmuster, bei dem Dienste durch das Erzeugen und Konsumieren von Ereignissen kommunizieren. Entkoppelt Produzenten von Konsumenten und ermöglicht Skalierbarkeit und lose Kopplung. Verwendet in serverlosen, Microservices- und Echtzeitsystemen.","fr":"Un patron de conception où les services communiquent en produisant et consommant des événements. Découple les producteurs des consommateurs, permettant la scalabilité et un couplage faible. Utilisé dans les systèmes serverless, microservices et temps réel.","tr":"Servislerin olay üreterek ve tüketerek iletişim kurduğu bir tasarım kalıbı. Üreticileri tüketicilerden ayırarak ölçeklenebilirlik ve gevşek bağlantı sağlar. Sunucusuz, mikro servisler ve gerçek zamanlı sistemlerde kullanılır.","nl":"Een ontwerppatroon waarbij services communiceren door events te produceren en te consumeren. Ontkoppelt producenten van consumenten, wat schaalbaarheid en losse koppeling mogelijk maakt. Gebruikt in serverless, microservices en realtime systemen.","ru":"Шаблон проектирования, при котором сервисы обмениваются данными через генерацию и потребление событий. Отделяет производителей от потребителей, обеспечивая масштабируемость и слабую связанность. Используется в бессерверных, микросервисных и системах реального времени.","zh":"一种服务通过生成和消费事件进行通信的设计模式。将生产者与消费者解耦，实现可扩展性和松耦合。用于无服务器、微服务和实时系统。","pt_BR":"Um padrão de design onde serviços se comunicam produzindo e consumindo eventos. Desacopla produtores de consumidores, permitindo escalabilidade e acoplamento fraco. Usado em sistemas serverless, microsserviços e tempo real.","pt_PT":"Um padrão de design onde serviços comunicam produzindo e consumindo eventos. Desacopla produtores de consumidores, permitindo escalabilidade e acoplamento fraco. Usado em sistemas serverless, microsserviços e tempo real."}},
  { id: 'dc-technology-0124', deck_id: 'deck-technology', sort_order: 124, front: "Idempotency", back: "A property of an operation that produces the same result regardless of how many times it is performed. Crucial in APIs and distributed systems. GET, PUT, DELETE should be idempotent; POST generally is not." , front_translations: {"es":"Idempotencia","it":"Idempotenza","de":"Idempotenz","fr":"Idempotence","tr":"İdempotentlik","nl":"Idempotentie","ru":"Идемпотентность","zh":"幂等性","pt_BR":"Idempotência","pt_PT":"Idempotência"}, back_translations: {"es":"Una propiedad de una operación que produce el mismo resultado independentemente de quantas veces es executada. Crucial en APIs y sistemas distribuídos. GET, PUT, DELETE devem ser idempotentes; POST generalmente no es.","it":"Una propriete d'una operazione che prodotto il stesso resultat quel che soit il nombre di fois che elle e executee. Crucial in i APIs e i sistemi distribues. GET, PUT, DELETE doivent etre idempotents ; POST non l'e generalement .","de":"Eine Eigenschaft einer Operation, die unabhängig davon, wie oft sie ausgeführt wird, dasselbe Ergebnis liefert. Entscheidend in APIs und verteilten Systemen. GET, PUT, DELETE sollten idempotent sein; POST ist es in der Regel nicht.","fr":"Une propriété d'une opération qui produit le même résultat quel que soit le nombre de fois qu'elle est exécutée. Crucial dans les APIs et les systèmes distribués. GET, PUT, DELETE doivent être idempotents ; POST ne l'est généralement pas.","tr":"Bir işlemin kaç kez yapılırsa yapılsın aynı sonucu üretme özelliği. API'ler ve dağıtık sistemlerde kritik öneme sahiptir. GET, PUT, DELETE idempotent olmalıdır; POST genellikle değildir.","nl":"Een eigenschap van een operatie die hetzelfde resultaat oplevert ongeacht hoe vaak deze wordt uitgevoerd. Cruciaal in APIs en gedistribueerde systemen. GET, PUT, DELETE moeten idempotent zijn; POST is dat over het algemeen niet.","ru":"Свойство операции, которая даёт одинаковый результат независимо от количества выполнений. Критически важно в API и распределённых системах. GET, PUT, DELETE должны быть идемпотентны; POST обычно нет.","zh":"一种操作的属性，无论执行多少次都会产生相同的结果。在API和分布式系统中至关重要。GET、PUT、DELETE应该是幂等的；POST通常不是。","pt_BR":"Uma propriedade de uma operação que produz o mesmo resultado independentemente de quantas vezes é executada. Crucial em APIs e sistemas distribuídos. GET, PUT, DELETE devem ser idempotentes; POST geralmente não é.","pt_PT":"Uma propriedade de uma operação que produz o mesmo resultado independentemente de quantas vezes é executada. Crucial em APIs e sistemas distribuídos. GET, PUT, DELETE devem ser idempotentes; POST geralmente não é."}},
  { id: 'dc-technology-0125', deck_id: 'deck-technology', sort_order: 125, front: "Latency vs. Throughput", back: "Latency: the time to complete a single operation (ms). Throughput: the number of operations completed per unit time (requests/sec). Optimizing for one can harm the other; balance depends on use case." , front_translations: {"es":"Latencia vs. Vazão","it":"Latenza vs. Debit","de":"Latenz vs. Durchsatz","fr":"Latence vs. Débit","tr":"Gecikme vs. İş Hacmi","nl":"Latentie vs. Doorvoer","ru":"Задержка и пропускная способность","zh":"延迟与吞吐量","pt_BR":"Latência vs. Vazão","pt_PT":"Latência vs. Débito"}, back_translations: {"es":"Latencia: el tiempo para completar una única operación (ms). Vazão: el número de operaciones completadas por unidad de tiempo (solicitudes/seg). Otimizar un puede prejudicar el outro; el equilíbrio depende del caso de uso.","it":"Latenza : il temps per effectuer una seule operazione (ms). Debit : il nombre d'operazioni effectuees per unite di temps (requetes/sec). Optimiser l'un può nuire all'autre ; l'equilibrio depend del cas d'utilisazione.","de":"Latenz: die Zeit zur Ausführung einer einzelnen Operation (ms). Durchsatz: die Anzahl der abgeschlossenen Operationen pro Zeiteinheit (Anfragen/Sek). Die Optimierung eines Aspekts kann den anderen beeinträchtigen; die Balance hängt vom Anwendungsfall ab.","fr":"Latence : le temps pour effectuer une seule opération (ms). Débit : le nombre d'opérations effectuées par unité de temps (requêtes/sec). Optimiser l'un peut nuire à l'autre ; l'équilibre dépend du cas d'utilisation.","tr":"Gecikme: tek bir işlemi tamamlama süresi (ms). İş hacmi: birim zamanda tamamlanan işlem sayısı (istek/sn). Birini optimize etmek diğerine zarar verebilir; denge kullanım durumuna bağlıdır.","nl":"Latentie: de tijd om een enkele operatie te voltooien (ms). Doorvoer: het aantal voltooide operaties per tijdseenheid (verzoeken/sec). Optimaliseren voor het ene kan het andere schaden; balans hangt af van het gebruik.","ru":"Задержка: время выполнения одной операции (мс). Пропускная способность: количество операций в единицу времени (запросов/сек). Оптимизация одного может ухудшить другое; баланс зависит от сценария использования.","zh":"延迟：完成单次操作的时间（毫秒）。吞吐量：单位时间内完成的操作数（请求/秒）。优化其中一个可能会损害另一个；平衡取决于使用场景。","pt_BR":"Latência: o tempo para completar uma única operação (ms). Vazão: o número de operações completadas por unidade de tempo (requisições/seg). Otimizar um pode prejudicar o outro; o equilíbrio depende do caso de uso.","pt_PT":"Latência: o tempo para completar uma única operação (ms). Débito: o número de operações completadas por unidade de tempo (pedidos/seg). Otimizar um pode prejudicar o outro; o equilíbrio depende do caso de uso."}},
  { id: 'dc-technology-0126', deck_id: 'deck-technology', sort_order: 126, front: "Horizontal vs. Vertical Scaling", back: "Vertical scaling (scale up): add more resources to one machine (CPU, RAM). Horizontal scaling (scale out): add more machines. Horizontal scaling is preferred for cloud-native systems; no single point of failure." , front_translations: {"es":"Escalabilidad horizontal vs. vertical","it":"Mise all'echelle horizontale vs. verticale","de":"Horizontale vs. vertikale Skalierung","fr":"Mise à l'échelle horizontale vs. verticale","tr":"Yatay ve Dikey Ölçeklendirme","nl":"Horizontale vs. verticale schaling","ru":"Горизонтальное и вертикальное масштабирование","zh":"水平扩展与垂直扩展","pt_BR":"Escalabilidade horizontal vs. vertical","pt_PT":"Escalabilidade horizontal vs. vertical"}, back_translations: {"es":"Escalabilidad vertical (scale up): adicionar más recursos a una máquina (CPU, RAM). Escalabilidad horizontal (scale out): adicionar más máquinas. La escalabilidad horizontal es preferida para sistemas nativos de nuvem; sin punto único de falha.","it":"Mise all'echelle verticale (scale up) : ajouter più di resurces à una machine (CPU, RAM). Mise all'echelle horizontale (scale out) : ajouter più di machines. La mise all'echelle horizontale e preferee per i sistemi cloud natifs ; di point di defaillanza unico.","de":"Vertikale Skalierung (Scale Up): mehr Ressourcen zu einer Maschine hinzufügen (CPU, RAM). Horizontale Skalierung (Scale Out): mehr Maschinen hinzufügen. Horizontale Skalierung wird für Cloud-native Systeme bevorzugt; kein einzelner Ausfallpunkt.","fr":"Mise à l'échelle verticale (scale up) : ajouter plus de ressources à une machine (CPU, RAM). Mise à l'échelle horizontale (scale out) : ajouter plus de machines. La mise à l'échelle horizontale est préférée pour les systèmes cloud natifs ; pas de point de défaillance unique.","tr":"Dikey ölçeklendirme (scale up): bir makineye daha fazla kaynak ekleme (CPU, RAM). Yatay ölçeklendirme (scale out): daha fazla makine ekleme. Bulut tabanlı sistemler için yatay ölçeklendirme tercih edilir; tek hata noktası yoktur.","nl":"Verticale schaling (scale up): meer resources toevoegen aan één machine (CPU, RAM). Horizontale schaling (scale out): meer machines toevoegen. Horizontale schaling heeft de voorkeur voor cloud-native systemen; geen single point of failure.","ru":"Вертикальное масштабирование (scale up): добавление ресурсов к одной машине (CPU, RAM). Горизонтальное масштабирование (scale out): добавление машин. Горизонтальное масштабирование предпочтительно для облачных систем; нет единой точки отказа.","zh":"垂直扩展（scale up）：向一台机器添加更多资源（CPU、RAM）。水平扩展（scale out）：添加更多机器。云原生系统优先选择水平扩展；无单点故障。","pt_BR":"Escalabilidade vertical (scale up): adicionar mais recursos a uma máquina (CPU, RAM). Escalabilidade horizontal (scale out): adicionar mais máquinas. A escalabilidade horizontal é preferida para sistemas nativos de nuvem; sem ponto único de falha.","pt_PT":"Escalabilidade vertical (scale up): adicionar mais recursos a uma máquina (CPU, RAM). Escalabilidade horizontal (scale out): adicionar mais máquinas. A escalabilidade horizontal é preferida para sistemas nativos de nuvem; sem ponto único de falha."}},
  { id: 'dc-technology-0127', deck_id: 'deck-technology', sort_order: 127, front: "Eventual Consistency", back: "A consistency model in distributed systems where all replicas will converge to the same value eventually, but may not be consistent at any given moment. Used by many NoSQL databases and DNS." , front_translations: {"es":"Consistencia eventual","it":"Coherenza à terme","de":"Eventuelle Konsistenz","fr":"Cohérence à terme","tr":"Nihai Tutarlılık","nl":"Uiteindelijke consistentie","ru":"Согласованность в конечном счёте","zh":"最终一致性","pt_BR":"Consistência eventual","pt_PT":"Consistência eventual"}, back_translations: {"es":"Un modelo de consistencia en sistemas distribuídos donde todas las réplicas convergirão eventualmente para el mismo valor, pero pueden no ser consistentes en un dato momento. Usado por muchos bases de datos NoSQL y DNS.","it":"Un modeil di coherenza in i sistemi distribues où tutti i replicas convergeront eventuellement verso la stesso valore, ma possono non etre coherents à un instant donne. Utilise per di nombreuses basi di donnees NoSQL e il DNS.","de":"Ein Konsistenzmodell in verteilten Systemen, bei dem alle Replikate schließlich zum selben Wert konvergieren, aber zu einem bestimmten Zeitpunkt inkonsistent sein können. Wird von vielen NoSQL-Datenbanken und DNS verwendet.","fr":"Un modèle de cohérence dans les systèmes distribués où tous les réplicas convergeront éventuellement vers la même valeur, mais peuvent ne pas être cohérents à un instant donné. Utilisé par de nombreuses bases de données NoSQL et le DNS.","tr":"Dağıtık sistemlerde tüm kopyaların sonunda aynı değere yakınsayacağı, ancak herhangi bir anda tutarlı olmayabileceği bir tutarlılık modeli. Birçok NoSQL veritabanı ve DNS tarafından kullanılır.","nl":"Een consistentiemodel in gedistribueerde systemen waarbij alle replica's uiteindelijk naar dezelfde waarde convergeren, maar op elk gegeven moment inconsistent kunnen zijn. Gebruikt door veel NoSQL-databases en DNS.","ru":"Модель согласованности в распределённых системах, при которой все реплики в конечном итоге сойдутся к одному значению, но могут быть несогласованными в любой момент времени. Используется многими NoSQL базами данных и DNS.","zh":"分布式系统中的一致性模型，所有副本最终会收敛到相同的值，但在任意时刻可能不一致。被许多NoSQL数据库和DNS使用。","pt_BR":"Um modelo de consistência em sistemas distribuídos onde todas as réplicas convergirão eventualmente para o mesmo valor, mas podem não ser consistentes em um dado momento. Usado por muitos bancos de dados NoSQL e DNS.","pt_PT":"Um modelo de consistência em sistemas distribuídos onde todas as réplicas convergirão eventualmente para o mesmo valor, mas podem não ser consistentes num dado momento. Usado por muitas bases de dados NoSQL e DNS."}},
  { id: 'dc-technology-0128', deck_id: 'deck-technology', sort_order: 128, front: "Sharding (Database)", back: "Horizontal partitioning of data across multiple database instances (shards) to distribute load and storage. Each shard holds a subset of the data. Increases scalability but complicates queries and transactions." , front_translations: {"es":"Sharding (base de datos)","it":"Sharding (base di dati)","de":"Sharding (Datenbank)","fr":"Sharding (base de données)","tr":"Sharding (Veritabanı)","nl":"Sharding (database)","ru":"Шардирование (база данных)","zh":"分片（数据库）","pt_BR":"Sharding (banco de dados)","pt_PT":"Sharding (base de dados)"}, back_translations: {"es":"Particionamento horizontal de datos en várias instancias de base de datos (shards) para distribuir carga y almacenamiento. Cada shard contiene un subconjunto de los datos. Aumenta a escalabilidad, pero complica consultas y transaciones.","it":"Partitionnement horizontal dei donnees su plusiori instanze di base di donnees (shards) per distribuer la charge e il stockage. Chaque shard contiene un sotto-ensemble dei donnees. Ameliore la scalabilite ma complexifie i requetes e i transaczioni.","de":"Horizontale Partitionierung von Daten über mehrere Datenbankinstanzen (Shards), um Last und Speicher zu verteilen. Jeder Shard enthält eine Teilmenge der Daten. Erhöht die Skalierbarkeit, verkompliziert aber Abfragen und Transaktionen.","fr":"Partitionnement horizontal des données sur plusieurs instances de base de données (shards) pour distribuer la charge et le stockage. Chaque shard contient un sous-ensemble des données. Améliore la scalabilité mais complexifie les requêtes et les transactions.","tr":"Yükü ve depolamayı dağıtmak için verilerin birden fazla veritabanı örneğine (shard) yatay olarak bölünmesi. Her shard verilerin bir alt kümesini tutar. Ölçeklenebilirliği artırır ancak sorguları ve işlemleri karmaşıklaştırır.","nl":"Horizontale partitionering van gegevens over meerdere database-instanties (shards) om belasting en opslag te verdelen. Elke shard bevat een subset van de gegevens. Verhoogt schaalbaarheid maar maakt queries en transacties complexer.","ru":"Горизонтальное разделение данных по нескольким экземплярам базы данных (шардам) для распределения нагрузки и хранения. Каждый шард содержит подмножество данных. Повышает масштабируемость, но усложняет запросы и транзакции.","zh":"将数据水平分区到多个数据库实例（分片）中以分配负载和存储。每个分片包含数据的一个子集。提高了可扩展性，但使查询和事务变得复杂。","pt_BR":"Particionamento horizontal de dados em várias instâncias de banco de dados (shards) para distribuir carga e armazenamento. Cada shard contém um subconjunto dos dados. Aumenta a escalabilidade, mas complica consultas e transações.","pt_PT":"Particionamento horizontal de dados em várias instâncias de base de dados (shards) para distribuir carga e armazenamento. Cada shard contém um subconjunto dos dados. Aumenta a escalabilidade, mas complica consultas e transações."}},
  { id: 'dc-technology-0129', deck_id: 'deck-technology', sort_order: 129, front: "Replication (Database)", back: "Maintaining copies of data on multiple servers for redundancy and read scalability. Primary-replica: writes to primary, reads from replicas. Multi-primary allows writes to any node. Trade-off: consistency complexity." , front_translations: {"es":"Replicación (base de datos)","it":"Replicatione (base di dati)","de":"Replikation (Datenbank)","fr":"Réplication (base de données)","tr":"Replikasyon (Veritabanı)","nl":"Replicatie (database)","ru":"Репликация (база данных)","zh":"复制（数据库）","pt_BR":"Replicação (banco de dados)","pt_PT":"Replicação (base de dados)"}, back_translations: {"es":"Mantener cópias de datos en vários servidores para redundancia y escalabilidad de leitura. Primário-réplica: escritas en el primário, leituras de las réplicas. Multi-primário permite escritas en cualquier nó. Compensación: complexidad de consistencia.","it":"Maintenir dei copies dei donnees su plusiori servori per la redondanza e la scalabilite en lecture. Primaire-replica : ecritures su il primaire, lectures depuis i replicas. Multi-primaire : ecritures su n'importe quel nœud. Compromis : complexite della coherenza.","de":"Kopien von Daten auf mehreren Servern für Redundanz und Lese-Skalierbarkeit pflegen. Primär-Replikat: Schreiben auf Primär, Lesen von Replikaten. Multi-Primär erlaubt Schreiben auf jeden Knoten. Kompromiss: Konsistenzkomplexität.","fr":"Maintenir des copies des données sur plusieurs serveurs pour la redondance et la scalabilité en lecture. Primaire-réplica : écritures sur le primaire, lectures depuis les réplicas. Multi-primaire : écritures sur n'importe quel nœud. Compromis : complexité de la cohérence.","tr":"Yedeklilik ve okuma ölçeklenebilirliği için verilerin birden fazla sunucuda kopyalarının tutulması. Birincil-kopya: birincile yazma, kopyalardan okuma. Çoklu birincil, herhangi bir düğüme yazmaya izin verir. Ödünleşim: tutarlılık karmaşıklığı.","nl":"Kopieën van gegevens op meerdere servers bewaren voor redundantie en leesschaalbaarheid. Primair-replica: schrijven naar primair, lezen van replica's. Multi-primair staat schrijven naar elk knooppunt toe. Afweging: consistentiecomplexiteit.","ru":"Поддержание копий данных на нескольких серверах для отказоустойчивости и масштабируемости чтения. Первичный-реплика: запись на первичный, чтение с реплик. Мульти-мастер позволяет запись на любой узел. Компромисс: сложность обеспечения согласованности.","zh":"在多台服务器上维护数据副本以实现冗余和读取可扩展性。主-副本：写入主节点，从副本读取。多主模式允许写入任何节点。权衡：一致性复杂度。","pt_BR":"Manter cópias de dados em vários servidores para redundância e escalabilidade de leitura. Primário-réplica: escritas no primário, leituras das réplicas. Multi-primário permite escritas em qualquer nó. Compensação: complexidade de consistência.","pt_PT":"Manter cópias de dados em vários servidores para redundância e escalabilidade de leitura. Primário-réplica: escritas no primário, leituras das réplicas. Multi-primário permite escritas em qualquer nó. Compensação: complexidade de consistência."}},
  { id: 'dc-technology-0130', deck_id: 'deck-technology', sort_order: 130, front: "Machine Learning: Supervised vs. Unsupervised", back: "Supervised learning: model trained on labeled data to predict outputs (classification, regression). Unsupervised learning: model finds patterns in unlabeled data (clustering, dimensionality reduction). Reinforcement learning: learns via rewards." , front_translations: {"es":"Machine Learning: supervisionado vs. no supervisionado","it":"Machine Learning : supervise vs. non supervise","de":"Machine Learning: Überwachtes vs. unüberwachtes Lernen","fr":"Machine Learning : supervisé vs. non supervisé","tr":"Makine Öğrenimi: Denetimli ve Denetimsiz","nl":"Machine Learning: gesuperviseerd vs. ongesuperviseerd","ru":"Машинное обучение: обучение с учителем и без учителя","zh":"机器学习：监督学习与无监督学习","pt_BR":"Machine Learning: supervisionado vs. não supervisionado","pt_PT":"Machine Learning: supervisionado vs. não supervisionado"}, back_translations: {"es":"Aprendizaje supervisionado: modelo treinado en datos rotulados para prever saídas (classificación, regresión). Aprendizaje no supervisionado: modelo encontra padrões en datos no rotulados (agrupamento, reducción de dimensionalidad). Aprendizaje por refuerzo: aprende via recompensas.","it":"Apprendimento supervise : il modeil e entraine su dei donnees etiquetees per predire dei resultats (classificazione, regression). Apprendimento non supervise : il modeil trouve dei patterns in dei donnees non etiquetees (clustering, reduczione di dimensionnalite). Apprendimento per rinforzo : apprendimento via dei recompenses.","de":"Überwachtes Lernen: Modell wird mit gelabelten Daten trainiert, um Ausgaben vorherzusagen (Klassifikation, Regression). Unüberwachtes Lernen: Modell findet Muster in ungelabelten Daten (Clustering, Dimensionsreduktion). Verstärkendes Lernen: lernt durch Belohnungen.","fr":"Apprentissage supervisé : le modèle est entraîné sur des données étiquetées pour prédire des résultats (classification, régression). Apprentissage non supervisé : le modèle trouve des patterns dans des données non étiquetées (clustering, réduction de dimensionnalité). Apprentissage par renforcement : apprentissage via des récompenses.","tr":"Denetimli öğrenme: model, çıktıları tahmin etmek için etiketli verilerle eğitilir (sınıflandırma, regresyon). Denetimsiz öğrenme: model, etiketlenmemiş verilerde kalıplar bulur (kümeleme, boyut azaltma). Pekiştirmeli öğrenme: ödüllerle öğrenir.","nl":"Gesuperviseerd leren: model getraind op gelabelde data om output te voorspellen (classificatie, regressie). Ongesuperviseerd leren: model vindt patronen in niet-gelabelde data (clustering, dimensiereductie). Reinforcement learning: leert via beloningen.","ru":"Обучение с учителем: модель обучается на размеченных данных для предсказания результатов (классификация, регрессия). Обучение без учителя: модель находит закономерности в неразмеченных данных (кластеризация, снижение размерности). Обучение с подкреплением: обучение через вознаграждения.","zh":"监督学习：模型在标注数据上训练以预测输出（分类、回归）。无监督学习：模型在未标注数据中发现模式（聚类、降维）。强化学习：通过奖励进行学习。","pt_BR":"Aprendizado supervisionado: modelo treinado em dados rotulados para prever saídas (classificação, regressão). Aprendizado não supervisionado: modelo encontra padrões em dados não rotulados (agrupamento, redução de dimensionalidade). Aprendizado por reforço: aprende via recompensas.","pt_PT":"Aprendizagem supervisionada: modelo treinado em dados rotulados para prever saídas (classificação, regressão). Aprendizagem não supervisionada: modelo encontra padrões em dados não rotulados (agrupamento, redução de dimensionalidade). Aprendizagem por reforço: aprende via recompensas."}},
  { id: 'dc-technology-0131', deck_id: 'deck-technology', sort_order: 131, front: "Overfitting and Underfitting", back: "Overfitting: model fits training data too closely, failing to generalize to new data. Underfitting: model is too simple to capture the underlying pattern. Balance via regularization, cross-validation, and appropriate model complexity." , front_translations: {"es":"Overfitting y underfitting","it":"Surapprendimento e sous-apprendimento","de":"Overfitting und Underfitting","fr":"Surapprentissage et sous-apprentissage","tr":"Aşırı Öğrenme ve Yetersiz Öğrenme","nl":"Overfitting en underfitting","ru":"Переобучение и недообучение","zh":"过拟合与欠拟合","pt_BR":"Overfitting e underfitting","pt_PT":"Overfitting e underfitting"}, back_translations: {"es":"Overfitting: modelo se ajusta demais a los datos de treino, falhando en generalizar para nuevos datos. Underfitting: modelo es simples demais para capturar el padrão subjacente. Equilíbrio via regularización, validación cruzada y complexidad de modelo adequada.","it":"Surapprendimento : il modeil s'ajuste trop ai donnees d'entrainement, echouant à generaliser. Sous-apprendimento : il modeil e trop simple per capturer il pattern sotto-jacent. Equilibre via la regularisazione, la validazione croisee e una complexite di modeil appropriee.","de":"Overfitting: Modell passt sich Trainingsdaten zu genau an, kann nicht auf neue Daten verallgemeinern. Underfitting: Modell ist zu einfach, um das zugrunde liegende Muster zu erfassen. Ausgleich durch Regularisierung, Kreuzvalidierung und angemessene Modellkomplexität.","fr":"Surapprentissage : le modèle s'ajuste trop aux données d'entraînement, échouant à généraliser. Sous-apprentissage : le modèle est trop simple pour capturer le pattern sous-jacent. Équilibre via la régularisation, la validation croisée et une complexité de modèle appropriée.","tr":"Aşırı öğrenme: model eğitim verilerine çok yakın uyar, yeni verilere genelleştiremez. Yetersiz öğrenme: model, altta yatan kalıbı yakalamak için çok basittir. Düzenleme, çapraz doğrulama ve uygun model karmaşıklığı ile dengelenir.","nl":"Overfitting: model past te nauw op trainingsdata en kan niet generaliseren naar nieuwe data. Underfitting: model is te simpel om het onderliggende patroon vast te leggen. Balanceer via regularisatie, kruisvalidatie en passende modelcomplexiteit.","ru":"Переобучение: модель слишком точно подстраивается под обучающие данные и не может обобщать на новые данные. Недообучение: модель слишком проста, чтобы уловить закономерность. Баланс через регуляризацию, кросс-валидацию и подбор сложности модели.","zh":"过拟合：模型过度拟合训练数据，无法泛化到新数据。欠拟合：模型过于简单，无法捕捉潜在模式。通过正则化、交叉验证和适当的模型复杂度来平衡。","pt_BR":"Overfitting: modelo se ajusta demais aos dados de treino, falhando em generalizar para novos dados. Underfitting: modelo é simples demais para capturar o padrão subjacente. Equilíbrio via regularização, validação cruzada e complexidade de modelo adequada.","pt_PT":"Overfitting: modelo ajusta-se demasiado aos dados de treino, falhando em generalizar para novos dados. Underfitting: modelo é demasiado simples para capturar o padrão subjacente. Equilíbrio via regularização, validação cruzada e complexidade de modelo adequada."}},
  { id: 'dc-technology-0132', deck_id: 'deck-technology', sort_order: 132, front: "Big Data: 3 Vs", back: "Volume (enormous amounts of data), Velocity (high speed of data generation and processing), Variety (diverse types: structured, semi-structured, unstructured). Sometimes extended to Veracity and Value." , front_translations: {"es":"Big Data: los 3 Vs","it":"Big Datha : i 3 V","de":"Big Data: Die 3 Vs","fr":"Big Data : les 3 V","tr":"Büyük Veri: 3 V","nl":"Big Data: de 3 V's","ru":"Большие данные: 3 V","zh":"大数据：3个V","pt_BR":"Big Data: os 3 Vs","pt_PT":"Big Data: os 3 Vs"}, back_translations: {"es":"Volumen (enormes quantidades de datos), Velocity (alta velocidad de geración y procesamiento), Variety (tipos diversos: estruturados, semiestruturados, no estruturados). Às veces estendido para Veracity y Value.","it":"Volume (enormes quantites di donnees), Velocite (vitesse elevee di generazione e di traitement), Variete (types divers : structure, semi-structure, non structure). Parfois etendu à Veracite e Valore.","de":"Volume (enorme Datenmengen), Velocity (hohe Geschwindigkeit der Datenerzeugung und -verarbeitung), Variety (vielfältige Typen: strukturiert, semi-strukturiert, unstrukturiert). Manchmal erweitert um Veracity und Value.","fr":"Volume (énormes quantités de données), Vélocité (vitesse élevée de génération et de traitement), Variété (types divers : structuré, semi-structuré, non structuré). Parfois étendu à Véracité et Valeur.","tr":"Volume (devasa veri miktarları), Velocity (yüksek hızda veri üretimi ve işleme), Variety (çeşitli türler: yapılandırılmış, yarı yapılandırılmış, yapılandırılmamış). Bazen Veracity ve Value ile genişletilir.","nl":"Volume (enorme hoeveelheden data), Velocity (hoge snelheid van datageneratie en -verwerking), Variety (diverse types: gestructureerd, semi-gestructureerd, ongestructureerd). Soms uitgebreid met Veracity en Value.","ru":"Volume (огромные объёмы данных), Velocity (высокая скорость генерации и обработки данных), Variety (разнообразие типов: структурированные, полуструктурированные, неструктурированные). Иногда расширяется до Veracity и Value.","zh":"Volume（海量数据）、Velocity（高速数据生成和处理）、Variety（多种类型：结构化、半结构化、非结构化）。有时扩展为Veracity和Value。","pt_BR":"Volume (enormes quantidades de dados), Velocity (alta velocidade de geração e processamento), Variety (tipos diversos: estruturados, semiestruturados, não estruturados). Às vezes estendido para Veracity e Value.","pt_PT":"Volume (enormes quantidades de dados), Velocity (alta velocidade de geração e processamento), Variety (tipos diversos: estruturados, semiestruturados, não estruturados). Por vezes estendido a Veracity e Value."}},
  { id: 'dc-technology-0133', deck_id: 'deck-technology', sort_order: 133, front: "Blockchain", back: "A distributed, append-only ledger where data is stored in cryptographically linked blocks. Immutable and tamper-resistant without a central authority. Basis of cryptocurrencies; also used in supply chain and smart contracts." , front_translations: {"es":"Blockchain","it":"Blockchain","de":"Blockchain","fr":"Blockchain","tr":"Blockchain","nl":"Blockchain","ru":"Блокчейн","zh":"区块链","pt_BR":"Blockchain","pt_PT":"Blockchain"}, back_translations: {"es":"Un livro-razão distribuído y solamente de adición, donde datos son armazenados en blocos criptograficamente vinculados. Imutable y resistente a adulteraciones sin autoridad central. Base de las criptomoedas; también usado en cadena de suministro y contratos inteligentes.","it":"Un registre distribue en ajout seul où i donnees sono stockees in dei blocs lies cryptographiquement. Immuable e resistant ai falsificazioni senza autorite centrale. Base dei cryptomonnaies ; anche utilise in la chainon d'approvisionnement e i contrats intelligents.","de":"Ein verteiltes, nur erweiterbares Hauptbuch, in dem Daten in kryptographisch verknüpften Blöcken gespeichert werden. Unveränderlich und manipulationssicher ohne zentrale Autorität. Grundlage von Kryptowährungen; auch in Lieferketten und Smart Contracts verwendet.","fr":"Un registre distribué en ajout seul où les données sont stockées dans des blocs liés cryptographiquement. Immuable et résistant aux falsifications sans autorité centrale. Base des cryptomonnaies ; aussi utilisé dans la chaîne d'approvisionnement et les contrats intelligents.","tr":"Verilerin kriptografik olarak bağlantılı bloklarda saklandığı dağıtık, yalnızca ekleme yapılabilen bir defter. Merkezi bir otorite olmadan değiştirilemez ve kurcalamaya dayanıklı. Kripto paraların temeli; tedarik zinciri ve akıllı sözleşmelerde de kullanılır.","nl":"Een gedistribueerd, append-only grootboek waarin data wordt opgeslagen in cryptografisch gekoppelde blokken. Onveranderlijk en manipulatiebestendig zonder centrale autoriteit. Basis van cryptovaluta; ook gebruikt in supply chain en smart contracts.","ru":"Распределённый реестр с возможностью только добавления, где данные хранятся в криптографически связанных блоках. Неизменяемый и устойчивый к подделке без центрального органа. Основа криптовалют; также используется в цепочках поставок и смарт-контрактах.","zh":"一种分布式、仅追加的账本，数据存储在加密链接的区块中。无需中心化机构即可实现不可篡改。加密货币的基础；也用于供应链和智能合约。","pt_BR":"Um livro-razão distribuído e somente de adição, onde dados são armazenados em blocos criptograficamente vinculados. Imutável e resistente a adulterações sem autoridade central. Base das criptomoedas; também usado em cadeia de suprimentos e contratos inteligentes.","pt_PT":"Um livro-razão distribuído e apenas de adição, onde dados são armazenados em blocos criptograficamente vinculados. Imutável e resistente a adulterações sem autoridade central. Base das criptomoedas; também usado em cadeia de abastecimento e contratos inteligentes."}},
  { id: 'dc-technology-0134', deck_id: 'deck-technology', sort_order: 134, front: "CORS — Cross-Origin Resource Sharing", back: "A browser mechanism allowing (or blocking) web pages from making requests to a different domain than the one serving the page. Servers must include appropriate CORS headers (Access-Control-Allow-Origin) to allow cross-origin requests." , front_translations: {"es":"CORS — Cross-Origin Resource Sharing","it":"CORS — Crossos-Origin Resource Sharing","de":"CORS — Cross-Origin Resource Sharing","fr":"CORS — Cross-Origin Resource Sharing","tr":"CORS — Cross-Origin Resource Sharing","nl":"CORS — Cross-Origin Resource Sharing","ru":"CORS — Cross-Origin Resource Sharing","zh":"CORS — 跨源资源共享","pt_BR":"CORS — Cross-Origin Resource Sharing","pt_PT":"CORS — Cross-Origin Resource Sharing"}, back_translations: {"es":"Un mecanismo del navegador que permite (o bloqueia) páginas web de fazer solicitudes a un domínio diferente daquele que serve a página. Servidores devem incluir los cabeçalhos CORS apropriados (Access-Control-Allow-Origin) para permitir solicitudes cross-origin.","it":"Un mecanisme del navigatore permettant (o bloquant) ai pages web d'effectuer dei requetes verso un domaine different di celui servant la page. I servori doivent inclure i en-tetes CORS appropries (Access-Control-Allow-Origin) per autoriser i requetes cross-origin.","de":"Ein Browsermechanismus, der es Webseiten erlaubt (oder blockiert), Anfragen an eine andere Domain zu senden als die, die die Seite bereitstellt. Server müssen entsprechende CORS-Header (Access-Control-Allow-Origin) setzen, um Cross-Origin-Anfragen zu erlauben.","fr":"Un mécanisme du navigateur permettant (ou bloquant) aux pages web d'effectuer des requêtes vers un domaine différent de celui servant la page. Les serveurs doivent inclure les en-têtes CORS appropriés (Access-Control-Allow-Origin) pour autoriser les requêtes cross-origin.","tr":"Web sayfalarının, sayfayı sunan alandan farklı bir alana istek yapmasına izin veren (veya engelleyen) bir tarayıcı mekanizması. Sunucular, çapraz kaynak isteklerine izin vermek için uygun CORS başlıklarını (Access-Control-Allow-Origin) içermelidir.","nl":"Een browsermechanisme dat webpagina's toestaat (of blokkeert) om verzoeken te doen naar een ander domein dan het domein dat de pagina serveert. Servers moeten de juiste CORS-headers (Access-Control-Allow-Origin) bevatten om cross-origin verzoeken toe te staan.","ru":"Механизм браузера, разрешающий (или блокирующий) веб-страницам отправлять запросы к домену, отличному от того, который обслуживает страницу. Серверы должны включать соответствующие CORS-заголовки (Access-Control-Allow-Origin) для разрешения кросс-доменных запросов.","zh":"一种浏览器机制，允许（或阻止）网页向与提供页面的域不同的域发起请求。服务器必须包含适当的CORS头（Access-Control-Allow-Origin）以允许跨源请求。","pt_BR":"Um mecanismo do navegador que permite (ou bloqueia) páginas web de fazer requisições a um domínio diferente daquele que serve a página. Servidores devem incluir os cabeçalhos CORS apropriados (Access-Control-Allow-Origin) para permitir requisições cross-origin.","pt_PT":"Um mecanismo do navegador que permite (ou bloqueia) páginas web de fazer pedidos a um domínio diferente daquele que serve a página. Os servidores devem incluir os cabeçalhos CORS apropriados (Access-Control-Allow-Origin) para permitir pedidos cross-origin."}},
  { id: 'dc-technology-0135', deck_id: 'deck-technology', sort_order: 135, front: "Serverless Computing", back: "A cloud execution model where the provider manages the infrastructure and automatically scales function execution. Developers deploy code (functions) without managing servers. Pay-per-use; examples: AWS Lambda, Azure Functions." , front_translations: {"es":"Computación serverless","it":"Serverless computing","de":"Serverless Computing","fr":"Serverless Computing","tr":"Sunucusuz Bilişim","nl":"Serverless Computing","ru":"Бессерверные вычисления","zh":"无服务器计算","pt_BR":"Computação serverless","pt_PT":"Computação serverless"}, back_translations: {"es":"Un modelo de execución en nuvem donde el provedor gerencia a infraestrutura y escala automáticamente a execución de funciones. Desarrolladores implantam código (funciones) sin gerenciar servidores. Pagamento por uso; ejemplos: AWS Lambda, Azure Functions.","it":"Un modeil d'execuzione cloud où il fournissore gere l'infrastructure e met automatiquement all'echelle l'execuzione dei fonczioni. I developpori deploient del code (fonczioni) senza gerer di servori. Paiement all'usage ; exemples : AWS Lambda, Azure Funczioni.","de":"Ein Cloud-Ausführungsmodell, bei dem der Anbieter die Infrastruktur verwaltet und die Funktionsausführung automatisch skaliert. Entwickler deployen Code (Funktionen) ohne Serververwaltung. Bezahlung nach Nutzung; Beispiele: AWS Lambda, Azure Functions.","fr":"Un modèle d'exécution cloud où le fournisseur gère l'infrastructure et met automatiquement à l'échelle l'exécution des fonctions. Les développeurs déploient du code (fonctions) sans gérer de serveurs. Paiement à l'usage ; exemples : AWS Lambda, Azure Functions.","tr":"Sağlayıcının altyapıyı yönettiği ve fonksiyon yürütmeyi otomatik olarak ölçeklendirdiği bir bulut yürütme modeli. Geliştiriciler sunucu yönetmeden kod (fonksiyonlar) dağıtır. Kullandığın kadar öde; örnekler: AWS Lambda, Azure Functions.","nl":"Een cloud-uitvoeringsmodel waarbij de provider de infrastructuur beheert en functie-uitvoering automatisch schaalt. Ontwikkelaars deployen code (functies) zonder servers te beheren. Pay-per-use; voorbeelden: AWS Lambda, Azure Functions.","ru":"Модель облачного выполнения, при которой провайдер управляет инфраструктурой и автоматически масштабирует выполнение функций. Разработчики развёртывают код (функции) без управления серверами. Оплата за использование; примеры: AWS Lambda, Azure Functions.","zh":"一种云执行模型，由提供商管理基础设施并自动扩展函数执行。开发者部署代码（函数）而无需管理服务器。按使用付费；例如：AWS Lambda、Azure Functions。","pt_BR":"Um modelo de execução em nuvem onde o provedor gerencia a infraestrutura e escala automaticamente a execução de funções. Desenvolvedores implantam código (funções) sem gerenciar servidores. Pagamento por uso; exemplos: AWS Lambda, Azure Functions.","pt_PT":"Um modelo de execução em nuvem onde o fornecedor gere a infraestrutura e escala automaticamente a execução de funções. Os programadores implantam código (funções) sem gerir servidores. Pagamento por utilização; exemplos: AWS Lambda, Azure Functions."}},
  { id: 'dc-technology-0136', deck_id: 'deck-technology', sort_order: 136, front: "Infrastructure as Code (IaC)", back: "Managing and provisioning infrastructure through machine-readable configuration files rather than manual processes. Tools: Terraform, AWS CloudFormation, Pulumi. Enables version control and reproducible environments." , front_translations: {"es":"Infraestrutura como código (IaC)","it":"Infrastruttura as Code (IaC)","de":"Infrastructure as Code (IaC)","fr":"Infrastructure as Code (IaC)","tr":"Infrastructure as Code (IaC)","nl":"Infrastructure as Code (IaC)","ru":"Инфраструктура как код (IaC)","zh":"基础设施即代码（IaC）","pt_BR":"Infraestrutura como código (IaC)","pt_PT":"Infraestrutura como código (IaC)"}, back_translations: {"es":"Gerenciamento y provisionamento de infraestrutura por medio de archivos de configuración legibles por máquina en vez de procesos manuais. Herramientas: Terraform, AWS CloudFormation, Pulumi. Permite controle de versão y ambientes reproduzibles.","it":"Geszione e provisionnement dell'infrastructure via dei fichiers di configurazione lisibles per machine plutot che dei processo manuels. Outils : Terraform, AWS CloudFormazione, Pulumi. Permet il controil di version e dei environnements reproductibles.","de":"Verwaltung und Bereitstellung von Infrastruktur durch maschinenlesbare Konfigurationsdateien statt manueller Prozesse. Tools: Terraform, AWS CloudFormation, Pulumi. Ermöglicht Versionskontrolle und reproduzierbare Umgebungen.","fr":"Gestion et provisionnement de l'infrastructure via des fichiers de configuration lisibles par machine plutôt que des processus manuels. Outils : Terraform, AWS CloudFormation, Pulumi. Permet le contrôle de version et des environnements reproductibles.","tr":"Altyapının manuel süreçler yerine makine tarafından okunabilir yapılandırma dosyaları aracılığıyla yönetilmesi ve sağlanması. Araçlar: Terraform, AWS CloudFormation, Pulumi. Sürüm kontrolü ve tekrarlanabilir ortamlar sağlar.","nl":"Beheer en provisioning van infrastructuur via machineleesbare configuratiebestanden in plaats van handmatige processen. Tools: Terraform, AWS CloudFormation, Pulumi. Maakt versiebeheer en reproduceerbare omgevingen mogelijk.","ru":"Управление и развёртывание инфраструктуры с помощью машиночитаемых конфигурационных файлов вместо ручных процессов. Инструменты: Terraform, AWS CloudFormation, Pulumi. Обеспечивает контроль версий и воспроизводимые среды.","zh":"通过机器可读的配置文件而非手动过程来管理和配置基础设施。工具：Terraform、AWS CloudFormation、Pulumi。支持版本控制和可重现的环境。","pt_BR":"Gerenciamento e provisionamento de infraestrutura por meio de arquivos de configuração legíveis por máquina em vez de processos manuais. Ferramentas: Terraform, AWS CloudFormation, Pulumi. Permite controle de versão e ambientes reproduzíveis.","pt_PT":"Gestão e aprovisionamento de infraestrutura através de ficheiros de configuração legíveis por máquina em vez de processos manuais. Ferramentas: Terraform, AWS CloudFormation, Pulumi. Permite controlo de versões e ambientes reproduzíveis."}},
  { id: 'dc-technology-0137', deck_id: 'deck-technology', sort_order: 137, front: "Proxy vs. Reverse Proxy", back: "Proxy (forward proxy): client-side; forwards client requests to servers (anonymity, caching). Reverse proxy: server-side; receives client requests and forwards to backend servers (load balancing, SSL termination, caching). Example: Nginx." , front_translations: {"es":"Proxy vs. proxy reverso","it":"Proxy vs. Reverse Proxy","de":"Proxy vs. Reverse Proxy","fr":"Proxy vs. Reverse Proxy","tr":"Proxy ve Ters Proxy","nl":"Proxy vs. reverse proxy","ru":"Прокси и обратный прокси","zh":"正向代理与反向代理","pt_BR":"Proxy vs. proxy reverso","pt_PT":"Proxy vs. proxy reverso"}, back_translations: {"es":"Proxy (forward proxy): lado del cliente; encaminha solicitudes del cliente para servidores (anonimato, cache). Proxy reverso: lado del servidor; recibe solicitudes del cliente y encaminha para servidores backend (balanceamento de carga, terminación SSL, cache). Ejemplo: Nginx.","it":"Proxy (forward proxy) : cote client ; transmet i requetes del client ai servori (anonymat, mise en cache). Reverse proxy : cote servore ; rezoit i requetes client e i transmet ai servori backend (repartizione di charge, terminaison SSL, mise en cache). Exemple : Nginx.","de":"Proxy (Forward Proxy): clientseitig; leitet Client-Anfragen an Server weiter (Anonymität, Caching). Reverse Proxy: serverseitig; empfängt Client-Anfragen und leitet sie an Backend-Server weiter (Lastverteilung, SSL-Terminierung, Caching). Beispiel: Nginx.","fr":"Proxy (forward proxy) : côté client ; transmet les requêtes du client aux serveurs (anonymat, mise en cache). Reverse proxy : côté serveur ; reçoit les requêtes client et les transmet aux serveurs backend (répartition de charge, terminaison SSL, mise en cache). Exemple : Nginx.","tr":"Proxy (ileri proxy): istemci tarafında; istemci isteklerini sunuculara iletir (anonimlik, önbellekleme). Ters proxy: sunucu tarafında; istemci isteklerini alır ve arka uç sunuculara iletir (yük dengeleme, SSL sonlandırma, önbellekleme). Örnek: Nginx.","nl":"Proxy (forward proxy): client-zijde; stuurt clientverzoeken door naar servers (anonimiteit, caching). Reverse proxy: server-zijde; ontvangt clientverzoeken en stuurt door naar backend-servers (load balancing, SSL-terminatie, caching). Voorbeeld: Nginx.","ru":"Прокси (прямой прокси): на стороне клиента; пересылает запросы клиента на серверы (анонимность, кэширование). Обратный прокси: на стороне сервера; принимает запросы клиентов и пересылает на серверы бэкенда (балансировка нагрузки, терминация SSL, кэширование). Пример: Nginx.","zh":"正向代理：客户端侧；将客户端请求转发到服务器（匿名、缓存）。反向代理：服务器侧；接收客户端请求并转发到后端服务器（负载均衡、SSL终止、缓存）。例如：Nginx。","pt_BR":"Proxy (forward proxy): lado do cliente; encaminha requisições do cliente para servidores (anonimato, cache). Proxy reverso: lado do servidor; recebe requisições do cliente e encaminha para servidores backend (balanceamento de carga, terminação SSL, cache). Exemplo: Nginx.","pt_PT":"Proxy (forward proxy): lado do cliente; encaminha pedidos do cliente para servidores (anonimato, cache). Proxy reverso: lado do servidor; recebe pedidos do cliente e encaminha para servidores backend (balanceamento de carga, terminação SSL, cache). Exemplo: Nginx."}},
  { id: 'dc-technology-0138', deck_id: 'deck-technology', sort_order: 138, front: "Object vs. Primitive Types", back: "Primitive types (int, float, bool, char) hold values directly and are typically stack-allocated. Objects/reference types hold a reference (pointer) to heap-allocated data. Copying primitives copies values; copying objects copies references." , front_translations: {"es":"Tipos objeto vs. primitivos","it":"Types objet vs. primitivi","de":"Objekt- vs. primitive Typen","fr":"Types objet vs. primitifs","tr":"Nesne ve İlkel Türler","nl":"Object- vs. primitieve typen","ru":"Объектные и примитивные типы","zh":"对象类型与基本类型","pt_BR":"Tipos objeto vs. primitivos","pt_PT":"Tipos objeto vs. primitivos"}, back_translations: {"es":"Tipos primitivos (int, float, bool, char) almacenan valores directamente y son típicamente alocados en la pilha. Objetos/tipos de referencia almacenan una referencia (pontero) para datos alocados en el heap. Copiar primitivos copia valores; copiar objetos copia referencias.","it":"I types primitifs (int, float, bool, char) contiennent directement dei valori e sono generalement alloues su la pile. I objets/types referenza contiennent una referenza (pointore) verso dei donnees allouees su il tas. Copier un primitif copie la valore ; copier un objet copie la referenza.","de":"Primitive Typen (int, float, bool, char) speichern Werte direkt und werden typischerweise auf dem Stack allokiert. Objekte/Referenztypen halten eine Referenz (Zeiger) auf heap-allokierte Daten. Kopieren von Primitiven kopiert Werte; Kopieren von Objekten kopiert Referenzen.","fr":"Les types primitifs (int, float, bool, char) contiennent directement des valeurs et sont généralement alloués sur la pile. Les objets/types référence contiennent une référence (pointeur) vers des données allouées sur le tas. Copier un primitif copie la valeur ; copier un objet copie la référence.","tr":"İlkel türler (int, float, bool, char) değerleri doğrudan tutar ve genellikle yığında tahsis edilir. Nesneler/referans türleri, heap'te tahsis edilen verilere bir referans (işaretçi) tutar. İlkelleri kopyalamak değerleri kopyalar; nesneleri kopyalamak referansları kopyalar.","nl":"Primitieve typen (int, float, bool, char) bevatten waarden direct en worden doorgaans op de stack gealloceerd. Objecten/referentietypen bevatten een referentie (pointer) naar heap-gealloceerde data. Primitieven kopiëren kopieert waarden; objecten kopiëren kopieert referenties.","ru":"Примитивные типы (int, float, bool, char) хранят значения напрямую и обычно размещаются в стеке. Объекты/ссылочные типы хранят ссылку (указатель) на данные в куче. Копирование примитивов копирует значения; копирование объектов копирует ссылки.","zh":"基本类型（int、float、bool、char）直接存储值，通常在栈上分配。对象/引用类型持有指向堆分配数据的引用（指针）。复制基本类型复制值；复制对象复制引用。","pt_BR":"Tipos primitivos (int, float, bool, char) armazenam valores diretamente e são tipicamente alocados na pilha. Objetos/tipos de referência armazenam uma referência (ponteiro) para dados alocados no heap. Copiar primitivos copia valores; copiar objetos copia referências.","pt_PT":"Tipos primitivos (int, float, bool, char) armazenam valores diretamente e são tipicamente alocados na pilha. Objetos/tipos de referência armazenam uma referência (ponteiro) para dados alocados no heap. Copiar primitivos copia valores; copiar objetos copia referências."}},
  { id: 'dc-technology-0139', deck_id: 'deck-technology', sort_order: 139, front: "Generics (Type Parameters)", back: "A programming feature allowing classes, functions, or interfaces to operate on types specified at instantiation time. Provides type safety without code duplication. E.g., List<T> in Java/C#, templates in C++." , front_translations: {"es":"Generics (parametros de tipo)","it":"Generici (parametres di tipo)","de":"Generics (Typparameter)","fr":"Génériques (paramètres de type)","tr":"Generics (Tür Parametreleri)","nl":"Generics (typeparameters)","ru":"Обобщения (параметры типов)","zh":"泛型（类型参数）","pt_BR":"Generics (parâmetros de tipo)","pt_PT":"Generics (parâmetros de tipo)"}, back_translations: {"es":"Un recurso de programación que permite que clases, funciones o interfaces operem en tipos especificados en el momento de la instanciación. Proporciona seguridad de tipos sin duplicación de código. Ex.: List<T> en Java/C#, templates en C++.","it":"Una fonctionnalite di programmazione permettant ai classes, fonczioni o interfaces d'operer su dei types specifies all'instanciazione. Assure la securite dei types senza duplicazione di code. Ex. : List<T> en Java/C#, templates en C++.","de":"Eine Programmierfunktion, die es Klassen, Funktionen oder Interfaces ermöglicht, mit zur Instanziierungszeit angegebenen Typen zu arbeiten. Bietet Typsicherheit ohne Code-Duplizierung. Z.B. List<T> in Java/C#, Templates in C++.","fr":"Une fonctionnalité de programmation permettant aux classes, fonctions ou interfaces d'opérer sur des types spécifiés à l'instanciation. Assure la sécurité des types sans duplication de code. Ex. : List<T> en Java/C#, templates en C++.","tr":"Sınıfların, fonksiyonların veya arayüzlerin örnekleme zamanında belirtilen türler üzerinde çalışmasına olanak tanıyan bir programlama özelliği. Kod tekrarı olmadan tür güvenliği sağlar. Örn.: Java/C#'da List<T>, C++'da templates.","nl":"Een programmeerfunctie waarmee klassen, functies of interfaces kunnen werken met typen die bij instantiatie worden opgegeven. Biedt typeveiligheid zonder codeduplicatie. Bijv. List<T> in Java/C#, templates in C++.","ru":"Возможность языка программирования, позволяющая классам, функциям или интерфейсам работать с типами, указываемыми при создании экземпляра. Обеспечивает типобезопасность без дублирования кода. Напр.: List<T> в Java/C#, шаблоны в C++.","zh":"一种编程特性，允许类、函数或接口在实例化时对指定的类型进行操作。在不重复代码的情况下提供类型安全。例如Java/C#中的List<T>，C++中的模板。","pt_BR":"Um recurso de programação que permite que classes, funções ou interfaces operem em tipos especificados no momento da instanciação. Fornece segurança de tipos sem duplicação de código. Ex.: List<T> em Java/C#, templates em C++.","pt_PT":"Um recurso de programação que permite que classes, funções ou interfaces operem em tipos especificados no momento da instanciação. Fornece segurança de tipos sem duplicação de código. Ex.: List<T> em Java/C#, templates em C++."}},
  { id: 'dc-technology-0140', deck_id: 'deck-technology', sort_order: 140, front: "Monads (Functional Programming)", back: "A design pattern for handling computations with context (e.g., nullable values, async operations, errors) in a chainable, composable way. Examples: Option/Maybe (null safety), Result/Either (error handling), Promise/Future (async)." , front_translations: {"es":"Monads (programación funcional)","it":"Monades (programmatione funzioneenelle)","de":"Monaden (funktionale Programmierung)","fr":"Monades (programmation fonctionnelle)","tr":"Monadlar (Fonksiyonel Programlama)","nl":"Monads (functioneel programmeren)","ru":"Монады (функциональное программирование)","zh":"单子（函数式编程）","pt_BR":"Monads (programação funcional)","pt_PT":"Monads (programação funcional)"}, back_translations: {"es":"Un padrão de design para lidar con computaciones con contexto (ex.: valores anulables, operaciones assíncronas, erros) de forma encadeable y composable. Ejemplos: Option/Maybe (seguridad contra nulos), Result/Either (tratamiento de erros), Promise/Future (assíncrono).","it":"Un patron di concepzione per gerer dei calculs con contexte (ex. : valori nullables, operazioni asynchrones, errori) di maniere chainable e composable. Exemples : Opzione/Maybe (securite null), Result/Either (geszione d'errori), Promise/Future (async).","de":"Ein Entwurfsmuster zur Handhabung von Berechnungen mit Kontext (z.B. nullable Werte, asynchrone Operationen, Fehler) auf eine verkettbare, komponierbare Weise. Beispiele: Option/Maybe (Null-Sicherheit), Result/Either (Fehlerbehandlung), Promise/Future (Async).","fr":"Un patron de conception pour gérer des calculs avec contexte (ex. : valeurs nullables, opérations asynchrones, erreurs) de manière chaînable et composable. Exemples : Option/Maybe (sécurité null), Result/Either (gestion d'erreurs), Promise/Future (async).","tr":"Bağlamla hesaplamaları (örn. nullable değerler, asenkron işlemler, hatalar) zincirlenebilir ve birleştirilebilir bir şekilde ele almak için bir tasarım kalıbı. Örnekler: Option/Maybe (null güvenliği), Result/Either (hata yönetimi), Promise/Future (asenkron).","nl":"Een ontwerppatroon voor het afhandelen van berekeningen met context (bijv. nullable waarden, async operaties, fouten) op een chainable, composable manier. Voorbeelden: Option/Maybe (null-veiligheid), Result/Either (foutafhandeling), Promise/Future (async).","ru":"Шаблон проектирования для обработки вычислений с контекстом (например, nullable значения, асинхронные операции, ошибки) цепочечным, компонуемым способом. Примеры: Option/Maybe (null-безопасность), Result/Either (обработка ошибок), Promise/Future (асинхронность).","zh":"一种设计模式，用于以可链式、可组合的方式处理带上下文的计算（如可空值、异步操作、错误）。例如：Option/Maybe（空安全）、Result/Either（错误处理）、Promise/Future（异步）。","pt_BR":"Um padrão de design para lidar com computações com contexto (ex.: valores anuláveis, operações assíncronas, erros) de forma encadeável e composável. Exemplos: Option/Maybe (segurança contra nulos), Result/Either (tratamento de erros), Promise/Future (assíncrono).","pt_PT":"Um padrão de design para lidar com computações com contexto (ex.: valores anuláveis, operações assíncronas, erros) de forma encadeável e composável. Exemplos: Option/Maybe (segurança contra nulos), Result/Either (tratamento de erros), Promise/Future (assíncrono)."}},
  { id: 'dc-technology-0141', deck_id: 'deck-technology', sort_order: 141, front: "Event Sourcing", back: "A persistence pattern where state is derived from a sequence of immutable events rather than storing the current state. Enables full audit trails, temporal queries, and easy event replay for rebuilding state." , front_translations: {"es":"Event Sourcing","it":"Event Sourcing","de":"Event Sourcing","fr":"Event Sourcing","tr":"Event Sourcing","nl":"Event Sourcing","ru":"Событийное хранение (Event Sourcing)","zh":"事件溯源","pt_BR":"Event Sourcing","pt_PT":"Event Sourcing"}, back_translations: {"es":"Un padrão de persistencia donde el estado es derivado de una secuencia de eventos imutables en vez de armazenar el estado atual. Permite trilhas de auditoria completas, consultas temporais y fácil replay de eventos para reconstrución de estado.","it":"Un patron di persistanza où l'etat e derive d'una sequenza d'evenements immuables plutot che di stocker l'etat actuel. Permet dei pistes d'audit completes, dei requetes temporelles e un rejeu facile dei evenements per reconstruire l'etat.","de":"Ein Persistenzmuster, bei dem der Zustand aus einer Sequenz unveränderlicher Ereignisse abgeleitet wird, anstatt den aktuellen Zustand zu speichern. Ermöglicht vollständige Audit-Trails, temporale Abfragen und einfaches Event-Replay zur Zustandsrekonstruktion.","fr":"Un patron de persistance où l'état est dérivé d'une séquence d'événements immuables plutôt que de stocker l'état actuel. Permet des pistes d'audit complètes, des requêtes temporelles et un rejeu facile des événements pour reconstruire l'état.","tr":"Durumun, mevcut durumu saklamak yerine değiştirilemez olaylar dizisinden türetildiği bir kalıcılık kalıbı. Tam denetim izleri, zamansal sorgular ve durumu yeniden oluşturmak için kolay olay tekrarı sağlar.","nl":"Een persistentiepatroon waarbij de staat wordt afgeleid uit een reeks onveranderlijke events in plaats van de huidige staat op te slaan. Maakt volledige audit trails, temporele queries en eenvoudige event replay voor het herbouwen van staat mogelijk.","ru":"Паттерн хранения, при котором состояние выводится из последовательности неизменяемых событий, а не путём сохранения текущего состояния. Обеспечивает полные аудиторские записи, темпоральные запросы и лёгкое воспроизведение событий для восстановления состояния.","zh":"一种持久化模式，状态从不可变事件序列中推导，而非存储当前状态。支持完整的审计追踪、时序查询和轻松的事件重放以重建状态。","pt_BR":"Um padrão de persistência onde o estado é derivado de uma sequência de eventos imutáveis em vez de armazenar o estado atual. Permite trilhas de auditoria completas, consultas temporais e fácil replay de eventos para reconstrução de estado.","pt_PT":"Um padrão de persistência onde o estado é derivado de uma sequência de eventos imutáveis em vez de armazenar o estado atual. Permite trilhos de auditoria completos, consultas temporais e fácil repetição de eventos para reconstrução de estado."}},
  { id: 'dc-technology-0142', deck_id: 'deck-technology', sort_order: 142, front: "CQRS — Command Query Responsibility Segregation", back: "An architectural pattern separating read (query) and write (command) operations into different models. Optimizes each independently; pairs well with event sourcing and microservices. Increases complexity." , front_translations: {"es":"CQRS — Segregación de Responsabilidad de Comando y Consulta","it":"CQRS — Command Query Responsibility Segregatione","de":"CQRS — Command Query Responsibility Segregation","fr":"CQRS — Command Query Responsibility Segregation","tr":"CQRS — Command Query Responsibility Segregation","nl":"CQRS — Command Query Responsibility Segregation","ru":"CQRS — разделение ответственности команд и запросов","zh":"CQRS — 命令查询职责分离","pt_BR":"CQRS — Segregação de Responsabilidade de Comando e Consulta","pt_PT":"CQRS — Segregação de Responsabilidade de Comando e Consulta"}, back_translations: {"es":"Un padrão arquitetural que separa operaciones de leitura (query) y escrita (command) en modelos diferentes. Otimiza cada un independentemente; combina bem con event sourcing y microsserviços. Aumenta a complexidad.","it":"Un patron architectural separant i operazioni di lecture (query) e d'ecriture (command) en modei differents. Optimise chacun independamment ; se combine bien con l'event sourcing e i microservices. Augmente la complexite.","de":"Ein Architekturmuster, das Lese- (Query) und Schreib- (Command) Operationen in verschiedene Modelle trennt. Optimiert jedes unabhängig; passt gut zu Event Sourcing und Microservices. Erhöht die Komplexität.","fr":"Un patron architectural séparant les opérations de lecture (query) et d'écriture (command) en modèles différents. Optimise chacun indépendamment ; se combine bien avec l'event sourcing et les microservices. Augmente la complexité.","tr":"Okuma (sorgu) ve yazma (komut) işlemlerini farklı modellere ayıran bir mimari kalıp. Her birini bağımsız olarak optimize eder; event sourcing ve mikroservislerle iyi çalışır. Karmaşıklığı artırır.","nl":"Een architectuurpatroon dat lees- (query) en schrijf- (command) operaties scheidt in verschillende modellen. Optimaliseert elk onafhankelijk; combineert goed met event sourcing en microservices. Verhoogt complexiteit.","ru":"Архитектурный паттерн, разделяющий операции чтения (запросы) и записи (команды) на разные модели. Оптимизирует каждую независимо; хорошо сочетается с event sourcing и микросервисами. Увеличивает сложность.","zh":"一种将读（查询）和写（命令）操作分离到不同模型的架构模式。独立优化每个模型；与事件溯源和微服务配合良好。增加了复杂性。","pt_BR":"Um padrão arquitetural que separa operações de leitura (query) e escrita (command) em modelos diferentes. Otimiza cada um independentemente; combina bem com event sourcing e microsserviços. Aumenta a complexidade.","pt_PT":"Um padrão arquitetural que separa operações de leitura (query) e escrita (command) em modelos diferentes. Otimiza cada um independentemente; combina bem com event sourcing e microsserviços. Aumenta a complexidade."}},
  { id: 'dc-technology-0143', deck_id: 'deck-technology', sort_order: 143, front: "Rate Limiting", back: "Controlling the number of requests a client can make to an API within a time window. Prevents abuse, DDoS attacks, and resource exhaustion. Implemented with token bucket or leaky bucket algorithms." , front_translations: {"es":"Limitación de taxa","it":"Limitatione di debit","de":"Rate Limiting","fr":"Limitation de débit","tr":"Hız Sınırlama","nl":"Rate limiting","ru":"Ограничение частоты запросов","zh":"速率限制","pt_BR":"Limitação de taxa","pt_PT":"Limitação de taxa"}, back_translations: {"es":"Controle del número de solicitudes que un cliente puede fazer a una API dentro de una janela de tiempo. Previene abuso, ataques DDoS y esgotamento de recursos. Implementado con algoritmos token bucket o leaky bucket.","it":"Controil del nombre di requetes che un client può effectuer verso una API in una fenetre di temps. Previent i abus, i attaques DDoS e l'epuisement dei resurces. Implemente con dei algorithmes token bucket o leaky bucket.","de":"Kontrolle der Anzahl von Anfragen, die ein Client innerhalb eines Zeitfensters an eine API stellen kann. Verhindert Missbrauch, DDoS-Angriffe und Ressourcenerschöpfung. Implementiert mit Token-Bucket- oder Leaky-Bucket-Algorithmen.","fr":"Contrôle du nombre de requêtes qu'un client peut effectuer vers une API dans une fenêtre de temps. Prévient les abus, les attaques DDoS et l'épuisement des ressources. Implémenté avec des algorithmes token bucket ou leaky bucket.","tr":"Bir istemcinin belirli bir zaman penceresinde bir API'ye yapabileceği istek sayısını kontrol etme. Kötüye kullanımı, DDoS saldırılarını ve kaynak tükenmesini önler. Token bucket veya leaky bucket algoritmaları ile uygulanır.","nl":"Het beperken van het aantal verzoeken dat een client binnen een tijdvenster naar een API kan doen. Voorkomt misbruik, DDoS-aanvallen en uitputting van resources. Geïmplementeerd met token bucket- of leaky bucket-algoritmen.","ru":"Контроль количества запросов, которые клиент может отправить к API в течение временного окна. Предотвращает злоупотребления, DDoS-атаки и исчерпание ресурсов. Реализуется алгоритмами token bucket или leaky bucket.","zh":"控制客户端在时间窗口内可以向API发出的请求数量。防止滥用、DDoS攻击和资源耗尽。通过令牌桶或漏桶算法实现。","pt_BR":"Controle do número de requisições que um cliente pode fazer a uma API dentro de uma janela de tempo. Previne abuso, ataques DDoS e esgotamento de recursos. Implementado com algoritmos token bucket ou leaky bucket.","pt_PT":"Controlo do número de pedidos que um cliente pode fazer a uma API dentro de uma janela de tempo. Previne abuso, ataques DDoS e esgotamento de recursos. Implementado com algoritmos token bucket ou leaky bucket."}},
  { id: 'dc-technology-0144', deck_id: 'deck-technology', sort_order: 144, front: "SSH — Secure Shell", back: "A cryptographic network protocol for secure remote login, command execution, and file transfer. Replaces insecure Telnet and FTP. Uses public-key authentication or passwords; all traffic is encrypted. Default port 22." , front_translations: {"es":"SSH — Secure Shell","it":"SSH — Secure Shell","de":"SSH — Secure Shell","fr":"SSH — Secure Shell","tr":"SSH — Secure Shell","nl":"SSH — Secure Shell","ru":"SSH — Secure Shell","zh":"SSH — 安全外壳协议","pt_BR":"SSH — Secure Shell","pt_PT":"SSH — Secure Shell"}, back_translations: {"es":"Un protocolo de red criptográfico para login remoto seguro, execución de comandos y transferencia de archivos. Substitui Telnet y FTP inseguros. Usa autenticación por chave pública o contraseñas; todo el tráfego es criptografado. Porta padrão 22.","it":"Un protocole reseau cryptographico per la connexion à distanza securisee, l'execuzione di commandes e il transfert di fichiers. Remplace Telnet e FTP non securises. Utilise l'authentificazione per cle publico o per mot di passe ; tutto il trafic e chiffre. Port per defaut 22.","de":"Ein kryptographisches Netzwerkprotokoll für sichere Remote-Anmeldung, Befehlsausführung und Dateiübertragung. Ersetzt unsicheres Telnet und FTP. Verwendet Public-Key-Authentifizierung oder Passwörter; gesamter Datenverkehr ist verschlüsselt. Standardport 22.","fr":"Un protocole réseau cryptographique pour la connexion à distance sécurisée, l'exécution de commandes et le transfert de fichiers. Remplace Telnet et FTP non sécurisés. Utilise l'authentification par clé publique ou par mot de passe ; tout le trafic est chiffré. Port par défaut 22.","tr":"Güvenli uzaktan oturum açma, komut yürütme ve dosya transferi için bir kriptografik ağ protokolü. Güvensiz Telnet ve FTP'nin yerini alır. Açık anahtar kimlik doğrulaması veya parolalar kullanır; tüm trafik şifrelenir. Varsayılan port 22.","nl":"Een cryptografisch netwerkprotocol voor veilige remote login, opdrachtuitvoering en bestandsoverdracht. Vervangt onveilig Telnet en FTP. Gebruikt public-key authenticatie of wachtwoorden; al het verkeer is versleuteld. Standaardpoort 22.","ru":"Криптографический сетевой протокол для безопасного удалённого входа, выполнения команд и передачи файлов. Заменяет небезопасные Telnet и FTP. Использует аутентификацию по открытому ключу или пароль; весь трафик зашифрован. Порт по умолчанию 22.","zh":"一种用于安全远程登录、命令执行和文件传输的加密网络协议。取代不安全的Telnet和FTP。使用公钥认证或密码；所有流量加密。默认端口22。","pt_BR":"Um protocolo de rede criptográfico para login remoto seguro, execução de comandos e transferência de arquivos. Substitui Telnet e FTP inseguros. Usa autenticação por chave pública ou senhas; todo o tráfego é criptografado. Porta padrão 22.","pt_PT":"Um protocolo de rede criptográfico para login remoto seguro, execução de comandos e transferência de ficheiros. Substitui Telnet e FTP inseguros. Usa autenticação por chave pública ou palavras-passe; todo o tráfego é cifrado. Porta predefinida 22."}},
  { id: 'dc-technology-0145', deck_id: 'deck-technology', sort_order: 145, front: "Monorepo vs. Polyrepo", back: "Monorepo: all projects in a single repository (easy sharing, atomic commits, complex tooling). Polyrepo: each project in its own repository (simpler per-project, harder cross-project coordination). Used by Google (monorepo) and Amazon (polyrepo)." , front_translations: {"es":"Monorepo vs. polyrepo","it":"Monorepo vs. Polyrepo","de":"Monorepo vs. Polyrepo","fr":"Monorepo vs. Polyrepo","tr":"Monorepo ve Polyrepo","nl":"Monorepo vs. polyrepo","ru":"Монорепозиторий и полирепозиторий","zh":"单一仓库与多仓库","pt_BR":"Monorepo vs. polyrepo","pt_PT":"Monorepo vs. polyrepo"}, back_translations: {"es":"Monorepo: todos los projetos en un único repositório (fácil compartilhamento, commits atomicos, herramientas complexas). Polyrepo: cada projeto en su propio repositório (más simples por projeto, coordenación entre projetos más difícil). Usado por el Google (monorepo) y Amazon (polyrepo).","it":"Monorepo : tutti i projets in un seul depot (partage facile, commits atomici, outillage complexe). Polyrepo : ogni projet in il suo propre depot (più simple per projet, coordinazione inter-projets più difficile). Utilise per Google (monorepo) e Amazon (polyrepo).","de":"Monorepo: alle Projekte in einem einzigen Repository (einfaches Teilen, atomare Commits, komplexes Tooling). Polyrepo: jedes Projekt in eigenem Repository (einfacher pro Projekt, schwierigere projektübergreifende Koordination). Genutzt von Google (Monorepo) und Amazon (Polyrepo).","fr":"Monorepo : tous les projets dans un seul dépôt (partage facile, commits atomiques, outillage complexe). Polyrepo : chaque projet dans son propre dépôt (plus simple par projet, coordination inter-projets plus difficile). Utilisé par Google (monorepo) et Amazon (polyrepo).","tr":"Monorepo: tüm projeler tek bir depoda (kolay paylaşım, atomik commitler, karmaşık araçlar). Polyrepo: her proje kendi deposunda (proje başına daha basit, projeler arası koordinasyon daha zor). Google (monorepo) ve Amazon (polyrepo) tarafından kullanılır.","nl":"Monorepo: alle projecten in één repository (eenvoudig delen, atomaire commits, complex tooling). Polyrepo: elk project in eigen repository (eenvoudiger per project, moeilijkere cross-project coördinatie). Gebruikt door Google (monorepo) en Amazon (polyrepo).","ru":"Монорепозиторий: все проекты в одном репозитории (простой обмен, атомарные коммиты, сложный инструментарий). Полирепозиторий: каждый проект в своём репозитории (проще на уровне проекта, сложнее межпроектная координация). Используется Google (моно) и Amazon (поли).","zh":"单一仓库：所有项目在一个仓库中（易于共享、原子提交、工具复杂）。多仓库：每个项目独立仓库（单项目更简单、跨项目协调更难）。Google使用单一仓库，Amazon使用多仓库。","pt_BR":"Monorepo: todos os projetos em um único repositório (fácil compartilhamento, commits atômicos, ferramentas complexas). Polyrepo: cada projeto em seu próprio repositório (mais simples por projeto, coordenação entre projetos mais difícil). Usado pelo Google (monorepo) e Amazon (polyrepo).","pt_PT":"Monorepo: todos os projetos num único repositório (partilha fácil, commits atómicos, ferramentas complexas). Polyrepo: cada projeto no seu próprio repositório (mais simples por projeto, coordenação entre projetos mais difícil). Usado pela Google (monorepo) e Amazon (polyrepo)."}},
  { id: 'dc-technology-0146', deck_id: 'deck-technology', sort_order: 146, front: "Code Review", back: "A systematic examination of code by peers before merging. Improves code quality, knowledge sharing, and catches bugs early. Pull/merge requests are the typical mechanism. Review focuses on logic, readability, and standards." , front_translations: {"es":"Revisão de código","it":"Revue di code","de":"Code-Review","fr":"Revue de code","tr":"Kod İncelemesi","nl":"Code review","ru":"Ревью кода","zh":"代码审查","pt_BR":"Revisão de código","pt_PT":"Revisão de código"}, back_translations: {"es":"Un examen sistemático de código por pares antes del merge. Melhora a calidad del código, compartilhamento de conocimiento y detecta bugs temprano. Pull/merge requests son el mecanismo típico. La revisão foca en lógica, legibilidad y padrões.","it":"Un examen systematico del code per dei pairs avant la fusion. Ameliore la qualite del code, il partage dei connaissanze e detecte i bugs tot. I pull/merge requests sono il mecanisme habituel. L'examen se concentre su la logico, la lisibilite e i standards.","de":"Eine systematische Überprüfung von Code durch Kollegen vor dem Zusammenführen. Verbessert Codequalität, Wissensaustausch und erkennt Fehler frühzeitig. Pull/Merge Requests sind der typische Mechanismus. Fokus auf Logik, Lesbarkeit und Standards.","fr":"Un examen systématique du code par des pairs avant la fusion. Améliore la qualité du code, le partage des connaissances et détecte les bugs tôt. Les pull/merge requests sont le mécanisme habituel. L'examen se concentre sur la logique, la lisibilité et les standards.","tr":"Birleştirmeden önce kodun eşler tarafından sistematik olarak incelenmesi. Kod kalitesini, bilgi paylaşımını artırır ve hataları erken yakalar. Pull/merge request'ler tipik mekanizmadır. İnceleme mantık, okunabilirlik ve standartlara odaklanır.","nl":"Een systematisch onderzoek van code door collega's vóór het mergen. Verbetert codekwaliteit, kennisdeling en vangt bugs vroeg op. Pull/merge requests zijn het gebruikelijke mechanisme. Review richt zich op logica, leesbaarheid en standaarden.","ru":"Систематическая проверка кода коллегами перед слиянием. Улучшает качество кода, обмен знаниями и выявляет ошибки на ранней стадии. Pull/merge requests — типичный механизм. Ревью фокусируется на логике, читаемости и стандартах.","zh":"合并前由同行对代码进行系统化审查。提高代码质量、知识共享，并及早发现缺陷。Pull/merge request是典型机制。审查关注逻辑、可读性和标准。","pt_BR":"Um exame sistemático de código por pares antes do merge. Melhora a qualidade do código, compartilhamento de conhecimento e detecta bugs cedo. Pull/merge requests são o mecanismo típico. A revisão foca em lógica, legibilidade e padrões.","pt_PT":"Um exame sistemático de código por pares antes do merge. Melhora a qualidade do código, partilha de conhecimento e deteta bugs cedo. Pull/merge requests são o mecanismo típico. A revisão foca em lógica, legibilidade e normas."}},
  { id: 'dc-technology-0147', deck_id: 'deck-technology', sort_order: 147, front: "Technical Debt", back: "The implied cost of rework caused by choosing an easy, short-term solution over a better but more complex approach. Accumulates over time; must be managed through refactoring. The 'interest' on technical debt grows with time." , front_translations: {"es":"Dívida técnica","it":"Dette technico","de":"Technische Schulden","fr":"Dette technique","tr":"Teknik Borç","nl":"Technische schuld","ru":"Технический долг","zh":"技术债务","pt_BR":"Dívida técnica","pt_PT":"Dívida técnica"}, back_translations: {"es":"El costo implicito del retrabajo causado por elegir una solucion facil y de corto plazo en vez de un enfoque mejor pero mas complejo.","it":"Il costo implicito della rilavorazione causato dalla scelta di una soluzione facile e a breve termine invece di un approccio migliore ma piu complesso.","de":"Die impliziten Kosten für Nacharbeit, die durch die Wahl einer einfachen, kurzfristigen Lösung statt eines besseren, aber komplexeren Ansatzes entstehen. Akkumuliert sich über die Zeit; muss durch Refactoring verwaltet werden. Die 'Zinsen' auf technische Schulden wachsen mit der Zeit.","tr":"Daha iyi ama daha karmaşık bir yaklaşım yerine kolay, kısa vadeli bir çözüm seçmenin neden olduğu yeniden çalışmanın zımni maliyeti. Zamanla birikir; yeniden yapılandırma ile yönetilmelidir. Teknik borcun 'faizi' zamanla büyür.","nl":"De impliciete kosten van herwerk door het kiezen van een makkelijke, kortetermijnoplossing boven een betere maar complexere aanpak. Accumuleert over tijd; moet worden beheerd door refactoring. De 'rente' op technische schuld groeit met de tijd.","pt_BR":"O custo implícito de retrabalho causado pela escolha de uma solução fácil e de curto prazo em vez de uma abordagem melhor, mas mais complexa. Acumula-se ao longo do tempo; deve ser gerenciada por refatoração. Os 'juros' da dívida técnica crescem com o tempo.","pt_PT":"O custo implícito de retrabalho causado pela escolha de uma solução fácil e de curto prazo em vez de uma abordagem melhor, mas mais complexa. Acumula-se ao longo do tempo; deve ser gerida por refatoração. Os 'juros' da dívida técnica crescem com o tempo."}},
  { id: 'dc-technology-0148', deck_id: 'deck-technology', sort_order: 148, front: "Agile Development", back: "An iterative software development methodology emphasizing collaboration, customer feedback, and small, frequent releases. Key practices: sprints (Scrum), user stories, retrospectives, continuous integration." , front_translations: {"es":"Desarrollo ágil","it":"Sviluppoo agile","de":"Agile Entwicklung","fr":"Développement agile","tr":"Çevik Geliştirme","nl":"Agile ontwikkeling","ru":"Гибкая разработка (Agile)","zh":"敏捷开发","pt_BR":"Desenvolvimento ágil","pt_PT":"Desenvolvimento ágil"}, back_translations: {"es":"Una metodologia iterativa de desarrollo de software que enfatiza colaboración, feedback del cliente y lançamentos pequeños y frequentes. Práticas-chave: sprints (Scrum), histórias de usuario, retrospectivas, integración contínua.","it":"Una metodologia iterative di sviluppo logiciel mettant l'accent su la collaborazione, il retour client e i petites livraisons frequentes. Pratici cles : sprints (Scrum), user stories, retrospectives, integrazione continue.","de":"Eine iterative Softwareentwicklungsmethodik, die Zusammenarbeit, Kundenfeedback und kleine, häufige Releases betont. Wichtige Praktiken: Sprints (Scrum), User Stories, Retrospektiven, kontinuierliche Integration.","fr":"Une méthodologie itérative de développement logiciel mettant l'accent sur la collaboration, le retour client et les petites livraisons fréquentes. Pratiques clés : sprints (Scrum), user stories, rétrospectives, intégration continue.","tr":"İş birliğini, müşteri geri bildirimini ve küçük, sık sürümleri vurgulayan yinelemeli bir yazılım geliştirme metodolojisi. Temel pratikler: sprintler (Scrum), kullanıcı hikayeleri, retrospektifler, sürekli entegrasyon.","nl":"Een iteratieve softwareontwikkelingsmethodologie die samenwerking, klantfeedback en kleine, frequente releases benadrukt. Belangrijke praktijken: sprints (Scrum), user stories, retrospectives, continue integratie.","ru":"Итеративная методология разработки ПО, акцентирующая сотрудничество, обратную связь от заказчика и небольшие частые релизы. Ключевые практики: спринты (Scrum), пользовательские истории, ретроспективы, непрерывная интеграция.","zh":"一种迭代式软件开发方法论，强调协作、客户反馈和小型频繁发布。关键实践：冲刺（Scrum）、用户故事、回顾会议、持续集成。","pt_BR":"Uma metodologia iterativa de desenvolvimento de software que enfatiza colaboração, feedback do cliente e lançamentos pequenos e frequentes. Práticas-chave: sprints (Scrum), histórias de usuário, retrospectivas, integração contínua.","pt_PT":"Uma metodologia iterativa de desenvolvimento de software que enfatiza colaboração, feedback do cliente e lançamentos pequenos e frequentes. Práticas-chave: sprints (Scrum), histórias de utilizador, retrospetivas, integração contínua."}},
  { id: 'dc-technology-0149', deck_id: 'deck-technology', sort_order: 149, front: "DevOps", back: "A cultural and technical practice combining development and operations teams to shorten the system development lifecycle. Emphasizes automation, monitoring, CI/CD, and infrastructure as code." , front_translations: {"es":"DevOps","it":"DevOps","de":"DevOps","fr":"DevOps","tr":"DevOps","nl":"DevOps","ru":"DevOps","zh":"DevOps","pt_BR":"DevOps","pt_PT":"DevOps"}, back_translations: {"es":"Una prática cultural y técnica que combina equipes de desarrollo y operaciones para encurtar el ciclo de desarrollo de sistemas. Enfatiza automación, monitoramento, CI/CD y infraestrutura como código.","it":"Una pratico culturelle e technico combinant i equipes di sviluppo e d'exploitazione per raccourcir il cycle di sviluppo sistema. Met l'accent su l'automatisazione, la surveillanza, il CI/CD e l'infrastructure as code.","de":"Eine kulturelle und technische Praxis, die Entwicklungs- und Betriebsteams vereint, um den Systementwicklungszyklus zu verkürzen. Betont Automatisierung, Monitoring, CI/CD und Infrastructure as Code.","fr":"Une pratique culturelle et technique combinant les équipes de développement et d'exploitation pour raccourcir le cycle de développement système. Met l'accent sur l'automatisation, la surveillance, le CI/CD et l'infrastructure as code.","tr":"Sistem geliştirme yaşam döngüsünü kısaltmak için geliştirme ve operasyon ekiplerini birleştiren kültürel ve teknik bir uygulama. Otomasyon, izleme, CI/CD ve altyapı olarak kodu vurgular.","nl":"Een culturele en technische praktijk die ontwikkelings- en operationele teams combineert om de systeemontwikkelingscyclus te verkorten. Benadrukt automatisering, monitoring, CI/CD en infrastructure as code.","ru":"Культурная и техническая практика, объединяющая команды разработки и эксплуатации для сокращения цикла разработки систем. Акцент на автоматизации, мониторинге, CI/CD и инфраструктуре как коде.","zh":"一种将开发和运维团队相结合的文化与技术实践，以缩短系统开发生命周期。强调自动化、监控、CI/CD和基础设施即代码。","pt_BR":"Uma prática cultural e técnica que combina equipes de desenvolvimento e operações para encurtar o ciclo de desenvolvimento de sistemas. Enfatiza automação, monitoramento, CI/CD e infraestrutura como código.","pt_PT":"Uma prática cultural e técnica que combina equipas de desenvolvimento e operações para encurtar o ciclo de desenvolvimento de sistemas. Enfatiza automação, monitorização, CI/CD e infraestrutura como código."}},
  { id: 'dc-technology-0150', deck_id: 'deck-technology', sort_order: 150, front: "Moore's Law", back: "The observation by Gordon Moore (1965) that the number of transistors on a microchip doubles approximately every two years, driving exponential growth in computing power while costs decline. Slowing since ~2015." , front_translations: {"es":"Ley de Moore","it":"Legge di Moore","de":"Moores Gesetz","fr":"Loi de Moore","tr":"Moore Yasası","nl":"Wet van Moore","ru":"Закон Мура","zh":"摩尔定律","pt_BR":"Lei de Moore","pt_PT":"Lei de Moore"}, back_translations: {"es":"La observación de Gordon Moore (1965) de que el número de transistores en un microchip dobra aproximadamente a cada de los anos, impulsionando crecimiento exponencial del poder computacional mientras los costos disminuyen. Desacelerando desde ~2015.","it":"L'observazione di Gordon Moore (1965) selon laquelle il nombre di transistors su una puce double environ tutti i deux ans, entrainant una croissanza exponentielle della puissanza di calcul tandis che i couts diminuent. Ralentissement depuis environ 2015.","de":"Die Beobachtung von Gordon Moore (1965), dass sich die Anzahl der Transistoren auf einem Mikrochip etwa alle zwei Jahre verdoppelt, was exponentielles Wachstum der Rechenleistung bei sinkenden Kosten antreibt. Verlangsamt sich seit ca. 2015.","fr":"L'observation de Gordon Moore (1965) selon laquelle le nombre de transistors sur une puce double environ tous les deux ans, entraînant une croissance exponentielle de la puissance de calcul tandis que les coûts diminuent. Ralentissement depuis environ 2015.","tr":"Gordon Moore'un (1965) bir mikroçip üzerindeki transistör sayısının yaklaşık her iki yılda bir ikiye katlandığı gözlemi; bu, maliyetler düşerken işlem gücünde üstel büyümeyi sağlar. Yaklaşık 2015'ten beri yavaşlamaktadır.","nl":"De observatie van Gordon Moore (1965) dat het aantal transistoren op een microchip ongeveer elke twee jaar verdubbelt, wat exponentiële groei in rekenkracht aandrijft terwijl kosten dalen. Vertraagt sinds ca. 2015.","ru":"Наблюдение Гордона Мура (1965) о том, что количество транзисторов на микросхеме удваивается примерно каждые два года, обеспечивая экспоненциальный рост вычислительной мощности при снижении затрат. Замедляется с ~2015 года.","zh":"戈登·摩尔（1965年）的观察：微芯片上的晶体管数量大约每两年翻一番，推动计算能力指数级增长同时成本下降。自2015年左右开始放缓。","pt_BR":"A observação de Gordon Moore (1965) de que o número de transistores em um microchip dobra aproximadamente a cada dois anos, impulsionando crescimento exponencial do poder computacional enquanto os custos diminuem. Desacelerando desde ~2015.","pt_PT":"A observação de Gordon Moore (1965) de que o número de transístores num microchip duplica aproximadamente a cada dois anos, impulsionando crescimento exponencial do poder computacional enquanto os custos diminuem. A abrandar desde ~2015."}},
];
